        public MainForm()
        {
            // PRUEBA DEFINITIVA: MessageBox para confirmar que el constructor se ejecuta
            MessageBox.Show("Constructor MainForm iniciado", "DEBUG", MessageBoxButtons.OK, MessageBoxIcon.Information);
            
            // Log de emergencia - escribir INMEDIATAMENTE
            try { System.IO.File.WriteAllText("CONSTRUCTOR_ENTRY.txt", $"Constructor iniciado: {DateTime.Now}\n"); } catch { }
            
            string ctorLog = "constructor_error.txt";
            
            try
            {
                var timestamp = DateTime.Now.ToString("HHmmss");
                var baseDir = AppDomain.CurrentDomain.BaseDirectory;
                ctorLog = Path.Combine(baseDir, $"constructor_{timestamp}.txt");
                System.IO.File.WriteAllText(ctorLog, $"=== CONSTRUCTOR INICIADO === {DateTime.Now:HH:mm:ss.fff}\n");
                System.IO.File.AppendAllText(ctorLog, $"BaseDir: {baseDir}\n");
                
                // CRÍTICO: Inicializar dataDir PRIMERO antes de usarlo
                System.IO.File.AppendAllText(ctorLog, "Inicializando dataDir...\n");
                dataDir = portableMode 
                    ? Path.Combine(AppDomain.CurrentDomain.BaseDirectory, "data")
                    : Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.ApplicationData), "SlskDown");
                
                // Crear directorio si no existe
                if (!System.IO.Directory.Exists(dataDir))
                    System.IO.Directory.CreateDirectory(dataDir);
                System.IO.File.AppendAllText(ctorLog, $"dataDir OK: {dataDir}\n");
                
                // Configuración básica del formulario
                System.IO.File.AppendAllText(ctorLog, "Configurando formulario...\n");
                this.Text = "SlskDown - Soulseek Downloader";
                this.Size = new Size(1200, 750);
                this.BackColor = Color.FromArgb(30, 30, 30);
                this.StartPosition = FormStartPosition.CenterScreen;
                this.FormBorderStyle = FormBorderStyle.Sizable;
                this.MinimumSize = new Size(1000, 600);
                this.MaximizeBox = true;
                this.Font = new Font("Segoe UI", 9F, FontStyle.Regular, GraphicsUnit.Point);
                this.AutoScaleMode = AutoScaleMode.Dpi;
                System.IO.File.AppendAllText(ctorLog, "Formulario configurado OK\n");
                
                // MEJORA #5: Inicializar logs separados por sesión
                System.IO.File.AppendAllText(ctorLog, "Inicializando logs de sesión...\n");
                sessionId = DateTime.Now.ToString("yyyyMMdd_HHmmss");
                sessionDownloadLog = Path.Combine(dataDir, $"download_log_{sessionId}.txt");
                sessionUploadLog = Path.Combine(dataDir, $"upload_log_{sessionId}.txt");
                System.IO.File.AppendAllText(ctorLog, "Logs de sesión OK\n");
                
                // MEJORA #6: Habilitar KeyPreview para atajos de teclado
                System.IO.File.AppendAllText(ctorLog, "Configurando eventos de teclado...\n");
                this.KeyPreview = true;
                this.KeyDown += MainForm_KeyDown;
                System.IO.File.AppendAllText(ctorLog, "Eventos de teclado OK\n");
                
                // Inicializar optimizaciones de Nicotine+
                System.IO.File.AppendAllText(ctorLog, "Inicializando NicotineOptimizations...\n");
                nicotineOpts = new SlskDown.Core.NicotineOptimizations(() => SaveDownloadQueue());
                System.IO.File.AppendAllText(ctorLog, "NicotineOptimizations OK (auto-save cada 3min)\n");
                
                // Inicializar estructuras de datos
                System.IO.File.AppendAllText(ctorLog, "Inicializando estructuras de datos...\n");
                logBuffer = new LockFreeStructures.LockFreeRingBuffer<string>(10000);
                bloomFilter = new BloomFilter(expectedItems: 1_000_000, falsePositiveRate: 0.001);
                System.IO.File.AppendAllText(ctorLog, "Estructuras de datos OK\n");
                
                // Crear layout principal con sidebar
                System.IO.File.AppendAllText(ctorLog, "Creando layout moderno...\n");
                CreateModernLayout();
                System.IO.File.AppendAllText(ctorLog, "Layout creado OK\n");
                
                // Crear solo la pestaña de búsqueda al inicio (lazy loading para las demás)
                System.IO.File.AppendAllText(ctorLog, "Creando tab de búsqueda...\n");
                CreateSearchTab(searchContentPanel);
                System.IO.File.AppendAllText(ctorLog, "SearchTab OK\n");
                
                // Las demás pestañas se crearán cuando el usuario las seleccione
                System.IO.File.AppendAllText(ctorLog, "Configurando lazy loading para otras tabs...\n");
                tabControl.SelectedIndexChanged += TabControl_SelectedIndexChanged;
                System.IO.File.AppendAllText(ctorLog, "Lazy loading configurado OK\n");
                
                // Aplicar estilos modernos a todas las pestañas
                System.IO.File.AppendAllText(ctorLog, "Aplicando estilos modernos...\n");
                ApplyModernStyles();
                System.IO.File.AppendAllText(ctorLog, "Estilos aplicados OK\n");
                
                // Inicializar tooltips descriptivos
                System.IO.File.AppendAllText(ctorLog, "Inicializando tooltips...\n");
                InitializeTooltips();
                System.IO.File.AppendAllText(ctorLog, "Tooltips inicializados OK\n");
                
                // Cargar configuración básica (solo lo esencial para mostrar la ventana)
                System.IO.File.AppendAllText(ctorLog, "Cargando configuración básica...\n");
                LoadConfigBasic();
                System.IO.File.AppendAllText(ctorLog, "LoadConfigBasic OK\n");
                
                // Cargar el resto de forma asíncrona después de mostrar la ventana
                System.IO.File.AppendAllText(ctorLog, "Programando carga asíncrona...\n");
                this.Load += async (s, e) => await LoadDataAsync();
                System.IO.File.AppendAllText(ctorLog, "Carga asíncrona programada OK\n");
                
                // Auto-conectar si está habilitado
                if (chkAutoConnect?.Checked == true)
                {
                    System.IO.File.AppendAllText(ctorLog, "Auto-connect programado\n");
                    Task.Run(async () =>
                    {
                        await Task.Delay(1000);
                        SafeInvoke(() => btnConnect?.PerformClick());
                    });
                }
                
                // Manejador de redimensionamiento para responsividad
                System.IO.File.AppendAllText(ctorLog, "Configurando eventos...\n");
                this.Resize += MainForm_Resize;
                this.FormClosing += MainForm_FormClosing;
                System.IO.File.AppendAllText(ctorLog, "Eventos configurados OK\n");
                
                // Inicializar tiempo de carga para detectar cierres prematuros
                formLoadTime = DateTime.Now;
                System.IO.File.AppendAllText(ctorLog, $"formLoadTime inicializado: {formLoadTime:HH:mm:ss.fff}\n");
                
                System.IO.File.AppendAllText(ctorLog, "=== CONSTRUCTOR COMPLETADO EXITOSAMENTE ===\n");
            }
            catch (Exception ex)
            {
                var errorMsg = $"ERROR EN CONSTRUCTOR:\n{ex.Message}\n\nStack Trace:\n{ex.StackTrace}";
                System.IO.File.AppendAllText(ctorLog, $"\n\n!!! ERROR !!!\n{errorMsg}\n");
                System.IO.File.WriteAllText(Path.Combine(AppDomain.CurrentDomain.BaseDirectory, "constructor_error.txt"), errorMsg);
                MessageBox.Show(errorMsg, "Error Fatal en Constructor", MessageBoxButtons.OK, MessageBoxIcon.Error);
                throw;
            }
        }
        
        private DateTime formLoadTime = DateTime.MinValue;
        
        private void MainForm_FormClosing(object sender, FormClosingEventArgs e)
        {
            var closeLog = Path.Combine(AppDomain.CurrentDomain.BaseDirectory, $"close_attempt_{DateTime.Now:HHmmss}.txt");
            
            try
            {
                var elapsed = DateTime.Now - formLoadTime;
                System.IO.File.WriteAllText(closeLog, $"=== INTENTO DE CIERRE ===\n");
                System.IO.File.AppendAllText(closeLog, $"Tiempo desde carga: {elapsed.TotalSeconds:F2}s\n");
                System.IO.File.AppendAllText(closeLog, $"Razón: {e.CloseReason}\n");
                System.IO.File.AppendAllText(closeLog, $"Cancel: {e.Cancel}\n");
                System.IO.File.AppendAllText(closeLog, $"Stack Trace:\n{Environment.StackTrace}\n");
                
                // Evitar cierre durante los primeros 5 segundos (probablemente un error)
                if (elapsed.TotalSeconds < 5 && e.CloseReason == CloseReason.UserClosing)
                {
                    System.IO.File.AppendAllText(closeLog, "\n!!! CIERRE BLOQUEADO - Demasiado rápido !!!\n");
                    e.Cancel = true;
                    MessageBox.Show(
                        $"La ventana intentó cerrarse automáticamente después de {elapsed.TotalSeconds:F2} segundos.\n\n" +
                        $"Esto indica un problema de inicialización.\n\n" +
                        $"Revisa el archivo: {closeLog}",
                        "Cierre Bloqueado",
                        MessageBoxButtons.OK,
                        MessageBoxIcon.Warning
                    );
                    return;
                }
            }
            catch (Exception ex)
            {
                System.IO.File.AppendAllText(closeLog, $"\nERROR en FormClosing: {ex.Message}\n{ex.StackTrace}\n");
            }
            
            // Guardar configuración antes de cerrar
            try
            {
                SaveConfig();
                SaveConnectionLog();
                Log("Configuración guardada al cerrar la aplicación");
            }
            catch (Exception ex)
            {
                System.IO.File.AppendAllText(closeLog, $"\nERROR guardando config: {ex.Message}\n");
            }
        }
        
        private void ApplyModernStyles()
        {
            // Aplicar estilos modernos a todos los controles de forma recursiva
            ApplyModernStylesToControl(this);
        }
        
        private void ApplyModernStylesToControl(Control parent)
        {
            foreach (Control control in parent.Controls)
            {
                // Aplicar estilos según el tipo de control
                switch (control)
                {
                    case Button btn when !(btn is ModernButton):
                        // Botones más grandes con fuente normal
                        btn.Font = new Font("Segoe UI", 11, FontStyle.Regular);
                        btn.Height = Math.Max(btn.Height, 36);
                        btn.MinimumSize = new Size(100, 36);
                        btn.FlatStyle = FlatStyle.Flat;
                        btn.FlatAppearance.BorderSize = 0;
                        btn.Cursor = Cursors.Hand;
                        
                        // Aplicar colores según el texto del botón
                        if (btn.Text.Contains("Buscar"))
                            btn.BackColor = Color.FromArgb(0, 120, 215);
                        else if (btn.Text.Contains("Conectar") || btn.Text.Contains("Iniciar"))
                            btn.BackColor = Color.FromArgb(16, 185, 129);
                        else if (btn.Text.Contains("Detener") || btn.Text.Contains("Pausar"))
                            btn.BackColor = Color.FromArgb(239, 68, 68);
                        else if (btn.Text.Contains("Descargar"))
                            btn.BackColor = Color.FromArgb(59, 130, 246);
                        else
                            btn.BackColor = Color.FromArgb(45, 45, 45);
                        break;
                        
                    case TextBox txt:
                        // TextBoxes legibles
                        txt.Font = new Font("Segoe UI", 10, FontStyle.Regular);
                        txt.BackColor = Color.FromArgb(35, 35, 35);
                        txt.ForeColor = Color.White;
                        txt.BorderStyle = BorderStyle.FixedSingle;
                        break;
                        
                    case Label lbl:
                        // Labels legibles
                        if (lbl.Font.Size < 10)
                            lbl.Font = new Font("Segoe UI", 10, lbl.Font.Style);
                        
                        // Mejorar contraste de colores
                        if (lbl.ForeColor.GetBrightness() < 0.5)
                            lbl.ForeColor = Color.White;
                        break;
                        
                    case CheckBox chk:
                        // CheckBoxes legibles
                        chk.Font = new Font("Segoe UI", 10, FontStyle.Regular);
                        chk.ForeColor = Color.White;
                        break;
                        
                    case NumericUpDown num:
                        // NumericUpDowns
                        num.Font = new Font("Segoe UI", 10, FontStyle.Regular);
                        num.BackColor = Color.FromArgb(35, 35, 35);
                        num.ForeColor = Color.White;
                        break;
                        
                    case ComboBox cmb:
                        // ComboBoxes
                        cmb.Font = new Font("Segoe UI", 10, FontStyle.Regular);
                        cmb.BackColor = Color.FromArgb(35, 35, 35);
                        cmb.ForeColor = Color.White;
                        cmb.FlatStyle = FlatStyle.Flat;
                        break;
                        
                    case ListView lv:
                        // ListViews con mejor contraste
                        lv.Font = new Font("Segoe UI", 10, FontStyle.Regular);
                        lv.BackColor = Color.FromArgb(35, 35, 35);
                        lv.ForeColor = Color.White;
                        lv.BorderStyle = BorderStyle.None;
                        lv.FullRowSelect = true;
                        lv.GridLines = true;
                        break;
                        
                    case TabControl tab:
                        // TabControls
                        tab.Font = new Font("Segoe UI", 10, FontStyle.Regular);
                        break;
                }
                
                // Aplicar recursivamente a controles hijos
                if (control.HasChildren)
                {
                    ApplyModernStylesToControl(control);
                }
            }
        }
        
        private HashSet<int> initializedTabs = new HashSet<int>();
        
        private void TabControl_SelectedIndexChanged(object sender, EventArgs e)
        {
            if (tabControl == null) return;
            
            int selectedIndex = tabControl.SelectedIndex;
            
            // Si la pestaña ya fue inicializada, no hacer nada
            if (initializedTabs.Contains(selectedIndex))
                return;
            
            // Marcar como inicializada
            initializedTabs.Add(selectedIndex);
            
            // Crear el contenido de la pestaña según el índice
            try
            {
                var selectedTab = tabControl.TabPages[selectedIndex];
                var contentPanel = selectedTab.Controls.OfType<Panel>().FirstOrDefault();
                
                if (contentPanel == null) return;
                
                Log($"Inicializando pestaña: {selectedTab.Text}");
                
                switch (selectedIndex)
                {
                    case 1: // Descargas
                        CreateDownloadsTab(contentPanel);
                        break;
                    case 2: // Configuración
                        CreateConfigTab(contentPanel);
                        break;
                    case 3: // Autores
                        CreateAuthorsTab(contentPanel);
                        break;
                    case 4: // Archivos
                        CreateFilesTab(contentPanel);
                        break;
                    case 5: // Wishlist
                        CreateWishlistTab(contentPanel);
                        break;
                    case 6: // Calibre
                        CreateCalibreTab(contentPanel);
                        break;
                    case 7: // Historial
                        CreateHistoryTab(contentPanel);
                        break;
                    case 8: // Automático
                        CreateAutoTab(contentPanel);
                        break;
                    case 9: // Log
                        CreateLogTab(contentPanel);
                        break;
                }
                
                Log($"Pestaña inicializada: {selectedTab.Text}");
            }
            catch (Exception ex)
            {
                Log($"Error inicializando pestaña: {ex.Message}");
            }
        }
        
        private void MainForm_Resize(object sender, EventArgs e)
        {
            // Ajustar dinámicamente el padding basado en el tamaño de la ventana
            if (this.WindowState == FormWindowState.Maximized)
            {
                // Cuando está maximizado, reducir padding para aprovechar espacio
                if (searchContentPanel != null) searchContentPanel.Padding = new Padding(5);
                if (downloadsContentPanel != null) downloadsContentPanel.Padding = new Padding(5);
                if (configContentPanel != null) configContentPanel.Padding = new Padding(10);
            }
            else
            {
                // En modo normal, usar padding estándar
                if (searchContentPanel != null) searchContentPanel.Padding = new Padding(10);
                if (downloadsContentPanel != null) downloadsContentPanel.Padding = new Padding(10);
                if (configContentPanel != null) configContentPanel.Padding = new Padding(20);
            }
        }
        
        private void CreateModernLayout()
        {
            // Layout principal usando TableLayoutPanel
            var mainLayout = new TableLayoutPanel
            {
                Dock = DockStyle.Fill,
                ColumnCount = 2,
                RowCount = 1,
                BackColor = Color.FromArgb(30, 30, 30),
                Padding = new Padding(0),
                CellBorderStyle = TableLayoutPanelCellBorderStyle.None
            };
            
            // Columna 1: Sidebar (200px optimizado)
            mainLayout.ColumnStyles.Add(new ColumnStyle(SizeType.Absolute, 200));
            // Columna 2: Contenido (resto del espacio)
            mainLayout.ColumnStyles.Add(new ColumnStyle(SizeType.Percent, 100));
            mainLayout.RowStyles.Add(new RowStyle(SizeType.Percent, 100));
            
            // IMPORTANTE: Crear área de contenido PRIMERO (inicializa los paneles)
            CreateContentArea();
            mainLayout.Controls.Add(contentPanel, 1, 0);
            
            // Crear sidebar DESPUÉS (los botones necesitan referencias a los paneles)
            CreateSidebar();
            mainLayout.Controls.Add(sidebarPanel, 0, 0);
            
            this.Controls.Add(mainLayout);
            
            // MEJORA #6: Inicializar diccionario de pestañas
            tabPanels["Chat IA"] = chatAIContentPanel;
            tabPanels["Búsqueda"] = searchContentPanel;
            tabPanels["Descargas"] = downloadsContentPanel;
            tabPanels["Configuración"] = configContentPanel;
            tabPanels["Automático"] = autoContentPanel;
            tabPanels["Historial"] = historyContentPanel;
        }
        
        // MEJORA #6: Manejador de atajos de teclado
        private void MainForm_KeyDown(object sender, KeyEventArgs e)
        {
            // Ctrl+Shift+T para reabrir pestaña cerrada
            if (e.Control && e.Shift && e.KeyCode == Keys.T)
            {
                if (closedTabs.Count > 0)
                {
                    string tabName = closedTabs.Pop();
                    if (tabPanels.ContainsKey(tabName))
                    {
                        SwitchToPanel(tabPanels[tabName], tabName);
                        Log($"Pestaña reabierta: {tabName}");
                    }
                }
                e.Handled = true;
            }
        }
        
