        private ModernButton CreateNavButton(string text, Panel targetPanel, bool isActive)
        {
            var btn = new ModernButton
            {
                Text = text,
                AutoSize = false,
                Width = 180,
                Height = 40,
                BackColor = isActive ? Color.FromArgb(0, 120, 215) : Color.FromArgb(40, 40, 40),
                ForeColor = Color.White,
                Font = new Font("Segoe UI", 9.5f, isActive ? FontStyle.Bold : FontStyle.Regular),
                TextAlign = ContentAlignment.MiddleLeft,
                Padding = new Padding(10, 0, 10, 0),
                Cursor = Cursors.Hand,
                Margin = new Padding(0, 1, 0, 1)
            };
            
            btn.Click += (s, e) =>
            {
                ShowContentPanel(targetPanel, text);
                UpdateNavButtonStates(btn);
            };
            
            // Guardar referencia para actualizar estado activo
            if (!navButtons.ContainsKey(text))
                navButtons[text] = btn;
            
            return btn;
        }
        
        private void UpdateNavButtonStates(Button activeButton)
        {
            foreach (var kvp in navButtons)
            {
                var btn = kvp.Value;
                bool isActive = btn == activeButton;
                btn.BackColor = isActive ? Color.FromArgb(0, 120, 215) : Color.FromArgb(40, 40, 40);
                btn.Font = new Font("Segoe UI", 9.5f, isActive ? FontStyle.Bold : FontStyle.Regular);
            }
        }
        
        private ModernButton CreateStyledButton(string text, Color? backgroundColor = null, int width = 0, int height = 50)
        {
            return new ModernButton
            {
                Text = text,
                AutoSize = true,
                AutoSizeMode = AutoSizeMode.GrowAndShrink,
                MinimumSize = new Size(0, height),
                Padding = new Padding(20, 0, 20, 0),
                BackColor = backgroundColor ?? Color.FromArgb(0, 120, 215),
                ForeColor = Color.White,
                Font = new Font("Segoe UI", 10, FontStyle.Bold),
                Margin = new Padding(0, 0, 6, 6)
            };
        }
        
