        private void ShowContentPanel(Panel panel, string title)
        {
            // Validar que el panel no sea null
            if (panel == null) return;
            
            // Inicializar contenido si es la primera vez (lazy loading)
            if (panel == chatAIContentPanel && panel.Controls.Count == 0)
            {
                CreateChatAITab(panel);
                Log("Pestaña Chat IA inicializada correctamente");
            }
            
            // Ocultar todos los paneles (con validación de null)
            if (chatAIContentPanel != null) chatAIContentPanel.Visible = false;
            if (searchContentPanel != null) searchContentPanel.Visible = false;
            if (downloadsContentPanel != null) downloadsContentPanel.Visible = false;
            if (configContentPanel != null) configContentPanel.Visible = false;
            if (authorsContentPanel != null) authorsContentPanel.Visible = false;
            if (filesContentPanel != null) filesContentPanel.Visible = false;
            if (wishlistContentPanel != null) wishlistContentPanel.Visible = false;
            if (calibreContentPanel != null) calibreContentPanel.Visible = false;
            if (historyContentPanel != null) historyContentPanel.Visible = false;
            if (autoContentPanel != null) autoContentPanel.Visible = false;
            if (logContentPanel != null) logContentPanel.Visible = false;
            
            // Mostrar el panel seleccionado
            panel.Visible = true;
            panel.BringToFront();
            
            // Actualizar título
            if (lblTitle != null)
            {
                lblTitle.Text = title;
            }
        }
        
