            btnOpenDownloadFolder.Click += (s, e) => Process.Start("explorer.exe", downloadDir);
            filterFlow.Controls.Add(btnOpenDownloadFolder);
            
            // Botón Limpiar Resultados
            btnClearResults = CreateStyledButton("LIMPIAR", Color.FromArgb(180, 50, 50), 120, 45);
            btnClearResults.Margin = new Padding(0, 0, 8, 8);
            btnClearResults.Click += (s, e) =>
            {
                var result = ShowDarkDialog(
                    "¿Eliminar TODOS los resultados de búsqueda?",
                    "Confirmar limpieza",
                    MessageBoxButtons.YesNo,
                    "ADVERTENCIA"
                );
                
                if (result == DialogResult.Yes)
                {
                    SafeInvoke(() =>
                    {
                        lock (lvResultsLock)
                        {
                            lvResults.BeginUpdate();
                            try
                            {
                                lvResults.Items.Clear();
                                allResults?.Clear();
                                lblResultsCount.Text = "0 resultados";
                                Log("Resultados de búsqueda limpiados");
                            }
                            finally
                            {
                                lvResults.EndUpdate();
                            }
                        }
                    });
                }
            };
            filterFlow.Controls.Add(btnClearResults);
            
            // Botón Exportar CSV
            btnExportCSV = CreateStyledButton("EXPORTAR", Color.FromArgb(0, 150, 0), 130, 45);
            btnExportCSV.Margin = new Padding(0, 0, 8, 8);
            btnExportCSV.Click += (s, e) =>
            {
                try
                {
                    if (allResults == null || allResults.Count == 0)
                    {
                        MessageBox.Show("No hay resultados para exportar", "Exportar CSV", MessageBoxButtons.OK, MessageBoxIcon.Information);
                        return;
                    }
                    
                    var csvPath = Path.Combine(AppDomain.CurrentDomain.BaseDirectory, "search_results.csv");
                    using (var writer = new StreamWriter(csvPath, false, System.Text.Encoding.UTF8))
                    {
                        writer.WriteLine("Usuario,Archivo,Tamaño,Extensión,Carpeta,Slots Libres,Velocidad");
                        foreach (var result in allResults)
                        {
                            var size = result.Size > 1024 * 1024 ? $"{result.Size / (1024.0 * 1024):F2} MB" : $"{result.Size / 1024.0:F2} KB";
                            var ext = Path.GetExtension(result.Filename);
                            var folder = Path.GetDirectoryName(result.Filename)?.Replace("\\", "/");
                            writer.WriteLine($"\"{result.Username}\",\"{result.Filename}\",\"{size}\",\"{ext}\",\"{folder}\",{result.FreeUploadSlots},{result.UploadSpeed}");
                        }
                    }
                    
                    Log($"Resultados exportados a CSV: {allResults.Count} archivos");
                    MessageBox.Show($"Exportado {allResults.Count} resultados a:\n{csvPath}", "Exportar CSV", MessageBoxButtons.OK, MessageBoxIcon.Information);
                }
                catch (Exception ex)
                {
                    Log($"Error al exportar CSV: {ex.Message}");
                    MessageBox.Show($"Error al exportar:\n{ex.Message}", "Error", MessageBoxButtons.OK, MessageBoxIcon.Error);
                }
            };
            filterFlow.Controls.Add(btnExportCSV);
            
            // Botón Toggle Filtros Avanzados
            btnToggleFilters = CreateStyledButton("FILTROS +", Color.FromArgb(100, 100, 200), 130, 45);
            btnToggleFilters.Margin = new Padding(0, 0, 8, 8);
            btnToggleFilters.Click += (s, e) => ToggleAdvancedFilters();
            filterFlow.Controls.Add(btnToggleFilters);
            
            filterPanel.Controls.Add(filterFlow);
            mainLayout.Controls.Add(filterPanel, 0, 1);
            
            // Crear panel de filtros avanzados (inicialmente oculto) en fila 2
            CreateAdvancedFiltersPanel(mainLayout);
            
            // ListView normal para resultados de búsqueda (ocupa toda la fila 4)
            SafeLog( "Creando lvResults...\n");
            try
            {
                lvResults = new ModernListView 
                { 
                    Dock = DockStyle.Fill,
                    VirtualMode = false
                };
                SafeLog( "lvResults creado OK\n");
                
                // Configurar columnas
                lvResults.Columns.Add("Fuente", 60);
                lvResults.Columns.Add("Usuario", 150);
                lvResults.Columns.Add("Archivo", 500);
                lvResults.Columns.Add("Tamaño", 100);
                lvResults.Columns.Add("Extensión", 80);
                lvResults.Columns.Add("Carpeta", 220);
                SafeLog( "lvResults columnas agregadas\n");
                
                lvResults.DoubleClick += async (s, e) => await DownloadAsync();
                lvResults.KeyDown += (s, e) => 
                { 
                    if (e.KeyCode == Keys.Enter && lvResults.SelectedItems.Count > 0) 
                        Task.Run(async () => await DownloadMultipleAsync());
                    else if (e.KeyCode == Keys.A && e.Control)
                        foreach (ListViewItem item in lvResults.Items) item.Selected = true;
                    else if (e.KeyCode == Keys.Escape)
                        foreach (ListViewItem item in lvResults.Items) item.Selected = false;
                };
                SafeLog( "lvResults event handlers agregados\n");
                
                mainLayout.Controls.Add(lvResults, 0, 3);
                SafeLog( "lvResults agregado al mainLayout\n");
            }
            catch (Exception ex)
            {
                SafeLog( $"ERROR creando lvResults: {ex.Message}\n");
                throw;
            }
            
            lvResults.SelectedIndexChanged += (s, e) => UpdateSelectionCount();
            lvResults.ColumnClick += (s, e) => SortResults(e.Column);
            
            // Menú contextual
            var contextMenu = new ContextMenuStrip();
            contextMenu.BackColor = Color.FromArgb(45, 45, 45);
            contextMenu.ForeColor = Color.White;
            
            var downloadItem = new ToolStripMenuItem("Descargar");
            downloadItem.Click += async (s, e) => await DownloadAsync();
            contextMenu.Items.Add(downloadItem);
            
            var downloadMultipleItem = new ToolStripMenuItem("Descargar seleccionados");
            downloadMultipleItem.Click += async (s, e) => await DownloadMultipleAsync();
            contextMenu.Items.Add(downloadMultipleItem);
            
            contextMenu.Items.Add(new ToolStripSeparator());
            
            var blacklistItem = new ToolStripMenuItem("Bloquear usuario");
            blacklistItem.Click += (s, e) => BlacklistSelectedUser();
            contextMenu.Items.Add(blacklistItem);
            
            var selectAllItem = new ToolStripMenuItem("Seleccionar todo");
            selectAllItem.Click += (s, e) => { foreach (ListViewItem item in lvResults.Items) item.Selected = true; };
            contextMenu.Items.Add(selectAllItem);
            
            contextMenu.Items.Add(new ToolStripSeparator());
            
            var synopsisItem = new ToolStripMenuItem("Ver Sinopsis");
            synopsisItem.Click += async (s, e) => await ShowBookSynopsis();
            contextMenu.Items.Add(synopsisItem);
            
            var detectSeriesItem = new ToolStripMenuItem("Detectar series");
            detectSeriesItem.Click += (s, e) => ShowSeriesDetection();
            contextMenu.Items.Add(detectSeriesItem);
            
            var analyzeUserItem = new ToolStripMenuItem("Analizar colección de usuario");
            analyzeUserItem.Click += async (s, e) => await AnalyzeUserCollection();
            contextMenu.Items.Add(analyzeUserItem);
            
            lvResults.ContextMenuStrip = contextMenu;
            
            // Agregar el mainLayout al parent
            parent.Controls.Add(mainLayout);
            SafeLog( "CreateSearchTab: Completado\n");
        }
        
        private void CreateDownloadsTab(Panel parent)
        {
            SafeLog( "CreateDownloadsTab: Inicio\n");
            parent.BackColor = Color.FromArgb(30, 30, 30);
            
            // Usar TableLayoutPanel para layout robusto sin superposiciones
            var mainLayout = new TableLayoutPanel
            {
                Dock = DockStyle.Fill,
                RowCount = 4,
                ColumnCount = 1,
                Padding = new Padding(10),
                BackColor = Color.FromArgb(30, 30, 30),
                CellBorderStyle = TableLayoutPanelCellBorderStyle.None
            };
            
            // Fila 1: Botones de acción (Dinamica)
            mainLayout.RowStyles.Add(new RowStyle(SizeType.AutoSize));
            // Fila 2: Botones de filtro (Dinamica)
            mainLayout.RowStyles.Add(new RowStyle(SizeType.AutoSize));
            // Fila 3: Progreso y gráfico
            mainLayout.RowStyles.Add(new RowStyle(SizeType.Absolute, 140));
            // Fila 4: ListView de descargas (resto del espacio)
            mainLayout.RowStyles.Add(new RowStyle(SizeType.Percent, 100));
            
            mainLayout.ColumnStyles.Add(new ColumnStyle(SizeType.Percent, 100));
            
            SafeLog( "CreateDownloadsTab: TableLayoutPanel creado\n");
            
            // === FILA 1: PANEL DE BOTONES DE ACCIÓN ===
            var buttonPanel = new ModernCard
            {
                Dock = DockStyle.Top,
                AutoSize = true,
                BorderRadius = 8,
                Padding = new Padding(0),
                Margin = new Padding(0, 0, 0, 10)
            };
            
            // Título "Descargas"
            var titleLabel = new Label
            {
                Text = "Descargas",
                Font = new Font("Segoe UI", 14, FontStyle.Bold),
                ForeColor = Color.White,
                Dock = DockStyle.Top,
                Height = 40,
                TextAlign = ContentAlignment.MiddleLeft,
                Padding = new Padding(15, 10, 0, 0),
                BackColor = Color.Transparent
            };
            buttonPanel.Controls.Add(titleLabel);
            
            var buttonFlow = new FlowLayoutPanel
            {
                Dock = DockStyle.Top,
                AutoSize = true,
                BackColor = Color.Transparent,
                Padding = new Padding(8, 5, 8, 10),
                FlowDirection = FlowDirection.LeftToRight,
                WrapContents = true,
                AutoScroll = false
            };
            
            var btnClearAll = CreateStyledButton("LIMPIAR", Color.FromArgb(180, 50, 50), 130, 45);
            btnClearAll.Margin = new Padding(0, 0, 8, 8);
            
            var clearTooltip = new ToolTip();
            clearTooltip.SetToolTip(btnClearAll, "Eliminar todas las entradas de la lista de descargas, cola e historial");
            
            btnClearAll.Click += (s, e) =>
            {
                var result = ShowDarkDialog(
                    "¿Eliminar TODAS las entradas de la lista de descargas?\n\nEsto limpiará:\n• Cola de descargas\n• Historial de descargas\n• Estadísticas de proveedores",
                    "Confirmar limpieza total",
                    MessageBoxButtons.YesNo,
                    "ADVERTENCIA"
                );
                
                if (result == DialogResult.Yes)
                {
                    SafeInvoke(() =>
                    {
                        int count = lvDownloads.Items.Count;
                        lvDownloads.Items.Clear();
                        
                        // Limpiar cola interna de descargas
                        lock (downloadQueueLock)
                        {
                            downloadQueue.Clear();
                        }
                        
                        // Limpiar historial de descargas
                        lock (downloadHistoryLock)
                        {
                            downloadHistory.Clear();
                        }
                        
                        // Limpiar estadísticas de proveedores
                        lock (providerStatsLock)
                        {
                            providerStats.Clear();
                        }
                        
                        Log($"[Descargas] Cola reseteada completamente: {count} entradas eliminadas + cola interna + historial + estadísticas");
                    });
                }
            };
            
            // Botón Reintentar Fallidos (#10)
            var btnRetryFailed = CreateStyledButton("REINTENTAR", Color.FromArgb(200, 100, 0), 140, 45);
            btnRetryFailed.Margin = new Padding(0, 0, 8, 8);
            AddTooltip(btnRetryFailed, "Reintenta automáticamente todas las descargas que han fallado, reseteando los contadores de error");
            
            btnRetryFailed.Click += (s, e) =>
            {
                lock (downloadQueueLock)
                {
                    var failed = downloadQueue.Where(t => t.Status == DownloadStatus.Failed).ToList();
                    
                    if (failed.Count == 0)
                    {
                        ShowDarkDialog("No hay descargas fallidas para reintentar.", "Sin fallos", MessageBoxButtons.OK, "INFO");
                        return;
                    }
                    
                    var result = ShowDarkDialog(
                        $"¿Reintentar {failed.Count} descarga(s) fallida(s)?\n\nSe resetearán los contadores de reintentos.",
                        "Confirmar reintento",
                        MessageBoxButtons.YesNo,
                        "PREGUNTA"
                    );
                    
                    if (result == DialogResult.Yes)
                    {
                        foreach (var task in failed)
                        {
                            task.Status = DownloadStatus.Queued;
                            task.RetryCount = 0;
                            task.ErrorMessage = null;
                            task.FinalFailureTime = null;
                            task.LastRetryTime = null;
                            UpdateDownloadUI(task, "En cola (reintento manual)");
                        }
                        
                        Log($"[Descargas] {failed.Count} descarga(s) fallida(s) reintentadas manualmente");
                    }
                }
            };
            
            // Botón Buscar en Otros Usuarios
            var btnSearchOthers = CreateStyledButton("OTROS", Color.FromArgb(0, 120, 215), 120, 45);
            btnSearchOthers.Margin = new Padding(0, 0, 8, 8);
            AddTooltip(btnSearchOthers, "Busca archivos fallidos en otros usuarios de la red P2P para encontrar fuentes alternativas");
            btnSearchOthers.Click += async (s, e) => await SearchFailedInOtherUsers();
            
            // Botones de control de descargas
            var btnPauseAll = CreateStyledButton("PAUSAR", Color.FromArgb(200, 150, 0), 120, 45);
            btnPauseAll.Margin = new Padding(0, 0, 8, 8);
            AddTooltip(btnPauseAll, "Pausa todas las descargas activas y en cola, manteniendo el progreso actual para reanudar después");
            btnPauseAll.Click += (s, e) => PauseAllDownloads();
            
            var btnResumeAll = CreateStyledButton("REANUDAR", Color.FromArgb(0, 150, 0), 140, 45);
            btnResumeAll.Margin = new Padding(0, 0, 8, 8);
            AddTooltip(btnResumeAll, "Reanuda todas las descargas pausadas y continúa procesando la cola desde donde se detuvo");
            btnResumeAll.Click += async (s, e) => await ResumeAllDownloads();
            
            // Botón Ver Metadata
            var btnViewMetadata = CreateStyledButton("METADATA", Color.FromArgb(0, 120, 215), 140, 45);
            btnViewMetadata.Margin = new Padding(0, 0, 8, 8);
            AddTooltip(btnViewMetadata, "Muestra información detallada del archivo seleccionado: tamaño, formato, bitrate, duración y metadatos ID3");
            
            btnViewMetadata.Click += (s, e) => ShowMetadataForSelectedFile();
            
            // Botón Limpiar No Español
            var btnCleanupNonSpanish = CreateCleanupButton();
            
            buttonFlow.Controls.Add(btnClearAll);
            buttonFlow.Controls.Add(btnRetryFailed);
            buttonFlow.Controls.Add(btnSearchOthers);
            buttonFlow.Controls.Add(btnViewMetadata);
            buttonFlow.Controls.Add(btnCleanupNonSpanish);
            buttonFlow.Controls.Add(btnPauseAll);
            buttonFlow.Controls.Add(btnResumeAll);
            buttonPanel.Controls.Add(buttonFlow);
            mainLayout.Controls.Add(buttonPanel, 0, 0);
            
            // Estrategia hardcodeada a Balanceado
            queueStrategy = QueuePrioritizationStrategy.Balanced;
            
            // === FILA 2: BOTONES DE FILTRO ===
            var filterContainer = new ModernCard
            {
                Dock = DockStyle.Top,
                AutoSize = true,
                BorderRadius = 8,
                Padding = new Padding(5),
                Margin = new Padding(0, 0, 0, 10)
            };
            
            // Título "Filtros"
            var filterTitleLabel = new Label
            {
                Text = "Filtros",
                Font = new Font("Segoe UI", 11, FontStyle.Bold),
                ForeColor = Color.LightGray,
                Dock = DockStyle.Top,
                Height = 30,
                TextAlign = ContentAlignment.MiddleLeft,
                Padding = new Padding(10, 5, 0, 0),
                BackColor = Color.Transparent
            };
            filterContainer.Controls.Add(filterTitleLabel);
            
            var filterPanel = new FlowLayoutPanel
            {
                Dock = DockStyle.Top,
                AutoSize = true,
                BackColor = Color.Transparent,
                Padding = new Padding(6, 4, 6, 8),
                WrapContents = true,
                AutoScroll = false,
                FlowDirection = FlowDirection.LeftToRight
            };
            
            string currentFilter = "Todos";
            var allDownloadItems = new List<ListViewItem>(); // Mantener lista completa
            
            var btnFilterAll = CreateFilterButton("Todos", true);
            AddTooltip(btnFilterAll, "Muestra todas las descargas sin filtrar por estado");
            var btnFilterDownloading = CreateFilterButton("Descargando", false);
            AddTooltip(btnFilterDownloading, "Muestra solo las descargas que están actualmente en progreso");
            var btnFilterCompleted = CreateFilterButton("Completados", false);
            AddTooltip(btnFilterCompleted, "Muestra solo las descargas que se completaron exitosamente al 100%");
            var btnFilterFailed = CreateFilterButton("Fallidos", false);
            AddTooltip(btnFilterFailed, "Muestra solo las descargas que fallaron por error, timeout o cancelación");
            var btnFilterPending = CreateFilterButton("En cola", false);
            AddTooltip(btnFilterPending, "Muestra solo las descargas que están esperando en cola para ser procesadas");
            
            Action<string> ApplyFilter = (filter) =>
            {
                currentFilter = filter;
                
                // Actualizar botones
                btnFilterAll.BackColor = filter == "Todos" ? Color.FromArgb(0, 120, 215) : Color.FromArgb(50, 50, 50);
                btnFilterDownloading.BackColor = filter == "Descargando" ? Color.FromArgb(0, 120, 215) : Color.FromArgb(50, 50, 50);
                btnFilterCompleted.BackColor = filter == "Completados" ? Color.FromArgb(0, 120, 215) : Color.FromArgb(50, 50, 50);
                btnFilterFailed.BackColor = filter == "Fallidos" ? Color.FromArgb(0, 120, 215) : Color.FromArgb(50, 50, 50);
                btnFilterPending.BackColor = filter == "En cola" ? Color.FromArgb(0, 120, 215) : Color.FromArgb(50, 50, 50);
                
                // Aplicar filtro
                SafeInvoke(() =>
                {
                    lvDownloads.BeginUpdate();
                    
                    // Guardar todos los items actuales si la lista está vacía
                    if (allDownloadItems.Count == 0)
                    {
                        foreach (ListViewItem item in lvDownloads.Items)
                        {
                            allDownloadItems.Add(item);
                        }
                    }
                    
                    // Limpiar lista visible
                    lvDownloads.Items.Clear();
                    
                    // Agregar solo items que coincidan con el filtro
                    int count = 0;
                    foreach (var item in allDownloadItems.ToList())
                    {
                        if (item.SubItems.Count < 4) continue;
                        
                        string estado = item.SubItems[3].Text;
                        bool shouldShow = filter switch
                        {
                            "Descargando" => estado.Contains("Descargando"),
                            "Completados" => estado.Contains("Completado") || estado.Contains("100%"),
                            "Fallidos" => estado.Contains("Error") || estado.Contains("Timeout") || estado.Contains("Cancelado"),
                            "En cola" => estado.Contains("En cola") || estado.Contains("Pendiente"),
                            _ => true // "Todos"
                        };
                        
                        if (shouldShow)
                        {
                            lvDownloads.Items.Add(item);
                            count++;
                        }
                    }
                    
                    lvDownloads.EndUpdate();
                    
                    // Actualizar contador
                    Log($"Filtro '{filter}' aplicado: {count} de {allDownloadItems.Count} descargas mostradas");
                });
            };
            
            btnFilterAll.Click += (s, e) => ApplyFilter("Todos");
            btnFilterDownloading.Click += (s, e) => ApplyFilter("Descargando");
            btnFilterCompleted.Click += (s, e) => ApplyFilter("Completados");
            btnFilterFailed.Click += (s, e) => ApplyFilter("Fallidos");
            btnFilterPending.Click += (s, e) => ApplyFilter("En cola");
            
            filterPanel.Controls.Add(btnFilterAll);
            filterPanel.Controls.Add(btnFilterDownloading);
            filterPanel.Controls.Add(btnFilterCompleted);
            filterPanel.Controls.Add(btnFilterFailed);
            filterPanel.Controls.Add(btnFilterPending);
            filterContainer.Controls.Add(filterPanel);
            
            // Panel de estadísticas en tiempo real
            var statsRealtimePanel = new FlowLayoutPanel
            {
                Dock = DockStyle.Top,
                AutoSize = true,
                BackColor = Color.Transparent,
                Padding = new Padding(6, 8, 6, 4),
                WrapContents = false,
                FlowDirection = FlowDirection.LeftToRight
            };
            
            var statsTitle = new Label
            {
                Text = "📊 ESTADÍSTICAS DE DESCARGAS EN TIEMPO REAL",
                Font = new Font("Segoe UI", 9, FontStyle.Bold),
                ForeColor = Color.FromArgb(100, 200, 255),
                AutoSize = true,
                Margin = new Padding(0, 0, 0, 8)
            };
            filterContainer.Controls.Add(statsTitle);
            
            // Crear cajas de estadísticas
            var lblStatsQueue = new Label { Text = "37", Font = new Font("Segoe UI", 18, FontStyle.Bold), ForeColor = Color.White, AutoSize = true };
            var lblStatsDownloading = new Label { Text = "0", Font = new Font("Segoe UI", 18, FontStyle.Bold), ForeColor = Color.White, AutoSize = true };
            var lblStatsPaused = new Label { Text = "34", Font = new Font("Segoe UI", 18, FontStyle.Bold), ForeColor = Color.Orange, AutoSize = true };
            var lblStatsCompleted = new Label { Text = "0", Font = new Font("Segoe UI", 18, FontStyle.Bold), ForeColor = Color.LightGreen, AutoSize = true };
            
            var CreateStatBox = new Func<string, Label, Color, Panel>((title, valueLabel, iconColor) =>
            {
                var box = new Panel
                {
                    Width = 240,
                    Height = 80,
                    BackColor = Color.FromArgb(40, 40, 40),
                    Margin = new Padding(0, 0, 10, 0)
                };
                
                var icon = new Label
                {
                    Text = "■",
                    Font = new Font("Segoe UI", 12, FontStyle.Bold),
                    ForeColor = iconColor,
                    Location = new Point(10, 10),
                    AutoSize = true
                };
                box.Controls.Add(icon);
                
                var titleLabel = new Label
                {
                    Text = title,
                    Font = new Font("Segoe UI", 9),
                    ForeColor = Color.LightGray,
                    Location = new Point(30, 12),
                    AutoSize = true
                };
                box.Controls.Add(titleLabel);
                
                valueLabel.Location = new Point(10, 35);
                box.Controls.Add(valueLabel);
                
                return box;
            });
            
            statsRealtimePanel.Controls.Add(CreateStatBox("Total en cola", lblStatsQueue, Color.White));
            statsRealtimePanel.Controls.Add(CreateStatBox("Descargando", lblStatsDownloading, Color.LightBlue));
            statsRealtimePanel.Controls.Add(CreateStatBox("Pausadas", lblStatsPaused, Color.Orange));
            statsRealtimePanel.Controls.Add(CreateStatBox("Completadas", lblStatsCompleted, Color.LightGreen));
            
            filterContainer.Controls.Add(statsRealtimePanel);
            
            // Timer para actualizar estadísticas en tiempo real
            var statsRealtimeTimer = new System.Windows.Forms.Timer();
            statsRealtimeTimer.Interval = 1000;
            statsRealtimeTimer.Tick += (s, e) =>
            {
                lock (downloadQueueLock)
                {
                    int totalQueue = downloadQueue.Count(t => t.Status == DownloadStatus.Queued);
                    int downloading = downloadQueue.Count(t => t.Status == DownloadStatus.Downloading);
                    int paused = downloadQueue.Count(t => t.Status == DownloadStatus.Paused);
                    int completed = downloadQueue.Count(t => t.Status == DownloadStatus.Completed);
                    
                    SafeInvoke(() =>
                    {
                        lblStatsQueue.Text = totalQueue.ToString();
                        lblStatsDownloading.Text = downloading.ToString();
                        lblStatsPaused.Text = paused.ToString();
                        lblStatsCompleted.Text = completed.ToString();
                    });
                }
            };
            statsRealtimeTimer.Start();
            
            mainLayout.Controls.Add(filterContainer, 0, 1);
            
            // === FILA 3: PROGRESO Y GRÁFICO ===
            var statsCard = new ModernCard
            {
                Dock = DockStyle.Fill,
                BorderRadius = 8,
                Padding = new Padding(10)
            };
            
            var statsLayout = new TableLayoutPanel
            {
                Dock = DockStyle.Fill,
                RowCount = 2,
                ColumnCount = 1,
                BackColor = Color.Transparent,
                CellBorderStyle = TableLayoutPanelCellBorderStyle.None
            };
            statsLayout.RowStyles.Add(new RowStyle(SizeType.Percent, 40));
            statsLayout.RowStyles.Add(new RowStyle(SizeType.Percent, 60));
            statsLayout.ColumnStyles.Add(new ColumnStyle(SizeType.Percent, 100));
            
            // Barra de progreso global
            var progressPanel = new Panel
            {
                Dock = DockStyle.Fill,
                BackColor = Color.Transparent,
                Padding = new Padding(5)
            };
            
            lblProgressInfo = new Label
            {
                Text = "Progreso total: 0/0 (0%)",
                Dock = DockStyle.Top,
                ForeColor = Color.White,
                Font = new Font("Segoe UI", 9),
                Height = 20
            };
            
            progressBar = new ProgressBar
            {
                Dock = DockStyle.Top,
                Height = 20,
                Style = ProgressBarStyle.Continuous
            };
            
            progressPanel.Controls.Add(progressBar);
            progressPanel.Controls.Add(lblProgressInfo);
            statsLayout.Controls.Add(progressPanel, 0, 0);
            
            // Actualizar progreso global cada segundo
            var progressTimer = new System.Windows.Forms.Timer();
            progressTimer.Interval = 1000;
            progressTimer.Tick += (s, e) =>
            {
                lock (downloadQueueLock)
                {
                    int total = downloadQueue.Count;
                    int completed = downloadQueue.Count(t => t.Status == DownloadStatus.Completed);
                    int percentage = total > 0 ? (completed * 100 / total) : 0;
                    
                    SafeInvoke(() =>
                    {
                        progressBar.Maximum = Math.Max(total, 1);
                        progressBar.Value = Math.Min(completed, progressBar.Maximum);
                        lblProgressInfo.Text = $"Progreso total: {completed}/{total} ({percentage}%)";
                    });
                }
            };
            progressTimer.Start();
            
            // Panel de gráfico de velocidad con título
            var graphContainer = new Panel
            {
                Dock = DockStyle.Fill,
                BackColor = Color.Transparent,
                Padding = new Padding(5)
            };
            
            var lblGraphTitle = new Label
            {
                Text = "📊 Velocidad de descarga",
                Dock = DockStyle.Top,
                ForeColor = Color.LightGray,
                Font = new Font("Segoe UI", 9, FontStyle.Bold),
                Height = 20,
                Padding = new Padding(2, 0, 0, 0)
            };
            graphContainer.Controls.Add(lblGraphTitle);
            
            speedGraphPanel = new Panel
            {
                Dock = DockStyle.Fill,
                BackColor = Color.Transparent
            };
            speedGraphPanel.Paint += (s, e) =>
            {
                if (downloadSpeedHistory.Count < 2) return;
                
                var g = e.Graphics;
                g.SmoothingMode = System.Drawing.Drawing2D.SmoothingMode.AntiAlias;
                
                int width = speedGraphPanel.Width;
                int height = speedGraphPanel.Height;
                int padding = 15;
                int topPadding = 5;
                
                // Fondo con gradiente sutil
                using (var bgBrush = new System.Drawing.Drawing2D.LinearGradientBrush(
                    new Rectangle(0, 0, width, height),
                    Color.FromArgb(35, 35, 35),
                    Color.FromArgb(30, 30, 30),
                    90f))
                {
                    g.FillRectangle(bgBrush, 0, 0, width, height);
                }
                
                // Calcular escala
                long maxSpeed = downloadSpeedHistory.Count > 0 ? (long)downloadSpeedHistory.Max() : 1;
                if (maxSpeed == 0) maxSpeed = 1;
                
                float scaleY = (height - topPadding - padding - 20) / (float)maxSpeed;
                float scaleX = (width - 2 * padding) / (float)Math.Max(downloadSpeedHistory.Count - 1, 1);
                
                // Dibujar líneas de cuadrícula
                using (var gridPen = new Pen(Color.FromArgb(50, 50, 50), 1))
                {
                    for (int i = 0; i <= 4; i++)
                    {
                        int y = topPadding + (int)((height - topPadding - padding - 20) * i / 4.0);
                        g.DrawLine(gridPen, padding, y, width - padding, y);
                    }
                }
                
                // Dibujar área bajo la curva
                var points = new System.Drawing.Point[downloadSpeedHistory.Count + 2];
                for (int i = 0; i < downloadSpeedHistory.Count; i++)
                {
                    int x = padding + (int)(i * scaleX);
                    int y = height - padding - 20 - (int)(downloadSpeedHistory[i] * scaleY);
                    points[i] = new System.Drawing.Point(x, y);
                }
                points[downloadSpeedHistory.Count] = new System.Drawing.Point(width - padding, height - padding - 20);
                points[downloadSpeedHistory.Count + 1] = new System.Drawing.Point(padding, height - padding - 20);
                
                using (var areaBrush = new System.Drawing.Drawing2D.LinearGradientBrush(
                    new Rectangle(0, 0, width, height),
                    Color.FromArgb(80, 0, 200, 255),
                    Color.FromArgb(20, 0, 200, 255),
                    90f))
                {
                    g.FillPolygon(areaBrush, points);
                }
                
                // Dibujar línea de velocidad
                var linePoints = new System.Drawing.Point[downloadSpeedHistory.Count];
                for (int i = 0; i < downloadSpeedHistory.Count; i++)
                {
                    int x = padding + (int)(i * scaleX);
                    int y = height - padding - 20 - (int)(downloadSpeedHistory[i] * scaleY);
                    linePoints[i] = new System.Drawing.Point(x, y);
                }
                
                if (linePoints.Length > 1)
                {
                    using (var pen = new Pen(Color.FromArgb(0, 200, 255), 3))
                    {
                        g.DrawLines(pen, linePoints);
                    }
                }
                
                // Dibujar etiquetas con mejor formato
                string maxLabel = FormatSpeed(maxSpeed);
                using (var brush = new SolidBrush(Color.LightGray))
                using (var font = new Font("Segoe UI", 8, FontStyle.Bold))
                {
                    g.DrawString(maxLabel, font, brush, padding + 2, topPadding + 2);
                    g.DrawString("0", font, brush, padding + 2, height - padding - 18);
                    
                    // Etiqueta de velocidad actual
                    if (downloadSpeedHistory.Count > 0)
                    {
                        string currentSpeed = FormatSpeed(downloadSpeedHistory[downloadSpeedHistory.Count - 1]);
                        var size = g.MeasureString(currentSpeed, font);
                        g.DrawString(currentSpeed, font, new SolidBrush(Color.FromArgb(0, 200, 255)), 
                            width - padding - size.Width - 2, topPadding + 2);
                    }
                }
            };
            
            // speedGraphPanel.Controls.Add(lblCurrentSpeed);
            graphContainer.Controls.Add(speedGraphPanel);
            statsLayout.Controls.Add(graphContainer, 0, 1);
            
            // Timer para actualizar velocidad
            var speedTimer = new System.Windows.Forms.Timer();
            speedTimer.Interval = 1000;
            speedTimer.Tick += (s, e) =>
            {
                lock (downloadQueueLock)
                {
                    double totalSpeed = 0;
                    var activeDownloads = downloadQueue.Where(t => t.Status == DownloadStatus.Downloading).ToList();
                    
                    foreach (var task in activeDownloads)
                    {
                        if (task.LastSpeedMeasurement > 0)
                        {
                            totalSpeed += task.LastSpeedMeasurement;
                        }
                    }
                    
                    downloadSpeedHistory.Add(totalSpeed);
                    if (downloadSpeedHistory.Count > MAX_SPEED_HISTORY)
                    {
                        downloadSpeedHistory.RemoveAt(0);
                    }
                    
                    SafeInvoke(() =>
                    {
                        // lblCurrentSpeed.Text = $"Velocidad: {FormatSpeed(totalSpeed)}"; // Comentado - no mostrar velocidad
                        speedGraphPanel.Invalidate();
                    });
                }
            };
            speedTimer.Start();
            
            statsCard.Controls.Add(statsLayout);
            mainLayout.Controls.Add(statsCard, 0, 2);
            
            // === FILA 4: LISTVIEW DE DESCARGAS ===
            SafeLog( "CreateDownloadsTab: Creando lvDownloads...\n");
            lvDownloads = new ModernListView 
            { 
                Dock = DockStyle.Fill,
                VirtualMode = false
            };
            SafeLog( $"CreateDownloadsTab: lvDownloads creado, VirtualMode={lvDownloads.VirtualMode}\n");
            SafeLog( "CreateDownloadsTab: Event handlers agregados\n");
            lvDownloads.Columns.Add("Fuente", 60);
            lvDownloads.Columns.Add("Archivo", 300);
            SafeLog( "CreateDownloadsTab: Primera columna agregada\n");
            lvDownloads.Columns.Add("Usuario", 120);
            lvDownloads.Columns.Add("Progreso", 100);
            lvDownloads.Columns.Add("Estado", 100);
            lvDownloads.Columns.Add("Prioridad", 80);
            lvDownloads.Columns.Add("Tamaño", 80);
            lvDownloads.Columns.Add("Metadata", 70);
            lvDownloads.ColumnWidthChanged += (s, e) => SaveConfig(); // Guardar anchos al cambiar
            lvDownloads.DoubleClick += (s, e) => OpenDownloadedFile();
            lvDownloads.ColumnClick += (s, e) => SortDownloads(e.Column);
            
            // Menú contextual para descargas
            var downloadContextMenu = new ContextMenuStrip();
            downloadContextMenu.BackColor = Color.FromArgb(45, 45, 45);
            downloadContextMenu.ForeColor = Color.White;
            
            var pauseItem = new ToolStripMenuItem("Pausar descarga");
            pauseItem.Click += (s, e) => PauseDownload();
            downloadContextMenu.Items.Add(pauseItem);
            
            var resumeItem = new ToolStripMenuItem("Reanudar descarga");
            resumeItem.Click += (s, e) => ResumeDownload();
            downloadContextMenu.Items.Add(resumeItem);
            
            var cancelItem = new ToolStripMenuItem("Cancelar descarga");
            cancelItem.Click += (s, e) => CancelDownload();
            downloadContextMenu.Items.Add(cancelItem);
            
            var retryItem = new ToolStripMenuItem("Reintentar descarga");
            retryItem.Click += async (s, e) => await RetryDownload();
            downloadContextMenu.Items.Add(retryItem);
            
            downloadContextMenu.Items.Add(new ToolStripSeparator());
            
            // Submenú de prioridad
            var priorityMenu = new ToolStripMenuItem("Prioridad");
            priorityMenu.BackColor = Color.FromArgb(45, 45, 45);
            priorityMenu.ForeColor = Color.White;
            
            var urgentItem = new ToolStripMenuItem("Urgente");
            urgentItem.Click += (s, e) => SetDownloadPriority(DownloadPriority.High);
            priorityMenu.DropDownItems.Add(urgentItem);
            
            var highItem = new ToolStripMenuItem("Alta");
            highItem.Click += (s, e) => SetDownloadPriority(DownloadPriority.High);
            priorityMenu.DropDownItems.Add(highItem);
            
            var normalItem = new ToolStripMenuItem("Normal");
            normalItem.Click += (s, e) => SetDownloadPriority(DownloadPriority.Normal);
            priorityMenu.DropDownItems.Add(normalItem);
            
            var lowItem = new ToolStripMenuItem("Baja");
            lowItem.Click += (s, e) => SetDownloadPriority(DownloadPriority.Low);
            priorityMenu.DropDownItems.Add(lowItem);
            
            downloadContextMenu.Items.Add(priorityMenu);
            
            downloadContextMenu.Items.Add(new ToolStripSeparator());
            
            // Gestión de usuarios premium
            var addPremiumItem = new ToolStripMenuItem("Marcar usuario como Premium");
            addPremiumItem.Click += (s, e) => AddUserToPremiumList();
            downloadContextMenu.Items.Add(addPremiumItem);
            
            var removePremiumItem = new ToolStripMenuItem("Quitar de Premium");
            removePremiumItem.Click += (s, e) => RemoveUserFromPremiumList();
            downloadContextMenu.Items.Add(removePremiumItem);
            
            var viewPremiumItem = new ToolStripMenuItem("Ver Lista Premium");
            viewPremiumItem.Click += (s, e) => ShowPremiumUsersList();
            downloadContextMenu.Items.Add(viewPremiumItem);
            
            downloadContextMenu.Items.Add(new ToolStripSeparator());
            
            var openFileItem = new ToolStripMenuItem("Abrir archivo");
            openFileItem.Click += (s, e) => OpenDownloadedFile();
            downloadContextMenu.Items.Add(openFileItem);
            
            var openFolderItem = new ToolStripMenuItem("Abrir carpeta");
            openFolderItem.Click += (s, e) => Process.Start("explorer.exe", downloadDir);
            downloadContextMenu.Items.Add(openFolderItem);
            
            var metadataItem = new ToolStripMenuItem("Ver Metadata");
            metadataItem.Click += (s, e) => ShowMetadataForSelectedFile();
            downloadContextMenu.Items.Add(metadataItem);
            
            lvDownloads.ContextMenuStrip = downloadContextMenu;
            mainLayout.Controls.Add(lvDownloads, 0, 3);
            
            // Agregar el mainLayout al parent
            parent.Controls.Add(mainLayout);
            SafeLog( "CreateDownloadsTab: Completado\n");
        }
        
        private ModernButton CreateFilterButton(string text, bool isActive)
        {
            return new ModernButton
            {
                Text = text,
                AutoSize = true,
                AutoSizeMode = AutoSizeMode.GrowAndShrink,
                MinimumSize = new Size(100, 40),
                Padding = new Padding(15, 0, 15, 0),
                BackColor = isActive ? Color.FromArgb(0, 120, 215) : Color.FromArgb(50, 50, 50),
                ForeColor = Color.White,
                Font = new Font("Segoe UI", 9, FontStyle.Bold),
                Margin = new Padding(0, 0, 6, 6)
            };
        }
        
