            var lblMinSize = new Label { Text = "Tamaño mínimo (KB):", Size = new Size(180, 25), ForeColor = Color.LightGray, TextAlign = ContentAlignment.MiddleLeft };
            var numMinFileSize = new NumericUpDown { Size = new Size(80, 25), BackColor = Color.FromArgb(60, 60, 60), ForeColor = Color.White, Minimum = 0, Maximum = 1048576, Value = minFileSizeKB };
            numMinFileSize.ValueChanged += (s, e) => { minFileSizeKB = (int)numMinFileSize.Value; SaveConfig(); };
            var lblMinSizeInfo = new Label { Text = "(0 = sin límite, afecta Auto y Vaciar)", Size = new Size(250, 25), ForeColor = Color.Gray, Font = new Font("Segoe UI", 8), TextAlign = ContentAlignment.MiddleLeft };
