            // Modo Agresivo Temporal
            var aggressiveRow = new FlowLayoutPanel { FlowDirection = FlowDirection.LeftToRight, AutoSize = true, WrapContents = false, BackColor = Color.Transparent, Margin = new Padding(0, 10, 0, 5) };
            var btnAggressiveMode = new ModernButton 
            { 
                Text = "MODO AGRESIVO (30 MIN)", 
                AutoSize = true,
                AutoSizeMode = AutoSizeMode.GrowAndShrink,
                MinimumSize = new Size(0, 40),
                Padding = new Padding(20, 0, 20, 0), 
                BackColor = Color.FromArgb(200, 50, 50),
                Font = new Font("Segoe UI", 10, FontStyle.Bold)
            };
            btnAggressiveMode.Click += (s, e) =>
            {
                if (!aggressiveModeActive)
                {
                    // Activar modo agresivo
                    savedMaxParallelDownloads = maxParallelDownloads;
                    savedMaxSimultaneousDownloads = maxSimultaneousDownloads;
                    savedMaxParallelSearches = maxParallelSearches;
                    savedSearchTimeout = searchTimeout;
                    
                    // Valores agresivos
                    maxParallelDownloads = 15;
                    maxSimultaneousDownloads = 15;
                    maxParallelSearches = 20;
                    searchTimeout = 15;
                    
                    aggressiveModeActive = true;
                    aggressiveModeEndTime = DateTime.Now.AddMinutes(30);
                    
                    // Timer para desactivar automáticamente
                    if (aggressiveModeTimer == null)
                    {
                        aggressiveModeTimer = new System.Windows.Forms.Timer();
                        aggressiveModeTimer.Interval = 60000; // 1 minuto
                        aggressiveModeTimer.Tick += (ts, te) =>
                        {
                            if (DateTime.Now >= aggressiveModeEndTime)
                            {
                                // Restaurar valores
                                maxParallelDownloads = savedMaxParallelDownloads;
                                maxSimultaneousDownloads = savedMaxSimultaneousDownloads;
                                maxParallelSearches = savedMaxParallelSearches;
                                searchTimeout = savedSearchTimeout;
                                
                                aggressiveModeActive = false;
                                aggressiveModeTimer.Stop();
                                
                                btnAggressiveMode.Text = "MODO AGRESIVO (30 MIN)";
                                btnAggressiveMode.BackColor = Color.FromArgb(200, 50, 50);
                                
                                Log("Modo Agresivo DESACTIVADO - Valores restaurados");
                                ShowNotification("Modo Agresivo", "Modo agresivo desactivado. Valores restaurados.", ToolTipIcon.Info);
                            }
                            else
                            {
                                var remaining = (aggressiveModeEndTime - DateTime.Now).TotalMinutes;
                                btnAggressiveMode.Text = $"ACTIVO ({remaining:F0} MIN)";
                            }
                        };
                    }
                    
                    aggressiveModeTimer.Start();
                    btnAggressiveMode.Text = "ACTIVO (30 MIN)";
                    btnAggressiveMode.BackColor = Color.FromArgb(255, 100, 0);
                    
                    Log("Modo Agresivo ACTIVADO por 30 minutos:");
                    Log($"  • Descargas simultáneas: {maxSimultaneousDownloads}");
                    Log($"  • Búsquedas paralelas: {maxParallelSearches}");
                    Log($"  • Timeout: {searchTimeout}s");
                    ShowNotification("Modo Agresivo", "Modo agresivo activado por 30 minutos.\nMáxima velocidad!", ToolTipIcon.Warning);
                }
                else
                {
                    // Desactivar manualmente
                    maxParallelDownloads = savedMaxParallelDownloads;
                    maxSimultaneousDownloads = savedMaxSimultaneousDownloads;
                    maxParallelSearches = savedMaxParallelSearches;
                    searchTimeout = savedSearchTimeout;
                    
                    aggressiveModeActive = false;
                    aggressiveModeTimer?.Stop();
                    
                    btnAggressiveMode.Text = "MODO AGRESIVO (30 MIN)";
                    btnAggressiveMode.BackColor = Color.FromArgb(200, 50, 50);
                    
                    Log("Modo Agresivo DESACTIVADO manualmente");
                    ShowNotification("Modo Agresivo", "Modo agresivo desactivado.", ToolTipIcon.Info);
                }
            };
            var lblAggressiveInfo = new Label 
