        private void CreateConfigTab_OLD_BACKUP(Panel parent)
        {
            // BACKUP DEL CÓDIGO ORIGINAL CON POSICIONES ABSOLUTAS
            // Mantener por si se necesita restaurar funcionalidad específica
            parent.BackColor = Color.FromArgb(30, 30, 30);
            var panel = new Panel { Dock = DockStyle.Fill, Padding = new Padding(20), BackColor = Color.FromArgb(30, 30, 30), AutoScroll = true };

            // === HERRAMIENTAS ===
            var lblToolsSection = new Label { Text = "HERRAMIENTAS", Location = new Point(600, 350), Size = new Size(300, 20), ForeColor = Color.FromArgb(0, 120, 215), Font = new Font("Segoe UI", 10, FontStyle.Bold) };
            panel.Controls.Add(lblToolsSection);
            
            // ELIMINADO: Test Conexión - Auto-test cada 5 min con Modo Automático

            // Botón editar blacklist
            var btnEditBlacklist = CreateStyledButton("BLACKLIST", Color.FromArgb(180, 50, 50), 140, 45);
            btnEditBlacklist.Location = new Point(770, 285);
            btnEditBlacklist.Click += (s, e) =>
            {
                try
                {
                    // Asegurar que el archivo existe
                    if (!System.IO.File.Exists(blacklistAuthorsFile))
                    {
                        SaveBlacklistedAuthors();
                    }
                    
                    // Abrir con notepad
                    Process.Start("notepad.exe", blacklistAuthorsFile);
                    
                    MessageBox.Show(
                        "Edita la blacklist en el Notepad que se abrió.\n\n" +
                        "• Un autor por línea\n" +
                        "• Las líneas con # son comentarios\n" +
                        "• Guarda y cierra para aplicar cambios\n\n" +
                        "Los cambios se aplicarán al recargar la grilla.",
                        "Editar Blacklist",
                        MessageBoxButtons.OK,
                        MessageBoxIcon.Information);
                    
                    // Recargar blacklist después de un delay
                    Task.Delay(1000).ContinueWith(_ => 
                    {
                        SafeBeginInvoke(() => LoadBlacklistedAuthors());
                    });
                }
                catch (Exception ex)
                {
                    MessageBox.Show($"Error abriendo blacklist:\n{ex.Message}", "Error", MessageBoxButtons.OK, MessageBoxIcon.Error);
                }
            };
            panel.Controls.Add(btnEditBlacklist);

            // Botón consolidar carpetas
            var btnConsolidateFolders = new ModernButton 
            { 
                Text = "Consolidar Carpetas", 
                Location = new Point(600, 380), 
                AutoSize = true,
                AutoSizeMode = AutoSizeMode.GrowAndShrink,
                MinimumSize = new Size(0, 40),
                Padding = new Padding(20, 0, 20, 0), 
                BackColor = Color.FromArgb(0, 120, 215), 
                Font = new Font("Segoe UI", 10, FontStyle.Bold) 
            };
            btnConsolidateFolders.Click += async (s, e) => await ConsolidateDuplicateFolders();
            AddTooltip(btnConsolidateFolders, "Organiza archivos descargados moviendo libros del mismo autor a una carpeta única por autor");
            panel.Controls.Add(btnConsolidateFolders);

            // ELIMINADO: Borrar cachés - Auto-limpieza con Modo Automático
            
            // ELIMINADO: "Limpiar Duplicados" - Auto-detección con Rust + Modo Automático
            
            // ELIMINADO: Ver Backups - Acceso desde explorador (carpeta data/backups)
            
            // === GESTIÓN DE COLA DE DESCARGAS ===
            var lblQueueSection = new Label { Text = "COLA DE DESCARGAS", Location = new Point(600, 520), Size = new Size(300, 20), ForeColor = Color.FromArgb(0, 120, 215), Font = new Font("Segoe UI", 10, FontStyle.Bold) };
            panel.Controls.Add(lblQueueSection);
            
            // Botón Iniciar Cola
            var btnStartQueue = new ModernButton 
            { 
                Text = "Iniciar Cola", 
                Location = new Point(600, 550), 
                AutoSize = true,
                AutoSizeMode = AutoSizeMode.GrowAndShrink,
                MinimumSize = new Size(0, 40),
                Padding = new Padding(20, 0, 20, 0), 
                BackColor = Color.FromArgb(60, 120, 60), 
                Font = new Font("Segoe UI", 10, FontStyle.Bold) 
            };
            btnStartQueue.Click += (s, e) =>
            {
                try
                {
                    int resumed = 0;
                    lock (downloadQueueLock)
                    {
                        foreach (var task in downloadQueue)
                        {
                            if (task.Status == DownloadStatus.Paused)
                            {
                                task.Status = DownloadStatus.Queued;
                                UpdateDownloadUI(task, "En cola");
                                resumed++;
                            }
                        }
                    }
                    
                    if (resumed > 0)
                    {
                        AutoLog($"{resumed} descarga(s) reanudada(s)");
                        ShowDarkDialog(
                            $"Se reanudaron {resumed} descarga(s).\n\nLas descargas comenzarán automáticamente según la capacidad disponible.",
                            "Cola Iniciada",
                            MessageBoxButtons.OK,
                            "INFO");
                    }
                    else
                    {
                        ShowDarkDialog(
                            "No hay descargas pausadas para reanudar.",
                            "Cola Iniciada",
                            MessageBoxButtons.OK,
                            "INFO");
                    }
                }
                catch (Exception ex)
                {
                    AutoLog($"Error al iniciar cola: {ex.Message}");
                    ShowDarkDialog($"Error al iniciar cola:\n{ex.Message}", "Error", MessageBoxButtons.OK, "ERROR");
                }
            };
            panel.Controls.Add(btnStartQueue);
            
            // Botón RESET COMPLETO
            var btnResetAll = new ModernButton 
            { 
                Text = "RESET COMPLETO", 
                Location = new Point(600, 475), 
                AutoSize = true,
                AutoSizeMode = AutoSizeMode.GrowAndShrink,
                MinimumSize = new Size(0, 40),
                Padding = new Padding(20, 0, 20, 0), 
                BackColor = Color.FromArgb(200, 0, 0), 
                Font = new Font("Segoe UI", 10, FontStyle.Bold) 
            };
            btnResetAll.Click += async (s, e) =>
            {
                var result = ShowDarkDialog(
                    "ADVERTENCIA: Esta acción:\n\n" +
                    "DETENDRÁ todas las descargas activas\n" +
                    "ELIMINARÁ todos los datos:\n\n" +
                    "• Base de datos SQLite completa\n" +
                    "• Cachés (búsqueda, Calibre, países, batch)\n" +
                    "• Resultados de búsqueda automática (CSV y JSON)\n" +
                    "• Historial de descargas y cola de descargas\n" +
                    "• Estadísticas y progreso de purga\n" +
                    "• Búsquedas recientes\n" +
                    "• Blacklist de usuarios y autores\n" +
                    "• Watchlist y Wishlist\n" +
                    "• Lista de autores\n" +
                    "• Memoria caché (metadata, deduplicación, etc.)\n\n" +
                    "NO se eliminará la configuración de usuario/contraseña.\n\n" +
                    "¿Estás seguro de que quieres continuar?",
                    "Reset Completo",
                    MessageBoxButtons.YesNo,
                    "ADVERTENCIA");
                
                if (result == DialogResult.Yes)
                {
                    try
                    {
                        AutoLog("═══════════════════════════════════════");
                        AutoLog("INICIANDO RESET COMPLETO");
                        AutoLog("═══════════════════════════════════════");
                        
                        var filesToDelete = new[]
                        {
                            // Cachés
                            Path.Combine(dataDir, "search_cache.json"),
                            calibreCacheFile,
                            countryCachePath,
                            progressPath, // batch_progress.json
                            
                            // Base de datos SQLite
                            dbPath,
                            
                            // Resultados de búsqueda
                            autoResultsCsvPath,
                            autoSearchResultsJsonPath,
                            
                            // Historial y estadísticas
                            downloadHistoryPath,
                            statsPath,
                            
                            // Progreso de purga
                            Path.Combine(dataDir, "purge_progress.json"),
                            
                            // Búsquedas
                            historyPath,
                            
                            // Blacklist y watchlist
                            blacklistAuthorsFile,
                            blacklistPath,
                            watchlistPath,
                            wishlistPath,
                            
                            // Cola de descargas
                            downloadQueuePath,
                            
                            // Autores
                            authorsPath,
                            Path.Combine(dataDir, "last_authors_file.txt")
                        };
                        
                        int deleted = 0;
                        long totalSize = 0;
                        
                        foreach (var path in filesToDelete)
                        {
                            try
                            {
                                if (System.IO.File.Exists(path))
                                {
                                    var size = new FileInfo(path).Length;
                                    System.IO.File.Delete(path);
                                    deleted++;
                                    totalSize += size;
                                    AutoLog($"   Eliminado: {Path.GetFileName(path)} ({FormatFileSize(size)})");
                                }
                            }
                            catch (Exception ex)
                            {
                                AutoLog($"   Error eliminando {Path.GetFileName(path)}: {ex.Message}");
                            }
                        }
                        
                        // Detener gestor de descargas
                        downloadManagerRunning = false;
                        await Task.Delay(1000); // Esperar a que termine el loop
                        
                        // Cancelar todas las descargas activas
                        lock (downloadQueueLock)
                        {
                            foreach (var task in downloadQueue)
                            {
                                try
                                {
                                    task.CancellationToken?.Cancel();
                                }
                                catch { }
                            }
                        }
                        
                        // Cerrar conexión a BD antes de eliminarla
                        try
                        {
                            dbConnection?.Close();
                            dbConnection?.Dispose();
                            dbConnection = null;
                        }
                        catch { }
                        
                        // Limpiar datos en memoria
                        autoSearchResults = new System.Collections.Concurrent.ConcurrentBag<AutoSearchFileResult>();
                        lock (downloadQueueLock)
                        {
                            downloadQueue.Clear();
                        }
                        lock (downloadHistoryLock)
                        {
                            downloadHistory.Clear();
                        }
                        lock (providerStatsLock)
                        {
                            providerStats.Clear();
                        }
                        lock (authorIndexLock)
                        {
                            filesByAuthorIndex.Clear();
                        }
                        
                        searchCache.Clear();
                        blacklistedAuthors.Clear();
                        carbarherFilesCache.Clear();
                        carbarherCacheLoaded = false;
                        wishlist.Clear();
                        fileExistsCache.Clear();
                        hashToFilePath.Clear();
                        allAuthorsData.Clear();
                        filteredAuthorsData.Clear();
                        
                        // Limpiar caché de metadata (MemoryCache no tiene Flush)
                        // Se limpiará automáticamente por tiempo de expiración
                        
                        // Limpiar grilla de descargas
                        SafeInvoke(() =>
                        {
                            if (lvDownloads != null)
                            {
                                lvDownloads.Items.Clear();
                            }
                            if (lvAutoAuthors != null)
                            {
                                // Limpiar items en modo normal
                                lvAutoAuthors.Items.Clear();
                            }
                        });
                        
                        AutoLog("");
                        AutoLog($"Reset completado:");
                        AutoLog($"   {deleted} archivos eliminados");
                        AutoLog($"   {FormatFileSize(totalSize)} liberados");
                        AutoLog($"   Memoria limpiada");
                        AutoLog("═══════════════════════════════════════");
                        AutoLog("");
                        
                        ShowDarkDialog(
                            $"Reset completado exitosamente\n\n" +
                            $"• {deleted} archivos eliminados\n" +
                            $"• {FormatFileSize(totalSize)} liberados\n\n" +
                            "La aplicación ha vuelto a condiciones iniciales.",
                            "Reset Completo",
                            MessageBoxButtons.OK,
                            "INFO");
                    }
                    catch (Exception ex)
                    {
                        AutoLog($"Error durante reset: {ex.Message}");
                        ShowDarkDialog($"Error durante reset:\n{ex.Message}", "Error", MessageBoxButtons.OK, "ERROR");
                    }
                }
            };
            panel.Controls.Add(btnResetAll);
            
            // Nota informativa sobre guardado automático
            var lblAutoSave = new Label 
            { 
                Text = "Los cambios se guardan automáticamente", 
                Location = new Point(20, 420), 
                Size = new Size(400, 30), 
                ForeColor = Color.FromArgb(100, 200, 100),
                Font = new Font("Segoe UI", 10, FontStyle.Italic)
            };
            panel.Controls.Add(lblAutoSave);
            
            parent.Controls.Add(panel);
        }
        
        private Panel CreateConfigSection(string title, Color titleColor)
        {
            var panel = new FlowLayoutPanel
            {
                AutoSize = true,
                FlowDirection = FlowDirection.TopDown,
                WrapContents = false,
                Margin = new Padding(0, 0, 0, 20),
                Padding = new Padding(0, 0, 0, 10)
            };
            
            var lblSection = new Label 
            { 
                Text = title, 
                AutoSize = true, 
                ForeColor = titleColor, 
                Font = new Font("Segoe UI", 10, FontStyle.Bold),
                Margin = new Padding(0, 0, 0, 10)
            };
            panel.Controls.Add(lblSection);
            
            return panel;
        }
        
        private FlowLayoutPanel CreateConfigRow(string labelText)
        {
            var row = new FlowLayoutPanel 
            { 
                AutoSize = true, 
                FlowDirection = FlowDirection.LeftToRight,
                Margin = new Padding(0, 5, 0, 5)
            };
            
            var lbl = new Label 
            { 
                Text = labelText, 
                Width = 200, 
                ForeColor = Color.LightGray,
                TextAlign = ContentAlignment.MiddleLeft
            };
            row.Controls.Add(lbl);
            
            return row;
        }
        
        private async Task ConnectToSoulseek()
        {
            // Obtener información del caller para debugging
            var stackTrace = new System.Diagnostics.StackTrace(1, false);
            var callerMethod = stackTrace.GetFrame(0)?.GetMethod()?.Name ?? "Unknown";
            
            // Protección contra intentos simultáneos
            lock (this)
            {
                if (isConnecting)
                {
                    Log($"Ya hay un intento de conexión en curso - ignorando llamada desde {callerMethod}");
                    return;
                }
                isConnecting = true;
            }
            
            Log($"ConnectToSoulseek llamado desde: {callerMethod}");
            
            if (client != null && client.State.HasFlag(SoulseekClientStates.Connected))
            {
                Log("Ya está conectado");
                isConnecting = false;
                return;
            }
            
            try
            {
                UpdateControlEnabled(btnConnect, false);
                UpdateControlText(lblStatus, "Conectando...");
                UpdateControl(lblStatus, c => c.ForeColor = Color.Orange);
                
                // Verificar credenciales
                if (string.IsNullOrWhiteSpace(username))
                {
                    Log("Error: Usuario vacío");
                    throw new Exception("El nombre de usuario no puede estar vacío");
                }
                if (string.IsNullOrWhiteSpace(password))
                {
                    Log("Error: Contraseña vacía");
                    throw new Exception("La contraseña no puede estar vacía");
                }
                
                Log($"Intentando conectar como: {username}");
                Log($"   Usuario: {username.Length} caracteres");
                Log($"   Password: {password.Length} caracteres");
                
                // Test de conectividad básico
                try
                {
                    Log($"Verificando conectividad con vps.slsknet.org:2271...");
                    using (var tcpClient = new System.Net.Sockets.TcpClient())
                    {
                        var connectTask = tcpClient.ConnectAsync("vps.slsknet.org", 2271);
                        if (await Task.WhenAny(connectTask, Task.Delay(5000)) == connectTask)
                        {
                            Log($"Servidor alcanzable");
                        }
                        else
                        {
                            Log($"Timeout al conectar con el servidor (5s)");
                        }
                    }
                }
                catch (Exception testEx)
                {
                    Log($"Error de conectividad: {testEx.Message}");
                }
            
            // Intentar con varios puertos si falla
            int maxAttempts = 5;
            bool connected = false;
            
            for (int attempt = 1; attempt <= maxAttempts && !connected; attempt++)
                {
                    try
                    {
                        // Limpiar cliente anterior si existe
                        if (client != null)
                        {
                            try 
                            { 
                                client.Dispose(); 
                            } 
                            catch { }
                            client = null;
                        }
                        
                        // Generar puerto aleatorio
                        int randomPort = new Random().Next(50000, 60000);
                        Log($"[CONEXIÓN] Intento {attempt}/{maxAttempts} - Puerto: {randomPort}");
                        
                        // Intentar configurar port forwarding automático
                        int finalPort = randomPort;
                        if (portForwardingManager != null)
                        {
                            Log("Intentando configurar port forwarding automático...");
                            var (success, mappedPort) = await portForwardingManager.AutoConfigure(randomPort);
                            if (success)
                            {
                                finalPort = mappedPort;
                                Log($"✓ Port forwarding configurado en puerto {mappedPort}");
                            }
                            else
                            {
                                Log("⚠ Port forwarding no disponible, usando puerto local");
                            }
                        }
                        
                        var options = new SoulseekClientOptions(
                            listenPort: finalPort,
                            enableDistributedNetwork: true,
                            enableListener: true,
                            autoAcknowledgePrivateMessages: false,
                            autoAcknowledgePrivilegeNotifications: false,
                            acceptPrivateRoomInvitations: false,
                            serverConnectionOptions: new ConnectionOptions(
                                connectTimeout: 30000,
                                inactivityTimeout: 600000
                            ),
                            userEndPointCache: null
                        );
                        
                        Log($"[CONEXIÓN] Servidor: vps.slsknet.org:2271");
                        Log($"[CONEXIÓN] Usuario: {username}");
                        Log($"[CONEXIÓN] Puerto local: {finalPort}");
                        
                        if (client != null)
                        {
                            Log($"ADVERTENCIA: Ya existe un cliente - esto NO debería pasar");
                            Log($"   Estado del cliente existente: {client.State}");
                        }
                        
                        client = new SoulseekClient(options);
                        
                        // Inicializar búsquedas correlacionadas ahora que tenemos el cliente
                        correlatedSearch = new SlskDown.Core.CorrelatedSearch(client);
                        Log($"Cliente creado, iniciando conexión...");
                        
                        // Configurar TCP Keepalive (reemplaza ServerPing obsoleto)
                        try
                        {
                            var socket = client.GetType().GetProperty("Socket", System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance)?.GetValue(client) as System.Net.Sockets.Socket;
                            if (socket != null)
                            {
                                SlskDown.Core.NicotineOptimizations.ConfigureTcpKeepalive(socket);
                                Log($"TCP Keepalive configurado (60s keepalive, 10s interval)");
                            }
                        }
                        catch (Exception ex)
                        {
                            Log($"No se pudo configurar TCP Keepalive: {ex.Message}");
                        }
                        
                        // Suscribirse a eventos de conexión (estilo Nicotine+)
                        client.StateChanged += (sender, args) =>
                        {
                            Log($"Estado cambiado: {args.PreviousState} -> {args.State}");
                            connectionLog.Add(new ConnectionEvent
                            {
                                Timestamp = DateTime.Now,
                                EventType = "StateChanged",
                                State = args.State.ToString(),
                                Reason = $"{args.PreviousState} → {args.State}"
                            });
                            lastActivityTime = DateTime.Now;
                        };
                        
                        client.LoggedIn += (sender, args) =>
                        {
                            Log($"[CONEXIÓN] Login exitoso - Estado: {client.State}");
                            Log($"[CONEXIÓN] Conectado a Soulseek en {DateTime.Now:HH:mm:ss}");
                            connectionStartTime = DateTime.Now;
                            connectionLog.Add(new ConnectionEvent
                            {
                                Timestamp = DateTime.Now,
                                EventType = "LoggedIn",
                                State = client.State.ToString(),
                                Reason = "Login exitoso"
                            });
                            lastActivityTime = DateTime.Now;
                            
                            // Notificación visual
                            ShowNotification("Conectado", "Conexión a Soulseek establecida", ToolTipIcon.Info);
                        };
                        
                        // Suscribirse a evento de desconexión
                        client.Disconnected += async (sender, args) =>
                        {
                            Log($"Evento Disconnected disparado - Estado: {client?.State}, Connected: {connected}, Mensaje: {args.Message}");
                            
                            // Solo loguear si ya estábamos conectados (no durante el intento inicial)
                            if (client.State == SoulseekClientStates.Disconnected && connected)
                            {
                                Log($"Evento de desconexión detectado: {args.Message}");
                                
                                // Registrar estadísticas de desconexión
                                if (connectionStartTime.HasValue)
                                {
                                    var sessionDuration = DateTime.Now - connectionStartTime.Value;
                                    totalConnectedTime += sessionDuration;
                                    Log($"Sesión duró: {sessionDuration.TotalMinutes:F1} minutos");
                                }
                                
                                lastDisconnectTime = DateTime.Now;
                                disconnectCount++;
                                disconnectHistory.Add(DateTime.Now);
                                
                                // Detectar si es "Relogged" (otra sesión con misma cuenta)
                                bool isRelogged = args.Message.Contains("Relogged") || args.Message.Contains("logged in from another location");
                                
                                connectionLog.Add(new ConnectionEvent
                                {
                                    Timestamp = DateTime.Now,
                                    EventType = isRelogged ? "Relogged" : "Disconnected",
                                    State = client.State.ToString(),
                                    Reason = args.Message,
                                    Duration = connectionStartTime.HasValue ? DateTime.Now - connectionStartTime.Value : null
                                });
                                
                                connectionStartTime = null;
                                
                                // Marcar como desconectado
                                connected = false;
                                
                                // Limpiar estados de Nicotine+ al desconectar
                                nicotineOpts?.ClearAllOnDisconnect();
                                Log("Estados de transferencias limpiados (Nicotine+ pattern)");
                                
                                // Si es Relogged, deshabilitar auto-reconexión temporalmente
                                if (isRelogged)
                                {
                                    AutoLog("OTRA SESIÓN DETECTADA (Relogged)");
                                    AutoLog("Otra instancia inició sesión con tu cuenta");
                                    AutoLog("Deshabilitando auto-reconexión por 60s para evitar conflictos...");
                                    
                                    // Notificación visual
                                    ShowNotification("Sesión duplicada", "Otra instancia inició sesión con tu cuenta", ToolTipIcon.Warning);
                                    
                                    var tempAutoReconnect = autoReconnect;
                                    autoReconnect = false;
                                    
                                    _ = Task.Run(async () =>
                                    {
                                        await Task.Delay(60000);
                                        autoReconnect = tempAutoReconnect;
                                        Log("Auto-reconexión reactivada");
                                    });
                                    
                                    return;
                                }
                                
                                // Evitar reconexiones si ya hay una en curso o si estamos conectando
                                if (isReconnecting || isConnecting)
                                {
                                    Log("Reconexión ya en curso, ignorando evento");
                                    return;
                                }
                                
                                AutoLog("═══════════════════════════════════════");
                                AutoLog($"DESCONECTADO DE SOULSEEK");
                                AutoLog($"Razón: {args.Message}");
                                
                                // También registrar en log general
                                Log($"Desconectado de Soulseek - Razón: {args.Message}");
                                
                                // Notificación visual
                                ShowNotification("Desconectado", $"Razón: {args.Message}", ToolTipIcon.Warning);
                                
                                // Delay fijo como Nicotine+ (10s normal, 30s si kicked)
                                int delaySeconds = args.Message.Contains("Kicked") ? 30 : 10;
                                
                                Log($"autoReconnect = {autoReconnect}");
                                
                                if (autoReconnect)
                                {
                                    if (args.Message.Contains("Kicked"))
                                    {
                                        AutoLog("EXPULSADO DEL SERVIDOR");
                                        AutoLog("Esto puede indicar:");
                                        AutoLog("   • Otra sesión activa con la misma cuenta");
                                        AutoLog("   • Cliente oficial (SoulseekQt) abierto");
                                        AutoLog("   • Cuenta siendo usada en otro dispositivo");
                                        AutoLog($"Esperando {delaySeconds}s antes de reconectar...");
                                    }
                                    else
                                    {
                                        AutoLog($"Auto-reconexión activada, reintentando en {delaySeconds}s...");
                                        Log($"Auto-reconexión activada, reintentando en {delaySeconds}s...");
                                    }
                                    
                                    Log($"Esperando {delaySeconds}s antes de llamar a CheckAndReconnect()...");
                                    await Task.Delay(delaySeconds * 1000);
                                    Log("Llamando a CheckAndReconnect()...");
                                    await CheckAndReconnect();
                                }
                                else
                                {
                                    AutoLog("Auto-reconexión DESHABILITADA");
                                    AutoLog("Reconecta manualmente desde la pestaña Config");
                                }
                                AutoLog("═══════════════════════════════════════");
                                AutoLog("");
                            }
                            else
                            {
                                Log($"Evento Disconnected ignorado - Estado: {client?.State}, Connected: {connected}");
                            }
                        };
                        
                        // Usar timeout para evitar esperas infinitas (45s para dar tiempo suficiente)
                        Log($"Intentando autenticar con el servidor...");
                        using (var cts = new CancellationTokenSource(TimeSpan.FromSeconds(45)))
                        {
                            try
                            {
                                await client.ConnectAsync(username, password, cts.Token);
                            }
                            catch (Exception connEx)
                            {
                                Log($"Error durante ConnectAsync: {connEx.GetType().Name}");
                                Log($"   Mensaje: {connEx.Message}");
                                if (connEx.InnerException != null)
                                {
                                    Log($"   Inner: {connEx.InnerException.GetType().Name} - {connEx.InnerException.Message}");
                                }
                                throw;
                            }
                        }
                        
                        Log($"[CONEXIÓN] Conexión exitosa en puerto {randomPort}");
                        Log($"[CONEXIÓN] Estado del cliente: {client.State}");
                        Log($"[CONEXIÓN] Red distribuida: {(options.EnableDistributedNetwork ? "HABILITADA ✓" : "DESHABILITADA ✗")}");
                        Log($"[CONEXIÓN] Sesión iniciada correctamente");
                        
                        AutoLog("═══════════════════════════════════════");
                        AutoLog($"✅ CONECTADO A SOULSEEK");
                        AutoLog($"👤 Usuario: {username}");
                        AutoLog($"🔌 Puerto: {randomPort}");
                        AutoLog($"🌐 Red distribuida: {(options.EnableDistributedNetwork ? "HABILITADA ✓" : "DESHABILITADA ✗")}");
                        AutoLog($"🖥️ Servidor: vps.slsknet.org:2271");
                        AutoLog("═══════════════════════════════════════");
                        AutoLog("");
                        
                        // También mostrar en log general
                        Log($"Conectado a Soulseek como {username} (puerto {randomPort})");
                        Log($"Servidor: vps.slsknet.org:2271");
                        
                        // DESHABILITADO: Pool de conexiones
                        // Soulseek NO permite múltiples conexiones simultáneas con la misma cuenta
                        // El servidor expulsa ("Kicked from server") cuando detecta múltiples sesiones
                        // Esta era la causa del problema de desconexión constante
                        /*
                        _ = Task.Run(async () =>
                        {
                            try
                            {
                                clientPool = new SoulseekClient[poolSize];
                                for (int i = 0; i < poolSize; i++)
                                {
                                    var poolPort = randomPort + i + 1;
                                    var poolOptions = new SoulseekClientOptions(
                                        listenPort: poolPort,
                                        enableDistributedNetwork: true,
                                        autoAcknowledgePrivateMessages: false,
                                        autoAcknowledgePrivilegeNotifications: false,
                                        acceptPrivateRoomInvitations: false,
                                        serverConnectionOptions: new ConnectionOptions(
                                            connectTimeout: 10000,
                                            inactivityTimeout: 15000
                                        )
                                    );
                                    
                                    clientPool[i] = new SoulseekClient(poolOptions);
                                    await clientPool[i].ConnectAsync(username, password);
                                    AutoLog($"Cliente pool #{i + 1} conectado (puerto {poolPort})");
                                    await Task.Delay(500);
                                }
                                AutoLog($"Pool de {poolSize} conexiones Soulseek listo");
                            }
                            catch (Exception poolEx)
                            {
                                AutoLog($"Error inicializando pool: {poolEx.Message}");
                            }
                        });
                        */
                        AutoLog("Pool de conexiones deshabilitado (Soulseek no permite múltiples sesiones)");
                        
                        UpdateControlText(btnConnect, "Desconectar");
                        UpdateControlEnabled(btnConnect, true);
                        UpdateControlEnabled(btnSearch, true);
                        UpdateControlText(lblStatus, "Conectado");
                        UpdateControl(lblStatus, c => c.ForeColor = Color.FromArgb(0, 200, 0));
                        
                        connected = true;
                        
                        // Iniciar gestor de descargas automáticamente tras conexión exitosa
                        if (!downloadManagerRunning)
                        {
                            AutoLog("Iniciando gestor de descargas automáticamente tras conexión...");
                            _ = Task.Run(async () => await StartDownloadManager());
                        }
                    }
                    catch (Exception ex)
                    {
                        client?.Dispose();
                        client = null;
                        
                        if (attempt < maxAttempts)
                        {
                            // Diagnosticar el tipo de error
                            string errorType = ex.GetType().Name;
                            Log($"Intento {attempt} falló ({errorType}): {ex.Message}");
                            
                            // Si es error de autenticación, no reintentar
                            if (ex.Message.Contains("Invalid credentials") || 
                                ex.Message.Contains("Login failed"))
                            {
                                Log("Error de autenticación - Verifica usuario y contraseña");
                                throw; // Re-lanzar para salir del bucle
                            }
                            
                            // Backoff lineal más suave: 3s, 6s, 9s, 12s
                            int delayMs = attempt * 3000;
                            Log($"Esperando {delayMs/1000}s antes del siguiente intento...");
                            await Task.Delay(delayMs);
                        }
                        else
                        {
                            // Último intento falló
                            string errorMsg = ex.Message;
                            string errorType = ex.GetType().Name;
                            
                            if (errorMsg.Contains("Failed to start listening") || errorMsg.Contains("port may be in use"))
                            {
                                errorMsg = $"No se pudo encontrar un puerto disponible después de {maxAttempts} intentos.\nCierra otras instancias de SlskDown.";
                            }
                            else if (errorMsg.Contains("Remote connection closed") || errorMsg.Contains("host remoto"))
                            {
                                errorMsg = $"El servidor Soulseek rechazó la conexión.\n\nPosibles causas:\n• Credenciales incorrectas (usuario/contraseña)\n• Servidor temporalmente no disponible\n• Demasiados intentos de conexión\n\nEspera unos minutos antes de reintentar.";
                            }
                            else if (errorMsg.Contains("timeout") || errorType.Contains("Timeout"))
                            {
                                errorMsg = $"Timeout de conexión.\n\nVerifica tu conexión a internet y firewall.";
                            }
                            
                            Log($"Error final de conexión ({errorType}): {ex.Message}");
                            if (btnConnect != null)
                            {
                                btnConnect.Text = "Conectar";
                                btnConnect.Enabled = true;
                            }
                            if (lblStatus != null) lblStatus.Text = "Error de conexión";
                            
                            MessageBox.Show(errorMsg, "Error de Conexión", MessageBoxButtons.OK, MessageBoxIcon.Error);
                        }
                    }
                }
            }
            finally
            {
                isConnecting = false;
            }
        }
        
        private async Task ConnectAsync()
        {
            if (client != null && client.State.HasFlag(SoulseekClientStates.Connected))
            {
                // Desconectar
                client.Dispose();
                client = null;
                
                // Optimización #8: Limpiar pool de conexiones
                if (clientPool != null)
                {
                    foreach (var poolClient in clientPool)
                    {
                        try { poolClient?.Dispose(); } catch { }
                    }
                    clientPool = null;
                    AutoLog("Pool de conexiones cerrado");
                }
                
                if (btnConnect != null) btnConnect.Text = "Conectar";
                if (btnSearch != null) btnSearch.Enabled = false;
                if (lblStatus != null)
                {
                    lblStatus.Text = "Desconectado";
                    lblStatus.ForeColor = Color.Gray;
                }
                Log("[CONEXIÓN] Desconectado manualmente");
                Log($"[CONEXIÓN] Desconexión manual a las {DateTime.Now:HH:mm:ss}");
            }
            else
            {
                // Conectar
                await ConnectToSoulseek();
            }
        }
        
        private (int totalFiles, int processedResponses, int processedFiles, int filteredBySize, int filteredByExt, int filteredBySpanish, int filteredByBlacklist) 
            ProcessAndDisplaySearchResponses(
                IEnumerable<Soulseek.SearchResponse> responses, 
                long minSizeBytes, long maxSizeBytes, string extFilter, bool spanishOnly,
                int totalFiles, int processedResponses, int processedFiles,
                int filteredBySize, int filteredByExt, int filteredBySpanish, int filteredByBlacklist,
                bool isExactPhrase = false, string exactPhrase = "")
        {
            foreach (var response in responses)
            {
                processedResponses++;
                
                if (blacklist.Contains(response.Username))
                {
                    filteredByBlacklist++;
                    continue;
                }
                
                foreach (var file in response.Files.Take(500))
                {
                    processedFiles++;
                    
                    // MEJORA #1: Filtrar por frase exacta si está activado
                    if (isExactPhrase && !file.Filename.Contains(exactPhrase, StringComparison.OrdinalIgnoreCase))
                    {
                        continue;
                    }
                    
                    if (minSizeBytes > 0 && file.Size < minSizeBytes)
                    {
                        filteredBySize++;
                        continue;
                    }
                    if (maxSizeBytes < long.MaxValue && file.Size > maxSizeBytes)
                    {
                        filteredBySize++;
                        continue;
                    }
                    
                    string fileExt = Path.GetExtension(file.Filename).ToLower();
                    if (!MatchesCategory(fileExt, extFilter))
                    {
                        filteredByExt++;
                        continue;
                    }
                    
                    if (chkSpanishOnly.Checked && !IsSpanishText(file.Filename))
                    {
                        filteredBySpanish++;
                        continue;
                    }
                    
                    var item = new ListViewItem(new string[] 
                    { 
                        response.Username,
                        Path.GetFileName(file.Filename), 
                        FormatSize(file.Size), 
                        fileExt,
                        Path.GetDirectoryName(file.Filename) ?? ""
                    });
                    
                    // Crear SearchResultItem
                    var searchItem = new SearchResultItem
                    {
                        Username = response.Username,
                        Filename = Path.GetFileName(file.Filename),
                        Size = file.Size,
                        Extension = Path.GetExtension(file.Filename).ToLower(),
                        FolderPath = Path.GetDirectoryName(file.Filename) ?? "",
                        UploadSpeed = response.UploadSpeed
                    };
                    allResults.Add(searchItem);
                    totalFiles++;
                }
            }
            
            // Actualizar Virtual ListView
            UpdateSearchResults(allResults);
            SafeInvoke(() => lblStatus.Text = $"Buscando... {totalFiles:N0} encontrados");
            
            return (totalFiles, processedResponses, processedFiles, filteredBySize, filteredByExt, filteredBySpanish, filteredByBlacklist);
        }
        
        private async Task SearchAsync()
        {
            if (client == null || string.IsNullOrWhiteSpace(cmbSearch.Text)) 
                return;
            
            // Guardar en historial (thread-safe)
            string searchText = "";
            SafeInvoke(() => searchText = cmbSearch.Text);
            
            if (!string.IsNullOrWhiteSpace(searchText) && !searchHistory.Contains(searchText))
            {
                searchHistory.Insert(0, searchText);
                if (searchHistory.Count > 20) searchHistory.RemoveAt(20);
                
                SafeInvoke(() =>
                {
                    cmbSearch.Items.Clear();
                    cmbSearch.Items.AddRange(searchHistory.ToArray());
                });
                
                SaveSearchHistory();
            }
            
            // Estadísticas
            totalSearches++;
            
            // Búsqueda múltiple (separada por comas)
            var searchTerms = cmbSearch.Text.Split(new[] { ',' }, StringSplitOptions.RemoveEmptyEntries)
                .Select(t => t.Trim())
                .Where(t => !string.IsNullOrEmpty(t))
                .ToList();
            
            if (searchTerms.Count > 1)
            {
                Log($"Búsqueda múltiple: {searchTerms.Count} términos (máx {maxParallelSearches} simultáneos)");
                await SearchMultipleTerms(searchTerms);
                return;
            }
            
            if (client == null || !client.State.HasFlag(SoulseekClientStates.Connected))
            {
                if (lblStatus != null)
                {
                    lblStatus.Text = "No conectado - Presiona el botón CONECTAR primero";
                    lblStatus.ForeColor = Color.Red;
                }
                Log($"Error: Cliente no conectado. Estado actual: {client?.State.ToString() ?? "null"}");
                
                // Verificar si está en proceso de conexión
                if (btnConnect != null && btnConnect.Text == "Conectar" && btnConnect.Enabled == false)
                {
                    MessageBox.Show("La conexión está en proceso. Espera unos segundos e intenta de nuevo.", 
                        "Conectando...", MessageBoxButtons.OK, MessageBoxIcon.Information);
                }
                else
                {
                    MessageBox.Show("Debes conectarte a Soulseek antes de buscar.\n\nPresiona el botón 'Conectar' en la parte superior.", 
                        "No Conectado", MessageBoxButtons.OK, MessageBoxIcon.Warning);
                }
                return;
            }
            
            Log($"Iniciando búsqueda: {cmbSearch.Text}");
            Log($"Estado del cliente: {client.State}");
            Log($"Red distribuida: {enableDistributedNetwork}");

            try
            {
                Log("Creando CancellationTokenSource...");
                // Crear nuevo CancellationTokenSource
                searchCancellationTokenSource?.Cancel();
                searchCancellationTokenSource = new System.Threading.CancellationTokenSource();
                
                Log("Actualizando controles UI...");
                if (btnSearch != null) btnSearch.Enabled = false;
                if (btnStopSearch != null) btnStopSearch.Enabled = true;
                if (lblStatus != null) lblStatus.Text = "Buscando...";
                
                Log("Limpiando resultados anteriores...");
                ClearSearchResults();
                allResults.Clear();
                
                Log("Calculando parámetros de búsqueda...");
                // Interpretar 0 como sin límite (int.MaxValue)
                int actualResponseLimit = responseLimit == 0 ? int.MaxValue : responseLimit;
                int actualFileLimit = fileLimit == 0 ? int.MaxValue : fileLimit;
                int actualTimeout = searchTimeout == 0 ? int.MaxValue : searchTimeout * 1000;
                
                Log($"Parámetros: responseLimit={actualResponseLimit}, fileLimit={actualFileLimit}, timeout={actualTimeout/1000}s");
                
                Log("Creando SearchOptions...");
                var searchOptions = new Soulseek.SearchOptions(
                    filterResponses: true,
                    maximumPeerQueueLength: actualResponseLimit,
                    searchTimeout: actualTimeout
                );
                
                Log($"Iniciando búsqueda en red Soulseek...");
                Log($"Término de búsqueda: '{cmbSearch.Text}'");
                
                // MEJORA #1: Búsqueda por frases exactas con comillas
                string searchTerm = cmbSearch.Text.Trim();
                bool isExactPhrase = searchTerm.StartsWith("\"") && searchTerm.EndsWith("\"") && searchTerm.Length > 2;
                if (isExactPhrase)
                {
                    searchTerm = searchTerm.Substring(1, searchTerm.Length - 2);
                    Log($"Búsqueda de frase exacta: '{searchTerm}'");
                }
                
                Log("Obteniendo filtros...");
                long minSizeBytes = numMinSize != null ? (long)(numMinSize.Value * 1024) : 0;
                long maxSizeBytes = numMaxSize != null && numMaxSize.Value > 0 ? (long)(numMaxSize.Value * 1024) : long.MaxValue;
                string extFilter = cmbExtension?.SelectedItem?.ToString();
                bool spanishOnly = chkSpanishOnly?.Checked ?? false; // Capturar valor antes del thread
                
                string maxSizeStr = maxSizeBytes == long.MaxValue ? "sin límite" : $"{maxSizeBytes/1024}KB";
                Log($"Filtros: minSize={minSizeBytes/1024}KB, maxSize={maxSizeStr}, ext={extFilter}, español={spanishOnly}");
                
                int processedResponses = 0;
                int processedFiles = 0;
                int filteredBySize = 0;
                int filteredByExt = 0;
                int filteredBySpanish = 0;
                int filteredByBlacklist = 0;
                int totalFiles = 0;
                
                // Búsqueda continua inteligente: continúa mientras haya respuestas nuevas
                if (continuousSearch && actualTimeout > 2000)
                {
                    Log($"Modo búsqueda continua inteligente: mostrando resultados cada 2 segundos...");
                    Log($"Se detendrá después de 3 búsquedas consecutivas sin resultados nuevos");
                    
                    int maxIterations = actualTimeout / 2000;
                    var allResponses = new List<Soulseek.SearchResponse>();
                    var seenUsers = new HashSet<string>();
                    int emptySearches = 0;
                    int iteration = 0;
                    
                    while (iteration < maxIterations && emptySearches < 3)
                    {
                        searchCancellationTokenSource.Token.ThrowIfCancellationRequested();
                        iteration++;
                        
                        Log($"📡 Búsqueda {iteration} (2s)...");
                        
                        var shortOptions = new Soulseek.SearchOptions(
                            filterResponses: true,
                            maximumPeerQueueLength: actualResponseLimit,
                            searchTimeout: 2000  // 2 segundos
                        );
                        
                        var searchResult = await client.SearchAsync(
                            SearchQuery.FromText(cmbSearch.Text),
                            options: shortOptions
                        );
                        
                        // Filtrar respuestas nuevas (no repetidas)
                        var newResponses = searchResult.Responses
                            .Where(r => !seenUsers.Contains(r.Username))
                            .ToList();
                        
                        if (newResponses.Count == 0)
                        {
                            emptySearches++;
                            Log($"Sin respuestas nuevas ({emptySearches}/3)");
                            
                            if (emptySearches >= 3)
                            {
                                Log($"Deteniendo búsqueda: 3 intentos consecutivos sin resultados nuevos");
                                break;
                            }
                        }
                        else
                        {
                            emptySearches = 0;  // Resetear contador si hay respuestas nuevas
                            
                            foreach (var r in newResponses)
                            {
                                seenUsers.Add(r.Username);
                                allResponses.Add(r);
                            }
                            
                            Log($"+{newResponses.Count} respuestas nuevas (total: {allResponses.Count})");
                            
                            // Procesar y mostrar resultados nuevos inmediatamente
                            foreach (var response in newResponses)
                            {
                                processedResponses++;
                                
                                // Filtrar usuarios de blacklist
                                if (blacklist.Contains(response.Username))
                                {
                                    filteredByBlacklist++;
                                    continue;
                                }
                                
                                foreach (var file in response.Files.Take(500))
                                {
                                    processedFiles++;
                                    
                                    // MEJORA #1: Filtrar por frase exacta si está activado
                                    if (isExactPhrase && !file.Filename.Contains(searchTerm, StringComparison.OrdinalIgnoreCase))
                                    {
                                        continue;
                                    }
                                    
                                    // Descartar archivos de tamaño 0
                                    if (file.Size == 0)
                                    {
                                        filteredBySize++;
                                        continue;
                                    }
                                    
                                    // Descartar archivos sin extensión
                                    string fileExt = Path.GetExtension(file.Filename);
                                    if (string.IsNullOrEmpty(fileExt))
                                    {
                                        filteredByExt++;
                                        continue;
                                    }
                                    fileExt = fileExt.ToLower();
                                    
                                    // Filtrar archivos que ya tiene carbarher
                                    string fileName = Path.GetFileName(file.Filename);
                                    if (carbarherCacheLoaded && carbarherFilesCache.Contains(fileName))
                                    {
                                        filteredByBlacklist++;
                                        continue;
                                    }
                                    
                                    if (minSizeBytes > 0 && file.Size < minSizeBytes)
                                    {
                                        filteredBySize++;
                                        continue;
                                    }
                                    if (maxSizeBytes < long.MaxValue && file.Size > maxSizeBytes)
                                    {
                                        filteredBySize++;
                                        continue;
                                    }
                                    if (!MatchesCategory(fileExt, extFilter))
                                    {
                                        filteredByExt++;
                                        continue;
                                    }
                                    
                                    // Filtro de idioma español
                                    if (spanishOnly && !IsSpanishText(file.Filename))
                                    {
                                        filteredBySpanish++;
                                        continue;
                                    }
                                    
                                    // Crear SearchResultItem en lugar de ListViewItem
                                    var searchItem = new SearchResultItem
                                    {
                                        Username = response.Username,
                                        Filename = Path.GetFileName(file.Filename),
                                        Size = file.Size,
                                        Extension = fileExt,
                                        FolderPath = Path.GetDirectoryName(file.Filename) ?? "",
                                        Bitrate = file.BitRate ?? 0,
                                        Length = file.Length ?? 0,
                                        UploadSpeed = response.UploadSpeed,
                                        QueueLength = response.QueueLength,
                                        FreeUploadSlots = 0
                                    };
                                    
                                    allResults.Add(searchItem);
                                    totalFiles++;
                                    
                                    // Actualizar grilla progresivamente cada 50 archivos (reducir carga UI)
                                    if (totalFiles % 50 == 0)
                                    {
                                        UpdateSearchResults(allResults);
                                        SafeInvoke(() =>
                                        {
                                            if (lblResultsCount != null) lblResultsCount.Text = $"{totalFiles:N0} archivos...";
                                            if (lblStatus != null) lblStatus.Text = $"Buscando... {totalFiles:N0} encontrados";
                                        });
                                    }
                                }
                            }
                        }
                    }
                    
                    Log($"Búsqueda continua completada. Total: {allResponses.Count} respuestas en {iteration} búsquedas");
                    
                    // Forzar actualización final (ignorar throttle)
                    lastUpdateTime = DateTime.MinValue;
                    UpdateSearchResults(allResults);
                    var results = allResponses;
                }
                else
                {
                    // Búsqueda normal (una sola vez) con retry automático
                    Log($"Esperando respuestas (timeout: {actualTimeout/1000}s)...");
                    
                    totalSearches++;
                    var searchResult = await RetryPolicy.ExecuteWithRetry(
                        async () => await client.SearchAsync(
                            SearchQuery.FromText(cmbSearch.Text),
                            options: searchOptions
                        ),
                        maxAttempts: 3,
                        initialDelayMs: 1000,
                        onRetry: (attempt, ex) =>
                        {
                            Log($"Reintentando búsqueda (intento {attempt}/3): {ex.Message}");
                        }
                    );
                    successfulSearches++;
                    
                    Log($"Búsqueda completada. Total respuestas recibidas: {searchResult.Responses.Count()}");
                    
                    var results = searchResult.Responses;
                    Log($"Procesando {results.Count()} respuestas...");
                    
                    foreach (var response in results)
                    {
                        // Verificar cancelación
                        searchCancellationTokenSource.Token.ThrowIfCancellationRequested();
                        
                        processedResponses++;
                        
                        // Filtrar usuarios en lista negra
                        if (blacklist.Contains(response.Username))
                    {
                        Log($"Usuario bloqueado: {response.Username}");
                        filteredByBlacklist++;
                        continue;
                    }
                    
                        // Filtrar usuario carbarher
                        if (response.Username.Equals("carbarher", StringComparison.OrdinalIgnoreCase))
                        {
                            Log($"Usuario filtrado (cbh): {response.Username}");
                            filteredByBlacklist++;
                            continue;
                        }
                    
                    int filesInResponse = response.Files.Count();
                    Log($"Usuario {response.Username}: {filesInResponse} archivos");
                    
                    // Procesar archivos en paralelo para mayor velocidad
                    var validFiles = new System.Collections.Concurrent.ConcurrentBag<SearchResultItem>();
                    var localFilteredSize = 0;
                    var localFilteredExt = 0;
                    var localFilteredSpanish = 0;
                    var localFilteredBlacklist = 0;
                    
                    System.Threading.Tasks.Parallel.ForEach(
                        response.Files.Take(500),
                        new System.Threading.Tasks.ParallelOptions { MaxDegreeOfParallelism = Environment.ProcessorCount },
                        file =>
                        {
                            System.Threading.Interlocked.Increment(ref processedFiles);
                            
                            // Descartar archivos de tamaño 0
                            if (file.Size == 0)
                            {
                                System.Threading.Interlocked.Increment(ref localFilteredSize);
                                return;
                            }
                            
                            // Descartar archivos sin extensión
                            string fileExt = Path.GetExtension(file.Filename);
                            if (string.IsNullOrEmpty(fileExt))
                            {
                                System.Threading.Interlocked.Increment(ref localFilteredExt);
                                return;
                            }
                            fileExt = fileExt.ToLower();
                            
                            // Filtrar archivos que ya tiene carbarher
                            string fileName = Path.GetFileName(file.Filename);
                            if (carbarherCacheLoaded && carbarherFilesCache.Contains(fileName))
                            {
                                System.Threading.Interlocked.Increment(ref localFilteredBlacklist);
                                return;
                            }
                            
                            // Aplicar filtros de tamaño
                            if (minSizeBytes > 0 && file.Size < minSizeBytes)
                            {
                                System.Threading.Interlocked.Increment(ref localFilteredSize);
                                return;
                            }
                            if (maxSizeBytes < long.MaxValue && file.Size > maxSizeBytes)
                            {
                                System.Threading.Interlocked.Increment(ref localFilteredSize);
                                return;
                            }
                            if (!MatchesCategory(fileExt, extFilter))
                            {
                                System.Threading.Interlocked.Increment(ref localFilteredExt);
                                return;
                            }
                            
                            // Filtro de idioma español (thread-safe con LRU Cache)
                            if (chkSpanishOnly.Checked && !IsSpanishText(file.Filename))
                            {
                                System.Threading.Interlocked.Increment(ref localFilteredSpanish);
                                return;
                            }
                            
                            // Crear SearchResultItem
                            var searchItem = new SearchResultItem
                            {
                                Username = response.Username,
                                Filename = Path.GetFileName(file.Filename),
                                Size = file.Size,
                                Extension = fileExt,
                                FolderPath = Path.GetDirectoryName(file.Filename) ?? "",
                                Bitrate = file.BitRate ?? 0,
                                Length = file.Length ?? 0,
                                UploadSpeed = response.UploadSpeed,
                                QueueLength = response.QueueLength
                            };
                            
                            // Filtro de calidad (SIEMPRE ACTIVO con mínimo 60)
                            searchItem.QualityScore = 100; // Default quality score
                            
                            validFiles.Add(searchItem);
                        });
                    
                    // Agregar resultados válidos
                    filteredBySize += localFilteredSize;
                    filteredByExt += localFilteredExt;
                    filteredBySpanish += localFilteredSpanish;
                    filteredByBlacklist += localFilteredBlacklist;
                    
                    foreach (var item in validFiles)
                    {
                        allResults.Add(item);
                        totalFiles++;
                    }
                    
                    // Actualizar UI cada 10 archivos (más inmediato)
                    if (totalFiles % 10 == 0)
                    {
                        UpdateSearchResults(allResults);
                        SafeInvoke(() => lblStatus.Text = $"Buscando... {totalFiles:N0} encontrados");
                    }
                    }  // Cierre del foreach
                }  // Cierre del else
                
                Log($"=== RESUMEN DE BÚSQUEDA ===");
                Log($"Respuestas procesadas: {processedResponses}");
                Log($"Usuarios bloqueados: {filteredByBlacklist}");
                Log($"Archivos procesados: {processedFiles}");
                Log($"Filtrados por tamaño: {filteredBySize}");
                Log($"Filtrados por extensión: {filteredByExt}");
                Log($"Filtrados por idioma español: {filteredBySpanish}");
                Log($"Archivos que pasaron filtros: {totalFiles}");
                Log($"Archivos en allResults: {allResults?.Count ?? 0}");
                
                // Mostrar estadísticas del filtro de idioma
                if (chkSpanishOnly?.Checked ?? false)
                {
                    Log($"=== ESTADÍSTICAS DE FILTRO DE IDIOMA ===");
                    Log(LanguageFilterStats.Instance.GetSummary());
                    var cacheStats = spanishTextCache.GetStats();
                    Log($"Cache: {cacheStats.Size}/{cacheStats.MaxSize} | Hit rate: {cacheStats.HitRate:F1}% | Evictions: {cacheStats.Evictions:N0}");
                }
                
                // Actualizar estadísticas
                if (!searchStats.ContainsKey(cmbSearch.Text))
                    searchStats[cmbSearch.Text] = 0;
                searchStats[cmbSearch.Text]++;
                SaveStats();
                
                // Forzar actualización final (ignorar throttle)
                lastUpdateTime = DateTime.MinValue;
                UpdateSearchResults(allResults);
                SafeInvoke(() => 
                {
                    lblStatus.Text = $"{totalFiles:N0} archivos encontrados";
                });
                
                Log($"Búsqueda completada: {totalFiles} archivos");
            }
            catch (OperationCanceledException)
            {
                // Forzar actualización final con resultados parciales
                lastUpdateTime = DateTime.MinValue;
                UpdateSearchResults(allResults);
                
                SafeInvoke(() =>
                {
                    if (lblStatus != null) lblStatus.Text = "Búsqueda cancelada";
                    if (lblResultsCount != null) lblResultsCount.Text = $"{allResults.Count} resultados (cancelado)";
                });
                Log("Búsqueda cancelada por el usuario");
            }
            catch (Exception ex) 
            { 
                if (lblStatus != null) lblStatus.Text = $"Error: {ex.Message}";
                Log($"Error en búsqueda: {ex.Message}");
            }
            finally 
            { 
                if (btnSearch != null) btnSearch.Enabled = true;
                if (btnStopSearch != null) btnStopSearch.Enabled = false;
            }
        }
        
        private void StopSearch()
        {
            if (searchCancellationTokenSource != null && !searchCancellationTokenSource.IsCancellationRequested)
            {
                Log("Botón DETENER presionado - Cancelando búsqueda...");
                searchCancellationTokenSource.Cancel();
                if (lblStatus != null) lblStatus.Text = "Deteniendo búsqueda...";
                if (btnStopSearch != null) btnStopSearch.Enabled = false;
            }
        }
        
        private async Task DownloadMultipleAsync()
        {
            if (lvResults.SelectedItems.Count == 0 || client == null)
                return;
            
            var itemsToDownload = new List<(ListViewItem downloadItem, dynamic result)>();
            int totalItems = lvResults.SelectedItems.Count;
            
            Log($"Procesando {totalItems} archivos para descarga...");
            
            // Suspender actualización de UI para mejor rendimiento
            SafeInvoke(() =>
            {
                lvDownloads.BeginUpdate();
            });
            
            try
            {
                System.IO.Directory.CreateDirectory(downloadDir);
                
                // Procesar en lotes de 100 para evitar bloqueos
                int batchSize = 100;
                int processed = 0;
                
                foreach (ListViewItem selectedItem in lvResults.SelectedItems)
                {
                    try
                    {
                        dynamic result = selectedItem.Tag;
                        var fileName = Path.GetFileName((string)result.Filename);
                        var username = (string)result.Username;
                        
                        // Verificar blacklist
                        if (blacklist.Contains(username))
                        {
                            Log($"Usuario bloqueado: {username} - Descarga omitida: {fileName}");
                            continue;
                        }
                        
                        var downloadItem = new ListViewItem(fileName);
                        downloadItem.SubItems.Add(username);
                        downloadItem.SubItems.Add("0%");
                        downloadItem.SubItems.Add("En cola...");
                        downloadItem.SubItems.Add(FormatSize((long)result.Size));
                        downloadItem.SubItems.Add(GetMetadataStatusSync(fileName));
                        
                        SafeInvoke(() =>
                        {
                            lvDownloads.Items.Add(downloadItem);
                        });
                        
                        itemsToDownload.Add((downloadItem, result));
                        processed++;
                        
                        // Cada 100 items, dar un respiro a la UI
                        if (processed % batchSize == 0)
                        {
                            Log($"Procesados {processed}/{totalItems} archivos...");
                            await Task.Delay(10);
                        }
                    }
                    catch { }
                }
                
                Log($"Total agregados a la cola: {itemsToDownload.Count} archivos");
            }
            finally
            {
                // Reanudar actualización de UI
                SafeInvoke(() =>
                {
                    lvDownloads.EndUpdate();
                });
            }
            
            tabControl.SelectedIndex = 1;
            
            // Modo Turbo: descargas paralelas
            if (maxParallelDownloads > 1)
            {
                var tasks = new List<Task>();
                using (var semaphore = new System.Threading.SemaphoreSlim(maxParallelDownloads))
                {
                    foreach (var (downloadItem, result) in itemsToDownload)
                    {
                        await semaphore.WaitAsync();
                        
                        var task = Task.Run(async () =>
                        {
                            try
                            {
                                await DownloadFileAsync(downloadItem, result);
                            }
                            finally
                            {
                                semaphore.Release();
                            }
                        });
                        
                        tasks.Add(task);
                    }
                    
                    await Task.WhenAll(tasks);
                }
            }
            else
            {
                // Modo normal: descargas secuenciales
                foreach (var (downloadItem, result) in itemsToDownload)
                {
                    await DownloadFileAsync(downloadItem, result);
                }
            }
        }
        
        private async Task DownloadFileAsync(ListViewItem downloadItem, dynamic result)
        {
            try
            {
                var fileName = Path.GetFileName((string)result.Filename);
                // Descargas manuales van directo a downloadDir (sin subcarpetas)
                // Solo las descargas automáticas usan GetDownloadPath con autor
                var localPath = Path.Combine(downloadDir, fileName);
                var username = (string)result.Username;
                long fileSize = (long)result.Size;
                
                // Timeout dinámico: 30s base + 1s por MB (mínimo 60s, máximo 10min)
                int timeoutSeconds = Math.Max(60, Math.Min(600, 30 + (int)(fileSize / (1024 * 1024))));
                var cts = new System.Threading.CancellationTokenSource(TimeSpan.FromSeconds(timeoutSeconds));
                
                Log($"[DESCARGA] Iniciando: {fileName} desde {username} ({FormatSize(fileSize)}) - Timeout: {timeoutSeconds}s");
                
                activeDownloads[fileName] = cts;
                
                SafeBeginInvoke(() =>
                {
                    downloadItem.SubItems[3].Text = "Descargando...";
                });
                
                // Obtener o crear circuit breaker para este usuario
                if (!userCircuitBreakers.ContainsKey(username))
                {
                    userCircuitBreakers[username] = new RetryPolicy.CircuitBreaker(
                        failureThreshold: 5, // Aumentado de 3 a 5 fallos
                        resetTimeoutSeconds: 180 // Reducido de 5min a 3min
                    );
                }
                
                var breaker = userCircuitBreakers[username];
                
                // Verificar si el circuit breaker está abierto
                if (breaker.State == RetryPolicy.CircuitState.Open)
                {
                    SafeBeginInvoke(() =>
                    {
                        downloadItem.SubItems[3].Text = $"Usuario bloqueado temporalmente";
                        downloadItem.ForeColor = Color.Orange;
                    });
                    Log($"Circuit breaker abierto para {username} - descarga omitida");
                    return;
                }
                
                // Descarga con retry automático y circuit breaker
                totalDownloads++;
                await breaker.Execute(async () =>
                {
                    await RetryPolicy.ExecuteWithRetry(
                        async () =>
                        {
                            await client.DownloadAsync(
                                username,
                                (string)result.Filename,
                                () => Task.FromResult<Stream>(new FileStream(localPath, FileMode.Create)),
                                fileSize,
                                cancellationToken: cts.Token,
                                options: new TransferOptions(
                                    progressUpdated: (args) =>
                                    {
                                        var percent = (int)((args.Transfer.BytesTransferred / (double)fileSize) * 100);
                                        SafeBeginInvoke(() =>
                                        {
                                            downloadItem.SubItems[2].Text = $"{percent}%";
                                            downloadItem.SubItems[3].Text = $"Descargando... {FormatSize(args.Transfer.BytesTransferred)} / {FormatSize(fileSize)}";
                                        });
                                    }
                                )
                            );
                        },
                        maxAttempts: 5, // Aumentado de 3 a 5 intentos
                        initialDelayMs: 3000, // Aumentado de 2s a 3s
                        onRetry: (attempt, ex) =>
                        {
                            SafeBeginInvoke(() =>
                            {
                                downloadItem.SubItems[3].Text = $"Reintento {attempt}/5: {ex.Message}";
                                downloadItem.ForeColor = Color.Orange;
                            });
                            Log($"[DESCARGA] Reintento {attempt}/5: {fileName} - {ex.GetType().Name}: {ex.Message}");
                        }
                    );
                    return true;
                });
                
                // Validar tamaño del archivo descargado
                if (System.IO.File.Exists(localPath))
                {
                    var downloadedSize = new FileInfo(localPath).Length;
                    if (Math.Abs(downloadedSize - fileSize) > 1024) // Tolerancia de 1KB
                    {
                        Log($"[DESCARGA] ADVERTENCIA: Tamaño incorrecto para {fileName}. Esperado: {FormatSize(fileSize)}, Descargado: {FormatSize(downloadedSize)}");
                    }
                    else
                    {
                        Log($"[DESCARGA] Completada: {fileName} ({FormatSize(downloadedSize)}) - Tamaño verificado OK");
                    }
                }
                
                successfulDownloads++;
                SafeBeginInvoke(() =>
                {
                    downloadItem.SubItems[2].Text = "100%";
                    downloadItem.SubItems[3].Text = "Completado";
                    downloadItem.ForeColor = Color.LightGreen;
                });
                
                // Notificación de progreso
                totalDownloadsInSession++;
                if (totalDownloadsInSession % 10 == 0)
                {
                    ShowNotification("Progreso de Descargas", 
                        $"{totalDownloadsInSession} archivos completados en esta sesión", 
                        ToolTipIcon.Info);
                }
                
                activeDownloads.Remove(fileName);
            }
            catch (OperationCanceledException)
            {
                SafeBeginInvoke(() =>
                {
                    downloadItem.SubItems[3].Text = "Cancelado";
                    downloadItem.ForeColor = Color.Orange;
                });
                activeDownloads.Remove((string)result.Filename);
            }
            catch (Exception ex)
            {
                var fileName = Path.GetFileName((string)result.Filename);
                var username = (string)result.Username;
                
                // Rastrear fallo del archivo
                TrackFileFailure(fileName, username, ex.Message);
                
                SafeBeginInvoke(() =>
                {
                    downloadItem.SubItems[3].Text = $"✗ Error: {ex.Message}";
                    downloadItem.ForeColor = Color.Red;
                });
                Log($"[DESCARGA] ERROR: {fileName} desde {username}");
                Log($"[DESCARGA] Tipo: {ex.GetType().Name}");
                Log($"[DESCARGA] Mensaje: {ex.Message}");
                if (ex.InnerException != null)
                {
                    Log($"[DESCARGA] Inner: {ex.InnerException.Message}");
                }
                activeDownloads.Remove(fileName);
                
                // No reintentar si el archivo está blacklisteado
                if (IsFileBlacklisted(fileName, username))
                {
                    SafeBeginInvoke(() =>
                    {
                        downloadItem.SubItems[3].Text = $"Blacklisteado (fallos repetidos)";
                        downloadItem.ForeColor = Color.DarkRed;
                    });
                    Log($"Archivo blacklisteado: {fileName} - No se reintentará");
                    return;
                }
                
                // Agregar a cola de reintentos si está habilitado
                if (maxRetries > 0)
                {
                    var existingRetry = retryQueue.FirstOrDefault(r => Path.GetFileName(((dynamic)r.result).Filename) == fileName);
                    if (existingRetry.result != null)
                    {
                        var retryCount = existingRetry.retryCount + 1;
                        retryQueue.Remove(existingRetry);
                        
                        if (retryCount <= maxRetries)
                        {
                            retryQueue.Add((result, downloadItem, retryCount));
                            SafeBeginInvoke(() =>
                            {
                                downloadItem.SubItems[3].Text = $"Reintentando ({retryCount}/{maxRetries})...";
                                downloadItem.ForeColor = Color.Orange;
                            });
                            Log($"Reintentando descarga: {fileName} (intento {retryCount}/{maxRetries})");
                            
                            // Reintentar después de 3 segundos
                            await Task.Delay(3000);
                            await DownloadFileAsync(downloadItem, result);
                        }
                        else
                        {
                            SafeBeginInvoke(() =>
                            {
                                downloadItem.SubItems[3].Text = $"✗ Fallo después de {maxRetries} reintentos";
                                downloadItem.ForeColor = Color.DarkRed;
                            });
                            Log($"Descarga fallida definitivamente: {fileName}");
                        }
                    }
                    else
                    {
                        retryQueue.Add((result, downloadItem, 1));
                        SafeBeginInvoke(() =>
                        {
                            downloadItem.SubItems[3].Text = "Reintentando (1/" + maxRetries + ")...";
                            downloadItem.ForeColor = Color.Orange;
                        });
                        Log($"Reintentando descarga: {fileName} (intento 1/{maxRetries})");
                        
                        await Task.Delay(3000);
                        await DownloadFileAsync(downloadItem, result);
                    }
                }
            }
        }
        
        private async Task DownloadAsync()
        {
            if (lvResults.SelectedIndices.Count == 0 || client == null) 
                return;
            
            try
            {
                // Obtener resultado del Tag del item seleccionado
                var selectedItem = lvResults.SelectedItems[0];
                var result = selectedItem.Tag as dynamic;
                
                var fullFilename = Path.Combine(result.FolderPath, result.Filename);
                var localPath = Path.Combine(downloadDir, result.Filename);
                
                System.IO.Directory.CreateDirectory(downloadDir);
                
                // Agregar a lista de descargas
                var downloadItem = new ListViewItem(result.Filename);
                downloadItem.SubItems.Add(result.Username);
                downloadItem.SubItems.Add("0%");
                downloadItem.SubItems.Add("Descargando...");
                downloadItem.SubItems.Add(FormatSize(result.Size));
                downloadItem.SubItems.Add(GetMetadataStatusSync(result.Filename));
                lvDownloads.Items.Add(downloadItem);
                
                // Cambiar a pestaña de descargas
                tabControl.SelectedIndex = 1;
                
                lblStatus.Text = $"Descargando: {result.Filename}...";
                
                await client.DownloadAsync(
                    result.Username, 
                    fullFilename, 
                    (Func<Task<Stream>>)(() => Task.FromResult<Stream>(new FileStream(localPath, FileMode.Create))), 
                    result.Size,
                    options: new TransferOptions(
                        progressUpdated: (args) =>
                        {
                            var percent = (int)((args.Transfer.BytesTransferred / (double)result.Size) * 100);
                            SafeBeginInvoke(() =>
                            {
                                downloadItem.SubItems[2].Text = $"{percent}%";
                                downloadItem.SubItems[3].Text = $"Descargando... {FormatSize(args.Transfer.BytesTransferred)} / {FormatSize(result.Size)}";
                            });
                        }
                    )
                );
                
                downloadItem.SubItems[2].Text = "100%";
                downloadItem.SubItems[3].Text = "Completado";
                downloadItem.ForeColor = Color.LimeGreen;
                Log($"Descarga completada: {result.Filename}");
                lblStatus.Text = $"Descargado: {result.Filename}";
                
                // Notificación de progreso
                totalDownloadsInSession++;
                if (totalDownloadsInSession % 10 == 0)
                {
                    ShowNotification("Progreso de Descargas", 
                        $"{totalDownloadsInSession} archivos completados en esta sesión", 
                        ToolTipIcon.Info);
                }
                
                // Actualizar estadísticas
                totalDownloads++;
                SaveStats();
            }
            catch (Exception ex) 
            { 
                lblStatus.Text = $"Error: {ex.Message}"; 
            }
        }
        
        private string FormatSize(long bytes)
        {
            // MEJORA #4: Mostrar tamaños exactos en bytes si está activado
            if (showExactSizes)
                return $"{bytes:N0} bytes";
            
            string[] sizes = { "B", "KB", "MB", "GB" };
            double len = bytes;
            int order = 0;
            while (len >= 1024 && order < sizes.Length - 1) 
            { 
                order++; 
                len /= 1024; 
            }
            return $"{len:0.##} {sizes[order]}";
        }
        
