        private void CleanupTempFiles()
        {
            // LOGGING ANTES de hacer cualquier cosa
            System.IO.File.AppendAllText("cleanup_log.txt", $"CleanupTempFiles llamado: {DateTime.Now:HH:mm:ss.fff}\n");
            
            try
            {
                var baseDir = AppDomain.CurrentDomain.BaseDirectory;
                
                // Limpiar startup_log.txt si es muy grande (>5MB)
                var logPath = Path.Combine(baseDir, "startup_log.txt");
                if (System.IO.File.Exists(logPath))
                {
                    var logInfo = new FileInfo(logPath);
                    System.IO.File.AppendAllText("cleanup_log.txt", $"  - startup_log.txt existe, tamaño: {logInfo.Length} bytes\n");
                    if (logInfo.Length > 5 * 1024 * 1024) // 5MB
                    {
                        System.IO.File.Delete(logPath);
                        System.IO.File.AppendAllText("cleanup_log.txt", $"  - startup_log.txt ELIMINADO (muy grande)\n");
                    }
                    else
                    {
                        System.IO.File.AppendAllText("cleanup_log.txt", $"  - startup_log.txt NO eliminado (tamaño OK)\n");
                    }
                }
                else
                {
                    System.IO.File.AppendAllText("cleanup_log.txt", $"  - startup_log.txt NO existe\n");
                }
                
                // Eliminar archivos .tmp antiguos (>7 días)
                var tempFiles = System.IO.Directory.GetFiles(baseDir, "*.tmp");
                foreach (var file in tempFiles)
                {
                    try
                    {
                        var fileInfo = new FileInfo(file);
                        if ((DateTime.Now - fileInfo.LastWriteTime).TotalDays > 7)
                        {
                            System.IO.File.Delete(file);
                        }
                    }
                    catch { }
                }
                
                // Rotar logs si son muy grandes
                RotateLogFile(Path.Combine(dataDir, "download_log.txt"), 10 * 1024 * 1024); // 10MB
            }
            catch (Exception ex)
            {
                SafeLog( $"Error en limpieza: {ex.Message}\n");
            }
        }
        
        private void RotateLogFile(string logPath, long maxSize)
        {
            try
            {
                if (!System.IO.File.Exists(logPath)) return;
                
                var fileInfo = new FileInfo(logPath);
                if (fileInfo.Length > maxSize)
                {
                    // Crear backup con timestamp
                    var backupPath = Path.Combine(
                        Path.GetDirectoryName(logPath),
                        $"{Path.GetFileNameWithoutExtension(logPath)}_{DateTime.Now:yyyyMMdd_HHmmss}.bak"
                    );
                    
                    System.IO.File.Move(logPath, backupPath);
                    
                    // Eliminar backups antiguos (mantener solo últimos 3)
                    var backups = System.IO.Directory.GetFiles(Path.GetDirectoryName(logPath), "*.bak")
                        .OrderByDescending(f => System.IO.File.GetCreationTime(f))
                        .Skip(3)
                        .ToList();
                    
                    foreach (var backup in backups)
                    {
                        try { System.IO.File.Delete(backup); } catch { }
                    }
                }
            }
            catch { }
        }
        
        private async Task<Dictionary<string, object>> GetDownloadStatistics()
        {
            var stats = new Dictionary<string, object>();
            
            try
            {
                // Verificar que la conexión existe y está abierta
                if (dbConnection == null || dbConnection.State != System.Data.ConnectionState.Open)
                {
                    return stats; // Retornar stats vacío si no hay conexión
                }
                
                using (var cmd = dbConnection.CreateCommand())
                {
                    // Total de archivos descargados
                    cmd.CommandText = "SELECT COUNT(*) FROM download_history WHERE status = 'Completed'";
                    stats["TotalDownloads"] = Convert.ToInt32(await cmd.ExecuteScalarAsync());
                    
                    // Espacio total descargado
                    cmd.CommandText = "SELECT SUM(size_bytes) FROM download_history WHERE status = 'Completed'";
                    var totalBytes = await cmd.ExecuteScalarAsync();
                    stats["TotalBytes"] = totalBytes != DBNull.Value ? Convert.ToInt64(totalBytes) : 0L;
                    stats["TotalSize"] = FormatFileSize((long)stats["TotalBytes"]);
                    
                    // Top 10 autores
                    cmd.CommandText = @"
                        SELECT author, COUNT(*) as count 
                        FROM download_history 
                        WHERE status = 'Completed' AND author IS NOT NULL
                        GROUP BY author 
                        ORDER BY count DESC 
                        LIMIT 10";
                    
                    var topAuthors = new List<(string author, int count)>();
                    using (var reader = await cmd.ExecuteReaderAsync())
                    {
                        while (await reader.ReadAsync())
                        {
                            topAuthors.Add((reader.GetString(0), reader.GetInt32(1)));
                        }
                    }
                    stats["TopAuthors"] = topAuthors;
                    
                    // Descargas hoy
                    cmd.CommandText = @"
                        SELECT COUNT(*) 
                        FROM download_history 
                        WHERE status = 'Completed' 
                        AND date(timestamp) = date('now')";
                    stats["TodayDownloads"] = Convert.ToInt32(await cmd.ExecuteScalarAsync());
                }
            }
            catch (Exception ex)
            {
                Log($"Error obteniendo estadísticas: {ex.Message}");
            }
            
            return stats;
        }
        
        private void PauseAllDownloads()
        {
            try
            {
                List<DownloadTask> tasksToPause;
                lock (downloadQueueLock)
                {
                    // Obtener lista de tareas a pausar (activas + pendientes)
                    tasksToPause = downloadQueue
                        .Where(t => t.Status == DownloadStatus.Downloading || t.Status == DownloadStatus.Queued)
                        .ToList();
                    
                    // Cambiar estado dentro del lock
                    foreach (var task in tasksToPause)
                    {
                        task.Status = DownloadStatus.Paused;
                        if (task.CancellationToken != null)
                        {
                            try { task.CancellationToken.Cancel(); } catch { }
                        }
                    }
                }
                
                // Actualizar UI fuera del lock
                foreach (var task in tasksToPause)
                {
                    UpdateDownloadUI(task, "Pausado");
                }
                
                Log($"{tasksToPause.Count} descargas pausadas (activas + en cola)");
                ShowNotification("Descargas pausadas", $"{tasksToPause.Count} descargas pausadas", ToolTipIcon.Info);
            }
            catch (Exception ex)
            {
                Log($"Error pausando descargas: {ex.Message}");
            }
        }
        
        private async Task ResumeAllDownloads()
        {
            try
            {
                List<DownloadTask> pausedTasks;
                lock (downloadQueueLock)
                {
                    pausedTasks = downloadQueue.Where(t => t.Status == DownloadStatus.Paused).ToList();
                    
                    foreach (var task in pausedTasks)
                    {
                        task.Status = DownloadStatus.Queued;
                        UpdateDownloadUI(task, "Pendiente");
                    }
                }
                
                // Reiniciar el gestor de descargas si no está corriendo
                if (!downloadManagerRunning)
                {
                    Log("Reiniciando gestor de descargas...");
                    _ = Task.Run(async () => await StartDownloadManager());
                }
                
                Log($"Reanudando {pausedTasks.Count} descargas");
                ShowNotification("Descargas reanudadas", $"Reanudando {pausedTasks.Count} descargas", ToolTipIcon.Info);
            }
            catch (Exception ex)
            {
                Log($"Error reanudando descargas: {ex.Message}");
            }
        }
        
        private async Task BackupDatabase()
        {
            try
            {
                var backupDir = Path.Combine(dataDir, "backups");
                System.IO.Directory.CreateDirectory(backupDir);
                
                var backupPath = Path.Combine(backupDir, $"slskdown_backup_{DateTime.Now:yyyyMMdd_HHmmss}.db");
                
                // Cerrar conexión temporalmente
                var wasOpen = dbConnection.State == System.Data.ConnectionState.Open;
                if (wasOpen)
                {
                    dbConnection.Close();
                }
                
                // Copiar archivo
                System.IO.File.Copy(dbPath, backupPath, true);
                
                // Reabrir conexión
                if (wasOpen)
                {
                    await dbConnection.OpenAsync();
                }
                
                // Mantener solo últimos 7 backups
                var backups = System.IO.Directory.GetFiles(backupDir, "slskdown_backup_*.db")
                    .OrderByDescending(f => System.IO.File.GetCreationTime(f))
                    .Skip(7)
                    .ToList();
                
                foreach (var backup in backups)
                {
                    try { System.IO.File.Delete(backup); } catch { }
                }
                
                Log($"Backup creado: {Path.GetFileName(backupPath)}");
            }
            catch (Exception ex)
            {
                Log($"Error creando backup: {ex.Message}");
            }
        }
        
