            }
        }
        
        private void LoadConfigBasic()
        {
            // Cargar solo configuración esencial para mostrar la ventana
            try
            {
                if (!System.IO.File.Exists(configPath))
                {
                    // Valores por defecto
                    downloadDir = Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.MyDocuments), "SlskDown");
                    return;
                }
                
                var json = System.IO.File.ReadAllText(configPath);
                var config = JsonSerializer.Deserialize<Dictionary<string, object>>(json);
                
                // Solo cargar lo esencial
                if (config != null && config.ContainsKey("downloadDir"))
                    downloadDir = config["downloadDir"].ToString();
                if (config != null && config.ContainsKey("username"))
                    username = config["username"].ToString()?.Trim() ?? "";
                if (config != null && config.ContainsKey("password"))
                    password = config["password"].ToString()?.Trim() ?? "";
                if (config != null && config.ContainsKey("autoConnect"))
                    autoConnect = ((JsonElement)config["autoConnect"]).GetBoolean();
                    
                // Restaurar tamaño de ventana
                if (config != null && config.ContainsKey("windowWidth") && config.ContainsKey("windowHeight"))
                {
                    int width = ((JsonElement)config["windowWidth"]).GetInt32();
                    int height = ((JsonElement)config["windowHeight"]).GetInt32();
                    this.Size = new Size(width, height);
                    
                    if (config.ContainsKey("windowMaximized") && ((JsonElement)config["windowMaximized"]).GetBoolean())
                        this.WindowState = FormWindowState.Maximized;
                }
            }
            catch (Exception ex)
            {
                Log($"ERROR en LoadConfigBasic: {ex.Message}");
            }
        }
        
