                    // Log de autores Gutenberg cargados
                    if (gutenbergAuthorsSet.Count > 0)
                        Log($"{gutenbergAuthorsSet.Count:N0} autores de Gutenberg cargados para priorización automática");
                    
                    // Inicializar mejoras de Nicotine+
                    InitializeNicotineEnhancements();
                    
                    // Inicializar timers de mantenimiento
                    InitializeMaintenanceTimers();
                    
                    if (lblStatus != null)
                        lblStatus.Text = "✅ Listo";
                    
                    Log("Configuración cargada completamente");
                });
            }
            catch (Exception ex)
            {
                SafeInvoke(() => Log($"ERROR en LoadDataAsync: {ex.Message}"));
            }
        }
        
