                    if (config != null && config.ContainsKey("ollamaModel"))
                    {
                        ollamaModel = config["ollamaModel"].ToString() ?? "llama2";
                        Log($"Config cargado - ollamaModel: {ollamaModel}");
                    }
                    
                    // Restaurar posición y tamaño de ventana
                    if (config != null && config.ContainsKey("windowX") && config.ContainsKey("windowY"))
                    {
                        int x = ((JsonElement)config["windowX"]).GetInt32();
                        int y = ((JsonElement)config["windowY"]).GetInt32();
            int width = config.ContainsKey("windowWidth") ? ((JsonElement)config["windowWidth"]).GetInt32() : 1300;
                        int height = config.ContainsKey("windowHeight") ? ((JsonElement)config["windowHeight"]).GetInt32() : 850;
                        bool maximized = config.ContainsKey("windowMaximized") && ((JsonElement)config["windowMaximized"]).GetBoolean();
                        
                        // Verificar que la posición esté dentro de los límites de la pantalla
                        bool isOnScreen = false;
                        foreach (Screen screen in Screen.AllScreens)
                        {
                            if (screen.WorkingArea.Contains(x, y))
                            {
                                isOnScreen = true;
                                break;
                            }
                        }
                        
                        // Siempre centrar la ventana, ignorar posición guardada
                        this.StartPosition = FormStartPosition.CenterScreen;
                        this.Size = new Size(width, height);
                        
                        if (maximized)
                        {
                            this.WindowState = FormWindowState.Maximized;
                        }
                        
                        Log($"Ventana centrada en pantalla: {width}x{height} [Maximizada: {maximized}]");
