                // Cargar watchlist
                if (System.IO.File.Exists(watchlistPath))
                {
                    watchlist = System.IO.File.ReadAllLines(watchlistPath).ToList();
                }
                
                // Cargar caché de países
                if (System.IO.File.Exists(countryCachePath))
                {
