                    countryCache = JsonSerializer.Deserialize<Dictionary<string, string>>(json) ?? new Dictionary<string, string>();
                }
            }
            catch (Exception ex)
            {
                Log($"ERROR en LoadConfig: {ex.Message}");
                Log($"Stack: {ex.StackTrace}");
            }
            
            Log($"LoadConfig completado. responseLimit={responseLimit}, fileLimit={fileLimit}");
        }
        
