                    ["autoConnect"] = autoConnect,
                    ["maxParallelDownloads"] = maxParallelDownloads,
                    ["maxParallelSearches"] = maxParallelSearches,
                    ["maxRetries"] = maxRetries,
                    ["maxAlternativeRetries"] = maxAlternativeRetries,
                    ["searchTimeout"] = searchTimeout,
                    ["responseLimit"] = responseLimit,
                    ["fileLimit"] = fileLimit,
                    ["listenPort"] = listenPort,
                    ["enableDistributedNetwork"] = enableDistributedNetwork,
                    ["minFileSizeKB"] = minFileSizeKB,
                    ["organizeByAuthor"] = organizeByAuthor,
                    ["autoBackup"] = autoBackup,
                    ["autoMode"] = autoMode,
                    ["instantDownload"] = instantDownload,
                    ["onlyNewFilesInAutoSearch"] = onlyNewFilesInAutoSearch,
                    ["priorityBySize"] = priorityBySize,
                    ["lvDownloadsColumnWidths"] = columnWidths,
                    ["windowX"] = this.Location.X,
                    ["windowY"] = this.Location.Y,
                    ["windowWidth"] = this.Width,
                    ["windowHeight"] = this.Height,
                    ["windowMaximized"] = this.WindowState == FormWindowState.Maximized,
                    ["showExactSizes"] = showExactSizes,
                    ["lastSortedColumn"] = lastSortedColumn,
                    ["lastSortOrder"] = lastSortOrder.ToString(),
                    ["autoReconnectEnabled"] = autoReconnectEnabled,
                    ["autoRetryEnabled"] = autoRetryEnabled,
                    ["autoRetryIntervalMinutes"] = autoRetryIntervalMinutes,
                    ["batchSmallFiles"] = batchSmallFiles,
                    ["smallFileThresholdBytes"] = smallFileThresholdBytes,
                    ["priorityBySlots"] = priorityBySlots,
                    ["maxParallelDownloadsPerUser"] = maxParallelDownloadsPerUser,
                    ["maxTotalParallelDownloads"] = maxTotalParallelDownloads,
                    ["searchTimeoutSeconds"] = searchTimeoutSeconds,
                    ["maxSearchResults"] = maxSearchResults,
                    ["maxResultsPerUser"] = maxResultsPerUser,
                    ["aiEnabled"] = aiEnabled,
                    ["ollamaUrl"] = ollamaUrl,
                    ["ollamaModel"] = ollamaModel
                };
                var json = JsonSerializer.Serialize(config, new JsonSerializerOptions { WriteIndented = true });
                System.IO.File.WriteAllText(configPath, json);
                
                // Backup automático si está activado
                if (autoBackup)
                {
                    CreateConfigBackup();
                }
            }
            catch { }
        }
        
        private void CreateConfigBackup()
        {
            try
            {
                var backupDir = Path.Combine(dataDir, "backups");
                System.IO.Directory.CreateDirectory(backupDir);
                
                // Mantener solo los últimos 5 backups
                var backupFiles = System.IO.Directory.GetFiles(backupDir, "config_*.json")
                    .OrderByDescending(f => System.IO.File.GetCreationTime(f))
                    .ToList();
                
                // Eliminar backups antiguos
                foreach (var oldBackup in backupFiles.Skip(4))
                {
                    try { System.IO.File.Delete(oldBackup); } catch { }
                }
                
                // Crear nuevo backup
                var backupPath = Path.Combine(backupDir, $"config_{DateTime.Now:yyyyMMdd_HHmmss}.json");
                System.IO.File.Copy(configPath, backupPath, true);
            }
            catch { }
        }
        
        // Helper para construir ruta de descarga con subcarpeta de autor
        private string GetDownloadPath(string fileName, string author)
        {
            // Sanitizar nombre de autor para usar como carpeta
            string sanitizedAuthor = string.IsNullOrWhiteSpace(author) ? "Unknown" : author.Trim();
            
            // Remover caracteres inválidos para nombres de carpeta
            char[] invalidChars = Path.GetInvalidFileNameChars();
            foreach (char c in invalidChars)
            {
                sanitizedAuthor = sanitizedAuthor.Replace(c, '_');
            }
            
            // Normalizar: Windows trata variantes como iguales
            // - "Jose" y "José" (con/sin acentos)
            // - "Pepe J. Perez" y "Pepe J Perez" (con/sin puntos)
            string authorFolder = Path.Combine(downloadDir, sanitizedAuthor);
            
            // Si el directorio base existe, buscar carpetas existentes con nombre similar
            if (System.IO.Directory.Exists(downloadDir))
            {
                try
                {
                    // Buscar carpetas que coincidan ignorando acentos y puntos
                    var existingFolders = System.IO.Directory.GetDirectories(downloadDir)
                        .Select(d => Path.GetFileName(d))
                        .Where(d => 
                            string.Equals(d, sanitizedAuthor, StringComparison.OrdinalIgnoreCase) ||
                            NormalizeForComparison(d).Equals(NormalizeForComparison(sanitizedAuthor), StringComparison.OrdinalIgnoreCase))
                        .ToList();
                    
                    // Si existe una carpeta similar, usar esa (preferir: sin puntos > con tildes > original)
                    if (existingFolders != null && existingFolders.Count > 0)
                    {
                        var preferredFolder = existingFolders
                            // 1. Preferir SIN puntos (más limpio)
                            .OrderBy(f => f.Count(c => c == '.'))
                            // 2. Luego preferir CON tildes/acentos (correcto en español)
                            .ThenByDescending(f => f.Any(c => c > 127))
                            // 3. Desempate alfabético
                            .ThenBy(f => f)
                            .First();
                        
                        authorFolder = Path.Combine(downloadDir, preferredFolder);
                    }
                }
                catch
                {
                    // Si hay error, usar el nombre original
                }
            }
            
            // Crear subcarpeta si no existe
            System.IO.Directory.CreateDirectory(authorFolder);
            
            return Path.Combine(authorFolder, fileName);
        }
        
        // Helper para normalizar nombres para comparación (sin acentos ni puntos)
        private string NormalizeForComparison(string text)
        {
            if (string.IsNullOrWhiteSpace(text))
                return text;
            
            // 1. Remover acentos
            var normalizedString = text.Normalize(System.Text.NormalizationForm.FormD);
            var stringBuilder = new System.Text.StringBuilder();
            
            foreach (var c in normalizedString)
            {
                var unicodeCategory = System.Globalization.CharUnicodeInfo.GetUnicodeCategory(c);
                if (unicodeCategory != System.Globalization.UnicodeCategory.NonSpacingMark)
                {
                    stringBuilder.Append(c);
                }
            }
            
            var withoutAccents = stringBuilder.ToString().Normalize(System.Text.NormalizationForm.FormC);
            
            // 2. Remover puntos y normalizar espacios
            var withoutPunctuation = withoutAccents
                .Replace(".", "")
                .Replace(",", "")
                .Replace(";", "")
                .Replace(":", "");
            
            // 3. Normalizar espacios múltiples a uno solo
            while (withoutPunctuation.Contains("  "))
            {
                withoutPunctuation = withoutPunctuation.Replace("  ", " ");
            }
            
            return withoutPunctuation.Trim();
        }
        
        // Helper para remover solo acentos/diacríticos (mantiene puntos)
        private string RemoveAccents(string text)
        {
            if (string.IsNullOrWhiteSpace(text))
                return text;
            
            var normalizedString = text.Normalize(System.Text.NormalizationForm.FormD);
            var stringBuilder = new System.Text.StringBuilder();
            
            foreach (var c in normalizedString)
            {
                var unicodeCategory = System.Globalization.CharUnicodeInfo.GetUnicodeCategory(c);
                if (unicodeCategory != System.Globalization.UnicodeCategory.NonSpacingMark)
                {
                    stringBuilder.Append(c);
                }
            }
            
            return stringBuilder.ToString().Normalize(System.Text.NormalizationForm.FormC);
        }
        
        // Consolidar carpetas duplicadas (variantes del mismo autor)
        private async Task ConsolidateDuplicateFolders()
        {
            try
            {
                if (!System.IO.Directory.Exists(downloadDir))
                {
                    MessageBox.Show(
                        $"La carpeta de descargas no existe:\n{downloadDir}",
                        "Carpeta no encontrada",
                        MessageBoxButtons.OK,
                        MessageBoxIcon.Warning);
                    return;
                }
                
                AutoLog("🔀 Iniciando consolidación de carpetas...");
                
                // Obtener todas las carpetas de autores
                var allFolders = System.IO.Directory.GetDirectories(downloadDir)
                    .Select(d => Path.GetFileName(d))
                    .ToList();
                
                if (allFolders == null || allFolders.Count == 0)
                {
                    MessageBox.Show(
                        "No hay carpetas de autores para consolidar.",
                        "Sin carpetas",
                        MessageBoxButtons.OK,
                        MessageBoxIcon.Information);
                    return;
                }
                
                // Agrupar carpetas similares
                var groups = new Dictionary<string, List<string>>();
                
                foreach (var folder in allFolders)
                {
                    var normalized = NormalizeForComparison(folder);
                    
                    if (!groups.ContainsKey(normalized))
                    {
                        groups[normalized] = new List<string>();
                    }
                    
                    groups[normalized].Add(folder);
                }
                
                // Filtrar solo grupos con duplicados
                var duplicateGroups = groups.Where(g => g.Value.Count > 1).ToList();
                
                if (duplicateGroups.Count == 0)
                {
                    MessageBox.Show(
                        "No se encontraron carpetas duplicadas.\n\nTodas las carpetas están correctamente organizadas.",
                        "Sin duplicados",
                        MessageBoxButtons.OK,
                        MessageBoxIcon.Information);
                    AutoLog("No se encontraron carpetas duplicadas");
                    return;
                }
                
                // Mostrar resumen
                var summary = new System.Text.StringBuilder();
                summary.AppendLine($"Se encontraron {duplicateGroups.Count} grupo(s) de carpetas duplicadas:\n");
                
                int totalFolders = 0;
                foreach (var group in duplicateGroups.Take(10))
                {
                    summary.AppendLine($"• {string.Join(" / ", group.Value)}");
                    totalFolders += group.Value.Count;
                }
                
                if (duplicateGroups.Count > 10)
                {
                    summary.AppendLine($"... y {duplicateGroups.Count - 10} grupo(s) más");
                }
                
                summary.AppendLine($"\nTotal: {totalFolders} carpetas se consolidarán en {duplicateGroups.Count} carpetas.");
                summary.AppendLine("\n¿Deseas continuar?");
                
                var result = MessageBox.Show(
                    summary.ToString(),
                    "Consolidar Carpetas",
                    MessageBoxButtons.YesNo,
                    MessageBoxIcon.Question);
                
                if (result != DialogResult.Yes)
                {
                    AutoLog("Consolidación cancelada por el usuario");
                    return;
                }
                
                // Consolidar
                int movedFiles = 0;
                int deletedFolders = 0;
                int errors = 0;
                
                foreach (var group in duplicateGroups)
                {
                    try
                    {
                        // Elegir carpeta preferida (sin puntos > con tildes > alfabético)
                        var preferredFolder = group.Value
                            .OrderBy(f => f.Count(c => c == '.'))
                            .ThenByDescending(f => f.Any(c => c > 127))
                            .ThenBy(f => f)
                            .First();
                        
                        var preferredPath = Path.Combine(downloadDir, preferredFolder);
                        
                        AutoLog($"🔀 Consolidando en: {preferredFolder}");
                        
                        // Mover archivos de las otras carpetas
                        foreach (var folder in group.Value)
                        {
                            if (folder == preferredFolder)
                                continue;
                            
                            var sourcePath = Path.Combine(downloadDir, folder);
                            
                            try
                            {
                                var files = System.IO.Directory.GetFiles(sourcePath);
                                
                                foreach (var file in files)
                                {
                                    var fileName = Path.GetFileName(file);
                                    var destFile = Path.Combine(preferredPath, fileName);
                                    
                                    // Si el archivo ya existe en destino, comparar tamaños
                                    if (System.IO.File.Exists(destFile))
                                    {
                                        var sourceInfo = new FileInfo(file);
                                        var destInfo = new FileInfo(destFile);
                                        
                                        // Mantener el más grande
                                        if (sourceInfo.Length > destInfo.Length)
                                        {
                                            System.IO.File.Delete(destFile);
                                            System.IO.File.Move(file, destFile);
                                            AutoLog($"  Reemplazado (más grande): {fileName}");
                                            movedFiles++;
                                        }
                                        else
                                        {
                                            System.IO.File.Delete(file);
                                            AutoLog($"  Omitido (ya existe): {fileName}");
                                        }
                                    }
                                    else
                                    {
                                        System.IO.File.Move(file, destFile);
                                        AutoLog($"  Movido: {fileName}");
                                        movedFiles++;
                                    }
                                }
                                
                                // Eliminar carpeta vacía
                                if (System.IO.Directory.GetFiles(sourcePath).Length == 0)
                                {
                                    System.IO.Directory.Delete(sourcePath);
                                    AutoLog($"  Eliminada carpeta vacía: {folder}");
                                    deletedFolders++;
                                }
                            }
                            catch (Exception ex)
                            {
                                AutoLog($"  Error procesando {folder}: {ex.Message}");
                                errors++;
                            }
                        }
                    }
                    catch (Exception ex)
                    {
                        AutoLog($"Error en grupo: {ex.Message}");
                        errors++;
                    }
                }
                
                // Resumen final
                var finalMessage = $"Consolidación completada:\n\n" +
                    $"• {movedFiles} archivo(s) movido(s)\n" +
                    $"• {deletedFolders} carpeta(s) eliminada(s)\n" +
                    $"• {duplicateGroups.Count} grupo(s) consolidado(s)";
                
                if (errors > 0)
                {
                    finalMessage += $"\n\n{errors} error(es) - revisa el log";
                }
                
                MessageBox.Show(
                    finalMessage,
                    "Consolidación Completada",
                    MessageBoxButtons.OK,
                    errors > 0 ? MessageBoxIcon.Warning : MessageBoxIcon.Information);
                
                AutoLog($"Consolidación completada: {movedFiles} archivos, {deletedFolders} carpetas eliminadas");
            }
            catch (Exception ex)
            {
                AutoLog($"Error en consolidación: {ex.Message}");
                MessageBox.Show(
                    $"Error durante la consolidación:\n\n{ex.Message}",
                    "Error",
                    MessageBoxButtons.OK,
                    MessageBoxIcon.Error);
            }
        }
        
        private void CleanDuplicateFiles()
        {
            try
            {
                var result = MessageBox.Show(
                    "Esta herramienta buscará archivos duplicados en tu carpeta de descargas.\n\n" +
                    "Se consideran duplicados los archivos con el mismo nombre (sin importar mayúsculas/minúsculas).\n" +
                    "Se conservará el archivo más reciente y se eliminarán los duplicados.\n\n" +
                    "¿Deseas continuar?",
                    "Limpiar Duplicados",
                    MessageBoxButtons.YesNo,
                    MessageBoxIcon.Question);
                
                if (result != DialogResult.Yes)
                    return;
                
                Log("Iniciando limpieza de duplicados...");
                
                if (!System.IO.Directory.Exists(downloadDir))
                {
                    MessageBox.Show("La carpeta de descargas no existe.", "Error", MessageBoxButtons.OK, MessageBoxIcon.Error);
                    return;
                }
                
                // Obtener todos los archivos recursivamente
                var allFiles = System.IO.Directory.GetFiles(downloadDir, "*.*", SearchOption.AllDirectories)
                    .Select(f => new FileInfo(f))
                    .ToList();
                
                Log($"Analizando {allFiles.Count} archivos...");
                
                // Agrupar por nombre de archivo (sin ruta, case-insensitive)
                var duplicateGroups = allFiles
                    .GroupBy(f => f.Name, StringComparer.OrdinalIgnoreCase)
                    .Where(g => g.Count() > 1)
                    .ToList();
                
                if (duplicateGroups.Count == 0)
                {
                    Log("No se encontraron duplicados");
                    MessageBox.Show("No se encontraron archivos duplicados.", "Limpiar Duplicados", MessageBoxButtons.OK, MessageBoxIcon.Information);
                    return;
                }
                
                int deletedCount = 0;
                long freedSpace = 0;
                
                foreach (var group in duplicateGroups)
                {
                    // Ordenar por fecha de modificación (más reciente primero)
                    var sorted = group.OrderByDescending(f => f.LastWriteTime).ToList();
                    var keep = sorted.First();
                    var toDelete = sorted.Skip(1).ToList();
                    
                    Log($"{group.Key}: conservando {keep.FullName}");
                    
                    foreach (var file in toDelete)
                    {
                        try
                        {
                            freedSpace += file.Length;
                            file.Delete();
                            deletedCount++;
                            Log($"  Eliminado: {file.FullName}");
                        }
                        catch (Exception ex)
                        {
                            Log($"  Error eliminando {file.FullName}: {ex.Message}");
                        }
                    }
                }
                
                var freedMB = freedSpace / (1024.0 * 1024.0);
                var message = $"Limpieza completada:\n\n" +
                             $"• Archivos eliminados: {deletedCount}\n" +
                             $"• Espacio liberado: {freedMB:F2} MB\n" +
                             $"• Grupos de duplicados: {duplicateGroups.Count}";
                
                Log($"{message.Replace("\n", " ")}");
                MessageBox.Show(message, "Limpiar Duplicados", MessageBoxButtons.OK, MessageBoxIcon.Information);
            }
            catch (Exception ex)
            {
                Log($"Error en CleanDuplicateFiles: {ex.Message}");
                MessageBox.Show($"Error limpiando duplicados:\n{ex.Message}", "Error", MessageBoxButtons.OK, MessageBoxIcon.Error);
            }
        }
        
