        // MEJORA #5: Verificar hitos de progreso
        private void CheckProgressMilestone()
        {
            try
            {
                if (totalDownloadsInSession == 0)
                    return;
                
                int completed = 0;
                lock (downloadQueueLock)
                {
                    completed = downloadQueue.Count(t => t.Status == DownloadStatus.Completed);
                }
                
                int progressPercent = (int)((double)completed / totalDownloadsInSession * 100);
                
                if (progressPercent >= 25 && lastProgressNotification < 25)
                {
                    ShowNotification("Progreso 25%", 
                        $"{completed}/{totalDownloadsInSession} archivos completados\n\n¡Vas por buen camino!", 
                        ToolTipIcon.Info);
                    lastProgressNotification = 25;
                    AutoLog($"Progreso 25%: {completed}/{totalDownloadsInSession} archivos");
                }
                else if (progressPercent >= 50 && lastProgressNotification < 50)
                {
                    ShowNotification("Progreso 50%", 
                        $"{completed}/{totalDownloadsInSession} archivos completados\n\n¡A mitad de camino!", 
                        ToolTipIcon.Info);
                    lastProgressNotification = 50;
                    AutoLog($"Progreso 50%: {completed}/{totalDownloadsInSession} archivos");
                }
                else if (progressPercent >= 75 && lastProgressNotification < 75)
                {
                    ShowNotification("Progreso 75%", 
                        $"{completed}/{totalDownloadsInSession} archivos completados\n\n¡Casi terminado!", 
                        ToolTipIcon.Info);
                    lastProgressNotification = 75;
                    AutoLog($"Progreso 75%: {completed}/{totalDownloadsInSession} archivos");
                }
                else if (progressPercent >= 100 && lastProgressNotification < 100)
                {
                    ShowNotification("¡Completado!", 
                        $"{completed}/{totalDownloadsInSession} archivos completados\n\n¡Todas las descargas finalizadas!", 
                        ToolTipIcon.Info);
                    lastProgressNotification = 100;
                    AutoLog($"100% Completado: {completed}/{totalDownloadsInSession} archivos");
                }
            }
            catch (Exception ex)
            {
                AutoLog($"Error verificando progreso: {ex.Message}");
            }
        }
        
        // MEJORA #8: Backoff exponencial para reintentos
        private int GetRetryDelay(int retryCount)
        {
            // Backoff exponencial: 30s, 60s, 120s, 240s, máximo 480s (8 minutos)
            return (int)Math.Min(30 * Math.Pow(2, retryCount), 480);
        }
        
        // MEJORA #7: Obtener proveedores cacheados
        private List<string> GetCachedProviders(string fileName)
        {
            lock (fileProvidersCache)
            {
                if (fileProvidersCache.TryGetValue(fileName, out var data))
                {
                    if ((DateTime.Now - data.cached).TotalHours < PROVIDER_CACHE_HOURS)
                    {
                        AutoLog($"Proveedores en caché para: {fileName} ({data.providers.Count})");
                        return new List<string>(data.providers);
                    }
                    else
                    {
                        fileProvidersCache.Remove(fileName);
                    }
                }
            }
            return null;
        }
        
        // MEJORA #7: Cachear proveedores
        private void CacheProviders(string fileName, List<string> providers)
        {
            if (providers == null || providers.Count == 0)
                return;
            
            lock (fileProvidersCache)
            {
                fileProvidersCache[fileName] = (new List<string>(providers), DateTime.Now);
                AutoLog($"Cacheados {providers.Count} proveedores para: {fileName}");
            }
        }
        
        // Levenshtein distance para fuzzy matching
        private int LevenshteinDistance(string s1, string s2)
        {
            if (string.IsNullOrEmpty(s1)) return s2?.Length ?? 0;
            if (string.IsNullOrEmpty(s2)) return s1.Length;
            
            int[,] d = new int[s1.Length + 1, s2.Length + 1];
            
            for (int i = 0; i <= s1.Length; i++)
                d[i, 0] = i;
            for (int j = 0; j <= s2.Length; j++)
                d[0, j] = j;
            
            for (int i = 1; i <= s1.Length; i++)
            {
                for (int j = 1; j <= s2.Length; j++)
                {
                    int cost = (s2[j - 1] == s1[i - 1]) ? 0 : 1;
                    d[i, j] = Math.Min(Math.Min(d[i - 1, j] + 1, d[i, j - 1] + 1), d[i - 1, j - 1] + cost);
                }
            }
            
            return d[s1.Length, s2.Length];
        }
        
        // Calcular similitud entre 0 y 1 (1 = idéntico, 0 = completamente diferente)
        private double CalculateSimilarity(string s1, string s2)
        {
            if (string.IsNullOrEmpty(s1) || string.IsNullOrEmpty(s2))
                return 0;
            
            int maxLen = Math.Max(s1.Length, s2.Length);
            if (maxLen == 0) return 1;
            
            int distance = LevenshteinDistance(s1.ToLowerInvariant(), s2.ToLowerInvariant());
            return 1.0 - ((double)distance / maxLen);
        }
        
        // Normalizar nombre de archivo para comparación
        private string NormalizeFileName(string fileName)
        {
            if (string.IsNullOrEmpty(fileName))
                return string.Empty;
            
            // Remover extensión
            fileName = Path.GetFileNameWithoutExtension(fileName);
            
            // Convertir a minúsculas
            fileName = fileName.ToLowerInvariant();
            
            // Remover caracteres especiales y espacios múltiples
            fileName = System.Text.RegularExpressions.Regex.Replace(fileName, @"[^\w\s]", " ");
            fileName = System.Text.RegularExpressions.Regex.Replace(fileName, @"\s+", " ");
            
            return fileName.Trim();
        }
        
        // Cargar blacklist de autores desde archivo
        private void LoadBlacklistedAuthors()
        {
            try
            {
                blacklistedAuthors.Clear();
                ClearBlacklistCache(); // Limpiar caché al recargar
                
                if (System.IO.File.Exists(blacklistAuthorsFile))
                {
                    var lines = System.IO.File.ReadAllLines(blacklistAuthorsFile, Encoding.UTF8);
                    foreach (var line in lines)
                    {
                        if (!string.IsNullOrWhiteSpace(line) && !line.TrimStart().StartsWith("#"))
                        {
                            blacklistedAuthors.Add(line.Trim());
                        }
                    }
                    Log($"Blacklist cargada: {blacklistedAuthors.Count} autores ignorados");
                }
            }
            catch (Exception ex)
            {
                Log($"Error cargando blacklist: {ex.Message}");
            }
        }
        
        // Guardar blacklist de autores a archivo
        private void SaveBlacklistedAuthors()
        {
            try
            {
                var lines = new List<string>
                {
                    "# Autores ignorados - uno por línea",
                    "# Las líneas que comienzan con # son comentarios",
                    ""
                };
                lines.AddRange(blacklistedAuthors.OrderBy(a => a));
                
                System.IO.File.WriteAllLines(blacklistAuthorsFile, lines, Encoding.UTF8);
                Log($"Blacklist guardada: {blacklistedAuthors.Count} autores");
            }
            catch (Exception ex)
            {
                Log($"Error guardando blacklist: {ex.Message}");
            }
        }
        
        // Agregar autor a blacklist
        private void AddToBlacklist(string author)
        {
            if (string.IsNullOrWhiteSpace(author))
                return;
            
            author = author.Trim();
            if (blacklistedAuthors.Add(author))
            {
                // Actualizar caché inmediatamente
                blacklistCache[author] = true;
                
                SaveBlacklistedAuthors();
                Log($"Autor agregado a blacklist: {author}");
            }
        }
        
        // Verificar si un autor está en blacklist (con caché para performance)
        private bool IsAuthorBlacklisted(string author)
        {
            if (string.IsNullOrWhiteSpace(author))
                return false;
            
            author = author.Trim();
            
            // Verificar caché primero (O(1) lookup)
            if (blacklistCache.TryGetValue(author, out bool isBlacklisted))
                return isBlacklisted;
            
            // Si no está en caché, verificar en HashSet y cachear resultado
            isBlacklisted = blacklistedAuthors.Contains(author);
            blacklistCache[author] = isBlacklisted;
            
            return isBlacklisted;
        }
        
        // Limpiar caché de blacklist (llamar al recargar blacklist)
        private void ClearBlacklistCache()
        {
            blacklistCache.Clear();
        }
        
