        private void CancelDownload()
        {
            if (lvDownloads.SelectedItems.Count == 0)
                return;
            
            int cancelledCount = 0;
            
            // Procesar TODOS los archivos seleccionados
            foreach (ListViewItem item in lvDownloads.SelectedItems)
            {
                var fileName = item.Text;
                
                if (activeDownloads.ContainsKey(fileName))
                {
                    activeDownloads[fileName].Cancel();
                    item.SubItems[3].Text = "Cancelando...";
                    cancelledCount++;
                }
            }
            
            if (cancelledCount > 0)
            {
                Log($"{cancelledCount} descarga(s) cancelada(s)");
            }
        }
        
        private void PauseDownload()
        {
            if (lvDownloads.SelectedItems.Count == 0)
                return;
            
            int pausedCount = 0;
            
            // Procesar TODOS los archivos seleccionados
            foreach (ListViewItem selectedItem in lvDownloads.SelectedItems)
            {
                var task = selectedItem.Tag as DownloadTask;
                
                if (task != null && task.Status == DownloadStatus.Downloading)
                {
                    lock (downloadQueueLock)
                    {
                        task.Status = DownloadStatus.Paused;
                        task.CancellationToken?.Cancel();
                        UpdateDownloadUI(task, "Pausado");
                        pausedCount++;
                    }
                }
            }
            
            if (pausedCount > 0)
            {
                AutoLog($"{pausedCount} descarga(s) pausada(s)");
            }
            else
            {
                MessageBox.Show("Solo se pueden pausar descargas activas", "Pausar descarga", MessageBoxButtons.OK, MessageBoxIcon.Warning);
            }
        }
        
        private void ResumeDownload()
        {
            if (lvDownloads.SelectedItems.Count == 0)
                return;
            
            int resumedCount = 0;
            
            // Procesar TODOS los archivos seleccionados
            foreach (ListViewItem selectedItem in lvDownloads.SelectedItems)
            {
                var task = selectedItem.Tag as DownloadTask;
                
                if (task != null && task.Status == DownloadStatus.Paused)
                {
                    lock (downloadQueueLock)
                    {
                        task.Status = DownloadStatus.Queued;
                        task.CancellationToken = new CancellationTokenSource();
                        UpdateDownloadUI(task, "Pendiente");
                        resumedCount++;
                    }
                }
            }
            
            if (resumedCount > 0)
            {
                AutoLog($"{resumedCount} descarga(s) reanudada(s)");
            }
            else
            {
                MessageBox.Show("Solo se pueden reanudar descargas pausadas", "Reanudar descarga", MessageBoxButtons.OK, MessageBoxIcon.Warning);
            }
        }
        
        private void SetDownloadPriority(DownloadPriority priority)
        {
            if (lvDownloads.SelectedItems.Count == 0)
                return;
            
            int changedCount = 0;
            string priorityIcon = priority switch
            {
                DownloadPriority.High => "HIGH",
                DownloadPriority.Normal => "NORMAL",
                DownloadPriority.Low => "LOW",
                _ => "NORMAL"
            };
            
            // Procesar TODOS los archivos seleccionados
            foreach (ListViewItem selectedItem in lvDownloads.SelectedItems)
            {
                var task = selectedItem.Tag as DownloadTask;
                
                if (task != null)
                {
                    lock (downloadQueueLock)
                    {
                        task.Priority = priority;
                        changedCount++;
                    }
                }
            }
            
            if (changedCount > 0)
            {
                AutoLog($"{priorityIcon} Prioridad cambiada a {priority}: {changedCount} descarga(s)");
                SaveDownloadQueue(); // Guardar cambio
            }
        }
        
        private void AddUserToPremiumList()
        {
            if (lvDownloads.SelectedItems.Count == 0)
            {
                ShowDarkDialog("Selecciona una descarga primero", "Info", MessageBoxButtons.OK, "Info");
                return;
            }
            
            var task = lvDownloads.SelectedItems[0].Tag as DownloadTask;
            if (task == null) return;
            
            string username = task.File.Username;
            
            if (premiumUsers.Contains(username))
            {
                ShowDarkDialog($"El usuario '{username}' ya está en la lista Premium", "Info", MessageBoxButtons.OK, "INFO");
                return;
            }
            
            premiumUsers.Add(username);
            SavePremiumUsers();
            
            Log($"Usuario agregado a lista Premium: {username}");
            ShowDarkDialog($"Usuario '{username}' agregado a lista Premium\n\nEste usuario tendrá máxima prioridad en futuras descargas.", 
                "Usuario Premium", MessageBoxButtons.OK, "PREMIUM");
        }
        
        private void RemoveUserFromPremiumList()
        {
            if (lvDownloads.SelectedItems.Count == 0)
            {
                ShowDarkDialog("Selecciona una descarga primero", "Info", MessageBoxButtons.OK, "Info");
                return;
            }
            
            var task = lvDownloads.SelectedItems[0].Tag as DownloadTask;
            if (task == null) return;
            
            string username = task.File.Username;
            
            if (!premiumUsers.Contains(username))
            {
                ShowDarkDialog($"El usuario '{username}' no está en la lista Premium", "Info", MessageBoxButtons.OK, "INFO");
                return;
            }
            
            premiumUsers.Remove(username);
            SavePremiumUsers();
            
            Log($"Usuario removido de lista Premium: {username}");
            ShowDarkDialog($"Usuario '{username}' removido de lista Premium", 
                "Usuario Premium", MessageBoxButtons.OK, "OK");
        }
        
