        }
        
        private bool IsFileDownloaded(string path)
        {
            lock (fileExistsCacheLock)
            {
                if (fileExistsCache.TryGetValue(path, out var cached))
                {
                    if (DateTime.Now - cached.checkedAt < cacheExpiration)
                        return cached.exists;
                }
                
                bool exists = System.IO.File.Exists(path);
                fileExistsCache[path] = (exists, DateTime.Now);
                return exists;
            }
        }
        
        private void InvalidateFileCache(string path)
        {
            lock (fileExistsCacheLock)
            {
                fileExistsCache.Remove(path);
            }
        }
        
        private void ClearFileCache()
        {
            lock (fileExistsCacheLock)
            {
                fileExistsCache.Clear();
            }
        }
        
        private void BuildAuthorIndex()
        {
            lock (authorIndexLock)
            {
                filesByAuthorIndex.Clear();
                
                // OPTIMIZACIÓN: Usar procesamiento paralelo para grandes volúmenes
                List<AutoSearchFileResult> filesToIndex;
                
                    filesToIndex = autoSearchResults.ToList();
                
                
                if (filesToIndex.Count > 1000)
                {
                    // Procesamiento paralelo para >1000 archivos (4x más rápido)
                    var tempIndex = new System.Collections.Concurrent.ConcurrentDictionary<string, System.Collections.Concurrent.ConcurrentBag<AutoSearchFileResult>>();
                    
                    Parallel.ForEach(filesToIndex, new ParallelOptions { MaxDegreeOfParallelism = Environment.ProcessorCount },
                        file =>
                        {
                            var bag = tempIndex.GetOrAdd(file.Author, _ => new System.Collections.Concurrent.ConcurrentBag<AutoSearchFileResult>());
                            bag.Add(file);
                        });
                    
                    // Convertir a diccionario normal
                    foreach (var kvp in tempIndex)
                    {
                        filesByAuthorIndex[kvp.Key] = kvp.Value.ToList();
                    }
                    
                    AutoLog($"📇 Índice de autores construido (paralelo): {filesByAuthorIndex.Count} autores indexados");
                }
                else
                {
                    // Procesamiento secuencial para pocos archivos
                    foreach (var file in filesToIndex)
                    {
                        if (!filesByAuthorIndex.ContainsKey(file.Author))
                        {
                            filesByAuthorIndex[file.Author] = new List<AutoSearchFileResult>();
                        }
                        filesByAuthorIndex[file.Author].Add(file);
                    }
                    
                    AutoLog($"📇 Índice de autores construido: {filesByAuthorIndex.Count} autores indexados");
                }
            }
        }
        
        private List<AutoSearchFileResult> SearchByAuthor(string authorQuery)
        {
            var results = new List<AutoSearchFileResult>();
            
            lock (authorIndexLock)
            {
                var matchingAuthors = filesByAuthorIndex.Keys
                    .Where(author => author.IndexOf(authorQuery, StringComparison.OrdinalIgnoreCase) >= 0)
                    .ToList();
                
                foreach (var author in matchingAuthors)
                {
                    results.AddRange(filesByAuthorIndex[author]);
                }
            }
            
            return results;
        }
        
        private void UpdateProviderStats(string username, bool success, double speedMBps, long bytes)
        {
            lock (providerStatsLock)
            {
                if (!providerStats.ContainsKey(username))
                {
                    providerStats[username] = new ProviderStats { Username = username };
                }
                
                var stats = providerStats[username];
                stats.TotalDownloads++;
                
                if (success)
                {
                    stats.SuccessfulDownloads++;
                    stats.TotalBytesDownloaded += bytes;
                    
                    // Calcular velocidad promedio ponderada
                    double totalSpeed = stats.AverageSpeed * (stats.SuccessfulDownloads - 1) + speedMBps;
                    stats.AverageSpeed = totalSpeed / stats.SuccessfulDownloads;
                }
                else
                {
                    stats.FailedDownloads++;
                }
                
                stats.LastDownload = DateTime.Now;
            }
        }
        
        private ProviderStats GetProviderStats(string username)
        {
            lock (providerStatsLock)
            {
                return providerStats.TryGetValue(username, out var stats) ? stats : null;
            }
        }
        
        private double GetProviderScore(string username)
        {
            var stats = GetProviderStats(username);
            return stats?.QualityScore ?? 0;
        }
        
        private async Task<bool> ShouldSkipDownloadDuplicate(AutoSearchFileResult file)
        {
            try
            {
                // 1. Verificación rápida: Ya descargado según historial
                if (IsAlreadyDownloaded(file.FileName, file.Username, file.SizeBytes))
                {
                    return true;
                }
                
                // 2. Buscar archivos con mismo nombre en disco
                var downloadPath = txtDownloadDir?.Text ?? 
                    Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.MyDocuments), "SlskDown");
                
                if (!System.IO.Directory.Exists(downloadPath))
                    return false;
                
                var existingFiles = System.IO.Directory.GetFiles(downloadPath, file.FileName, SearchOption.AllDirectories);
                
                if (!existingFiles.Any())
                    return false;
                
                // 3. Verificar por hash (ultra-rápido con Rust)
                foreach (var existingFile in existingFiles)
                {
                    try
                    {
                        var fileInfo = new FileInfo(existingFile);
                        
                        // Si el tamaño es diferente, no es duplicado
                        if (Math.Abs(fileInfo.Length - file.SizeBytes) > 1024) // Tolerancia de 1KB
                            continue;
                        
                        // Calcular hash del archivo existente
                        string existingHash = await Task.Run(() => 
                            SlskDownCore.HashFileBlake3(existingFile)
                        );
                        
                        // Buscar en historial si ya tenemos este hash
                        bool hashExists = false;
                        lock (downloadHistoryLock)
                        {
                            hashExists = downloadHistory.Any(h => 
                                h.Hash == existingHash && 
                                !string.IsNullOrEmpty(h.Hash)
                            );
                        }
                        
                        if (hashExists)
                        {
                            AutoLog($"Hash duplicado encontrado: {file.FileName}");
                            return true; // Es duplicado
                        }
                    }
                    catch (Exception ex)
                    {
                        AutoLog($"Error verificando hash de {Path.GetFileName(existingFile)}: {ex.Message}");
                    }
                }
                
                return false; // No es duplicado
            }
            catch (Exception ex)
            {
                AutoLog($"Error en verificación de duplicados: {ex.Message}");
                return false; // En caso de error, permitir descarga
            }
        }
        
        private void RenameToLibreFormat(string filePath, string author)
        {
            try
            {
                // Extensiones de ebooks soportadas
                string[] ebookExtensions = { ".epub", ".mobi", ".azw", ".azw3", ".pdf", ".fb2", ".lit", ".prc", ".djvu", ".cbr", ".cbz" };
                
                string extension = Path.GetExtension(filePath).ToLower();
                if (!ebookExtensions.Contains(extension))
                {
                    return; // No es un ebook, no renombrar
                }
                
                string fileName = Path.GetFileNameWithoutExtension(filePath);
                string directory = Path.GetDirectoryName(filePath);
                
                // Limpiar nombre del archivo
                string cleanTitle = CleanFileName(fileName);
                
                // Limpiar nombre del autor
                string cleanAuthor = CleanAuthorName(author);
                
                // Formato Calibre: "Título - Autor.ext"
                string newFileName = $"{cleanTitle} - {cleanAuthor}{extension}";
                string newFilePath = Path.Combine(directory, newFileName);
                
                // Evitar sobrescribir si ya existe
                if (System.IO.File.Exists(newFilePath))
                {
                    AutoLog($"El archivo ya existe: {newFileName}");
                    return;
                }
                
                // Renombrar archivo
                System.IO.File.Move(filePath, newFilePath);
                AutoLog($"Renombrado a formato Calibre: {newFileName}");
            }
            catch (Exception ex)
            {
                AutoLog($"Error renombrando archivo: {ex.Message}");
            }
        }
        
        private string CleanFileName(string fileName)
        {
            // Remover caracteres inválidos y limpiar
            string cleaned = fileName;
            
            // Remover extensiones comunes que vienen en el nombre
            cleaned = System.Text.RegularExpressions.Regex.Replace(cleaned, @"\.(epub|mobi|pdf|azw3?)$", "", System.Text.RegularExpressions.RegexOptions.IgnoreCase);
            
            // Remover caracteres especiales comunes
            cleaned = cleaned.Replace("_", " ");
            cleaned = cleaned.Replace(".", " ");
            cleaned = cleaned.Replace("-", " ");
            
            // Remover múltiples espacios
            cleaned = System.Text.RegularExpressions.Regex.Replace(cleaned, @"\s+", " ");
            
            // Capitalizar primera letra de cada palabra
            cleaned = System.Globalization.CultureInfo.CurrentCulture.TextInfo.ToTitleCase(cleaned.ToLower());
            
            return cleaned.Trim();
        }
        
        private string CleanAuthorName(string author)
        {
            if (string.IsNullOrWhiteSpace(author))
            {
                return "Unknown Author";
            }
            
            string cleaned = author;
            
            // Remover caracteres especiales
            cleaned = cleaned.Replace("_", " ");
            cleaned = cleaned.Replace(".", " ");
            
            // Remover múltiples espacios
            cleaned = System.Text.RegularExpressions.Regex.Replace(cleaned, @"\s+", " ");
            
            // Capitalizar nombre
            cleaned = System.Globalization.CultureInfo.CurrentCulture.TextInfo.ToTitleCase(cleaned.ToLower());
            
            return cleaned.Trim();
        }
        
        private List<ProviderStats> GetTopProviders(int count = 10)
        {
            lock (providerStatsLock)
            {
                return providerStats.Values
                    .OrderByDescending(p => p.QualityScore)
                    .Take(count)
                    .ToList();
            }
        }
        
        private void InitializeDatabase()
        {
            try
            {
                SafeLog( "  - Creando connection string...\n");
                var connectionString = $"Data Source={dbPath}";
                SafeLog( $"  - DB Path: {dbPath}\n");
                
                SafeLog( "  - Creando SqliteConnection...\n");
                dbConnection = new SqliteConnection(connectionString);
                
                SafeLog( "  - Abriendo conexión...\n");
                dbConnection.Open();
                SafeLog( "  - Conexión abierta OK\n");
                
                // Crear tablas
                SafeLog( "  - Preparando SQL para crear tablas...\n");
                var createTables = @"
                    CREATE TABLE IF NOT EXISTS Files (
                        Id INTEGER PRIMARY KEY AUTOINCREMENT,
                        FileName TEXT NOT NULL,
                        Author TEXT NOT NULL,
                        Username TEXT NOT NULL,
                        Directory TEXT,
                        SizeBytes INTEGER NOT NULL,
                        IsSpanish INTEGER DEFAULT 0,
                        IsDocument INTEGER DEFAULT 0,
                        Timestamp TEXT NOT NULL,
                        UNIQUE(FileName, Author, Username)
                    );
                    
                    CREATE TABLE IF NOT EXISTS DownloadHistory (
                        Id INTEGER PRIMARY KEY AUTOINCREMENT,
                        FileName TEXT NOT NULL,
                        Author TEXT,
                        Username TEXT NOT NULL,
                        SizeBytes INTEGER NOT NULL,
                        DownloadedAt TEXT NOT NULL,
                        Status TEXT NOT NULL,
                        SpeedMBps REAL,
                        LocalPath TEXT
                    );
                    
                    CREATE TABLE IF NOT EXISTS ProviderStats (
                        Username TEXT PRIMARY KEY,
                        TotalDownloads INTEGER DEFAULT 0,
                        SuccessfulDownloads INTEGER DEFAULT 0,
                        FailedDownloads INTEGER DEFAULT 0,
                        AverageSpeed REAL DEFAULT 0,
                        TotalBytesDownloaded INTEGER DEFAULT 0,
                        LastDownload TEXT
                    );
                    
                    -- Optimización #10: Índices inteligentes para queries frecuentes
                    CREATE INDEX IF NOT EXISTS idx_files_author ON Files(Author);
                    CREATE INDEX IF NOT EXISTS idx_files_filename ON Files(FileName);
                    CREATE INDEX IF NOT EXISTS idx_history_date ON DownloadHistory(DownloadedAt);
                    CREATE INDEX IF NOT EXISTS idx_provider_quality ON ProviderStats(SuccessfulDownloads, AverageSpeed);
                    
                    -- Índices compuestos para búsquedas complejas (100-1000x más rápido)
                    CREATE INDEX IF NOT EXISTS idx_files_author_filename ON Files(Author, FileName);
                    CREATE INDEX IF NOT EXISTS idx_files_author_spanish ON Files(Author, IsSpanish, IsDocument);
                    CREATE INDEX IF NOT EXISTS idx_files_size_ext ON Files(SizeBytes, FileName);
                    CREATE INDEX IF NOT EXISTS idx_files_timestamp_spanish ON Files(Timestamp, IsSpanish);
                    CREATE INDEX IF NOT EXISTS idx_files_spanish_doc ON Files(IsSpanish, IsDocument) WHERE IsSpanish = 1 AND IsDocument = 1;
                    CREATE INDEX IF NOT EXISTS idx_files_username_size ON Files(Username, SizeBytes);
                    
                    -- Índices para historial y estadísticas
                    CREATE INDEX IF NOT EXISTS idx_history_status ON DownloadHistory(Status, DownloadedAt);
                    CREATE INDEX IF NOT EXISTS idx_history_author ON DownloadHistory(Author);
                    CREATE INDEX IF NOT EXISTS idx_history_author_status ON DownloadHistory(Author, Status);
                    CREATE INDEX IF NOT EXISTS idx_provider_success_rate ON ProviderStats(SuccessfulDownloads, TotalDownloads);
                ";
                
                SafeLog( "  - Ejecutando CREATE TABLES...\n");
                using (var cmd = new SqliteCommand(createTables, dbConnection))
                {
                    cmd.ExecuteNonQuery();
                }
                SafeLog( "  - Tablas e índices creados OK\n");
                
                // PRAGMA OPTIMIZATIONS para máximo rendimiento
                SafeLog( "  - Aplicando PRAGMA optimizations...\n");
                var pragmas = @"
                    PRAGMA journal_mode = WAL;
                    PRAGMA synchronous = NORMAL;
                    PRAGMA cache_size = -64000;
                    PRAGMA temp_store = MEMORY;
                    PRAGMA mmap_size = 268435456;
                    PRAGMA page_size = 4096;
                    PRAGMA auto_vacuum = INCREMENTAL;
                ";
                
                using (var cmd = new SqliteCommand(pragmas, dbConnection))
                {
                    cmd.ExecuteNonQuery();
                }
                SafeLog( "  - PRAGMA optimizations aplicadas OK\n");
                
                AutoLog("Base de datos SQLite inicializada");
                
                // Migrar datos existentes si es necesario
                SafeLog( "  - Iniciando migración CSV...\n");
                MigrateFromCsvToSqlite();
                SafeLog( "  - Migración completada\n");
            }
            catch (Exception ex)
            {
                AutoLog($"Error inicializando base de datos: {ex.Message}");
            }
        }
        
        private void MigrateFromCsvToSqlite()
        {
            try
            {
                SafeLog( "    - Verificando datos existentes en BD...\n");
                // Verificar si ya hay datos en la BD
                using (var cmd = new SqliteCommand("SELECT COUNT(*) FROM Files", dbConnection))
                {
                    var count = Convert.ToInt64(cmd.ExecuteScalar());
                    SafeLog( $"    - BD contiene {count} archivos\n");
                    if (count > 0)
                    {
                        AutoLog($"Base de datos ya contiene {count} archivos");
                        SafeLog( "    - Cargando archivos desde BD de forma asíncrona...\n");
                        
                        // Cargar de forma asíncrona para no bloquear el UI
                        Task.Run(() =>
                        {
                            try
                            {
                                LoadFilesFromDatabase();
                                SafeLog( "    - Archivos cargados OK (async)\n");
                            }
                            catch (Exception ex)
                            {
                                SafeLog($"    - Error cargando archivos: {ex.Message}\n");
                            }
                        });
                        
                        return;
                    }
                }
                
                SafeLog( $"    - Verificando CSV: {autoResultsCsvPath}\n");
                // Migrar desde CSV si existe
                if (System.IO.File.Exists(autoResultsCsvPath))
                {
                    SafeLog( "    - CSV existe, iniciando migración...\n");
                    AutoLog("Migrando datos desde CSV a SQLite...");
                    
                    
                        SafeLog( $"    - autoSearchResults.Count: {autoSearchResults.Count}\n");
                        if (autoSearchResults.Count > 0)
                        {
                            SafeLog( "    - Guardando archivos en BD...\n");
                            SaveFilesToDatabase(autoSearchResults);
                            SafeLog( "    - Archivos guardados OK\n");
                            AutoLog($"Migrados {autoSearchResults.Count} archivos a SQLite");
                        }
                        else
                        {
                            SafeLog( "    - No hay archivos para migrar\n");
                        }
                    
                }
                else
                {
                    SafeLog( "    - CSV no existe, saltando migración\n");
                }
            }
            catch (Exception ex)
            {
                SafeLog( $"    - ERROR en migración: {ex.Message}\n");
                AutoLog($"Error en migración: {ex.Message}");
            }
        }
        
        private void SaveFilesToDatabase(IEnumerable<AutoSearchFileResult> files)
        {
            try
            {
                // Verificar que la conexión existe y está abierta
                if (dbConnection == null || dbConnection.State != System.Data.ConnectionState.Open)
                {
                    return; // No guardar si no hay conexión
                }
                
                using (var transaction = dbConnection.BeginTransaction())
                {
                    var insertCmd = @"INSERT OR REPLACE INTO Files 
                        (FileName, Author, Username, Directory, SizeBytes, IsSpanish, IsDocument, Timestamp) 
                        VALUES (@fileName, @author, @username, @directory, @sizeBytes, @isSpanish, @isDocument, @timestamp)";
                    
                    foreach (var file in files)
                    {
                        using (var cmd = new SqliteCommand(insertCmd, dbConnection, transaction))
                        {
                            cmd.Parameters.AddWithValue("@fileName", file.FileName);
                            cmd.Parameters.AddWithValue("@author", file.Author);
                            cmd.Parameters.AddWithValue("@username", file.Username);
                            cmd.Parameters.AddWithValue("@directory", file.Directory ?? "");
                            cmd.Parameters.AddWithValue("@sizeBytes", file.SizeBytes);
                            cmd.Parameters.AddWithValue("@isSpanish", file.IsSpanish ? 1 : 0);
                            cmd.Parameters.AddWithValue("@isDocument", file.IsDocument ? 1 : 0);
                            cmd.Parameters.AddWithValue("@timestamp", file.Timestamp.ToString("o"));
                            cmd.ExecuteNonQuery();
                        }
                    }
                    
                    transaction.Commit();
                }
            }
            catch (Exception ex)
            {
                AutoLog($"Error guardando archivos en BD: {ex.Message}");
            }
        }
        
        private void LoadFilesFromDatabase()
        {
            try
            {
                // Verificar que la conexión esté abierta
                if (dbConnection == null || dbConnection.State != System.Data.ConnectionState.Open)
                {
                    AutoLog("No se puede cargar archivos: conexión a BD no está abierta");
                    return;
                }
                
                var query = "SELECT FileName, Author, Username, Directory, SizeBytes, IsSpanish, IsDocument, Timestamp FROM Files";
                
                using (var cmd = new SqliteCommand(query, dbConnection))
                using (var reader = cmd.ExecuteReader())
                {
                    var files = new List<AutoSearchFileResult>();
                    
                    while (reader.Read())
                    {
                        files.Add(new AutoSearchFileResult
                        {
                            FileName = reader.GetString(0),
                            Author = reader.GetString(1),
                            Username = reader.GetString(2),
                            Directory = reader.GetString(3),
                            SizeBytes = reader.GetInt64(4),
                            SizeReadable = FormatFileSize(reader.GetInt64(4)),
                            IsSpanish = reader.GetInt32(5) == 1,
                            IsDocument = reader.GetInt32(6) == 1,
                            Timestamp = DateTime.Parse(reader.GetString(7))
                        });
                    }
                    
                    
                        autoSearchResults = new System.Collections.Concurrent.ConcurrentBag<AutoSearchFileResult>();
                        AddRangeToAutoSearchResults(files);
                    
                    
                    AutoLog($"Cargados {files.Count} archivos desde SQLite");
                }
            }
            catch (Exception ex)
            {
                AutoLog($"Error cargando archivos desde BD: {ex.Message}");
            }
        }
        
        private void SaveProviderStatsToDatabase()
        {
            try
            {
                // Verificar que la conexión existe y está abierta
                if (dbConnection == null || dbConnection.State != System.Data.ConnectionState.Open)
                {
                    return; // No guardar si no hay conexión
                }
                
                lock (providerStatsLock)
                {
                    using (var transaction = dbConnection.BeginTransaction())
                    {
                        var insertCmd = @"INSERT OR REPLACE INTO ProviderStats 
                            (Username, TotalDownloads, SuccessfulDownloads, FailedDownloads, AverageSpeed, TotalBytesDownloaded, LastDownload) 
                            VALUES (@username, @total, @success, @failed, @speed, @bytes, @lastDownload)";
                        
                        foreach (var stat in providerStats.Values)
                        {
                            using (var cmd = new SqliteCommand(insertCmd, dbConnection, transaction))
                            {
                                cmd.Parameters.AddWithValue("@username", stat.Username);
                                cmd.Parameters.AddWithValue("@total", stat.TotalDownloads);
                                cmd.Parameters.AddWithValue("@success", stat.SuccessfulDownloads);
                                cmd.Parameters.AddWithValue("@failed", stat.FailedDownloads);
                                cmd.Parameters.AddWithValue("@speed", stat.AverageSpeed);
                                cmd.Parameters.AddWithValue("@bytes", stat.TotalBytesDownloaded);
                                cmd.Parameters.AddWithValue("@lastDownload", stat.LastDownload.ToString("o"));
                                cmd.ExecuteNonQuery();
                            }
                        }
                        
                        transaction.Commit();
                    }
                }
            }
            catch (Exception ex)
            {
                AutoLog($"Error guardando stats de proveedores: {ex.Message}");
            }
        }
        
        private void LoadProviderStatsFromDatabase()
        {
            try
            {
                // Verificar que la conexión esté abierta
                if (dbConnection == null || dbConnection.State != System.Data.ConnectionState.Open)
                {
                    AutoLog("No se puede cargar estadísticas: conexión a BD no está abierta");
                    return;
                }
                
                var query = "SELECT Username, TotalDownloads, SuccessfulDownloads, FailedDownloads, AverageSpeed, TotalBytesDownloaded, LastDownload FROM ProviderStats";
                
                using (var cmd = new SqliteCommand(query, dbConnection))
                using (var reader = cmd.ExecuteReader())
                {
                    lock (providerStatsLock)
                    {
                        providerStats.Clear();
                        
                        while (reader.Read())
                        {
                            var stat = new ProviderStats
                            {
                                Username = reader.GetString(0),
                                TotalDownloads = reader.GetInt32(1),
                                SuccessfulDownloads = reader.GetInt32(2),
                                FailedDownloads = reader.GetInt32(3),
                                AverageSpeed = reader.GetDouble(4),
                                TotalBytesDownloaded = reader.GetInt64(5),
                                LastDownload = DateTime.Parse(reader.GetString(6))
                            };
                            
                            providerStats[stat.Username] = stat;
                        }
                    }
                    
                    AutoLog($"Cargadas estadísticas de {providerStats.Count} proveedores");
                }
            }
            catch (Exception ex)
            {
                AutoLog($"Error cargando stats de proveedores: {ex.Message}");
            }
        }
        
        private async Task<List<string>> FindMultipleSources(AutoSearchFileResult file, int maxSources = 3)
        {
            try
            {
                // MEJORA #7: Verificar caché primero
                var cached = GetCachedProviders(file.FileName);
                if (cached != null && cached.Count > 0)
                {
                    return cached.Take(maxSources).ToList();
                }
                
                AutoLog($"Buscando fuentes múltiples para: {file.FileName}");
                
                // Optimización #8: Usar cliente del pool
                var searchClient = GetClientFromPool();
                var searchResults = await searchClient.SearchAsync(
                    SearchQuery.FromText(file.FileName),
                    options: new Soulseek.SearchOptions(
                        searchTimeout: 10000,
                        filterResponses: true,
                        minimumResponseFileCount: 1
                    )
                );
                
                // Obtener usuarios únicos con el archivo
                var candidateUsers = searchResults.Responses
                    .SelectMany(r => r.Files.Select(f => new { Username = r.Username, File = f, Response = r }))
                    .Where(item => 
                        item.File.Filename.Equals(file.FileName, StringComparison.OrdinalIgnoreCase) &&
                        Math.Abs(item.File.Size - file.SizeBytes) < 1024 * 10) // Tolerancia 10KB
                    .GroupBy(item => item.Username)
                    .Select(g => new
                    {
                        Username = g.Key,
                        HasFreeSlot = g.First().Response.HasFreeUploadSlot,
                        QueueLength = g.First().Response.QueueLength,
                        UploadSpeed = g.First().Response.UploadSpeed
                    })
                    .ToList();
                
                // Filtrar blacklist temporal (usuarios con 3+ fallos en últimas 24h)
                var now = DateTime.Now;
                candidateUsers = candidateUsers
                    .Where(u =>
                    {
                        lock (providerBlacklist)
                        {
                            if (providerBlacklist.TryGetValue(u.Username, out var data))
                            {
                                // Excluir si tiene 3+ fallos y no han pasado 24 horas
                                if (data.failures >= PROVIDER_BLACKLIST_THRESHOLD && 
                                    (now - data.lastFail).TotalHours < PROVIDER_BLACKLIST_HOURS)
                                {
                                    return false;
                                }
                            }
                            return true;
                        }
                    })
                    .ToList();
                
                // Ordenar por: 1) Premium, 2) Disponibilidad, 3) Velocidad histórica, 4) Velocidad actual
                var sources = candidateUsers
                    .OrderByDescending(u => premiumUsers.Contains(u.Username) ? 2000 : 0) // Prioridad máxima a usuarios premium
                    .ThenByDescending(u => u.HasFreeSlot ? 1000 : 0) // Prioridad a slots libres
                    .ThenBy(u => u.QueueLength) // Menor cola es mejor
                    .ThenByDescending(u =>
                    {
                        var stats = GetProviderStats(u.Username);
                        return stats != null ? stats.QualityScore : 0; // Score incluye velocidad histórica
                    })
                    .ThenByDescending(u => u.UploadSpeed) // Velocidad actual como último criterio
                    .Select(u => u.Username)
                    .Take(maxSources)
                    .ToList();
                
                if (sources.Count > 1)
                {
                    AutoLog($"Encontradas {sources.Count} fuentes para descarga multi-source");
                    
                    // MEJORA #7: Cachear proveedores encontrados
                    CacheProviders(file.FileName, sources);
                }
                
                return sources;
            }
            catch (Exception ex)
            {
                AutoLog($"Error buscando fuentes múltiples: {ex.Message}");
                return new List<string>();
            }
        }
        
        private async Task DownloadMultiSource(DownloadTask task)
        {
            try
            {
                task.Status = DownloadStatus.Downloading;
                task.StartTime = DateTime.Now;
                
                // Dividir archivo en chunks según número de fuentes
                int numSources = task.AlternativeSources.Count;
                long chunkSize = task.File.SizeBytes / numSources;
                
                AutoLog($"Descarga multi-source: {numSources} fuentes, {FormatFileSize(chunkSize)} por chunk");
                
                var downloadTasks = new List<Task>();
                
                for (int i = 0; i < numSources; i++)
                {
                    var username = task.AlternativeSources[i];
                    long startOffset = i * chunkSize;
                    long endOffset = (i == numSources - 1) ? task.File.SizeBytes : (i + 1) * chunkSize;
                    
                    var chunk = new ChunkDownload
                    {
                        Username = username,
                        StartOffset = startOffset,
                        EndOffset = endOffset,
                        BytesDownloaded = 0,
                        IsComplete = false
                    };
                    
                    task.ActiveChunks[username] = chunk;
                    
                    // Descargar chunk en paralelo
                    downloadTasks.Add(DownloadChunk(task, chunk));
                }
                
                // Esperar a que todos los chunks se completen
                await Task.WhenAll(downloadTasks);
                
                // Verificar que todos los chunks se completaron
                bool allComplete = task.ActiveChunks.Values.All(c => c.IsComplete);
                
                if (allComplete)
                {
                    task.Status = DownloadStatus.Completed;
                    task.EndTime = DateTime.Now;
                    task.BytesDownloaded = task.File.SizeBytes;
                    task.ProgressPercent = 100;
                    
                    AutoLog($"Descarga multi-source completada: {task.File.FileName}");
                    UpdateDownloadUI(task, "Completado (multi-source)");
                }
                else
                {
                    throw new Exception("No se completaron todos los chunks");
                }
            }
            catch (Exception ex)
            {
                task.Status = DownloadStatus.Failed;
                task.ErrorMessage = ex.Message;
                AutoLog($"Error en descarga multi-source: {ex.Message}");
                UpdateDownloadUI(task, $"Error: {ex.Message}");
            }
        }
        
        private async Task DownloadChunk(DownloadTask task, ChunkDownload chunk)
        {
            try
            {
                var remotePath = $"{task.File.Directory}\\{task.File.FileName}";
                long chunkSize = chunk.EndOffset - chunk.StartOffset;
                
                AutoLog($"Chunk desde {chunk.Username}: {FormatFileSize(chunk.StartOffset)}-{FormatFileSize(chunk.EndOffset)}");
                
                await client.DownloadAsync(
                    chunk.Username,
                    remotePath,
                    () => Task.FromResult<Stream>(new FileStream(task.LocalPath, FileMode.OpenOrCreate)),
                    chunkSize,
                    startOffset: chunk.StartOffset,
                    cancellationToken: task.CancellationToken.Token,
                    options: new TransferOptions(
                        progressUpdated: (args) =>
                        {
                            chunk.BytesDownloaded = args.Transfer.BytesTransferred;
                            
                            // Actualizar progreso total
                            lock (task.ActiveChunks)
                            {
                                task.BytesDownloaded = task.ActiveChunks.Values.Sum(c => c.BytesDownloaded + c.StartOffset);
                                task.ProgressPercent = (double)task.BytesDownloaded / task.File.SizeBytes * 100;
                                
                                var totalSpeed = task.ActiveChunks.Values.Sum(c => c.SpeedMBps);
                                task.SpeedMBps = totalSpeed;
                            }
                            
                            var elapsed = (DateTime.Now - task.StartTime)?.TotalSeconds ?? 0;
                            if (elapsed > 0)
                            {
                                chunk.SpeedMBps = (chunk.BytesDownloaded / elapsed) / 1024.0 / 1024.0;
                            }
                        }
                    )
                );
                
                chunk.IsComplete = true;
                AutoLog($"Chunk completado desde {chunk.Username}");
            }
            catch (Exception ex)
            {
                AutoLog($"Error descargando chunk desde {chunk.Username}: {ex.Message}");
                throw;
            }
        }
        
