        }
        
        private void SaveDownloadQueue()
        {
            try
            {
                var queueData = downloadQueue
                    .Where(t => t.Status == DownloadStatus.Queued || t.Status == DownloadStatus.Paused)
                    .Select(t => new
                    {
                        FileName = t.File.FileName,
                        Author = t.File.Author,
                        Username = t.File.Username,
                        SizeBytes = t.File.SizeBytes,
                        LocalPath = t.LocalPath,
                        Status = t.Status.ToString(),
                        Priority = t.Priority.ToString(),
                        BytesDownloaded = t.BytesDownloaded
                    })
                    .ToList();
                
                var json = JsonSerializer.Serialize(queueData, new JsonSerializerOptions { WriteIndented = true });
                System.IO.File.WriteAllText(downloadQueuePath, json);
                AutoLog($"Cola de descargas guardada: {queueData.Count} pendientes");
            }
            catch (Exception ex)
            {
                AutoLog($"Error al guardar cola: {ex.Message}");
            }
        }
        
        private void LoadDownloadQueue()
        {
            try
            {
                if (!System.IO.File.Exists(downloadQueuePath))
                    return;
                
                var json = System.IO.File.ReadAllText(downloadQueuePath);
                var queueData = JsonSerializer.Deserialize<List<JsonElement>>(json);
                
                if (queueData == null || queueData.Count == 0)
                    return;
                
                int restored = 0;
                foreach (var item in queueData)
                {
                    try
                    {
                        // Usar TryGetProperty para evitar errores si falta alguna propiedad
                        if (!item.TryGetProperty("FileName", out var fileNameProp) ||
                            !item.TryGetProperty("Username", out var usernameProp) ||
                            !item.TryGetProperty("SizeBytes", out var sizeProp) ||
                            !item.TryGetProperty("LocalPath", out var localPathProp) ||
                            !item.TryGetProperty("Status", out var statusProp))
                        {
                            AutoLog($"Descarga con datos incompletos, omitiendo...");
                            continue;
                        }
                        
                        var file = new AutoSearchFileResult
                        {
                            FileName = fileNameProp.GetString(),
                            Author = item.TryGetProperty("Author", out var authorProp) ? authorProp.GetString() : "",
                            Username = usernameProp.GetString(),
                            SizeBytes = sizeProp.GetInt64(),
                            SizeReadable = FormatFileSize(sizeProp.GetInt64())
                        };
                        
                        var localPath = localPathProp.GetString();
                        var status = Enum.Parse<DownloadStatus>(statusProp.GetString());
                        var priority = item.TryGetProperty("Priority", out var priorityProp) 
                            ? Enum.Parse<DownloadPriority>(priorityProp.GetString()) 
                            : DownloadPriority.Normal;
                        
                        // Verificar blacklist antes de restaurar
                        if (blacklist.Contains(file.Username))
                        {
                            Log($"Usuario bloqueado al restaurar cola: {file.Username} - Descarga omitida: {file.FileName}");
                            continue;
                        }
                        
                        // Crear tarea de descarga
                        var task = new DownloadTask
                        {
                            File = file,
                            LocalPath = localPath,
                            Status = status,
                            Priority = priority,
                            BytesDownloaded = item.TryGetProperty("BytesDownloaded", out var bytesProp) ? bytesProp.GetInt64() : 0,
                            CancellationToken = new CancellationTokenSource(),
                            StartTime = DateTime.Now
                        };
                        
                        lock (downloadQueueLock)
                        {
                            downloadQueue.Add(task);
                        }
                        
                        // Agregar a la grilla visual
                        SafeInvoke(() =>
                        {
                            if (lvDownloads != null)
                            {
                                // Detectar fuente
                                var source = SlskDown.Core.SourceIdentifier.SearchSource.Soulseek;
                                if (file.Network != null && file.Network.Contains("emule", StringComparison.OrdinalIgnoreCase))
                                    source = SlskDown.Core.SourceIdentifier.SearchSource.EMule;
                                
                                var sourceIcon = SlskDown.Core.SourceIdentifier.GetSourceIcon(source);
                                var downloadItem = new ListViewItem(sourceIcon);
                                downloadItem.SubItems.Add(file.FileName);
                                downloadItem.SubItems.Add(file.Username);
                                downloadItem.SubItems.Add($"{task.ProgressPercent:F1}%");
                                downloadItem.SubItems.Add(GetStatusText(status));
                                
                                var sourceColor = SlskDown.Core.SourceIdentifier.GetSourceColor(source);
                                downloadItem.SubItems[0].ForeColor = sourceColor;
                                downloadItem.SubItems.Add(task.Priority.ToString());
                                downloadItem.SubItems.Add(file.SizeReadable);
                                downloadItem.SubItems.Add(GetMetadataStatusSync(file.FileName));
                                downloadItem.ForeColor = GetStatusColor(status);
                                downloadItem.Tag = task;
                                task.ListViewItem = downloadItem;
                                lvDownloads.Items.Add(downloadItem);
                            }
                        });
                        
                        restored++;
                    }
                    catch (Exception ex)
                    {
                        AutoLog($"Error al restaurar descarga: {ex.Message}");
                    }
                }
                
                if (restored > 0)
                {
                    AutoLog($"Restauradas {restored} descargas pendientes");
                    ShowNotification("Descargas restauradas", 
                        $"Se restauraron {restored} descargas pendientes de la sesión anterior", 
                        ToolTipIcon.Info);
                    
                    // Actualizar progreso inmediatamente
                    UpdateProgressDisplay();
                }
            }
            catch (Exception ex)
            {
                AutoLog($"Error al cargar cola: {ex.Message}");
            }
        }
        
        private void UpdateProgressDisplay()
        {
            try
            {
                lock (downloadQueueLock)
                {
                    int total = downloadQueue.Count;
                    int completed = downloadQueue.Count(t => t.Status == DownloadStatus.Completed);
                    int percentage = total > 0 ? (completed * 100 / total) : 0;
                    
                    SafeInvoke(() =>
                    {
                        if (progressBar != null && lblProgressInfo != null)
                        {
                            progressBar.Maximum = Math.Max(total, 1);
                            progressBar.Value = Math.Min(completed, progressBar.Maximum);
                            lblProgressInfo.Text = $"Progreso total: {completed}/{total} ({percentage}%)";
                        }
                    });
                }
            }
            catch (Exception ex)
            {
                Log($"Error actualizando progreso: {ex.Message}");
            }
        }
        
