        private void LoadLastAuthorsFile()
        {
            try
            {
                var configFile = Path.Combine(dataDir, "auto_config.json");
                if (System.IO.File.Exists(configFile))
                {
                    var json = System.IO.File.ReadAllText(configFile);
                    var config = JsonSerializer.Deserialize<Dictionary<string, string>>(json);
                    if (config != null && config.ContainsKey("lastAuthorsFile"))
                    {
                        lastAuthorsFilePath = config["lastAuthorsFile"];
                        // No cargar automáticamente - el usuario debe hacerlo manualmente
                        if (System.IO.File.Exists(lastAuthorsFilePath))
                        {
                            AutoLog($"Último archivo usado: {Path.GetFileName(lastAuthorsFilePath)}");
                            AutoLog($"Usa 'Seleccionar autores' para cargar el archivo");
                            return;
                        }
                    }
                }
            }
            catch (Exception ex)
            {
                AutoLog($"Error al cargar configuración: {ex.Message}");
            }
            
            AutoLog("Selecciona un archivo TXT con la lista de autores");
        }
        
        private void SelectAndLoadAuthorsFile()
        {
            var openDialog = new OpenFileDialog
            {
                Filter = "Archivos de texto (*.txt)|*.txt|Todos los archivos (*.*)|*.*",
                Title = "Seleccionar archivo de autores",
                InitialDirectory = !string.IsNullOrEmpty(lastAuthorsFilePath) ? Path.GetDirectoryName(lastAuthorsFilePath) : ""
            };
            
            if (openDialog.ShowDialog() == DialogResult.OK)
            {
                lastAuthorsFilePath = openDialog.FileName;
                SaveLastAuthorsFile();
                LoadAuthorsFromFile(openDialog.FileName);
            }
        }
        
        private void SaveLastAuthorsFile()
        {
            try
            {
                var config = new Dictionary<string, string>
                {
                    ["lastAuthorsFile"] = lastAuthorsFilePath
                };
                var json = JsonSerializer.Serialize(config);
                var configFile = Path.Combine(dataDir, "auto_config.json");
                System.IO.File.WriteAllText(configFile, json);
            }
            catch (Exception ex)
            {
                AutoLog($"Error al guardar configuración: {ex.Message}");
            }
        }
        
        private void DeleteSelectedAuthors()
        {
            var checkedAuthors = filteredAuthorsData.Where(a => a.IsChecked).ToList();
            
            if (checkedAuthors.Count == 0)
            {
                AutoLog("No hay autores seleccionados para borrar");
                return;
            }
            
            var count = checkedAuthors.Count;
            var result = MessageBox.Show(
                $"¿Borrar {count} autor(es) seleccionado(s)?",
                "Confirmar borrado",
                MessageBoxButtons.YesNo,
                MessageBoxIcon.Question
            );
            
            if (result == DialogResult.Yes)
            {
                // Remover de ambas listas
                foreach (var author in checkedAuthors)
                {
                    allAuthorsData.Remove(author);
                    filteredAuthorsData.Remove(author);
                    authorIndex.Remove(author.Name);
                }
                
                // Actualizar el ListView
                RefreshAuthorsListView();
                UpdateAuthorCount();
                
                AutoLog($"Borrados {count} autor(es)");
                
                // Guardar cambios en el archivo
                SaveAuthorsToFile();
            }
        }
        
        private async Task DownloadSelectedAuthorsFiles()
        {
            var checkedAuthors = filteredAuthorsData.Where(a => a.IsChecked).ToList();
            
            if (checkedAuthors.Count == 0)
            {
                AutoLog("No hay autores seleccionados para descargar");
                MessageBox.Show("Selecciona al menos un autor para descargar sus archivos", "Sin selección", MessageBoxButtons.OK, MessageBoxIcon.Warning);
                return;
            }
            
            AutoLog($"DEBUG: Autores seleccionados: {checkedAuthors.Count}");
            AutoLog($"DEBUG: Total archivos en autoSearchResults: {autoSearchResults.Count}");
            
            // Obtener archivos de los autores seleccionados (con filtros aplicados)
            List<AutoSearchFileResult> filesToDownload;
            int totalFilesBeforeFilters;
            int totalFilesAfterFilters;
            int filteredByGarbage = 0;
            int filteredByDocument = 0;
            int filteredByLanguage = 0;
            int filteredByBlacklist = 0;
            
            bool checkSpanish = chkAutoSpanishDocuments?.Checked ?? false;
            
            
                var allFiles = autoSearchResults
                    .Where(f => checkedAuthors.Any(a => a.Name.Equals(f.Author, StringComparison.OrdinalIgnoreCase)))
                    .ToList();
                
                totalFilesBeforeFilters = allFiles.Count;
                AutoLog($"DEBUG: Archivos encontrados para autores seleccionados: {totalFilesBeforeFilters}");
                
                // Aplicar filtros (igual que en la búsqueda automática)
                var filteredFiles = new List<AutoSearchFileResult>();
                
                foreach (var file in allFiles)
                {
                    // Filtro 1: Tamaño > 0
                    if (file.SizeBytes == 0) continue;
                    
                    // Filtro 2: No debe ser archivo basura
                    if (IsGarbageFile(file.FileName))
                    {
                        filteredByGarbage++;
                        continue;
                    }
                    
                    // Filtro 3: Debe ser documento
                    if (!IsDocumentFile(file.FileName))
                    {
                        filteredByDocument++;
                        continue;
                    }
                    
                    // Filtro 4: Idioma español (si está activado)
                    if (checkSpanish && !IsSpanishText(file.FileName))
                    {
                        filteredByLanguage++;
                        continue;
                    }
                    
                    // Filtro 5: No debe estar blacklisteado
                    if (IsFileBlacklisted(file.FileName, file.Username))
                    {
                        filteredByBlacklist++;
                        continue;
                    }
                    
                    filteredFiles.Add(file);
                }
                
                totalFilesAfterFilters = filteredFiles.Count;
                
                // Eliminar duplicados por nombre de archivo (mantener el de mejor proveedor)
                filesToDownload = filteredFiles
                    .GroupBy(f => f.FileName, StringComparer.OrdinalIgnoreCase)
                    .Select(g => g.OrderByDescending(f => GetProviderScore(f.Username)).First())
                    .ToList();
            
            
            if (filesToDownload.Count == 0)
            {
                AutoLog($"No hay archivos disponibles para los {checkedAuthors.Count} autor(es) seleccionado(s)");
                MessageBox.Show(
                    $"No se encontraron archivos para los autores seleccionados.\n\nEjecuta una búsqueda automática primero.",
                    "Sin archivos",
                    MessageBoxButtons.OK,
                    MessageBoxIcon.Information
                );
                return;
            }
            
            var downloadPath = txtDownloadDir?.Text ?? Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.MyDocuments), "SlskDown");
            
            // Contar archivos existentes vs nuevos
            int existingFiles = 0;
            int newFiles = 0;
            foreach (var file in filesToDownload)
            {
                var fullPath = GetDownloadPath(file.FileName, file.Author);
                if (IsFileDownloaded(fullPath))
                    existingFiles++;
                else
                    newFiles++;
            }
            
            if (newFiles == 0)
            {
                MessageBox.Show(
                    $"Todos los archivos ({existingFiles}) ya están descargados.\n\nUsa el botón 'Redescargar' si quieres descargarlos de nuevo.",
                    "Archivos existentes",
                    MessageBoxButtons.OK,
                    MessageBoxIcon.Information
                );
                AutoLog($"{existingFiles} archivo(s) ya descargado(s), omitidos");
                return;
            }
            
            string message = existingFiles == 0
                ? $"¿Descargar {newFiles} archivo(s) de {checkedAuthors.Count} autor(es)?"
                : $"¿Descargar {newFiles} archivo(s) nuevo(s) de {checkedAuthors.Count} autor(es)?\n({existingFiles} ya descargado(s) serán omitidos)";
            
            var result = MessageBox.Show(message, "Confirmar descarga", MessageBoxButtons.YesNo, MessageBoxIcon.Question);
            
            if (result == DialogResult.Yes)
            {
                AutoLog("═══════════════════════════════════════");
                AutoLog("INICIANDO DESCARGA DE AUTORES SELECCIONADOS");
                AutoLog($"Autores: {checkedAuthors.Count}");
                AutoLog($"Archivos totales encontrados: {totalFilesBeforeFilters}");
                
                // Mostrar estadísticas de filtrado
                if (totalFilesBeforeFilters > totalFilesAfterFilters)
                {
                    AutoLog($"Filtros aplicados:");
                    if (filteredByGarbage > 0)
                        AutoLog($"   Archivos basura: {filteredByGarbage}");
                    if (filteredByDocument > 0)
                        AutoLog($"   No documentos: {filteredByDocument}");
                    if (filteredByLanguage > 0)
                        AutoLog($"   Otros idiomas: {filteredByLanguage}");
                    if (filteredByBlacklist > 0)
                        AutoLog($"   Blacklisteados: {filteredByBlacklist}");
                    AutoLog($"   Archivos válidos: {totalFilesAfterFilters}");
                }
                
                // Mostrar duplicados eliminados
                int duplicatesRemoved = totalFilesAfterFilters - filesToDownload.Count;
                if (duplicatesRemoved > 0)
                {
                    AutoLog($"   Duplicados eliminados: {duplicatesRemoved}");
                }
                
                AutoLog($"Archivos únicos a procesar: {filesToDownload.Count}");
                AutoLog($"   • Nuevos a descargar: {newFiles}");
                AutoLog($"   • Ya descargados (omitidos): {existingFiles}");
                AutoLog($"Destino: {downloadPath}");
                AutoLog("═══════════════════════════════════════");
                
                // Crear directorio si no existe
                if (!System.IO.Directory.Exists(downloadPath))
                {
                    System.IO.Directory.CreateDirectory(downloadPath);
                    AutoLog($"Carpeta creada: {downloadPath}");
                }
                
                int added = 0;
                int skipped = 0;
                
                // Suspender actualización de UI para mejor rendimiento con grandes volúmenes
                SafeInvoke(() => lvDownloads.BeginUpdate());
                
                try
                {
                    int batchSize = 100;
                    int processed = 0;
                    
                    foreach (var file in filesToDownload)
                    {
                        var fullPath = GetDownloadPath(file.FileName, file.Author);
                        
                        if (IsFileDownloaded(fullPath))
                        {
                            skipped++;
                        }
                        else
                        {
                            // Crear ListViewItem para la grilla de descargas
                            ListViewItem downloadItem = null;
                            SafeInvoke(() =>
                            {
                                // Detectar fuente
                                var source = SlskDown.Core.SourceIdentifier.SearchSource.Soulseek;
                                if (file.Network != null && file.Network.Contains("emule", StringComparison.OrdinalIgnoreCase))
                                    source = SlskDown.Core.SourceIdentifier.SearchSource.EMule;
                                
                                var sourceIcon = SlskDown.Core.SourceIdentifier.GetSourceIcon(source);
                                downloadItem = new ListViewItem(sourceIcon);
                                downloadItem.SubItems.Add(file.FileName);
                                // Agregar indicador premium al username
                                string usernameDisplay = premiumUsers.Contains(file.Username) ? $"[PREMIUM] {file.Username}" : file.Username;
                                downloadItem.SubItems.Add(usernameDisplay);
                                downloadItem.SubItems.Add("0%");
                                downloadItem.SubItems.Add("En cola");
                                
                                var sourceColor = SlskDown.Core.SourceIdentifier.GetSourceColor(source);
                                downloadItem.SubItems[0].ForeColor = sourceColor;
                                downloadItem.SubItems.Add(file.SizeReadable);
                                downloadItem.SubItems.Add(GetMetadataStatusSync(file.FileName));
                                downloadItem.Tag = file;
                                lvDownloads.Items.Add(downloadItem);
                            });
                            
                            AddToDownloadQueue(file, fullPath, downloadItem);
                            added++;
                            processed++;
                            
                            // Cada 100 items, dar un respiro
                            if (processed % batchSize == 0)
                            {
                                AutoLog($"Procesados {processed}/{filesToDownload.Count} archivos...");
                                System.Threading.Thread.Sleep(10);
                            }
                        }
                    }
                }
                finally
                {
                    // Reanudar actualización de UI
                    SafeInvoke(() => lvDownloads.EndUpdate());
                }
                
                AutoLog($"{added} archivo(s) agregado(s) a la cola de descargas");
                if (skipped > 0)
                    AutoLog($"{skipped} archivo(s) omitido(s) (ya descargados)");
                AutoLog("═══════════════════════════════════════");
                
                // Cambiar a pestaña de descargas
                if (added > 0)
                {
                    SafeInvoke(() =>
                    {
                        var tabControl = (TabControl)this.Controls.Find("tabControl", true).FirstOrDefault();
                        if (tabControl != null)
                        {
                            for (int i = 0; i < tabControl.TabPages.Count; i++)
                            {
                                if (tabControl.TabPages[i].Text.Contains("Descargas"))
                                {
                                    tabControl.SelectedIndex = i;
                                    break;
                                }
                            }
                        }
                    });
                }
            }
        }
        
        private void SaveAuthorsToFile()
        {
            if (string.IsNullOrEmpty(lastAuthorsFilePath))
            {
                AutoLog("No hay archivo cargado para guardar");
                return;
            }
            
            try
            {
                var authors = allAuthorsData.Select(a => a.Name).ToList();
                
                System.IO.File.WriteAllLines(lastAuthorsFilePath, authors);
                AutoLog($"Guardados {authors.Count} autores en {Path.GetFileName(lastAuthorsFilePath)}");
            }
            catch (Exception ex)
            {
                AutoLog($"Error al guardar archivo: {ex.Message}");
                MessageBox.Show($"Error al guardar:\n{ex.Message}", "Error", MessageBoxButtons.OK, MessageBoxIcon.Error);
            }
        }
        
        private void LoadAuthorsFromFile(string filePath)
        {
            try
            {
                if (!System.IO.File.Exists(filePath))
                {
                    AutoLog($"No se encontró el archivo: {filePath}");
                    return;
                }
                
                AutoLog($"Cargando autores desde {Path.GetFileName(filePath)}...");
                var sw = System.Diagnostics.Stopwatch.StartNew();
                
                var authorsFromFile = System.IO.File.ReadAllLines(filePath)
                    .Where(line => !string.IsNullOrWhiteSpace(line))
                    .Select(line => line.Trim())
                    .ToList();
                
                // Duplicar autores con puntos y tildes: agregar versiones sin puntos/tildes
                var expandedAuthors = new List<string>();
                foreach (var author in authorsFromFile)
                {
                    expandedAuthors.Add(author);
                    
                    // Si el autor contiene puntos, agregar versión sin puntos
                    if (author.Contains('.'))
                    {
                        var withoutDots = author.Replace(".", "");
                        if (!string.IsNullOrWhiteSpace(withoutDots) && withoutDots != author)
                        {
                            expandedAuthors.Add(withoutDots);
                        }
                    }
                    
                    // Si el autor contiene tildes, agregar versión sin tildes
                    var withoutAccents = RemoveAccents(author);
                    if (withoutAccents != author)
                    {
                        expandedAuthors.Add(withoutAccents);
                        
                        // También agregar versión sin puntos ni tildes si tiene ambos
                        if (author.Contains('.'))
                        {
                            var withoutDotsOrAccents = RemoveAccents(author.Replace(".", ""));
                            if (!string.IsNullOrWhiteSpace(withoutDotsOrAccents) && 
                                withoutDotsOrAccents != author && 
                                withoutDotsOrAccents != withoutAccents)
                            {
                                expandedAuthors.Add(withoutDotsOrAccents);
                            }
                        }
                    }
                }
                
                var authors = expandedAuthors
                    .Distinct(StringComparer.OrdinalIgnoreCase)
                    .OrderBy(a => a)
                    .ToArray();
                
                if (authors.Length == 0)
                {
                    AutoLog($"El archivo está vacío: {Path.GetFileName(filePath)}");
                    return;
                }
                
                // Usar VirtualMode para cargar eficientemente
                LoadAuthorsIntoVirtualList(authors);
                
                sw.Stop();
                var originalCount = authorsFromFile.Count;
                var expandedCount = expandedAuthors.Count;
                var finalCount = authors.Length;
                
                AutoLog($"Cargados {finalCount:N0} autores únicos en {sw.ElapsedMilliseconds}ms");
                if (expandedCount > originalCount)
                {
                    AutoLog($"   Expandidos: {originalCount:N0} -> {expandedCount:N0} (variantes sin puntos/tildes)");
                    AutoLog($"   Unicos: {finalCount:N0} (después de deduplicar)");
                }
                AutoLog($"   Usa checkboxes para seleccionar autores y luego 'Iniciar Purga' o 'Iniciar Búsqueda'");
                
                // También mostrar en log principal
                Log($"Cargados {finalCount:N0} autores desde {Path.GetFileName(filePath)}");
            }
            catch (Exception ex)
            {
                AutoLog($"Error al cargar autores: {ex.Message}");
            }
        }
        
