        private void AutoLog(string message)
        {
            if (txtAutoLog != null)
            {
                // Determinar estado de conexión: S (conectado) o N (no conectado)
                var connectionStatus = (client != null && client.State.HasFlag(SoulseekClientStates.Connected)) ? "S" : "N";
                var timestamp = DateTime.Now.ToString("HH:mm:ss");
                txtAutoLog.AppendText($"[{timestamp}|{connectionStatus}] {message}\r\n");
            }
            
            // También escribir en logger secundario si existe (ventana de descargas)
            secondaryLogger?.Invoke(message);
        }
        
