        private void DeleteSelectedAuthorsFromContext()
        {
            if (lvAutoAuthors.SelectedIndices.Count == 0)
            {
                AutoLog("No hay autores seleccionados para borrar");
                return;
            }
            
            var count = lvAutoAuthors.SelectedIndices.Count;
            var result = MessageBox.Show(
                $"¿Borrar {count} autor(es) seleccionado(s)?\n\nSi hay una búsqueda activa, estos autores serán excluidos.",
                "Confirmar borrado",
                MessageBoxButtons.YesNo,
                MessageBoxIcon.Question
            );
            
            if (result == DialogResult.Yes)
            {
                // Obtener los autores seleccionados por índice
                var indicesToRemove = new List<int>();
                foreach (int index in lvAutoAuthors.SelectedIndices)
                {
                    indicesToRemove.Add(index);
                }
                
                // Ordenar en orden descendente para no afectar los índices al eliminar
                indicesToRemove.Sort((a, b) => b.CompareTo(a));
                
                // Remover de las listas
                var authorsToRemove = new List<AuthorData>();
                foreach (int index in indicesToRemove)
                {
                    if (index >= 0 && index < filteredAuthorsData.Count)
                    {
                        var author = filteredAuthorsData[index];
                        authorsToRemove.Add(author);
                    }
                }
                
                // Agregar a blacklist permanente y eliminar archivos
                foreach (var author in authorsToRemove)
                {
                    // Agregar a blacklist para que no reaparezca
                    AddToBlacklist(author.Name);
                    AutoLog($"   Autor agregado a blacklist: {author.Name}");
                    
                    // Agregar a lista de excluidos si hay búsqueda activa
                    if (autoSearchRunning)
                    {
                        excludedAuthors.Add(author.Name);
                        AutoLog($"   Autor excluido de búsqueda activa: {author.Name}");
                    }
                    
                    // Eliminar archivos del autor de autoSearchResults
                    
                        int removedCount = RemoveAllFromAutoSearchResults(f => 
                            f.Author.Equals(author.Name, StringComparison.OrdinalIgnoreCase));
                        if (removedCount > 0)
                        {
                            AutoLog($"   Eliminados {removedCount} archivos de {author.Name}");
                        }
                    
                }
                
                foreach (var author in authorsToRemove)
                {
                    allAuthorsData.Remove(author);
                    filteredAuthorsData.Remove(author);
                    authorIndex.Remove(author.Name);
                }
                
                // Actualizar el ListView
                RefreshAuthorsListView();
                UpdateAuthorCount();
                
                AutoLog($"Borrados {count} autor(es)");
                if (autoSearchRunning)
                {
                    AutoLog($"{count} autor(es) excluidos de búsqueda activa");
                }
                SaveAuthorsToFile();
                
                // Guardar CSV actualizado sin los autores eliminados
                SaveAutoResultsToCsv();
                AutoLog($"CSV actualizado - autores eliminados del archivo");
            }
        }
        
