        private async Task StartAutomaticSearch()
        {
            var checkedAuthors = GetCheckedAuthorsFromVirtualList();
            if (checkedAuthors.Length == 0)
            {
                Log("[AUTORES] No hay autores seleccionados para búsqueda automática");
                AutoLog("No hay autores seleccionados. Marca al menos uno en la lista.");
                return;
            }
            
            Log($"[AUTORES] Iniciando búsqueda automática de {checkedAuthors.Length} autores");
            AutoLog($"Iniciando búsqueda automática de {checkedAuthors.Length} autores...");
            
            if (checkedAuthors.Length == 0)
            {
                AutoLog("No hay autores seleccionados");
                MessageBox.Show("Selecciona al menos un autor de la lista (usa los checkboxes)", "Búsqueda Automática", MessageBoxButtons.OK, MessageBoxIcon.Warning);
                return;
            }
            
            if (client == null)
            {
                AutoLog("Cliente no inicializado");
                MessageBox.Show("Error: Cliente no inicializado", "Búsqueda Automática", MessageBoxButtons.OK, MessageBoxIcon.Error);
                return;
            }
            
            // Verificar si está conectado (puede tener múltiples flags)
            bool isConnected = client.State.HasFlag(SoulseekClientStates.Connected) || 
                               client.State.HasFlag(SoulseekClientStates.LoggedIn);
            
            if (!isConnected)
            {
                AutoLog($"No estás conectado a Soulseek (Estado: {client.State})");
                MessageBox.Show($"Debes estar conectado a Soulseek\nEstado actual: {client.State}", "Búsqueda Automática", MessageBoxButtons.OK, MessageBoxIcon.Error);
                return;
            }
            
            AutoLog($"Conectado (Estado: {client.State})");
            
            var selectedAuthors = checkedAuthors.ToList();
            
            // OPTIMIZACIÓN #10: Cargar checkpoint si existe
            selectedAuthors = await LoadCheckpointIfExists(selectedAuthors);
            
            autoSearchRunning = true;

            autoSearchCts?.Dispose();
            autoSearchCts = new CancellationTokenSource();
            var cancellationToken = autoSearchCts.Token;
            
            // Limpiar lista de autores excluidos al iniciar nueva búsqueda
            excludedAuthors.Clear();

            UpdateAutoControlsEnabled();
            
            AutoLog("");
            AutoLog("═══════════════════════════════════════");
            AutoLog("INICIANDO BÚSQUEDA AUTOMÁTICA");
            AutoLog($"{selectedAuthors.Count} autores seleccionados");
            AutoLog("═══════════════════════════════════════");
            
            // También mostrar en log principal
            Log($"Iniciando búsqueda automática de {selectedAuthors.Count} autores");
            
            int round = 1;
            bool anyResultsFound = true;
            int totalNewFilesThisRound = 0;
            var authorNoResultsCount = new Dictionary<string, int>();
            var authorUniqueFiles = new Dictionary<string, HashSet<string>>(); // Trackear archivos únicos por autor
            var globalUniqueFiles = new HashSet<string>(); // Todos los archivos únicos globales
            
            // Inicializar contador para cada autor y resetear contadores
            foreach (var author in selectedAuthors)
            {
                authorNoResultsCount[author] = 0;
                authorUniqueFiles[author] = new HashSet<string>();
                
                // Resetear columnas de archivos y estado
                if (InvokeRequired)
                {
                    Invoke(new Action(() => UpdateAuthorInList(author, 0, "Listo", true)));
                }
                else
                {
                    UpdateAuthorInList(author, 0, "Listo", true);
                }
            }
            
            try
            {
                while (anyResultsFound && autoSearchRunning)
                {
                    AutoLog("");
                    AutoLog($"=== RONDA {round} ===");
                    AutoLog($"Buscando {selectedAuthors.Count} autores en paralelo ({MAX_PARALLEL_SEARCHES} simultáneos)...");
                    anyResultsFound = false;
                    totalNewFilesThisRound = 0;
                    var authorsToRemove = new List<string>();
                    var roundStopwatch = System.Diagnostics.Stopwatch.StartNew();
                    
                    // OPTIMIZACIÓN #1: Búsqueda paralela masiva (128 simultáneas = 16x más rápido)
                    using (var semaphore = new SemaphoreSlim(MAX_PARALLEL_SEARCHES, MAX_PARALLEL_SEARCHES))
                    {
                        var processedInRound = 0;
                        var totalInRound = selectedAuthors.Count;
                        var tasks = selectedAuthors.ToList().Select(async author =>
                        {
                            await semaphore.WaitAsync(cancellationToken);
                            try
                            {
                                if (!autoSearchRunning || cancellationToken.IsCancellationRequested)
                                {
                                    return;
                                }
                            
                            // Verificar si el autor fue excluido durante la búsqueda
                            if (excludedAuthors.Contains(author))
                            {
                                AutoLog($"Autor excluido, saltando: {author}");
                                UpdateAuthorStatus(author, "Excluido");
                                return;
                            }
                            
                            // OPTIMIZACIÓN #8: Skip autores sin resultados después de 5 intentos
                            if (noResultsAuthors.Contains(author))
                            {
                                AutoLog($"Autor sin resultados, saltando: {author}");
                                UpdateAuthorStatus(author, "Sin resultados");
                                return;
                            }
                            
                            // OPTIMIZACIÓN #3: Verificar caché de búsquedas (24h)
                            if (authorSearchCache.TryGetValue(author, out var cachedSearch))
                            {
                                if ((DateTime.Now - cachedSearch.cached).TotalHours < AUTHOR_CACHE_HOURS)
                                {
                                    AutoLog($"Usando caché para: {author} ({cachedSearch.files.Count} archivos)");
                                    
                                    
                                        AddRangeToAutoSearchResults(cachedSearch.files);
                                    
                                    
                                    UpdateAuthorStatus(author, $"Caché ({cachedSearch.files.Count})");
                                    return;
                                }
                            }
                            
                            // Actualizar estado a "Buscando..."
                            if (InvokeRequired)
                            {
                                Invoke(new Action(() => UpdateAuthorStatus(author, "Buscando...")));
                            }
                            else
                            {
                                UpdateAuthorStatus(author, "Buscando...");
                            }
                            
                            int uniqueNewFiles = 0;
                            
                            try
                            {
                                // OPTIMIZACIÓN #7: Timeout reducido para mayor velocidad (3s si ya falló, 5s si no)
                                int timeout = authorNoResultsCount.ContainsKey(author) && authorNoResultsCount[author] > 2 
                                    ? 3000 
                                    : 5000;
                                
                                var searchOptions = new Soulseek.SearchOptions(
                                    searchTimeout: timeout,  // Adaptativo: 3s o 5s
                                    maximumPeerQueueLength: 5000,
                                    filterResponses: true,
                                    minimumResponseFileCount: 1,
                                    minimumPeerUploadSpeed: 0
                                );
                                
                                // Búsqueda rápida: solo 1 búsqueda por autor para mayor velocidad
                                int searchIteration = 0;
                                int consecutiveEmptySearches = 0;
                                const int MAX_EMPTY_SEARCHES = 1;
                                
                                while (consecutiveEmptySearches < MAX_EMPTY_SEARCHES && autoSearchRunning && !cancellationToken.IsCancellationRequested)
                                {
                                    searchIteration++;
                                    
                                    // Verificar cancelación antes de buscar
                                    if (!autoSearchRunning || cancellationToken.IsCancellationRequested)
                                    {
                                        return;
                                    }
                                    
                                    // Optimización #8: Usar cliente del pool para evitar throttling
                                    var searchClient = GetClientFromPool();
                                    var results = await searchClient.SearchAsync(
                                        SearchQuery.FromText(author),
                                        options: searchOptions,
                                        cancellationToken: cancellationToken
                                    );
                                    
                                    // Verificar cancelación después de buscar
                                    if (!autoSearchRunning || cancellationToken.IsCancellationRequested)
                                    {
                                        return;
                                    }
                                    
                                    int totalFiles = results.Responses.Sum(r => r.FileCount);
                                    int totalUsers = results.Responses.Count;
                                    int newFilesThisIteration = 0;
                                    
                                    foreach (var response in results.Responses)
                                {
                                        // Verificar cancelación en cada respuesta
                                        if (!autoSearchRunning || cancellationToken.IsCancellationRequested)
                                        {
                                            return;
                                        }
                                    // Filtrar usuarios de blacklist
                                    if (blacklist.Contains(response.Username))
                                        continue;
                                    
                                    foreach (var file in response.Files)
                                    {
                                        // Verificar cancelación cada 100 archivos
                                        if (!autoSearchRunning || cancellationToken.IsCancellationRequested)
                                        {
                                            return;
                                        }
                                        
                                        // Filtrar archivos de 0 bytes o sin extensión
                                        if (file.Size == 0)
                                            continue;
                                        
                                        string extension = Path.GetExtension(file.Filename);
                                        if (string.IsNullOrEmpty(extension))
                                            continue;
                                        
                                        // Filtrar por tamaño mínimo configurado
                                        if (minFileSizeKB > 0 && file.Size < (minFileSizeKB * 1024))
                                            continue;
                                        
                                        // Verificar si es documento y español ANTES de agregar
                                        bool isDocument = IsDocumentFile(file.Filename);
                                        bool isSpanish = IsSpanishText(file.Filename);
                                        
                                        // Solo procesar documentos en español
                                        if (!isDocument || !isSpanish)
                                            continue;
                                        
                                        // VERIFICAR SI YA EXISTE EN CARBARHER (cbh)
                                        string fileName = Path.GetFileName(file.Filename);
                                        if (carbarherCacheLoaded && carbarherFilesCache.Contains(fileName))
                                            continue;
                                        
                                        // VERIFICAR SI YA ESTÁ DESCARGADO (carpeta de descargas)
                                        if (IsAlreadyDownloaded(fileName, "", 0))
                                            continue;
                                        
                                        string fileKey = $"{file.Filename}|{file.Size}";
                                        if (!authorUniqueFiles[author].Contains(fileKey))
                                        {
                                            authorUniqueFiles[author].Add(fileKey);
                                            globalUniqueFiles.Add(fileKey);
                                            uniqueNewFiles++;
                                            newFilesThisIteration++;
                                            
                                            // OPTIMIZACIÓN #4: Bloom Filter (C#)
                                            var bloomKey = $"{author}:{Path.GetFileName(file.Filename)}";
                                            BloomAdd(bloomKey);
                                            
                                            // Guardar archivo en la lista de resultados
                                            // OPTIMIZACIÓN: Crear objeto fuera del lock
                                            var newFile = new AutoSearchFileResult
                                            {
                                                Author = author,
                                                Username = response.Username,
                                                FileName = Path.GetFileName(file.Filename),
                                                Directory = Path.GetDirectoryName(file.Filename) ?? "",
                                                SizeBytes = file.Size,
                                                SizeReadable = FormatFileSize(file.Size),
                                                IsSpanish = isSpanish,
                                                IsDocument = isDocument,
                                                Timestamp = DateTime.Now
                                            };
                                            
                                            // MEJORA #9: Filtro 'Solo Nuevos'
                                            if (onlyNewFilesInAutoSearch)
                                            {
                                                string localPath = GetDownloadPath(newFile.FileName, newFile.Author);
                                                if (System.IO.File.Exists(localPath))
                                                {
                                                    continue; // Omitir archivos ya descargados
                                                }
                                            }
                                            
                                            // Lock corto: solo agregar
                                            
                                                autoSearchResults.Add(newFile);
                                            
                                            
                                            // Cachear metadatos fuera del lock
                                            SetCachedMetadata(fileKey, newFile);
                                            
                                            // DESCARGA INMEDIATA (estilo Nicotine+)
                                            if (instantDownload)
                                            {
                                                _ = Task.Run(async () =>
                                                {
                                                    try
                                                    {
                                                        // FILTRO DE SEGURIDAD: Verificar nuevamente que es español antes de descargar
                                                        if (!newFile.IsSpanish)
                                                        {
                                                            AutoLog($"⚠️ Archivo rechazado (no español): {newFile.FileName}");
                                                            return;
                                                        }
                                                        
                                                        // FILTRO DE SEGURIDAD: Verificar que el autor del archivo coincida con el autor buscado
                                                        if (!newFile.Author.Equals(author, StringComparison.OrdinalIgnoreCase))
                                                        {
                                                            AutoLog($"⚠️ Archivo rechazado (autor no coincide): {newFile.FileName} - Esperado: {author}, Encontrado: {newFile.Author}");
                                                            return;
                                                        }
                                                        
                                                        
                                                        string localPath = GetDownloadPath(newFile.FileName, newFile.Author);
                                                        
                                                        // Crear ListViewItem para UI
                                                        ListViewItem downloadItem = null;
                                                        SafeInvoke(() =>
                                                        {
                                                            downloadItem = new ListViewItem(newFile.FileName);
                                                            string usernameDisplay = premiumUsers.Contains(newFile.Username) ? $"[PREMIUM] {newFile.Username}" : newFile.Username;
                                                            downloadItem.SubItems.Add(usernameDisplay);
                                                            downloadItem.SubItems.Add("0%");
                                                            downloadItem.SubItems.Add("En cola");
                                                            downloadItem.SubItems.Add(newFile.SizeReadable);
                                                            downloadItem.SubItems.Add(GetMetadataStatusSync(newFile.FileName));
                                                            downloadItem.ForeColor = Color.LightGray;
                                                            lvDownloads.Items.Add(downloadItem);
                                                        });
                                                        
                                                        // Agregar a cola de descarga inmediatamente
                                                        AddToDownloadQueue(newFile, localPath, downloadItem, false);
                                                    }
                                                    catch (Exception ex)
                                                    {
                                                        AutoLog($"Error agregando descarga inmediata: {ex.Message}");
                                                    }
                                                });
                                            }
                                            
                                            // Notificar actualización en tiempo real
                                            int count = autoSearchResults.Count;
                                            
                                            // OPTIMIZACIÓN #6: Deduplicar con Rust cada 1000 archivos
                                            if (count % DEDUPE_INTERVAL == 0 && SlskNativeInterop.IsAvailable)
                                            {
                                                var sw = System.Diagnostics.Stopwatch.StartNew();
                                                var deduplicated = SlskNativeInterop.DeduplicateFiles(
                                                    autoSearchResults.ToList(),
                                                    f => f.FileName,
                                                    f => f.Username,
                                                    f => f.SizeBytes,
                                                    username => (int)GetProviderScore(username)
                                                );
                                                autoSearchResults = new System.Collections.Concurrent.ConcurrentBag<AutoSearchFileResult>();
                                                AddRangeToAutoSearchResults(deduplicated);
                                                sw.Stop();
                                                AutoLog($"Deduplicación Rust en {sw.ElapsedMilliseconds}ms ({count} -> {autoSearchResults.Count})");
                                            }
                                            
                                            // Actualizar estadísticas cada 10 archivos (rápido, no recarga grilla)
                                            if (count % 10 == 0)
                                            {
                                                realtimeStatsUpdater?.Invoke(count);
                                            }
                                            
                                            // Log cada 50 archivos
                                            if (count % 50 == 0)
                                            {
                                                secondaryLogger?.Invoke($"{count:N0} archivos encontrados hasta ahora...");
                                            }
                                            
                                            // Actualizar grilla completa solo cada 200 archivos (para no saturar con miles)
                                            if (count % 200 == 0)
                                            {
                                                realtimeGridUpdater?.Invoke();
                                            }
                                        }
                                    }
                                    }
                                
                                    // Controlar búsquedas vacías consecutivas
                                    if (newFilesThisIteration == 0)
                                    {
                                        consecutiveEmptySearches++;
                                    }
                                    else
                                    {
                                        consecutiveEmptySearches = 0;
                                    }
                                    
                                    // Pequeña pausa entre iteraciones
                                    if (consecutiveEmptySearches < MAX_EMPTY_SEARCHES)
                                    {
                                        await Task.Delay(500, cancellationToken);
                                    }
                                }
                            }
                            catch (OperationCanceledException)
                            {
                                AutoLog($"{author}: Búsqueda cancelada");
                            }
                            catch (Exception ex)
                            {
                                AutoLog($"   {author}: Error - {ex.Message}");
                            }
                            finally
                            {
                                lock (authorNoResultsCount)
                                {
                                    processedInRound++;
                                    
                                    // OPTIMIZACIÓN #5: Guardado incremental cada 50 autores
                                    if (processedInRound % SAVE_INTERVAL == 0)
                                    {
                                        AutoLog($"Guardando progreso ({processedInRound}/{totalInRound})...");
                                        _ = Task.Run(async () =>
                                        {
                                            await SaveAutoResultsToJsonAsync();
                                            await SaveProgressCheckpoint(processedInRound, selectedAuthors);
                                        });
                                    }
                                    
                                    // Log de progreso cada 10 autores
                                    if (processedInRound % 10 == 0)
                                    {
                                        var elapsed = roundStopwatch.Elapsed;
                                        var speed = processedInRound / elapsed.TotalSeconds;
                                        var remaining = totalInRound - processedInRound;
                                        var eta = TimeSpan.FromSeconds(remaining / speed);
                                        AutoLog($"   Progreso: {processedInRound}/{totalInRound} ({(processedInRound * 100.0 / totalInRound):F0}%) | ETA: {eta:mm\\:ss}");
                                    }
                                    
                                    if (uniqueNewFiles > 0)
                                    {
                                        anyResultsFound = true;
                                        totalNewFilesThisRound += uniqueNewFiles;
                                        authorNoResultsCount[author] = 0; // Resetear contador
                                        int totalUniqueForAuthor = authorUniqueFiles[author].Count;
                                        
                                        // OPTIMIZACIÓN #3: Guardar en caché de búsquedas
                                        var authorFiles = autoSearchResults
                                            .Where(f => f.Author.Equals(author, StringComparison.OrdinalIgnoreCase))
                                            .ToList();
                                        authorSearchCache[author] = (authorFiles, DateTime.Now);
                                        
                                        // Log siempre que encuentre archivos
                                        AutoLog($"   {author}: +{uniqueNewFiles} archivos (total: {totalUniqueForAuthor})");
                                        
                                        // Actualizar columnas con total de archivos únicos del autor
                                        if (InvokeRequired)
                                        {
                                            Invoke(new Action(() => UpdateAuthorInList(author, totalUniqueForAuthor, "Encontrado", false)));
                                        }
                                        else
                                        {
                                            UpdateAuthorInList(author, totalUniqueForAuthor, "Encontrado", false);
                                        }
                                    }
                                    else
                                    {
                                        authorNoResultsCount[author]++;
                                        
                                        // OPTIMIZACIÓN #8: Añadir a blacklist después de 5 intentos
                                        if (authorNoResultsCount[author] >= 5)
                                        {
                                            noResultsAuthors.Add(author);
                                            AutoLog($"   {author}: Sin resultados después de 5 intentos, añadido a blacklist");
                                            authorsToRemove.Add(author);
                                        }
                                        // Log solo si es la primera vez sin resultados o la tercera
                                        if (authorNoResultsCount[author] == 1 || authorNoResultsCount[author] == 3)
                                            AutoLog($"   {author}: Sin resultados ({authorNoResultsCount[author]}/3)");
                                        
                                        // Actualizar estado
                                        if (InvokeRequired)
                                        {
                                            Invoke(new Action(() => UpdateAuthorStatus(author, $"Sin resultados ({authorNoResultsCount[author]}/3)")));
                                        }
                                        else
                                        {
                                            UpdateAuthorStatus(author, $"Sin resultados ({authorNoResultsCount[author]}/3)");
                                        }
                                        
                                        // Si lleva 3 rondas sin resultados, marcarlo para eliminar
                                        if (authorNoResultsCount[author] >= 3)
                                        {
                                            authorsToRemove.Add(author);
                                            AutoLog($"   {author} será eliminado (3 rondas sin resultados)");
                                            
                                            if (InvokeRequired)
                                            {
                                                Invoke(new Action(() => UpdateAuthorStatus(author, "Eliminado")));
                                            }
                                            else
                                            {
                                                UpdateAuthorStatus(author, "Eliminado");
                                            }
                                        }
                                    }
                                }
                            }
                            }
                            finally
                            {
                                // Asegurar que el semaphore siempre se libere
                                semaphore.Release();
                            }
                        });
                        
                        try
                        {
                            await Task.WhenAll(tasks);
                        }
                        catch (OperationCanceledException)
                        {
                            AutoLog("Búsqueda cancelada por el usuario");
                        }
                    } // Cerrar using del semaphore
                    
                    // Eliminar autores que llevan 3 rondas sin resultados
                    if (authorsToRemove.Count > 0)
                    {
                        AutoLog("");
                        AutoLog($"Eliminando {authorsToRemove.Count} autor(es) inactivo(s):");
                        foreach (var author in authorsToRemove)
                        {
                            selectedAuthors.Remove(author);
                            authorNoResultsCount.Remove(author);
                            AutoLog($"   {author}");
                        }
                    }
                    
                    if (!anyResultsFound || selectedAuthors.Count == 0)
                    {
                        AutoLog("");
                        AutoLog("═══════════════════════════════════════");
                        if (selectedAuthors.Count == 0)
                        {
                            AutoLog($"COMPLETADO - Todos los autores eliminados (sin resultados)");
                        }
                        else
                        {
                            AutoLog($"COMPLETADO - Ningún autor devolvió resultados en ronda {round}");
                        }
                        AutoLog("═══════════════════════════════════════");
                    }
                    else
                    {
                        AutoLog("");
                        AutoLog($"RESUMEN RONDA {round}:");
                        roundStopwatch.Stop();
                        AutoLog($"   Archivos nuevos: {totalNewFilesThisRound}");
                        AutoLog($"   Autores activos: {selectedAuthors.Count}");
                        AutoLog($"   Tiempo ronda: {roundStopwatch.Elapsed:mm\\:ss}");
                        AutoLog($"   Velocidad: {(selectedAuthors.Count / roundStopwatch.Elapsed.TotalSeconds):F1} autores/seg");
                        
                        // También mostrar en log principal
                        Log($"Ronda {round}: {totalNewFilesThisRound} archivos nuevos, {selectedAuthors.Count} autores activos");
                        
                        // Guardar resultados después de cada ronda
                        int totalResults;
                        
                            totalResults = autoSearchResults.Count;
                        
                        if (totalResults > 0)
                        {
                            SaveAutoResultsToCsv();
                            AutoLog($"   Total archivos guardados: {totalResults}");
                        }
                        
                        AutoLog($"   Continuando con ronda {round + 1}...");
                        round++;
                    }
                }
            }
            finally
            {
                autoSearchRunning = false;
                UpdateAutoControlsEnabled();
                
                // OPTIMIZACIÓN #10: Eliminar checkpoint al finalizar
                DeleteCheckpoint();
                
                // Guardar resultados finales
                int finalCount;
                
                    finalCount = autoSearchResults.Count;
                
                if (finalCount > 0)
                {
                    SaveAutoResultsToCsv();
                    AutoLog("");
                    AutoLog($"Guardado final: {finalCount} archivos únicos en {autoResultsCsvPath}");
                }
            }
        }
        
        private void CreateHistoryTab(Panel parent)
        {
            parent.BackColor = Color.FromArgb(25, 25, 25);
            
            var mainLayout = new TableLayoutPanel
            {
                Dock = DockStyle.Fill,
                ColumnCount = 1,
                RowCount = 3,
                BackColor = Color.FromArgb(25, 25, 25),
                Padding = new Padding(10)
            };
            mainLayout.RowStyles.Add(new RowStyle(SizeType.AutoSize)); // AutoSize para botones
            mainLayout.RowStyles.Add(new RowStyle(SizeType.Percent, 100F));
            mainLayout.RowStyles.Add(new RowStyle(SizeType.AutoSize)); // AutoSize para stats
            
            // Panel de botones superior
            var buttonPanel = new FlowLayoutPanel
            {
                Dock = DockStyle.Fill,
                FlowDirection = FlowDirection.LeftToRight,
                WrapContents = true,
                AutoSize = true,
                AutoSizeMode = AutoSizeMode.GrowAndShrink,
                BackColor = Color.Transparent,
                Padding = new Padding(0, 5, 0, 5)
            };
            
            var btnRefresh = new ModernButton
            {
                Text = "ACTUALIZAR",
                Size = new Size(140, 40),
                BackColor = Color.FromArgb(0, 120, 215),
                Font = new Font("Segoe UI", 9, FontStyle.Bold),
                Margin = new Padding(0, 0, 8, 0)
            };
            AddTooltip(btnRefresh, "Actualiza el historial de descargas mostrando las entradas más recientes");
            buttonPanel.Controls.Add(btnRefresh);
            
            var btnExportCsv = new ModernButton
            {
                Text = "EXPORTAR CSV",
                Size = new Size(160, 40),
                BackColor = Color.FromArgb(0, 150, 0),
                Font = new Font("Segoe UI", 9, FontStyle.Bold),
                Margin = new Padding(0, 0, 8, 0)
            };
            AddTooltip(btnExportCsv, "Exporta el historial completo de descargas a un archivo CSV para análisis externo");
            buttonPanel.Controls.Add(btnExportCsv);
            
            var btnClearHistory = new ModernButton
            {
                Text = "LIMPIAR",
                Size = new Size(120, 40),
                BackColor = Color.FromArgb(180, 50, 50),
                Font = new Font("Segoe UI", 9, FontStyle.Bold),
                Margin = new Padding(0, 0, 8, 0)
            };
            AddTooltip(btnClearHistory, "Elimina todo el historial de descargas (requiere confirmación)");
            buttonPanel.Controls.Add(btnClearHistory);
            
            var btnLoadMore = new ModernButton
            {
                Text = "CARGAR MÁS",
                Size = new Size(140, 40),
                BackColor = Color.FromArgb(100, 100, 100),
                Font = new Font("Segoe UI", 9, FontStyle.Bold),
                Margin = new Padding(0, 0, 8, 0)
            };
            AddTooltip(btnLoadMore, "Carga más entradas antiguas del historial de descargas");
            buttonPanel.Controls.Add(btnLoadMore);
            
            mainLayout.Controls.Add(buttonPanel, 0, 0);
            
            // ListView para historial
            var lvHistory = new ListView
            {
                Dock = DockStyle.Fill,
                View = View.Details,
                FullRowSelect = true,
                GridLines = true,
                VirtualMode = false,
                BackColor = Color.FromArgb(30, 30, 30),
                ForeColor = Color.White,
                Font = new Font("Segoe UI", 10, FontStyle.Bold),
                HoverSelection = false
            };
            
            lvHistory.Columns.Add("Fecha/Hora", 150);
            lvHistory.Columns.Add("Archivo", 250);
            lvHistory.Columns.Add("Autor", 130);
            lvHistory.Columns.Add("Usuario", 100);
            lvHistory.Columns.Add("Tamaño", 80);
            lvHistory.Columns.Add("Velocidad", 90);
            lvHistory.Columns.Add("Estado", 100);
            
            mainLayout.Controls.Add(lvHistory, 0, 1);
            
            // Panel inferior con estadísticas
            var bottomPanel = new FlowLayoutPanel
            {
                Dock = DockStyle.Fill,
                FlowDirection = FlowDirection.LeftToRight,
                WrapContents = false,
                BackColor = Color.Transparent,
                Padding = new Padding(0)
            };
            
            var lblStats = new Label
            {
                AutoSize = true,
                ForeColor = Color.LightBlue,
                Font = new Font("Segoe UI", 9),
                TextAlign = ContentAlignment.MiddleLeft,
                Margin = new Padding(0, 6, 10, 0)
            };
            bottomPanel.Controls.Add(lblStats);
            bottomPanel.Controls.Add(btnLoadMore);
            
            mainLayout.Controls.Add(bottomPanel, 0, 2);
            
            // Lazy loading: solo cargar últimos 500 registros por defecto
            int historyPageSize = 500;
            int historyCurrentPage = 0;
            
            // Método para cargar historial con lazy loading
            Action<bool> loadHistory = (loadAll) =>
            {
                lvHistory.BeginUpdate();
                try
                {
                    if (loadAll)
                    {
                        lvHistory.Items.Clear();
                        historyCurrentPage = 0;
                    }
                    
                    lock (downloadHistoryLock)
                    {
                        var orderedHistory = downloadHistory.OrderByDescending(h => h.DownloadedAt).ToList();
                        int skip = historyCurrentPage * historyPageSize;
                        var pageItems = orderedHistory.Skip(skip).Take(historyPageSize).ToList();
                        
                        foreach (var item in pageItems)
                        {
                            var listItem = new ListViewItem(item.DownloadedAt.ToString("yyyy-MM-dd HH:mm:ss"));
                            listItem.SubItems.Add(item.FileName);
                            listItem.SubItems.Add(item.Author);
                            listItem.SubItems.Add(item.Username);
                            listItem.SubItems.Add(FormatFileSize(item.SizeBytes));
                            listItem.SubItems.Add($"{item.SpeedMBps:F2} MB/s");
                            listItem.SubItems.Add(item.Status);
                            
                            listItem.ForeColor = item.Status == "Completed" ? Color.LightGreen : Color.Red;
                            lvHistory.Items.Add(listItem);
                        }
                        
                        historyCurrentPage++;
                        
                        // Mostrar botón "Cargar más" si hay más registros
                        btnLoadMore.Visible = (skip + historyPageSize) < orderedHistory.Count;
                        
                        var completed = downloadHistory.Count(h => h.Status == "Completed");
                        var failed = downloadHistory.Count(h => h.Status == "Failed");
                        var totalSize = FormatFileSize(downloadHistory.Where(h => h.Status == "Completed").Sum(h => h.SizeBytes));
                        
                        lblStats.Text = $"Total: {downloadHistory.Count} | Mostrando: {lvHistory.Items.Count} | OK: {completed} | Error: {failed} | Tamaño: {totalSize}";
                    }
                }
                finally
                {
                    lvHistory.EndUpdate();
                }
            };
            
            // Event handlers
            btnRefresh.Click += (s, e) => loadHistory(true);
            btnLoadMore.Click += (s, e) => loadHistory(false);
            
            btnExportCsv.Click += (s, e) =>
            {
                try
                {
                    var saveDialog = new SaveFileDialog
                    {
                        Filter = "CSV files (*.csv)|*.csv",
                        FileName = $"historial_descargas_{DateTime.Now:yyyyMMdd_HHmmss}.csv",
                        DefaultExt = "csv"
                    };
                    
                    if (saveDialog.ShowDialog() == DialogResult.OK)
                    {
                        var sb = new StringBuilder();
                        sb.AppendLine("Fecha/Hora,Archivo,Autor,Usuario,TamañoBytes,Velocidad MB/s,Estado");
                        
                        lock (downloadHistoryLock)
                        {
                            foreach (var item in downloadHistory.OrderByDescending(h => h.DownloadedAt))
                            {
                                sb.AppendLine($"{item.DownloadedAt:yyyy-MM-dd HH:mm:ss},{item.FileName},{item.Author},{item.Username},{item.SizeBytes},{item.SpeedMBps:F2},{item.Status}");
                            }
                        }
                        
                        System.IO.File.WriteAllText(saveDialog.FileName, sb.ToString(), Encoding.UTF8);
                        MessageBox.Show($"Historial exportado a:\n{saveDialog.FileName}", "Exportación exitosa", MessageBoxButtons.OK, MessageBoxIcon.Information);
                    }
                }
                catch (Exception ex)
                {
                    MessageBox.Show($"Error al exportar: {ex.Message}", "Error", MessageBoxButtons.OK, MessageBoxIcon.Error);
                }
            };
            
            btnClearHistory.Click += (s, e) =>
            {
                var result = MessageBox.Show(
                    "¿Estás seguro de que quieres limpiar todo el historial de descargas?",
                    "Confirmar limpieza",
                    MessageBoxButtons.YesNo,
                    MessageBoxIcon.Warning);
                
                if (result == DialogResult.Yes)
                {
                    lock (downloadHistoryLock)
                    {
                        downloadHistory.Clear();
                    }
                    loadHistory(true);
                    MessageBox.Show("Historial limpiado correctamente", "Historial", MessageBoxButtons.OK, MessageBoxIcon.Information);
                }
            };
            
            parent.Controls.Add(mainLayout);
            
            // Cargar historial inicial (solo primeros 500)
            loadHistory(true);
        }
        
