        private void Log(string message)
        {
            // Determinar estado de conexión: S (conectado) o N (no conectado)
            var connectionStatus = (client != null && client.State.HasFlag(SoulseekClientStates.Connected)) ? "S" : "N";
            var logMessage = $"[{DateTime.Now:HH:mm:ss}|{connectionStatus}] {message}";
            
            // Guardar mensajes tempranos si txtLog aún no existe
            if (txtLog == null)
            {
                earlyLogMessages.Add(logMessage);
                return;
            }
            
            // Usar buffer lock-free (ultra-rápido, sin locks!)
            if (logBuffer != null)
            {
                if (!logBuffer.TryWrite(logMessage))
                {
                    // Buffer lleno, fallback a escritura directa
                    ProcessLogMessage(logMessage);
                }
                return;
            }
            
            // Fallback si aún no se inicializó el buffer
            ProcessLogMessage(logMessage);
        }
        
        private async Task<string> GetCountryAsync(string ip)
        {
            if (string.IsNullOrEmpty(ip) || ip == "0.0.0.0")
                return "??";
            
            if (countryCache.ContainsKey(ip))
                return countryCache[ip];
            
            try
            {
                using (var client = new HttpClient())
                {
                    client.Timeout = TimeSpan.FromSeconds(2);
                    var response = await client.GetStringAsync($"http://ip-api.com/json/{ip}?fields=countryCode");
                    var json = JsonSerializer.Deserialize<Dictionary<string, object>>(response);
                    var country = json.ContainsKey("countryCode") ? json["countryCode"].ToString() : "??";
                    countryCache[ip] = country;
                    
                    if (countryCache.Count % 50 == 0)
                        SaveCountryCache();
                    
                    return country;
                }
            }
            catch
            {
                return "??";
            }
        }
        
        private bool IsHispanic(string country)
        {
            var hispanicCountries = new[] { "ES", "MX", "AR", "CO", "CL", "PE", "VE", "EC", "GT", "CU", "BO", "DO", "HN", "PY", "SV", "NI", "CR", "PA", "UY", "PR" };
            return hispanicCountries.Contains(country);
        }
        
        private void SaveCountryCache()
        {
            try
            {
                var json = JsonSerializer.Serialize(countryCache, new JsonSerializerOptions { WriteIndented = true });
                System.IO.File.WriteAllText(countryCachePath, json);
            }
            catch { }
        }
        
        private void UpdateSelectionCount()
        {
            try
            {
                // Validar que el label existe antes de usarlo
                if (lblSelectionCount == null)
                    return;
                
                // En modo virtual, no podemos acceder a SelectedItems directamente
                // Por ahora, simplemente no mostramos el contador de selección
                lblSelectionCount.Text = "";
            }
            catch
            {
                // Ignorar errores silenciosamente
            }
        }
        
        private bool MatchesCategory(string fileExt, string category)
        {
            if (category == "Todos") return true;
            
            fileExt = fileExt.ToLower();
            
            return category switch
            {
                "Documentos" => fileExt == ".pdf" || fileExt == ".epub" || fileExt == ".mobi" || fileExt == ".azw3" || fileExt == ".djvu" || fileExt == ".doc" || fileExt == ".docx" || fileExt == ".txt",
                "Comics" => fileExt == ".cbr" || fileExt == ".cbz" || fileExt == ".cb7" || fileExt == ".cbt",
                "Videos" => fileExt == ".mp4" || fileExt == ".mkv" || fileExt == ".avi" || fileExt == ".mov" || fileExt == ".wmv" || fileExt == ".flv" || fileExt == ".webm",
                "Musica" => fileExt == ".mp3" || fileExt == ".flac" || fileExt == ".wav" || fileExt == ".m4a" || fileExt == ".ogg" || fileExt == ".wma" || fileExt == ".aac",
                "Comprimidos" => fileExt == ".zip" || fileExt == ".rar" || fileExt == ".7z" || fileExt == ".tar" || fileExt == ".gz" || fileExt == ".bz2",
                _ => true
            };
        }
        
        // ===== COLORES POR CALIDAD =====
        private Color GetQualityColor(long fileSize, string extension)
        {
            extension = extension.ToLower();
            
            // Para ebooks
            if (extension == ".epub" || extension == ".mobi" || extension == ".pdf" || extension == ".azw3" || extension == ".djvu")
            {
                if (fileSize > 50 * 1024 * 1024) return Color.FromArgb(255, 80, 80); // Rojo brillante
                if (fileSize > 5 * 1024 * 1024) return Color.FromArgb(50, 255, 50); // Verde brillante
                if (fileSize > 1 * 1024 * 1024) return Color.FromArgb(255, 255, 50); // Amarillo brillante
                return Color.FromArgb(240, 240, 240); // Blanco
            }
            
            // Para comics
            if (extension == ".cbr" || extension == ".cbz" || extension == ".cb7" || extension == ".cbt")
            {
                if (fileSize > 200 * 1024 * 1024) return Color.FromArgb(50, 255, 255); // Cyan brillante
                if (fileSize > 50 * 1024 * 1024) return Color.FromArgb(50, 255, 50); // Verde brillante
                if (fileSize > 20 * 1024 * 1024) return Color.FromArgb(255, 255, 50); // Amarillo brillante
                return Color.FromArgb(240, 240, 240); // Blanco
            }
            
            // Para música
            if (extension == ".mp3" || extension == ".flac" || extension == ".m4a" || extension == ".ogg" || extension == ".wav" || extension == ".wma" || extension == ".aac")
            {
                if (extension == ".flac" || extension == ".wav") return Color.FromArgb(50, 255, 255); // Cyan brillante
                if (fileSize > 10 * 1024 * 1024) return Color.FromArgb(50, 255, 50); // Verde brillante
                if (fileSize > 5 * 1024 * 1024) return Color.FromArgb(255, 255, 50); // Amarillo brillante
                return Color.FromArgb(240, 240, 240); // Blanco
            }
            
            // Para videos
            if (extension == ".mp4" || extension == ".mkv" || extension == ".avi" || extension == ".mov" || extension == ".wmv" || extension == ".flv" || extension == ".webm")
            {
                if (fileSize > 2000 * 1024 * 1024) return Color.FromArgb(50, 255, 255); // Cyan brillante
                if (fileSize > 700 * 1024 * 1024) return Color.FromArgb(50, 255, 50); // Verde brillante
                if (fileSize > 300 * 1024 * 1024) return Color.FromArgb(255, 255, 50); // Amarillo brillante
                return Color.FromArgb(240, 240, 240); // Blanco
            }
            
            // Para comprimidos
            if (extension == ".zip" || extension == ".rar" || extension == ".7z" || extension == ".tar" || extension == ".gz")
            {
                if (fileSize > 500 * 1024 * 1024) return Color.FromArgb(50, 255, 255); // Cyan brillante
                if (fileSize > 100 * 1024 * 1024) return Color.FromArgb(50, 255, 50); // Verde brillante
                if (fileSize > 10 * 1024 * 1024) return Color.FromArgb(255, 255, 50); // Amarillo brillante
                return Color.FromArgb(240, 240, 240); // Blanco
            }
            
            // Para otros archivos (imágenes, documentos, etc.)
            if (fileSize > 50 * 1024 * 1024) return Color.FromArgb(50, 255, 255); // Cyan brillante
            if (fileSize > 10 * 1024 * 1024) return Color.FromArgb(50, 255, 50); // Verde brillante
            if (fileSize > 1 * 1024 * 1024) return Color.FromArgb(255, 255, 50); // Amarillo brillante
            return Color.FromArgb(240, 240, 240); // Blanco
        }
        
        private string GetFileIcon(string extension)
        {
            extension = extension.ToLower();
            return extension switch
            {
                ".epub" or ".mobi" or ".azw3" or ".pdf" => "EPUB",
                ".cbr" or ".cbz" or ".cb7" => "CBR",
                ".mp3" or ".flac" or ".wav" or ".m4a" or ".ogg" => "MP3",
                ".mp4" or ".mkv" or ".avi" or ".mov" => "MP4",
                ".zip" or ".rar" or ".7z" => "ZIP",
                ".jpg" or ".png" or ".gif" => "IMG",
                ".txt" or ".doc" or ".docx" => "DOC",
                _ => "FILE"
            };
        }
        
        // ===== DETECCIÓN DE SERIES =====
        private (string seriesName, int? volume) DetectSeries(string filename)
        {
            var patterns = new[]
            {
                @"(.+?)\s+(?:Vol\.?|Volume|Tomo|Libro)\s*(\d+)",
                @"(.+?)\s+(\d+)\s+(?:de|of)\s+\d+",
                @"(.+?)\s+\[(\d+)\]",
                @"(.+?)\s+-\s+(\d+)",
                @"(.+?)\s+#(\d+)"
            };
            
            foreach (var pattern in patterns)
            {
                var match = System.Text.RegularExpressions.Regex.Match(filename, pattern, System.Text.RegularExpressions.RegexOptions.IgnoreCase);
                if (match.Success)
                {
                    string seriesName = match.Groups[1].Value.Trim();
                    if (int.TryParse(match.Groups[2].Value, out int volume))
                    {
                        return (seriesName, volume);
                    }
                }
            }
            
            return (null, null);
        }
        
        private Dictionary<string, List<ListViewItem>> GroupBySeries(List<ListViewItem> items)
        {
            var series = new Dictionary<string, List<ListViewItem>>();
            
            foreach (var item in items)
            {
                string filename = item.SubItems[1].Text;
                var (seriesName, volume) = DetectSeries(filename);
                
                if (seriesName != null)
                {
                    if (!series.ContainsKey(seriesName))
                        series[seriesName] = new List<ListViewItem>();
                    
                    series[seriesName].Add(item);
                }
            }
            
            return series;
        }
        
        private void ShowSeriesDetection()
        {
            var allItems = lvResults.Items.Cast<ListViewItem>().ToList();
            var seriesGroups = GroupBySeries(allItems);
            
            if (seriesGroups.Count == 0)
            {
                MessageBox.Show("No se detectaron series en los resultados actuales.", "Detección de Series", MessageBoxButtons.OK, MessageBoxIcon.Information);
                return;
            }
            
            var form = new Form
            {
                Text = "Series Detectadas",
                Size = new Size(800, 600),
                BackColor = Color.FromArgb(25, 25, 25),
                ForeColor = Color.White,
                StartPosition = FormStartPosition.CenterParent
            };
            
            var listView = new ListView
            {
                Dock = DockStyle.Fill,
                View = View.Details,
                FullRowSelect = true,
                BackColor = Color.FromArgb(30, 30, 30),
                ForeColor = Color.White,
                HoverSelection = false
            };
            
            listView.Columns.Add("Serie", 400);
            listView.Columns.Add("Volúmenes", 100);
            listView.Columns.Add("Archivos", 100);
            listView.Columns.Add("Tamaño Total", 150);
            
            foreach (var kvp in seriesGroups.OrderByDescending(x => x.Value.Count))
            {
                var volumes = kvp.Value.Select(item => DetectSeries(item.SubItems[1].Text).volume)
                    .Where(v => v.HasValue)
                    .Select(v => v.Value)
                    .OrderBy(v => v)
                    .ToList();
                
                long totalSize = 0;
                foreach (var item in kvp.Value)
                {
                    dynamic tag = item.Tag;
                    totalSize += tag?.Size ?? 0;
                }
                
                string volumeRange = volumes.Count > 0 ? $"{volumes.Min()}-{volumes.Max()}" : "?";
                
                var listItem = new ListViewItem(new[]
                {
                    kvp.Key,
                    volumeRange,
                    kvp.Value.Count.ToString(),
                    FormatSize(totalSize)
                });
                listItem.Tag = kvp.Value;
                listItem.BackColor = Color.FromArgb(30, 30, 30);
                listItem.ForeColor = Color.White;
                listView.Items.Add(listItem);
            }
            
            listView.DoubleClick += (s, e) =>
            {
                if (listView.SelectedItems.Count > 0)
                {
                    var items = (List<ListViewItem>)listView.SelectedItems[0].Tag;
                    lvResults.SelectedItems.Clear();
                    foreach (var item in items)
                    {
                        item.Selected = true;
                        item.EnsureVisible();
                    }
                    form.Close();
                }
            };
            
            var btnPanel = new Panel { Dock = DockStyle.Bottom, Height = 50, BackColor = Color.FromArgb(25, 25, 25) };
            var btnDownloadSeries = new Button 
            { 
                Text = "Descargar Serie Completa", 
                Location = new Point(10, 10), 
                Size = new Size(200, 30),
                BackColor = Color.FromArgb(0, 150, 0),
                ForeColor = Color.White,
                FlatStyle = FlatStyle.Flat
            };
            btnDownloadSeries.Click += async (s, e) =>
            {
                if (listView.SelectedItems.Count > 0)
                {
                    var items = (List<ListViewItem>)listView.SelectedItems[0].Tag;
                    lvResults.SelectedItems.Clear();
                    foreach (var item in items)
                        item.Selected = true;
                    
                    form.Close();
                    await DownloadMultipleAsync();
                }
            };
            btnPanel.Controls.Add(btnDownloadSeries);
            
            form.Controls.Add(btnPanel);
            form.Controls.Add(listView);
            form.ShowDialog();
        }
        
        private async Task ShowBookSynopsis()
        {
            if (lvResults.SelectedItems.Count == 0)
            {
                MessageBox.Show("Selecciona un libro para ver su sinopsis.", "Ver Sinopsis", MessageBoxButtons.OK, MessageBoxIcon.Information);
                return;
            }
            
            var selectedItem = lvResults.SelectedItems[0];
            var fileName = selectedItem.SubItems[0].Text;
            
            // Extraer título y autor del nombre del archivo
            var (title, author) = ParseFileName(fileName);
            
            if (string.IsNullOrEmpty(title))
            {
                MessageBox.Show("No se pudo extraer el título del archivo.", "Ver Sinopsis", MessageBoxButtons.OK, MessageBoxIcon.Warning);
                return;
            }
            
            // Crear ventana de carga
            var loadingForm = new Form
            {
                Text = "Obteniendo sinopsis...",
                Size = new Size(400, 150),
                StartPosition = FormStartPosition.CenterParent,
                FormBorderStyle = FormBorderStyle.FixedDialog,
                MaximizeBox = false,
                MinimizeBox = false,
                BackColor = Color.FromArgb(30, 30, 30)
            };
            
            var loadingLabel = new Label
            {
                Text = $"Buscando información de:\n{title}",
                Dock = DockStyle.Fill,
                TextAlign = ContentAlignment.MiddleCenter,
                ForeColor = Color.White,
                Font = new Font("Segoe UI", 10)
            };
            
            loadingForm.Controls.Add(loadingLabel);
            
            // Mostrar ventana de carga de forma no bloqueante
            loadingForm.Show();
            Application.DoEvents();
            
            try
            {
                // Buscar metadata en caché
                var cacheKey = $"synopsis_{title}_{author}";
                var cachedMetadata = GetCachedMetadata<BookMetadata>(cacheKey);
                
