        private async Task<BookMetadata> FetchBookMetadataFromGoogleBooks(string title, string author)
        {
            try
            {
                using (var httpClient = new System.Net.Http.HttpClient())
                {
                    httpClient.Timeout = TimeSpan.FromSeconds(10);
                    
                    var query = string.IsNullOrEmpty(author) ? title : $"{title} {author}";
                    var url = $"https://www.googleapis.com/books/v1/volumes?q={Uri.EscapeDataString(query)}&maxResults=1";
                    
                    var response = await httpClient.GetStringAsync(url);
                    var json = System.Text.Json.JsonDocument.Parse(response);
                    
                    if (json.RootElement.TryGetProperty("items", out var items) && items.GetArrayLength() > 0)
                    {
                        var book = items[0].GetProperty("volumeInfo");
                        
                        var metadata = new BookMetadata
                        {
                            Title = book.TryGetProperty("title", out var t) ? t.GetString() : title,
                            Author = book.TryGetProperty("authors", out var a) && a.GetArrayLength() > 0 
                                ? a[0].GetString() 
                                : author,
                            Synopsis = book.TryGetProperty("description", out var d) ? d.GetString() : null,
                            PublishDate = book.TryGetProperty("publishedDate", out var pd) ? pd.GetString() : null,
                            PageCount = book.TryGetProperty("pageCount", out var pc) ? pc.GetInt32() : 0,
                            Rating = book.TryGetProperty("averageRating", out var r) ? r.GetDouble() : 0,
                            Source = "Google Books"
                        };
                        
                        return metadata;
                    }
                }
            }
            catch (Exception ex)
            {
                Log($"Error en Google Books: {ex.Message}");
            }
            
            return null;
        }
        
        private async Task<BookMetadata> FetchBookMetadataFromOpenLibrary(string title, string author)
        {
            try
            {
                using (var httpClient = new System.Net.Http.HttpClient())
                {
                    httpClient.Timeout = TimeSpan.FromSeconds(10);
                    
                    var query = string.IsNullOrEmpty(author) ? title : $"{title} {author}";
                    var url = $"https://openlibrary.org/search.json?q={Uri.EscapeDataString(query)}&limit=1";
                    
                    var response = await httpClient.GetStringAsync(url);
                    var json = System.Text.Json.JsonDocument.Parse(response);
                    
                    if (json.RootElement.TryGetProperty("docs", out var docs) && docs.GetArrayLength() > 0)
                    {
                        var book = docs[0];
                        
                        // Obtener descripción de la obra
                        string description = null;
                        if (book.TryGetProperty("key", out var key))
                        {
                            try
                            {
                                var workUrl = $"https://openlibrary.org{key.GetString()}.json";
                                var workResponse = await httpClient.GetStringAsync(workUrl);
                                var workJson = System.Text.Json.JsonDocument.Parse(workResponse);
                                
                                if (workJson.RootElement.TryGetProperty("description", out var desc))
                                {
                                    if (desc.ValueKind == System.Text.Json.JsonValueKind.String)
                                    {
                                        description = desc.GetString();
                                    }
                                    else if (desc.ValueKind == System.Text.Json.JsonValueKind.Object && 
                                             desc.TryGetProperty("value", out var descValue))
                                    {
                                        description = descValue.GetString();
                                    }
                                }
                            }
                            catch { }
                        }
                        
                        var metadata = new BookMetadata
                        {
                            Title = book.TryGetProperty("title", out var t) ? t.GetString() : title,
                            Author = book.TryGetProperty("author_name", out var a) && a.GetArrayLength() > 0 
                                ? a[0].GetString() 
                                : author,
                            Synopsis = description,
                            PublishDate = book.TryGetProperty("first_publish_year", out var py) ? py.GetInt32().ToString() : null,
                            PageCount = book.TryGetProperty("number_of_pages_median", out var pc) ? pc.GetInt32() : 0,
                            Rating = 0,
                            Source = "Open Library"
                        };
                        
                        return metadata;
                    }
                }
            }
            catch (Exception ex)
            {
                Log($"Error en Open Library: {ex.Message}");
            }
            
            return null;
        }
        
        private async Task AnalyzeUserCollection()
        {
            if (lvResults.SelectedItems.Count == 0)
            {
                MessageBox.Show("Selecciona un archivo para analizar la colección de su usuario.", "Análisis de Colección", MessageBoxButtons.OK, MessageBoxIcon.Information);
                return;
            }
            
            dynamic tag = lvResults.SelectedItems[0].Tag;
            string username = tag?.Username;
            
            if (string.IsNullOrEmpty(username))
                return;
            
            var result = MessageBox.Show($"¿Buscar todos los archivos del usuario '{username}'?\n\nEsto puede tardar varios segundos.", 
                "Análisis de Colección", MessageBoxButtons.YesNo, MessageBoxIcon.Question);
            
            if (result != DialogResult.Yes)
                return;
            
            try
            {
                if (lblStatus != null) lblStatus.Text = $"Analizando colección de {username}...";
                Log($"Obteniendo información de usuario: {username}");
                
                var userInfo = await client.GetUserInfoAsync(username);
                
                var stats = new StringBuilder();
                stats.AppendLine($"Usuario: {username}");
                stats.AppendLine($"Descripción: {userInfo.Description ?? "Sin descripción"}");
                stats.AppendLine($"Imagen: {(userInfo.HasPicture ? "Sí" : "No")}");
                stats.AppendLine($"Carpetas en cola: {userInfo.QueueLength}");
                stats.AppendLine();
                stats.AppendLine("¿Deseas buscar todos sus archivos?");
                
                var searchResult = MessageBox.Show(stats.ToString(), $"Colección de {username}", 
                    MessageBoxButtons.YesNo, MessageBoxIcon.Information);
                
                if (searchResult == DialogResult.Yes)
                {
                    // Buscar por usuario específico
                    cmbSearch.Text = username;
                    await SearchAsync();
                }
                
                if (lblStatus != null) lblStatus.Text = "Análisis completado";
            }
            catch (Exception ex)
            {
                Log($"Error al analizar colección: {ex.Message}");
                MessageBox.Show($"Error al obtener información del usuario:\n{ex.Message}", "Error", MessageBoxButtons.OK, MessageBoxIcon.Error);
            }
        }
        
        private void SortResults(int column)
        {
            try
            {
                // Alternar orden si se hace clic en la misma columna
                if (sortColumn == column)
                    sortAscending = !sortAscending;
                else
                {
                    sortColumn = column;
                    sortAscending = true;
                }
                
                // MEJORA #7: Guardar columna ordenada
                lastSortedColumn = column;
                lastSortOrder = sortAscending ? SortOrder.Ascending : SortOrder.Descending;
                SaveConfig();
                
                // Ordenar allResults
                if (allResults != null && allResults.Count > 0)
                {
                    lock (lvResultsLock)
                    {
                        // Ordenar la lista de resultados
                        allResults.Sort((x, y) =>
                        {
                            int result = 0;
                            try
                            {
                                switch (column)
                                {
                                    case 0: // Usuario
                                        result = string.Compare(x.Username ?? "", y.Username ?? "", StringComparison.OrdinalIgnoreCase);
                                        break;
                                    case 1: // Archivo
                                        result = string.Compare(x.Filename ?? "", y.Filename ?? "", StringComparison.OrdinalIgnoreCase);
                                        break;
                                    case 2: // Tamaño
                                        result = x.Size.CompareTo(y.Size);
                                        break;
                                    case 3: // Extensión
                                        result = string.Compare(x.Extension ?? "", y.Extension ?? "", StringComparison.OrdinalIgnoreCase);
                                        break;
                                    case 4: // Carpeta
                                        result = string.Compare(x.FolderPath ?? "", y.FolderPath ?? "", StringComparison.OrdinalIgnoreCase);
                                        break;
                                }
                            }
                            catch { result = 0; }
                            
                            return sortAscending ? result : -result;
                        });
                        
                        // Actualizar vista
                        UpdateSearchResults(allResults);
                        
                        // Actualizar encabezados con indicador visual
                        UpdateColumnHeaders(lvResults, column, sortAscending);
                    }
                }
            }
            catch (Exception ex)
            {
                Log($"Error ordenando resultados: {ex.Message}");
            }
        }
        
        private void UpdateColumnHeaders(ListView lv, int sortColumn, bool ascending)
        {
            if (lv == null || lv.Columns.Count == 0) return;
            
            try
            {
                string[] columnNames = { "Usuario", "Archivo", "Tamaño", "Extensión", "Carpeta" };
                
                for (int i = 0; i < Math.Min(lv.Columns.Count, columnNames.Length); i++)
                {
                    if (i == sortColumn)
                    {
                        lv.Columns[i].Text = $"{columnNames[i]} {(ascending ? "▲" : "▼")}";
                    }
                    else
                    {
                        lv.Columns[i].Text = columnNames[i];
                    }
                }
            }
            catch { }
        }
        
        private int downloadSortColumn = -1;
        private bool downloadSortAscending = true;
        
        private void SortDownloads(int column)
        {
            try
            {
                // Alternar orden si se hace clic en la misma columna
                if (downloadSortColumn == column)
                    downloadSortAscending = !downloadSortAscending;
                else
                {
                    downloadSortColumn = column;
                    downloadSortAscending = true;
                }
                
                // Ordenar items del ListView
                var items = lvDownloads.Items.Cast<ListViewItem>().ToList();
                
                items.Sort((x, y) =>
                {
                    int result = 0;
                    try
                    {
                        switch (column)
                        {
                            case 0: // Archivo
                                result = string.Compare(x.Text ?? "", y.Text ?? "", StringComparison.OrdinalIgnoreCase);
                                break;
                            case 1: // Usuario
                                result = string.Compare(x.SubItems[1].Text ?? "", y.SubItems[1].Text ?? "", StringComparison.OrdinalIgnoreCase);
                                break;
                            case 2: // Progreso
                                {
                                    var prog1 = x.SubItems[2].Text.Replace("%", "").Trim();
                                    var prog2 = y.SubItems[2].Text.Replace("%", "").Trim();
                                    if (double.TryParse(prog1, out double p1) && double.TryParse(prog2, out double p2))
                                        result = p1.CompareTo(p2);
                                }
                                break;
                            case 3: // Estado
                                result = string.Compare(x.SubItems[3].Text ?? "", y.SubItems[3].Text ?? "", StringComparison.OrdinalIgnoreCase);
                                break;
                            case 4: // Prioridad
                                result = string.Compare(x.SubItems[4].Text ?? "", y.SubItems[4].Text ?? "", StringComparison.OrdinalIgnoreCase);
                                break;
                            case 5: // Tamaño
                                {
                                    // Extraer tamaño numérico para ordenar correctamente
                                    var task1 = x.Tag as DownloadTask;
                                    var task2 = y.Tag as DownloadTask;
                                    if (task1 != null && task2 != null)
                                        result = task1.File.SizeBytes.CompareTo(task2.File.SizeBytes);
                                }
                                break;
                        }
                    }
                    catch { result = 0; }
                    
                    return downloadSortAscending ? result : -result;
                });
                
                // Actualizar ListView
                lock (lvResultsLock)
                {
                    lvDownloads.BeginUpdate();
                    try
                    {
                        lvDownloads.Items.Clear();
                        lvDownloads.Items.AddRange(items.ToArray());
                        
                        // Actualizar encabezados
                        UpdateDownloadColumnHeaders(column, downloadSortAscending);
                    }
                    finally
                    {
                        lvDownloads.EndUpdate();
                    }
                }
            }
            catch (Exception ex)
            {
                Log($"Error ordenando descargas: {ex.Message}");
            }
        }
        
        private void UpdateDownloadColumnHeaders(int sortColumn, bool ascending)
        {
            if (lvDownloads == null || lvDownloads.Columns.Count == 0) return;
            
            try
            {
                string[] columnNames = { "Archivo", "Usuario", "Progreso", "Estado", "Prioridad", "Tamaño", "Metadata" };
                
                for (int i = 0; i < Math.Min(lvDownloads.Columns.Count, columnNames.Length); i++)
                {
                    if (i == sortColumn)
                    {
                        lvDownloads.Columns[i].Text = $"{columnNames[i]} {(ascending ? "▲" : "▼")}";
                    }
                    else
                    {
                        lvDownloads.Columns[i].Text = columnNames[i];
                    }
                }
            }
            catch { }
        }
        
        
        private void OpenDownloadedFile()
        {
            if (lvDownloads.SelectedItems.Count == 0)
                return;
            
            var selectedItem = lvDownloads.SelectedItems[0];
            var fileName = selectedItem.Text;
            
            // Buscar la tarea en downloadQueue para obtener la ruta real
            var task = downloadQueue.FirstOrDefault(t => 
                Path.GetFileName(t.File.FileName) == fileName || t.File.FileName == fileName);
            
            string filePath = null;
            
            if (task != null && !string.IsNullOrEmpty(task.LocalPath))
            {
                // Usar la ruta local guardada en la tarea
                filePath = task.LocalPath;
            }
            else
            {
                // Intentar construir la ruta (fallback)
                filePath = Path.Combine(downloadDir, fileName);
                
                // Si no existe, buscar en subdirectorios
                if (!System.IO.File.Exists(filePath))
                {
                    try
                    {
                        var files = System.IO.Directory.GetFiles(downloadDir, fileName, SearchOption.AllDirectories);
                        if (files.Length > 0)
                        {
                            filePath = files[0];
                        }
                    }
                    catch { }
                }
            }
            
            if (!string.IsNullOrEmpty(filePath) && System.IO.File.Exists(filePath))
            {
                try
                {
                    Log($"Abriendo archivo: {filePath}");
                    Process.Start(new ProcessStartInfo(filePath) { UseShellExecute = true });
                }
                catch (Exception ex)
                {
                    MessageBox.Show($"Error al abrir archivo: {ex.Message}", "Error", MessageBoxButtons.OK, MessageBoxIcon.Error);
                    Log($"Error abriendo archivo: {ex.Message}");
                }
            }
            else
            {
                MessageBox.Show($"El archivo no existe en:\n{filePath ?? "ruta desconocida"}\n\nVerifica que la descarga se haya completado correctamente.", 
                    "Archivo no encontrado", MessageBoxButtons.OK, MessageBoxIcon.Warning);
                Log($"Archivo no encontrado: {fileName}");
            }
        }
        
