        private bool checkWatchlistRunning = false;
        
        private async Task CheckWatchlist()
        {
            // Protección contra ejecuciones concurrentes
            if (checkWatchlistRunning)
            {
                Log("⚠️ CheckWatchlist: ejecución anterior aún en curso, omitiendo...");
                return;
            }
            
            if (client == null || watchlist.Count == 0)
                return;
            
            try
            {
                checkWatchlistRunning = true;
                Log($"🔍 Vigilancia: iniciando búsqueda de {watchlist.Count} autores...");
                
                foreach (var term in watchlist)
                {
                    try
                    {
                        // CRÍTICO: NO modificar UI (cmbSearch.Text) para evitar disparar eventos
                        // Ejecutar búsqueda directa sin tocar controles
                        
                        // Timeout de 30 segundos por búsqueda
                        using (var cts = new CancellationTokenSource(TimeSpan.FromSeconds(30)))
                        {
                            await ExecuteSearchAsync(term, cts.Token);
                        }
                        
                        // Delay entre búsquedas para no saturar la red
                        await Task.Delay(2000, CancellationToken.None);
                    }
                    catch (OperationCanceledException)
                    {
                        Log($"⏱️ Timeout en búsqueda de vigilancia: {term}");
                    }
                    catch (Exception ex)
                    {
                        Log($"❌ Error en vigilancia para '{term}': {ex.Message}");
                    }
                }
                
                Log($"✅ Vigilancia completada: {watchlist.Count} autores procesados");
            }
            finally
            {
                checkWatchlistRunning = false;
            }
        }
        
        private async Task RetryDownload()
        {
            if (lvDownloads.SelectedItems.Count == 0)
                return;
            
            int retriedCount = 0;
            var tasksToRetry = new List<(DownloadTask task, ListViewItem item)>();
            
            // Procesar TODOS los archivos seleccionados
            foreach (ListViewItem selectedItem in lvDownloads.SelectedItems)
            {
                var fileName = selectedItem.Text;
                
                // Buscar en la lista allDownloadItems o en downloadQueue
                var task = downloadQueue.FirstOrDefault(t => 
                    Path.GetFileName(t.File.FileName) == fileName || t.File.FileName == fileName);
                
                if (task != null)
                {
                    // Preparar para reintentar
                    selectedItem.SubItems[2].Text = "0%";
                    selectedItem.SubItems[3].Text = "Reintentando...";
                    selectedItem.ForeColor = Color.White;
                    
                    // Resetear estado de la tarea
                    task.Status = DownloadStatus.Queued;
                    task.ProgressPercent = 0;
                    task.BytesDownloaded = 0;
                    task.CancellationToken = new CancellationTokenSource();
                    
                    tasksToRetry.Add((task, selectedItem));
                    retriedCount++;
                }
            }
            
            if (retriedCount > 0)
            {
                Log($"Reintentando {retriedCount} descarga(s)");
                
                // Procesar todas las descargas en paralelo
                var retryTasks = tasksToRetry.Select(async pair =>
                {
                    try
                    {
                        await ProcessDownload(pair.task);
                    }
                    catch (Exception ex)
                    {
                        Log($"Error al reintentar {pair.task.File.FileName}: {ex.Message}");
                        SafeInvoke(() =>
                        {
                            pair.item.SubItems[3].Text = $"Error: {ex.Message}";
                            pair.item.ForeColor = Color.Red;
                        });
                    }
                });
                
                await Task.WhenAll(retryTasks);
            }
            else
            {
                MessageBox.Show("No se encontraron descargas en la cola para reintentar", "Error", MessageBoxButtons.OK, MessageBoxIcon.Warning);
            }
        }
        
        private string FormatDuration(int seconds)
        {
            var ts = TimeSpan.FromSeconds(seconds);
            return ts.Hours > 0 ? $"{ts.Hours}:{ts.Minutes:D2}:{ts.Seconds:D2}" : $"{ts.Minutes}:{ts.Seconds:D2}";
        }
        
        private void FilterResults()
        {
            if (string.IsNullOrWhiteSpace(txtFilterResults.Text))
            {
                for (int i = 0; i < lvResults.Items.Count; i++)
                {
                    lvResults.Items[i].BackColor = Color.FromArgb(45, 45, 45);
                }
                return;
            }
            
            var filterText = txtFilterResults.Text.ToLower();
            for (int i = 0; i < lvResults.Items.Count; i++)
            {
                var item = lvResults.Items[i];
                bool matches = false;
                
                for (int j = 0; j < item.SubItems.Count; j++)
                {
                    if (item.SubItems[j].Text.ToLower().Contains(filterText))
                    {
                        matches = true;
                        break;
                    }
                }
                
                item.BackColor = matches ? Color.FromArgb(45, 45, 45) : Color.FromArgb(30, 30, 30);
            }
        }
        
        private void ExportToCSV()
        {
