            {
                using (var dialog = new SaveFileDialog())
                {
                    dialog.Filter = "CSV files (*.csv)|*.csv";
                    dialog.FileName = $"slskdown-results-{DateTime.Now:yyyy-MM-dd-HHmmss}.csv";
                    
                    if (dialog.ShowDialog() == DialogResult.OK)
                    {
                        var lines = new List<string>();
                        lines.Add("Usuario,Archivo,Tamaño,Velocidad,Bitrate,Duración,Extensión,Carpeta");
                        
                        foreach (ListViewItem item in lvResults.Items)
                        {
                            var line = string.Join(",", item.SubItems.Cast<ListViewItem.ListViewSubItem>().Select(s => $"\"{s.Text}\""));
