        private void TabControl_DrawItem(object sender, DrawItemEventArgs e)
        {
            TabControl tabControl = (TabControl)sender;
            TabPage tabPage = tabControl.TabPages[e.Index];
            Rectangle tabRect = tabControl.GetTabRect(e.Index);
            
            // Color de fondo de la pestaña
            Color backColor = (e.State == DrawItemState.Selected) 
                ? Color.FromArgb(45, 45, 45) 
                : Color.FromArgb(25, 25, 25);
            
            using (SolidBrush brush = new SolidBrush(backColor))
            {
                e.Graphics.FillRectangle(brush, tabRect);
            }
            
            // Borde superior de la pestaña seleccionada
            if (e.State == DrawItemState.Selected)
            {
                using (Pen pen = new Pen(Color.FromArgb(0, 120, 215), 3))
                {
                    e.Graphics.DrawLine(pen, tabRect.Left, tabRect.Top, tabRect.Right, tabRect.Top);
                }
            }
            
            // Texto de la pestaña
            TextRenderer.DrawText(
                e.Graphics,
                tabPage.Text,
                tabControl.Font,
                tabRect,
                Color.White,
                TextFormatFlags.HorizontalCenter | TextFormatFlags.VerticalCenter
            );
        }
        
        // ===== FUNCIONALIDADES ADICIONALES =====
        
        private async Task SearchMultipleTerms(List<string> terms)
        {
            try
            {
                // Crear nuevo CancellationTokenSource
                searchCancellationTokenSource?.Cancel();
                searchCancellationTokenSource = new System.Threading.CancellationTokenSource();
                
                if (btnSearch != null) btnSearch.Enabled = false;
                if (btnStopSearch != null) btnStopSearch.Enabled = true;
                if (lblStatus != null) lblStatus.Text = $"Buscando {terms.Count} términos...";
                if (lvResults != null)
                {
                    lock (lvResultsLock)
                    {
                        lvResults.BeginUpdate();
                        try
                        {
                            lvResults.Items.Clear();
                        }
                        finally
                        {
                            lvResults.EndUpdate();
                        }
                    }
                }
                allResults.Clear();
                
                int totalFiles = 0;
                
                // Interpretar 0 como sin límite
                int actualResponseLimit = responseLimit == 0 ? int.MaxValue : responseLimit;
                int actualFileLimit = fileLimit == 0 ? int.MaxValue : fileLimit;
                int actualTimeout = searchTimeout == 0 ? int.MaxValue : searchTimeout * 1000;
                
                // Procesar términos en lotes paralelos según maxParallelSearches
                for (int i = 0; i < terms.Count; i += maxParallelSearches)
                {
                    var batch = terms.Skip(i).Take(maxParallelSearches).ToList();
                    Log($"Procesando lote {(i/maxParallelSearches)+1}: {batch.Count} términos en paralelo");
                    
                    // Crear tareas de búsqueda para este lote
                    var searchTasks = batch.Select(async term =>
                    {
                        try
                        {
                            // Verificar si se canceló
                            searchCancellationTokenSource.Token.ThrowIfCancellationRequested();
                            
                            var startTime = DateTime.Now;
                            Log($"Iniciando: {term} (timeout: {actualTimeout/1000}s)");
                            
                            var searchOptions = new Soulseek.SearchOptions(
                                filterResponses: true,
                                maximumPeerQueueLength: actualResponseLimit,
                                searchTimeout: actualTimeout
                            );
                            
                            var searchResult = await client.SearchAsync(
                                SearchQuery.FromText(term), 
                                options: searchOptions
                            );
                            
                            var results = searchResult.Responses;
                            var elapsed = (DateTime.Now - startTime).TotalSeconds;
                            Log($"{term}: {results.Count()} respuestas en {elapsed:F1}s");
                            
                            return (term, results);
                        }
                        catch (Exception ex)
                        {
                            Log($"Error en {term}: {ex.Message}");
                            return (term, Enumerable.Empty<Soulseek.SearchResponse>());
                        }
                    }).ToList();
                    
                    // Esperar a que todas las búsquedas del lote terminen
                    var batchResults = await Task.WhenAll(searchTasks);
                    
                    // Procesar resultados de este lote
                    long minSizeBytes = numMinSize != null ? (long)(numMinSize.Value * 1024) : 0;
                    long maxSizeBytes = numMaxSize != null && numMaxSize.Value > 0 ? (long)(numMaxSize.Value * 1024) : long.MaxValue;
                    string extFilter = cmbExtension?.SelectedItem?.ToString();
                    
                    foreach (var (term, results) in batchResults)
                    {
                        foreach (var response in results)
                        {
                            // Verificar cancelación
                            searchCancellationTokenSource.Token.ThrowIfCancellationRequested();
                            
                            if (blacklist.Contains(response.Username))
                                continue;
                            
                            foreach (var file in response.Files.Take(500))
                            {
                                // Descartar archivos de tamaño 0
                                if (file.Size == 0)
                                    continue;
                                
                                if (minSizeBytes > 0 && file.Size < minSizeBytes)
                                    continue;
                                if (maxSizeBytes < long.MaxValue && file.Size > maxSizeBytes)
                                    continue;
                                
                                string fileExt = Path.GetExtension(file.Filename).ToLower();
                                if (!MatchesCategory(fileExt, extFilter))
                                    continue;
                                
                                // Filtro de idioma español
                                if (chkSpanishOnly != null && chkSpanishOnly.Checked && !IsSpanishText(file.Filename))
                                    continue;
                                
                                // Crear SearchResultItem
                                var searchItem = new SearchResultItem
                                {
                                    Username = response.Username,
                                    Filename = Path.GetFileName(file.Filename),
                                    Size = file.Size,
                                    Extension = fileExt,
                                    FolderPath = Path.GetDirectoryName(file.Filename) ?? "",
                                    UploadSpeed = response.UploadSpeed
                                };
                                allResults.Add(searchItem);
                                totalFiles++;
                                
                                // Actualizar contador cada 10 archivos (más inmediato)
                                if (totalFiles % 10 == 0)
                                {
                                    UpdateSearchResults(allResults);
                                    SafeInvoke(() =>
                                    {
                                        if (lblResultsCount != null) lblResultsCount.Text = $"{totalFiles:N0} archivos...";
                                        if (lblStatus != null) lblStatus.Text = $"Búsqueda múltiple... {totalFiles:N0} encontrados";
                                    });
                                }
                            }
                        }
                    }
                }
                
                // Actualizar Virtual ListView con todos los resultados
                UpdateSearchResults(allResults);
                
                if (lblStatus != null) lblStatus.Text = $"{totalFiles} archivos encontrados ({terms.Count} búsquedas)";
                if (lblResultsCount != null) lblResultsCount.Text = $"{totalFiles} resultados";
                Log($"Búsqueda múltiple completada: {totalFiles} archivos de {terms.Count} términos");
            }
            catch (OperationCanceledException)
            {
                if (lblStatus != null) lblStatus.Text = "Búsqueda múltiple cancelada";
                if (lblResultsCount != null) lblResultsCount.Text = $"{allResults.Count} resultados (cancelado)";
                Log("Búsqueda múltiple cancelada por el usuario");
            }
            catch (Exception ex)
            {
                if (lblStatus != null) lblStatus.Text = $"Error: {ex.Message}";
                Log($"Error en búsqueda múltiple: {ex.Message}");
            }
            finally
            {
                if (btnSearch != null) btnSearch.Enabled = true;
                if (btnStopSearch != null) btnStopSearch.Enabled = false;
            }
        }
        
        
        private void SaveStats()
        {
            try
            {
                var stats = new
                {
                    totalSearches,
                    totalDownloads,
                    searchStats,
                    lastUpdate = DateTime.Now
                };
                System.IO.File.WriteAllText(statsPath, JsonSerializer.Serialize(stats));
            }
            catch (Exception ex)
            {
                Log($"Error al guardar estadísticas: {ex.Message}");
            }
        }
        
        private void LoadStats()
        {
            try
            {
                if (System.IO.File.Exists(statsPath))
                {
                    var json = System.IO.File.ReadAllText(statsPath);
                    var doc = JsonDocument.Parse(json);
                    totalSearches = doc.RootElement.GetProperty("totalSearches").GetInt32();
                    totalDownloads = doc.RootElement.GetProperty("totalDownloads").GetInt32();
                    
                    if (doc.RootElement.TryGetProperty("searchStats", out var statsElement))
                    {
                        foreach (var prop in statsElement.EnumerateObject())
                        {
                            searchStats[prop.Name] = prop.Value.GetInt32();
                        }
                    }
                }
            }
            catch (Exception ex)
            {
                Log($"Error al cargar estadísticas: {ex.Message}");
            }
        }
        
        // ===== OPTIMIZACIÓN #8: POOL DE CONEXIONES =====
        
        private SoulseekClient GetClientFromPool()
        {
            // Si el pool no está listo, usar cliente principal
            if (clientPool == null || clientPool.Length == 0)
                return client;
            
            lock (clientPoolLock)
            {
                // Rotar entre clientes del pool
                var selectedClient = clientPool[currentClientIndex];
                currentClientIndex = (currentClientIndex + 1) % poolSize;
                
                // Verificar que el cliente esté conectado
                if (selectedClient?.State == SoulseekClientStates.Connected)
                    return selectedClient;
                
                // Fallback al cliente principal
                return client;
            }
        }
        
        // ===== OPTIMIZACIÓN #16: BLOOM FILTER =====
        
        private void InitializeBloomFilter()
        {
            bloomFilter = new BloomFilter(expectedItems: 1_000_000, falsePositiveRate: 0.001);
            AutoLog($"🌸 Bloom Filter inicializado con capacidad para 1M items (FPR: 0.1%)");
        }
        
        private void InitializeLockFreeLogging()
        {
            // Buffer de 50,000 mensajes (sin locks!)
            logBuffer = new LockFreeStructures.LockFreeRingBuffer<string>(50000);
            
            // Thread dedicado para procesar logs
            logProcessorRunning = true;
            logProcessorThread = new System.Threading.Thread(() =>
            {
                while (logProcessorRunning)
                {
                    if (logBuffer.TryRead(out string message))
                    {
                        ProcessLogMessage(message);
                    }
                    else
                    {
                        System.Threading.Thread.Sleep(10); // Esperar si no hay mensajes
                    }
                }
            })
            {
                IsBackground = true,
                Priority = System.Threading.ThreadPriority.BelowNormal
            };
            logProcessorThread.Start();
            
            // Inicializar timer de actualización de UI en lotes
            InitializeLogUpdateTimer();
            
            AutoLog("Sistema de logs lock-free inicializado (buffer: 50K mensajes)");
            AutoLog($"Los logs se guardan en: {logDir}");
        }
        
        private void ProcessLogMessage(string message)
        {
            try
            {
                // Crear directorio de logs si no existe
                System.IO.Directory.CreateDirectory(logDir);
                var logFile = Path.Combine(logDir, $"slskdown-{DateTime.Now:yyyy-MM-dd}.txt");
                
                // Escribir en archivo con retry simple
                for (int i = 0; i < 3; i++)
                {
                    try
                    {
                        System.IO.File.AppendAllText(logFile, message + Environment.NewLine);
                        break;
                    }
                    catch (IOException) when (i < 2)
                    {
                        System.Threading.Thread.Sleep(10); // Esperar un poco si el archivo está bloqueado
                    }
                }
                
                // Agregar a cola de mensajes pendientes en lugar de actualizar inmediatamente
                if (txtLog != null && !txtLog.IsDisposed)
                {
                    pendingLogMessages.Enqueue(message);
                }
            }
            catch
            {
                // Ignorar errores silenciosamente para no interrumpir el flujo
            }
        }
        
        private void InitializeLogUpdateTimer()
        {
            // Timer para actualizar el log en lotes cada 200ms (reduce lag)
            logUpdateTimer = new System.Windows.Forms.Timer();
            logUpdateTimer.Interval = 200;
            logUpdateTimer.Tick += (s, e) =>
            {
                if (txtLog == null || txtLog.IsDisposed || pendingLogMessages.IsEmpty)
                    return;
                
                try
                {
                    // Procesar hasta 50 mensajes por tick
                    var batch = new System.Text.StringBuilder();
                    int count = 0;
                    
                    while (count < 50 && pendingLogMessages.TryDequeue(out string message))
                    {
                        batch.AppendLine(message);
                        count++;
                    }
                    
                    if (count > 0)
                    {
                        SafeInvoke(() =>
                        {
                            // Limitar número de líneas para evitar lag
                            var lines = txtLog.Lines;
                            if (lines.Length > MAX_LOG_LINES)
                            {
                                var newLines = lines.Skip(lines.Length - MAX_LOG_LINES + 500).ToArray();
                                txtLog.Lines = newLines;
                            }
                            
                            // Agregar nuevos mensajes
                            txtLog.AppendText(batch.ToString());
                            
                            // Solo hacer scroll si estamos cerca del final
                            if (txtLog.SelectionStart >= txtLog.Text.Length - 1000)
                            {
                                txtLog.SelectionStart = txtLog.Text.Length;
                                txtLog.ScrollToCaret();
                            }
                        });
                    }
                }
                catch
                {
                    // Ignorar errores
                }
            };
            logUpdateTimer.Start();
        }
        
        private void InitializeCircuitBreakerPersistence()
        {
            try
            {
                circuitBreakerPersistence = new CircuitBreakerPersistence(dataDir);
                
                // Cargar circuit breakers guardados
                userCircuitBreakers = circuitBreakerPersistence.LoadCircuitBreakers();
                
                var stats = circuitBreakerPersistence.GetStatistics();
                AutoLog($"Circuit breakers cargados: {stats.total} total ({stats.open} abiertos, {stats.halfOpen} semi-abiertos)");
                
                // Limpiar breakers antiguos
                var cleaned = circuitBreakerPersistence.CleanupOldBreakers();
                if (cleaned > 0)
                {
                    AutoLog($"Limpiados {cleaned} circuit breakers antiguos");
                }
                
                // Timer para guardar periódicamente (cada 30 segundos)
                var saveTimer = new System.Windows.Forms.Timer { Interval = 30000 };
                saveTimer.Tick += (s, e) => SaveCircuitBreakers();
                saveTimer.Start();
            }
            catch (Exception ex)
            {
                AutoLog($"Error inicializando persistencia de circuit breakers: {ex.Message}");
            }
        }
        
        private void SaveCircuitBreakers()
        {
            try
