                System.Diagnostics.Debug.WriteLine($"Error guardando circuit breakers: {ex.Message}");
            }
        }
        
        private void InitializeConnectionMonitor()
        {
            connectionMonitor = new ConnectionMonitor();
            
            connectionMonitor.NetworkStatusChanged += (isAvailable) =>
            {
                SafeBeginInvoke(() =>
                {
                    if (isAvailable)
                    {
                        AutoLog("Conexión a internet restaurada");
                    }
                    else
                    {
                        AutoLog("Sin conexión a internet");
                        lblStatus.Text = "Sin conexión a internet";
                        lblStatus.ForeColor = Color.Red;
                    }
                });
            };
            
            connectionMonitor.ConnectionLost += () =>
            {
                SafeBeginInvoke(() =>
                {
                    AutoLog("Conexión perdida - pausando operaciones");
                    lblConnectionQuality.Text = "Sin conexión";
                    lblConnectionQuality.ForeColor = Color.Red;
                });
            };
            
            connectionMonitor.ConnectionRestored += async () =>
            {
                SafeBeginInvoke(() =>
                {
                    AutoLog("Conexión restaurada - reanudando");
                    lblConnectionQuality.Text = "Conectado";
                    lblConnectionQuality.ForeColor = Color.LimeGreen;
                });
                
                // Intentar reconectar si es necesario
                if (autoReconnect)
                {
                    await Task.Delay(2000);
                    await CheckAndReconnect();
                }
            };
            
            // Iniciar monitoreo
            connectionMonitor.Start(intervalSeconds: 30);
            
            // Actualizar calidad de conexión periódicamente
            var qualityTimer = new System.Windows.Forms.Timer { Interval = 60000 }; // Cada minuto
            qualityTimer.Tick += async (s, e) =>
            {
                // Protección contra ejecuciones concurrentes
                if (qualityCheckRunning)
                    return;
                
                try
                {
                    qualityCheckRunning = true;
                    await UpdateConnectionQuality();
                }
                catch (Exception ex)
                {
                    Log($"❌ Error en quality timer: {ex.Message}");
                }
                finally
                {
                    qualityCheckRunning = false;
                }
            };
            qualityTimer.Start();
            
            AutoLog("Monitor de conexión inicializado");
        }
        
        private async Task UpdateConnectionQuality()
        {
            try
            {
                var quality = await connectionMonitor.GetConnectionQuality();
                var latency = await connectionMonitor.GetLatency("8.8.8.8");
                
                SafeBeginInvoke(() =>
                {
                    switch (quality)
                    {
                        case ConnectionQuality.Excellent:
                            lblConnectionQuality.Text = $"Excelente ({latency}ms)";
                            lblConnectionQuality.ForeColor = Color.LimeGreen;
                            break;
                        case ConnectionQuality.Good:
                            lblConnectionQuality.Text = $"Buena ({latency}ms)";
                            lblConnectionQuality.ForeColor = Color.Yellow;
                            break;
                        case ConnectionQuality.Fair:
                            lblConnectionQuality.Text = $"Regular ({latency}ms)";
                            lblConnectionQuality.ForeColor = Color.Orange;
                            break;
                        case ConnectionQuality.Poor:
                            lblConnectionQuality.Text = $"Mala ({latency}ms)";
                            lblConnectionQuality.ForeColor = Color.OrangeRed;
                            break;
                        case ConnectionQuality.None:
                            lblConnectionQuality.Text = "Sin conexión";
                            lblConnectionQuality.ForeColor = Color.Red;
                            break;
                    }
                });
            }
            catch
            {
                // Ignorar errores silenciosamente
            }
        }
        
        private void BloomAdd(string key)
        {
            if (bloomFilter == null) return;
            bloomFilter.Add(key);
        }
        
        private bool BloomMightContain(string key)
        {
            if (bloomFilter == null) return true; // Si no hay bloom, asumir que puede existir
            return bloomFilter.MightContain(key);
        }
        
        // ===== OPTIMIZACIÓN #15: DEDUPLICACIÓN POR HASH =====
        
        private string CheckDuplicateFile(string filePath, string hash)
        {
            lock (deduplicationLock)
            {
                if (hashToFilePath.TryGetValue(hash, out var existingPath))
                {
                    if (System.IO.File.Exists(existingPath))
                    {
                        AutoLog($"Archivo duplicado detectado: {Path.GetFileName(filePath)}");
                        return existingPath;
                    }
                }
                hashToFilePath[hash] = filePath;
                return null;
            }
        }
        
        private void CreateHardLink(string existingPath, string newPath)
        {
            try
            {
                // Crear hardlink en Windows
                var result = System.IO.File.CreateSymbolicLink(newPath, existingPath);
                AutoLog($"Hardlink creado: {Path.GetFileName(newPath)} → {Path.GetFileName(existingPath)}");
            }
            catch (Exception ex)
            {
                AutoLog($"No se pudo crear hardlink: {ex.Message}");
            }
        }
        
