        // ===== OPTIMIZACIÓN #13: COMPRESIÓN LZ4 =====
        
        private byte[] CompressLZ4(byte[] data)
        {
            var target = new byte[K4os.Compression.LZ4.LZ4Codec.MaximumOutputSize(data.Length)];
            var encodedLength = K4os.Compression.LZ4.LZ4Codec.Encode(
                data, 0, data.Length,
                target, 0, target.Length,
                K4os.Compression.LZ4.LZ4Level.L00_FAST
            );
            Array.Resize(ref target, encodedLength);
            return target;
        }
        
        private byte[] DecompressLZ4(byte[] compressed, int originalSize)
        {
            var target = new byte[originalSize];
            var decodedLength = K4os.Compression.LZ4.LZ4Codec.Decode(
                compressed, 0, compressed.Length,
                target, 0, target.Length
            );
            return target;
        }
        
        // ===== OPTIMIZACIÓN #23: SIMD PARA PROCESAMIENTO DE TEXTO =====
        
        private bool ContainsSpanishKeywordsSIMD(string text)
        {
            if (string.IsNullOrEmpty(text)) return false;
            
            // Convertir a lowercase usando Span<char> (zero-copy)
            Span<char> textSpan = stackalloc char[Math.Min(text.Length, 512)];
            text.AsSpan(0, Math.Min(text.Length, 512)).ToLowerInvariant(textSpan);
            
            // Búsqueda vectorizada de keywords
            ReadOnlySpan<char> keywords = "español spanish castellano es-es latino";
            return textSpan.IndexOfAny(keywords) >= 0;
        }
        
        private bool FastStringContains(ReadOnlySpan<char> haystack, ReadOnlySpan<char> needle)
        {
            // Usar SIMD-optimized IndexOf de .NET
            return haystack.IndexOf(needle, StringComparison.OrdinalIgnoreCase) >= 0;
        }
        
        // ===== RECONEXIÓN AUTOMÁTICA =====
        
        // private int reconnectAttempts = 0; // DUPLICADO - Ya definido en otra parte
        // private const int MAX_RECONNECT_ATTEMPTS = 5; // DUPLICADO - Ya definido en otra parte
        private DateTime lastReconnectAttempt = DateTime.MinValue;
        private bool isReconnecting = false;
        private bool isConnecting = false;
        
        private async Task CheckAndReconnect()
        {
            // Protección contra reconexiones simultáneas
            lock (this)
            {
                if (!autoReconnect || isReconnecting || isConnecting)
                {
                    Log("Reconexión ignorada - ya hay un intento en curso");
                    return;
                }
                isReconnecting = true;
            }
            
            try
            {
                // Verificar si el cliente está desconectado o en estado inválido
                bool needsReconnect = false;
                string reason = "";
                
                if (client == null)
                {
                    needsReconnect = true;
                    reason = "Cliente nulo";
                }
                else if (client.State == SoulseekClientStates.Disconnected)
                {
                    needsReconnect = true;
                    reason = "Desconectado";
                }
                else if (!client.State.HasFlag(SoulseekClientStates.Connected) && 
                         !client.State.HasFlag(SoulseekClientStates.LoggedIn))
                {
                    needsReconnect = true;
                    reason = $"Estado inválido: {client.State}";
                }
                
                if (!needsReconnect)
                {
                    // Verificar pool de conexiones
                    if (clientPool != null)
                    {
                        int disconnected = 0;
                        foreach (var poolClient in clientPool)
                        {
                            if (poolClient?.State == SoulseekClientStates.Disconnected)
                                disconnected++;
                        }
                        
                        if (disconnected > 0)
                        {
                            AutoLog($"{disconnected}/{poolSize} clientes del pool desconectados");
                        }
                    }
                    
                    // Resetear contador si está conectado
                    reconnectAttempts = 0;
                    return;
                }
                
                // Evitar intentos muy frecuentes
                var timeSinceLastAttempt = (DateTime.Now - lastReconnectAttempt).TotalSeconds;
                if (timeSinceLastAttempt < 10)
                    return;
                
                lastReconnectAttempt = DateTime.Now;
                reconnectAttempts++;
                
                if (reconnectAttempts > MAX_RECONNECT_ATTEMPTS)
                {
                    Log($"[RECONEXIÓN] Máximo de reintentos alcanzado ({MAX_RECONNECT_ATTEMPTS})");
                    Log($"[RECONEXIÓN] Auto-reconexión deshabilitada");
                    Log($"[RECONEXIÓN] Reconecta manualmente desde la pestaña Config");
                    autoReconnect = false;
                    
                    SafeBeginInvoke(() => 
                    {
                        lblStatus.Text = "Desconectado (auto-reconexión deshabilitada)";
                        lblStatus.ForeColor = Color.Red;
                    });
                    return;
                }
                
                // Delay fijo como Nicotine+ (sin backoff exponencial)
                int delaySeconds = 10;
                
                Log($"[RECONEXIÓN] Conexión perdida: {reason}");
                Log($"[RECONEXIÓN] Intento {reconnectAttempts}/{MAX_RECONNECT_ATTEMPTS}");
                Log($"[RECONEXIÓN] Esperando {delaySeconds} segundos antes de reconectar...");
                
                SafeBeginInvoke(() => 
                {
                    lblStatus.Text = $"Reconectando ({reconnectAttempts}/{MAX_RECONNECT_ATTEMPTS})...";
                    lblStatus.ForeColor = Color.Orange;
                });
                
                await Task.Delay(delaySeconds * 1000);
                
                // Limpiar cliente anterior
                if (client != null)
                {
                    try { client.Dispose(); } catch { }
                    client = null;
                }
                
                // Limpiar pool
                if (clientPool != null)
                {
                    foreach (var poolClient in clientPool)
                    {
                        try { poolClient?.Dispose(); } catch { }
                    }
                    clientPool = null;
                }
                
                // Intentar reconexión
                await ConnectToSoulseek();
                
                SafeBeginInvoke(() => 
                {
                    btnConnect.Text = "Desconectar";
                    btnConnect.Enabled = true;
                    btnSearch.Enabled = true;
                    lblStatus.Text = "Reconectado";
                    lblStatus.ForeColor = Color.FromArgb(0, 200, 0);
                });
                
                Log($"[RECONEXIÓN] Reconexión exitosa en intento {reconnectAttempts}");
                Log($"[RECONEXIÓN] Conexión restablecida a las {DateTime.Now:HH:mm:ss}");
                reconnectAttempts = 0; // Reset en éxito
            }
            catch (TimeoutException)
            {
                Log($"[RECONEXIÓN] Timeout en reconexión");
                Log($"[RECONEXIÓN] Intento {reconnectAttempts}/{MAX_RECONNECT_ATTEMPTS} fallido");
            }
            catch (System.Net.Sockets.SocketException ex)
            {
                Log($"[RECONEXIÓN] Error de red: {ex.Message}");
                Log($"[RECONEXIÓN] Intento {reconnectAttempts}/{MAX_RECONNECT_ATTEMPTS} fallido");
            }
            catch (Exception ex)
            {
                Log($"[RECONEXIÓN] Error: {ex.Message}");
                Log($"[RECONEXIÓN] Intento {reconnectAttempts}/{MAX_RECONNECT_ATTEMPTS} fallido");
                
                // Deshabilitar auto-reconexión si es un error de autenticación
                if (ex.Message.Contains("Remote connection closed") || 
                    ex.Message.Contains("host remoto") ||
                    ex.Message.Contains("Invalid credentials"))
                {
                    Log("Error de autenticación detectado. Deshabilitando auto-reconexión para evitar bloqueos.");
                    autoReconnect = false;
                    
                    SafeBeginInvoke(() => 
                    {
                        lblStatus.Text = "Error de autenticación";
                        lblStatus.ForeColor = Color.Red;
                    });
                }
            }
            finally
            {
                isReconnecting = false;
            }
        }
        
