        private void LvResults_DrawColumnHeader(object sender, DrawListViewColumnHeaderEventArgs e)
        {
            // Fondo oscuro para encabezados
            using (SolidBrush backBrush = new SolidBrush(Color.FromArgb(35, 35, 35)))
            {
                e.Graphics.FillRectangle(backBrush, e.Bounds);
            }
            
            // Borde inferior
            using (Pen borderPen = new Pen(Color.FromArgb(60, 60, 60)))
            {
                e.Graphics.DrawLine(borderPen, e.Bounds.Left, e.Bounds.Bottom - 1, e.Bounds.Right, e.Bounds.Bottom - 1);
            }
            
            // Texto del encabezado con padding
            Rectangle textBounds = new Rectangle(e.Bounds.X + 5, e.Bounds.Y, e.Bounds.Width - 5, e.Bounds.Height);
            TextRenderer.DrawText(
                e.Graphics,
                e.Header.Text,
                new Font("Segoe UI", 9, FontStyle.Bold),
                textBounds,
                Color.White,
                TextFormatFlags.Left | TextFormatFlags.VerticalCenter
            );
            
            e.DrawDefault = false;
        }
        
