            e.DrawDefault = true;
        }
        
        private void LvResults_DrawSubItem(object sender, DrawListViewSubItemEventArgs e)
        {
            // Columna 3 = Estado
            if (e.ColumnIndex == 3 && e.SubItem != null)
            {
                // Determinar color según el estado
                Color textColor = Color.White;
                Color backColor = e.Item.BackColor;
                
                string estado = e.SubItem.Text.ToLowerInvariant();
                
                if (estado.Contains("completado"))
                {
                    textColor = Color.LightGreen;
                }
                else if (estado.Contains("descargando"))
                {
                    textColor = Color.Cyan;
                }
                else if (estado.Contains("en cola"))
                {
                    textColor = Color.Yellow;
                }
                else if (estado.Contains("pausado"))
                {
                    textColor = Color.Orange;
                }
                else if (estado.Contains("error") || estado.Contains("fallido"))
                {
                    textColor = Color.Red;
                }
                else if (estado.Contains("cancelado"))
                {
                    textColor = Color.Gray;
                }
                
                // Dibujar fondo
                e.Graphics.FillRectangle(new SolidBrush(backColor), e.Bounds);
                
                // Dibujar texto con color
                TextRenderer.DrawText(e.Graphics, e.SubItem.Text, e.Item.Font, e.Bounds, textColor, 
                    TextFormatFlags.Left | TextFormatFlags.VerticalCenter);
            }
            else
            {
                e.DrawDefault = true;
            }
        }
        
