        // Caché LRU para IsSpanishText - Optimizado con evicción automática
        private readonly LRUCache<string, bool> spanishTextCache = new LRUCache<string, bool>(10000);
        private const int MAX_SPANISH_CACHE_SIZE = 10000;
        
        // ArrayPool para caracteres españoles (Optimización #18)
        private static readonly char[] spanishChars = new[] { 'ñ', 'á', 'é', 'í', 'ó', 'ú', 'ü' };
        
        private bool IsSpanishText(string text)
        {
            if (string.IsNullOrWhiteSpace(text))
                return false;
            
            // Verificar caché primero
            if (spanishTextCache.TryGetValue(text, out var cached))
