                    textLower.Contains(" nevertheless ") || textLower.Contains(" otherwise ") ||
                    textLower.Contains(" meanwhile ") || textLower.Contains(" instead ") ||
                    textLower.Contains(" rather ") || textLower.Contains(" either ") ||
                    textLower.Contains(" neither ") || textLower.Contains(" both ") ||
                    textLower.Contains(" such ") || textLower.Contains(" which ") ||
                    textLower.Contains(" whose ") || textLower.Contains(" whom ") ||
                    textLower.Contains(" what ") || textLower.Contains(" when ") ||
                    textLower.Contains(" where ") || textLower.Contains(" why ") ||
                    textLower.Contains(" how ") || textLower.Contains(" that ") ||
                    textLower.Contains(" this ") || textLower.Contains(" these ") ||
                    textLower.Contains(" those ") || textLower.Contains(" there ") ||
                    textLower.Contains(" here ") || textLower.Contains(" some ") ||
                    textLower.Contains(" any ") || textLower.Contains(" many ") ||
                    textLower.Contains(" much ") || textLower.Contains(" few ") ||
                    textLower.Contains(" little ") || textLower.Contains(" more ") ||
                    textLower.Contains(" most ") || textLower.Contains(" less ") ||
                    textLower.Contains(" least ") || textLower.Contains(" several ") ||
                    textLower.Contains(" every ") || textLower.Contains(" each ") ||
                    textLower.Contains(" all ") || textLower.Contains(" both ") ||
                    textLower.Contains(" half ") || textLower.Contains(" other ") ||
                    textLower.Contains(" another ") || textLower.Contains(" such ") ||
                    textLower.Contains(" own ") || textLower.Contains(" same ") ||
                    textLower.Contains(" very ") || textLower.Contains(" too ") ||
                    textLower.Contains(" quite ") || textLower.Contains(" rather ") ||
                    textLower.Contains(" just ") || textLower.Contains(" only ") ||
                    textLower.Contains(" even ") || textLower.Contains(" also ") ||
                    textLower.Contains(" still ") || textLower.Contains(" yet ") ||
                    textLower.Contains(" already ") || textLower.Contains(" never ") ||
                    textLower.Contains(" always ") || textLower.Contains(" often ") ||
                    textLower.Contains(" sometimes ") || textLower.Contains(" usually ") ||
                    textLower.Contains(" seldom ") || textLower.Contains(" rarely ") ||
                    textLower.Contains(" hardly ") || textLower.Contains(" scarcely ") ||
                    textLower.Contains(" barely ") || textLower.Contains(" nearly ") ||
                    textLower.Contains(" almost ") || textLower.Contains(" quite ") ||
                    textLower.Contains(" enough ") || textLower.Contains(" indeed ") ||
                    textLower.Contains(" perhaps ") || textLower.Contains(" maybe ") ||
                    textLower.Contains(" probably ") || textLower.Contains(" possibly ") ||
                    textLower.Contains(" certainly ") || textLower.Contains(" surely ") ||
                    textLower.Contains(" definitely ") || textLower.Contains(" absolutely ") ||
                    textLower.EndsWith("ing") || textLower.EndsWith("tion") ||
                    textLower.EndsWith("ness") || textLower.EndsWith("ment") ||
                    textLower.EndsWith("ship") || textLower.EndsWith("hood") ||
                    textLower.EndsWith("dom") || textLower.EndsWith("ism") ||
                    textLower.EndsWith("ist") || textLower.EndsWith("ity") ||
                    textLower.EndsWith("ty") || textLower.EndsWith("ance") ||
                    textLower.EndsWith("ence") || textLower.EndsWith("ful") ||
                    textLower.EndsWith("less") || textLower.EndsWith("ous") ||
                    textLower.EndsWith("ious") || textLower.EndsWith("eous") ||
                    textLower.EndsWith("ive") || textLower.EndsWith("ative") ||
                    textLower.EndsWith("able") || textLower.EndsWith("ible") ||
                    textLower.EndsWith("al") || textLower.EndsWith("ial") ||
                    textLower.EndsWith("ic") || textLower.EndsWith("ical") ||
                    textLower.EndsWith("ly") || textLower.EndsWith("ward") ||
                    textLower.EndsWith("wards") || textLower.EndsWith("wise"))
                {
                    LanguageFilterStats.Instance.RecordFiltered("inglés", "the/of/and/with/prepositions");
                    spanishTextCache.Add(text, false);
                    return false;
                }
                
                // Rechazar italiano obvio (artículos y palabras comunes) - REFORZADO
                if (textLower.Contains(" il ") || textLower.Contains(" della ") || textLower.Contains(" degli ") ||
                    textLower.Contains(" nell") || textLower.Contains(" dell") || textLower.Contains(" che ") ||
                    textLower.Contains(" di ") || textLower.Contains(" sono ") || textLower.Contains(" è ") || 
                    textLower.Contains(" era ") || textLower.Contains(" gli ") || textLower.Contains(" lo ") ||
                    textLower.Contains("zione") || textLower.Contains("zioni") ||
                    textLower.Contains("aggio") || textLower.Contains("eggio"))
                {
                    LanguageFilterStats.Instance.RecordFiltered("italiano", "il/della/di/sono");
                    spanishTextCache.Add(text, false);
                    return false;
                }
                
                // Rechazar francés obvio (contracciones)
                if (textLower.Contains("l'") || textLower.Contains("d'") || textLower.Contains("c'"))
                {
                    LanguageFilterStats.Instance.RecordFiltered("francés", "l'/d'/c'");
                    spanishTextCache.Add(text, false);
                    return false;
                }
                
                // Rechazar alemán obvio (artículos, preposiciones y palabras comunes) - REFORZADO
                if (textLower.Contains(" der ") || textLower.Contains(" die ") || textLower.Contains(" das ") ||
                    textLower.Contains(" den ") || textLower.Contains(" dem ") || textLower.Contains(" des ") ||
                    textLower.Contains(" ein ") || textLower.Contains(" eine ") || textLower.Contains(" einen ") ||
                    textLower.Contains(" und ") || textLower.Contains(" oder ") || textLower.Contains(" aber ") ||
                    textLower.Contains(" nicht ") || textLower.Contains(" ist ") || textLower.Contains(" sind ") ||
                    textLower.Contains(" von ") || textLower.Contains(" zu ") || textLower.Contains(" mit ") ||
                    textLower.Contains(" für ") || textLower.Contains(" auf ") || textLower.Contains(" aus ") ||
                    textLower.Contains(" bei ") || textLower.Contains(" nach ") || textLower.Contains(" über ") ||
                    textLower.Contains(" unter ") || textLower.Contains(" durch ") || textLower.Contains(" gegen ") ||
                    textLower.Contains(" ohne ") || textLower.Contains(" um ") || textLower.Contains(" bis ") ||
                    textLower.Contains(" seit ") || textLower.Contains(" während ") || textLower.Contains(" wahrend ") ||
                    textLower.Contains(" dass ") || textLower.Contains(" daß ") || textLower.Contains(" wenn ") ||
                    textLower.Contains(" weil ") || textLower.Contains(" als ") || textLower.Contains(" wie ") ||
                    textLower.Contains(" auch ") || textLower.Contains(" noch ") || textLower.Contains(" nur ") ||
                    textLower.Contains(" schon ") || textLower.Contains(" sehr ") || textLower.Contains(" mehr ") ||
                    textLower.Contains(" können ") || textLower.Contains(" konnen ") || textLower.Contains(" müssen ") ||
                    textLower.Contains(" mussen ") || textLower.Contains(" sollen ") || textLower.Contains(" werden ") ||
                    textLower.Contains(" wurde ") || textLower.Contains(" wurden ") || textLower.Contains(" gewesen ") ||
                    textLower.Contains(" haben ") || textLower.Contains(" hatte ") || textLower.Contains(" hatten ") ||
                    textLower.Contains(" sein ") || textLower.Contains(" war ") || textLower.Contains(" waren ") ||
                    textLower.Contains("schaft") || textLower.Contains("keit") || textLower.Contains("ung ") ||
                    textLower.Contains("lich ") || textLower.Contains("isch ") || textLower.Contains("bar ") ||
                    textLower.StartsWith("ge") && textLower.Length > 5 ||
                    textLower.Contains("ß")) // Eszett (letra alemana)
                {
                    LanguageFilterStats.Instance.RecordFiltered("alemán", "der/die/das/und/nicht/von");
                    spanishTextCache.Add(text, false);
                    return false;
                }
                
                // Rechazar portugués obvio (caracteres y palabras distintivas)
                if (text.Contains("ã") || text.Contains("õ") || text.Contains("ç") ||
                    textLower.Contains(" não ") || textLower.Contains(" nao ") ||
                    textLower.Contains(" dos ") || textLower.Contains(" das ") ||
                    textLower.Contains(" uma ") || textLower.Contains(" com ") ||
                    textLower.Contains(" para ") || textLower.Contains(" pela ") ||
                    textLower.Contains(" pelo ") || textLower.Contains(" pelos ") ||
                    textLower.Contains(" pelas ") || textLower.Contains(" também ") ||
                    textLower.Contains(" tambem ") || textLower.Contains(" você ") ||
                    textLower.Contains(" voce ") || textLower.Contains(" está ") ||
                    textLower.Contains(" esta ") || textLower.Contains(" são ") ||
                    textLower.Contains(" sao ") || textLower.Contains(" português ") ||
                    textLower.Contains(" portugues ") || textLower.Contains(" brasil "))
                {
                    LanguageFilterStats.Instance.RecordFiltered("portugués", "ã/õ/ç/não");
                    spanishTextCache.Add(text, false);
                    return false;
                }
                
                // Si tiene caracteres españoles (pero NO portugueses), aceptar
                if (text.Contains("ñ") || text.Contains("á") || text.Contains("é") || 
                    text.Contains("í") || text.Contains("ó") || text.Contains("ú"))
                {
                    spanishTextCache.Add(text, true);
                    return true;
                }
                
                // Buscar palabras españolas comunes (evidencia positiva)
                int spanishScore = 0;
                
                // Artículos y preposiciones españolas distintivas
                if (textLower.Contains(" del ")) spanishScore += 3;  // Muy distintivo
                if (textLower.Contains(" los ")) spanishScore += 2;
                if (textLower.Contains(" las ")) spanishScore += 2;
                if (textLower.Contains(" por ")) spanishScore += 2;
                if (textLower.Contains(" para ")) spanishScore += 3;
                if (textLower.Contains(" donde ")) spanishScore += 3;
                if (textLower.Contains(" cuando ")) spanishScore += 3;
                if (textLower.Contains(" con ")) spanishScore += 1;
                if (textLower.Contains(" sin ")) spanishScore += 2;
                if (textLower.Contains(" sobre ")) spanishScore += 2;
                if (textLower.Contains(" entre ")) spanishScore += 2;
                if (textLower.Contains(" desde ")) spanishScore += 2;
                if (textLower.Contains(" hasta ")) spanishScore += 2;
                
                // Palabras comunes en títulos de libros en español
                if (textLower.Contains(" una ")) spanishScore += 1;
                if (textLower.Contains(" uno ")) spanishScore += 1;
                if (textLower.Contains(" esta ")) spanishScore += 1;
                if (textLower.Contains(" este ")) spanishScore += 1;
                if (textLower.Contains(" ese ")) spanishScore += 1;
                if (textLower.Contains(" esa ")) spanishScore += 1;
                if (textLower.Contains(" aquel ")) spanishScore += 2;
                if (textLower.Contains(" aquella ")) spanishScore += 2;
                if (textLower.Contains(" como ")) spanishScore += 1;
                if (textLower.Contains(" porque ")) spanishScore += 2;
                if (textLower.Contains(" aunque ")) spanishScore += 2;
                if (textLower.Contains(" mientras ")) spanishScore += 2;
                if (textLower.Contains(" siempre ")) spanishScore += 2;
                if (textLower.Contains(" nunca ")) spanishScore += 2;
                if (textLower.Contains(" también ")) spanishScore += 2;
                if (textLower.Contains(" tampoco ")) spanishScore += 2;
                if (textLower.Contains(" después ")) spanishScore += 2;
                if (textLower.Contains(" antes ")) spanishScore += 2;
                if (textLower.Contains(" ahora ")) spanishScore += 2;
                if (textLower.Contains(" entonces ")) spanishScore += 2;
                if (textLower.Contains(" todo ")) spanishScore += 1;
                if (textLower.Contains(" todos ")) spanishScore += 1;
                if (textLower.Contains(" toda ")) spanishScore += 1;
                if (textLower.Contains(" todas ")) spanishScore += 1;
                if (textLower.Contains(" nada ")) spanishScore += 2;
                if (textLower.Contains(" algo ")) spanishScore += 1;
                if (textLower.Contains(" alguien ")) spanishScore += 2;
                if (textLower.Contains(" nadie ")) spanishScore += 2;
                if (textLower.Contains(" otro ")) spanishScore += 1;
                if (textLower.Contains(" otra ")) spanishScore += 1;
                if (textLower.Contains(" otros ")) spanishScore += 1;
                if (textLower.Contains(" otras ")) spanishScore += 1;
                if (textLower.Contains(" mismo ")) spanishScore += 1;
                if (textLower.Contains(" misma ")) spanishScore += 1;
                
                // Verbos españoles comunes
                if (textLower.Contains(" ser ")) spanishScore += 2;
                if (textLower.Contains(" estar ")) spanishScore += 2;
                if (textLower.Contains(" haber ")) spanishScore += 2;
                if (textLower.Contains(" hacer ")) spanishScore += 2;
                if (textLower.Contains(" tener ")) spanishScore += 2;
                
                // Términos literarios españoles (alto valor)
                if (textLower.Contains(" libro ")) spanishScore += 3;
                if (textLower.Contains(" novela ")) spanishScore += 3;
                if (textLower.Contains(" historia ")) spanishScore += 2;
                if (textLower.Contains(" cuento ")) spanishScore += 2;
                if (textLower.Contains(" saga ")) spanishScore += 2;
                if (textLower.Contains(" serie ")) spanishScore += 2;
                if (textLower.Contains(" tomo ")) spanishScore += 2;
                if (textLower.Contains(" volumen ")) spanishScore += 2;
                if (textLower.Contains(" edición ") || textLower.Contains(" edicion ")) spanishScore += 2;
                if (textLower.Contains(" español ") || textLower.Contains(" espanol ")) spanishScore += 3;
                if (textLower.Contains(" castellano ")) spanishScore += 3;
                
                // Ajustar umbral según longitud del texto (títulos cortos necesitan menos evidencia)
                int requiredScore = text.Length < 20 ? 2 : 3;
                bool isSpanish = spanishScore >= requiredScore;
                
                if (isSpanish)
                {
                    LanguageFilterStats.Instance.RecordPassed();
                }
                
                spanishTextCache.Add(text, isSpanish);
                return isSpanish;
        }
        
