                textLower.Contains(" avec ") || textLower.Contains(" sans ") || textLower.Contains(" pour ") ||
                textLower.Contains(" dans ") || textLower.Contains(" sur ") || textLower.Contains(" sous ") ||
                textLower.Contains(" par ") || textLower.Contains(" chez ") || textLower.Contains(" vers ") ||
                textLower.Contains(" entre ") || textLower.Contains(" parmi ") || textLower.Contains(" pendant ") ||
                textLower.Contains(" depuis ") || textLower.Contains(" avant ") || textLower.Contains(" après "))
            {
                spanishTextCache[text] = false;
                return false;
            }
            
            // Palabras francesas muy comunes en títulos
            if (textLower.Contains(" est ") || textLower.Contains(" sont ") || textLower.Contains(" était ") ||
                textLower.Contains(" étaient ") || textLower.Contains(" sera ") || textLower.Contains(" seront ") ||
                textLower.Contains(" a ") || textLower.Contains(" ont ") || textLower.Contains(" avait ") ||
                textLower.Contains(" avaient ") || textLower.Contains(" aura ") || textLower.Contains(" auront ") ||
                textLower.Contains(" peut ") || textLower.Contains(" peuvent ") || textLower.Contains(" doit ") ||
                textLower.Contains(" doivent ") || textLower.Contains(" fait ") || textLower.Contains(" font ") ||
                textLower.Contains(" pas ") || textLower.Contains(" plus ") || textLower.Contains(" très ") ||
                textLower.Contains(" bien ") || textLower.Contains(" tout ") || textLower.Contains(" tous ") ||
                textLower.Contains(" toute ") || textLower.Contains(" toutes ") || textLower.Contains(" autre ") ||
                textLower.Contains(" autres ") || textLower.Contains(" même ") || textLower.Contains(" mêmes ") ||
                textLower.Contains(" quel ") || textLower.Contains(" quelle ") || textLower.Contains(" quels ") ||
                textLower.Contains(" quelles ") || textLower.Contains(" qui ") || textLower.Contains(" que ") ||
                textLower.Contains(" quoi ") || textLower.Contains(" dont ") || textLower.Contains(" où "))
            {
                spanishTextCache[text] = false;
                return false;
            }
            
            // Terminaciones francesas típicas
            if (textLower.EndsWith("tion") || textLower.EndsWith("sion") || textLower.EndsWith("ment") ||
                textLower.EndsWith("eur") || textLower.EndsWith("euse") || textLower.EndsWith("eux") ||
                textLower.EndsWith("eaux") || textLower.EndsWith("ance") || textLower.EndsWith("ence") ||
                textLower.Contains("tion ") || textLower.Contains("sion ") || textLower.Contains("ment "))
            {
                spanishTextCache[text] = false;
                return false;
            }
            
            // Contracciones y elisiones francesas
            if (textLower.Contains("l'") || textLower.Contains("d'") || textLower.Contains("n'") ||
                textLower.Contains("c'") || textLower.Contains("s'") || textLower.Contains("m'") ||
                textLower.Contains("t'") || textLower.Contains("qu'") || textLower.Contains("j'"))
            {
                spanishTextCache[text] = false;
                return false;
            }
            
            // Acentos franceses específicos (à, è, é, ê, ë, ù, û, ç, œ)
            if (textLower.Contains("à") || textLower.Contains("è") || textLower.Contains("ê") ||
                textLower.Contains("ë") || textLower.Contains("ù") || textLower.Contains("û") ||
                textLower.Contains("ç") || textLower.Contains("œ") || textLower.Contains("æ"))
            {
                spanishTextCache[text] = false;
                return false;
            }
            
            // Usar librería nativa si está disponible (50x más rápido)
            if (useNativeLib)
            {
                try
                {
                    var result = NativeInterop.IsSpanishTextNative(text);
                    spanishTextCache[text] = result;
                    return result;
                }
                catch
                {
                    // Fallback a implementación C# si falla
                }
            }
            
            // Early exit: Caracteres españoles = definitivamente español (Optimización #19)
            bool hasSpanishChars = text.IndexOfAny(spanishChars) >= 0;
            if (hasSpanishChars)
            {
                spanishTextCache[text] = true;
                return true;
            }
            
            // Usar IndexOf con StringComparison en lugar de ToLower + Contains (Optimización #22)
            var comparison = StringComparison.OrdinalIgnoreCase;
            
            // Detectar apóstrofes/acentos invertidos (italiano/francés: l'uomo, l'homme, c'est)
            // Español NO usa apóstrofes en palabras
            if (text.Contains("l'") || text.Contains("l´") || text.Contains("l`") ||
                text.Contains("d'") || text.Contains("d´") || text.Contains("d`") ||
                text.Contains("c'") || text.Contains("c´") || text.Contains("c`") ||
                text.Contains("n'") || text.Contains("n´") || text.Contains("n`") ||
                text.Contains("s'") || text.Contains("s´") || text.Contains("s`") ||
                text.Contains("t'") || text.Contains("t´") || text.Contains("t`") ||
                text.Contains("m'") || text.Contains("m´") || text.Contains("m`") ||
                text.Contains("qu'") || text.Contains("qu´") || text.Contains("qu`") ||
                text.Contains("j'") || text.Contains("j´") || text.Contains("j`"))
            {
                spanishTextCache[text] = false;
                return false;
            }
            
            // Palabras comunes en inglés que NO son español (solo las más comunes)
            if (text.IndexOf(" the ", comparison) >= 0 || 
                text.IndexOf(" and ", comparison) >= 0 || 
                text.IndexOf(" with ", comparison) >= 0)
            {
                spanishTextCache[text] = false;
                return false;
            }
            
            // Palabras comunes en italiano (SUPER REFORZADO)
            // Artículos y preposiciones italianas
            if (text.IndexOf(" il ", comparison) >= 0 || 
                text.IndexOf(" lo ", comparison) >= 0 ||
                text.IndexOf(" gli ", comparison) >= 0 ||
                text.IndexOf(" della ", comparison) >= 0 || 
                text.IndexOf(" degli ", comparison) >= 0 ||
                text.IndexOf(" delle ", comparison) >= 0 ||
                text.IndexOf(" dello ", comparison) >= 0 ||
                text.IndexOf(" nell", comparison) >= 0 ||
                text.IndexOf(" dall", comparison) >= 0 ||
                text.IndexOf(" all", comparison) >= 0 ||
                text.IndexOf(" sul ", comparison) >= 0 ||
                text.IndexOf(" sulla ", comparison) >= 0 ||
                text.IndexOf(" sugli ", comparison) >= 0 ||
                text.IndexOf(" sulle ", comparison) >= 0 ||
                text.IndexOf(" agli ", comparison) >= 0 ||
                text.IndexOf(" ai ", comparison) >= 0 ||
                text.IndexOf(" col ", comparison) >= 0 ||
                text.IndexOf(" coi ", comparison) >= 0 ||
                text.IndexOf(" nel ", comparison) >= 0 ||
                text.IndexOf(" nei ", comparison) >= 0 ||
                text.IndexOf(" dal ", comparison) >= 0 ||
                text.IndexOf(" dai ", comparison) >= 0 ||
                text.IndexOf(" al ", comparison) >= 0 ||
                text.IndexOf(" allo ", comparison) >= 0 ||
                text.IndexOf(" alla ", comparison) >= 0 ||
                text.IndexOf(" alle ", comparison) >= 0 ||
                // Palabras comunes italianas
                text.IndexOf(" con ", comparison) >= 0 ||
                text.IndexOf(" per ", comparison) >= 0 ||
                text.IndexOf(" tra ", comparison) >= 0 ||
                text.IndexOf(" fra ", comparison) >= 0 ||
                text.IndexOf(" che ", comparison) >= 0 ||
                text.IndexOf(" una ", comparison) >= 0 ||
                text.IndexOf(" uno ", comparison) >= 0 ||
                text.IndexOf(" sono ", comparison) >= 0 ||
                text.IndexOf(" questo ", comparison) >= 0 ||
                text.IndexOf(" questa ", comparison) >= 0 ||
                text.IndexOf(" questi ", comparison) >= 0 ||
                text.IndexOf(" queste ", comparison) >= 0 ||
                text.IndexOf(" quello ", comparison) >= 0 ||
                text.IndexOf(" quella ", comparison) >= 0 ||
                text.IndexOf(" quelli ", comparison) >= 0 ||
                text.IndexOf(" quelle ", comparison) >= 0 ||
                text.IndexOf(" anche ", comparison) >= 0 ||
                text.IndexOf(" molto ", comparison) >= 0 ||
                text.IndexOf(" più ", comparison) >= 0 ||
                text.IndexOf(" più", comparison) >= 0 ||
                text.IndexOf(" meno ", comparison) >= 0 ||
                text.IndexOf(" quando ", comparison) >= 0 ||
                text.IndexOf(" dove ", comparison) >= 0 ||
                text.IndexOf(" come ", comparison) >= 0 ||
                text.IndexOf(" perché ", comparison) >= 0 ||
                text.IndexOf(" perche ", comparison) >= 0 ||
                text.IndexOf(" quindi ", comparison) >= 0 ||
                text.IndexOf(" però ", comparison) >= 0 ||
                text.IndexOf(" pero ", comparison) >= 0 ||
                text.IndexOf(" ancora ", comparison) >= 0 ||
                text.IndexOf(" sempre ", comparison) >= 0 ||
                text.IndexOf(" mai ", comparison) >= 0 ||
                text.IndexOf(" già ", comparison) >= 0 ||
                text.IndexOf(" gia ", comparison) >= 0 ||
                text.IndexOf(" dopo ", comparison) >= 0 ||
                text.IndexOf(" prima ", comparison) >= 0 ||
                text.IndexOf(" ora ", comparison) >= 0 ||
                text.IndexOf(" adesso ", comparison) >= 0 ||
                text.IndexOf(" oggi ", comparison) >= 0 ||
                text.IndexOf(" ieri ", comparison) >= 0 ||
                text.IndexOf(" domani ", comparison) >= 0 ||
                text.IndexOf(" ogni ", comparison) >= 0 ||
                text.IndexOf(" tutto ", comparison) >= 0 ||
                text.IndexOf(" tutta ", comparison) >= 0 ||
                text.IndexOf(" tutti ", comparison) >= 0 ||
                text.IndexOf(" tutte ", comparison) >= 0 ||
                text.IndexOf(" niente ", comparison) >= 0 ||
                text.IndexOf(" nulla ", comparison) >= 0 ||
                text.IndexOf(" qualche ", comparison) >= 0 ||
                text.IndexOf(" qualcosa ", comparison) >= 0 ||
                text.IndexOf(" qualcuno ", comparison) >= 0 ||
                text.IndexOf(" nessuno ", comparison) >= 0 ||
                text.IndexOf(" nessuna ", comparison) >= 0 ||
                text.IndexOf(" altro ", comparison) >= 0 ||
                text.IndexOf(" altra ", comparison) >= 0 ||
                text.IndexOf(" altri ", comparison) >= 0 ||
                text.IndexOf(" altre ", comparison) >= 0 ||
                text.IndexOf(" stesso ", comparison) >= 0 ||
                text.IndexOf(" stessa ", comparison) >= 0 ||
                text.IndexOf(" stessi ", comparison) >= 0 ||
                text.IndexOf(" stesse ", comparison) >= 0 ||
                text.IndexOf(" proprio ", comparison) >= 0 ||
                text.IndexOf(" propria ", comparison) >= 0 ||
                text.IndexOf(" propri ", comparison) >= 0 ||
                text.IndexOf(" proprie ", comparison) >= 0 ||
                // Terminaciones típicas italianas
                text.IndexOf("zione", comparison) >= 0 ||
                text.IndexOf("zioni", comparison) >= 0 ||
                text.IndexOf("aggio", comparison) >= 0 ||
                text.IndexOf("eggio", comparison) >= 0 ||
                text.IndexOf("iglia", comparison) >= 0 ||
                text.IndexOf("iglio", comparison) >= 0 ||
                // Verbos italianos comunes
                text.IndexOf(" essere ", comparison) >= 0 ||
                text.IndexOf(" avere ", comparison) >= 0 ||
                text.IndexOf(" fare ", comparison) >= 0 ||
                text.IndexOf(" dire ", comparison) >= 0 ||
                text.IndexOf(" andare ", comparison) >= 0 ||
                text.IndexOf(" venire ", comparison) >= 0 ||
                text.IndexOf(" sapere ", comparison) >= 0 ||
                text.IndexOf(" volere ", comparison) >= 0 ||
                text.IndexOf(" potere ", comparison) >= 0 ||
                text.IndexOf(" dovere ", comparison) >= 0 ||
                text.IndexOf(" vedere ", comparison) >= 0 ||
                text.IndexOf(" dare ", comparison) >= 0 ||
                text.IndexOf(" stare ", comparison) >= 0 ||
                text.IndexOf(" prendere ", comparison) >= 0 ||
                text.IndexOf(" trovare ", comparison) >= 0 ||
                text.IndexOf(" pensare ", comparison) >= 0 ||
                text.IndexOf(" credere ", comparison) >= 0 ||
                text.IndexOf(" capire ", comparison) >= 0 ||
                text.IndexOf(" sentire ", comparison) >= 0 ||
                text.IndexOf(" parlare ", comparison) >= 0 ||
                // Doble consonante típica italiana (gg, zz, cc, tt, ll, nn, mm, pp, bb, dd, ff, rr, ss)
                text.Contains("gg") || text.Contains("zz") || text.Contains("cc") ||
                text.Contains("tt") || text.Contains("ll") || text.Contains("nn") ||
                text.Contains("mm") || text.Contains("pp") || text.Contains("bb") ||
                text.Contains("dd") || text.Contains("ff") || text.Contains("rr") ||
                text.Contains("ss"))
            {
                spanishTextCache[text] = false;
                return false;
            }
            
            // Palabras comunes en francés (solo las más comunes)
            if (text.IndexOf(" le ", comparison) >= 0 || 
                text.IndexOf(" la ", comparison) >= 0 || 
                text.IndexOf(" les ", comparison) >= 0)
            {
                // Ambiguo: "la" existe en español, verificar más
                if (text.IndexOf(" dans ", comparison) >= 0 || 
                    text.IndexOf(" pour ", comparison) >= 0 || 
                    text.IndexOf(" avec ", comparison) >= 0)
                {
                    spanishTextCache[text] = false;
                    return false;
                }
            }
            
            // Palabras comunes en español (solo las más distintivas)
            int spanishCount = 0;
            if (text.IndexOf(" del ", comparison) >= 0) spanishCount += 2; // Muy distintivo
            if (text.IndexOf(" los ", comparison) >= 0) spanishCount++;
            if (text.IndexOf(" las ", comparison) >= 0) spanishCount++;
            if (text.IndexOf(" por ", comparison) >= 0) spanishCount++;
            if (text.IndexOf(" para ", comparison) >= 0) spanishCount++;
            if (text.IndexOf(" donde ", comparison) >= 0) spanishCount++;
            if (text.IndexOf(" cuando ", comparison) >= 0) spanishCount++;
            
            // Si tiene caracteres españoles o al menos 2 palabras españolas, es español
            var isSpanish = hasSpanishChars || spanishCount >= 2;
            
            // Cachear resultado (con límite de tamaño)
            if (spanishTextCache.Count < MAX_SPANISH_CACHE_SIZE)
            {
                spanishTextCache[text] = isSpanish;
            }
            return isSpanish;
        }

        // Caché de extensiones para IsDocumentFile (Optimización #2)
        */
        
        private readonly System.Collections.Concurrent.ConcurrentDictionary<string, bool> extensionCache = 
            new System.Collections.Concurrent.ConcurrentDictionary<string, bool>(StringComparer.OrdinalIgnoreCase);
        
        private bool IsDocumentFile(string filename)
        {
            string extension = Path.GetExtension(filename);
            if (string.IsNullOrEmpty(extension))
                return false;
            
            // Usar caché para evitar lookups repetidos
            return extensionCache.GetOrAdd(extension, ext => DocumentExtensions.Contains(ext));
        }
        
        private bool IsGarbageFile(string filename)
        {
            if (string.IsNullOrEmpty(filename))
                return true;
            
            string filenameLower = filename.ToLowerInvariant();
            
            // Verificar patrones de basura
            foreach (var pattern in GarbageFilePatterns)
            {
                if (filenameLower.Contains(pattern))
                    return true;
            }
            
            // Archivos con nombres sospechosos
            if (filenameLower.Length < 3) // Nombres muy cortos como "a.pdf"
                return true;
            
            // Archivos que son solo comillas o caracteres especiales
            if (filenameLower.StartsWith("\"") && filenameLower.Length < 10)
                return true;
            
            return false;
        }
        
        private void TrackFileFailure(string filename, string username, string errorMessage)
        {
            string fileKey = $"{username}|{filename}";
            
            lock (fileFailureTracker)
            {
                if (!fileFailureTracker.ContainsKey(fileKey))
                {
                    fileFailureTracker[fileKey] = new FileFailureInfo();
                }
                
                var info = fileFailureTracker[fileKey];
                info.FailureCount++;
                info.LastFailure = DateTime.Now;
                info.LastError = errorMessage;
                
                if (info.FailureCount >= MAX_FILE_FAILURES)
                {
                    Log($"Archivo blacklisteado después de {info.FailureCount} fallos: {filename} ({errorMessage})");
                }
            }
        }
        
        private bool IsFileBlacklisted(string filename, string username)
        {
            // Verificar si el usuario está en la blacklist
            if (blacklist.Contains(username))
            {
                return true;
            }
            
            // Verificar si el archivo ha fallado muchas veces
            string fileKey = $"{username}|{filename}";
            
            lock (fileFailureTracker)
            {
                if (fileFailureTracker.TryGetValue(fileKey, out var info))
                {
                    return info.FailureCount >= MAX_FILE_FAILURES;
                }
            }
            
            return false;
        }

        private void SaveAutoResultsToCsv()
        {
            // Reconstruir índice después de guardar
            BuildAuthorIndex();
            
            try
            {
                List<AutoSearchFileResult> snapshot;
                
                    snapshot = autoSearchResults.ToList();
                
                
                // Guardar en SQLite (prioridad)
                if (dbConnection != null && dbConnection.State == System.Data.ConnectionState.Open)
                {
                    SaveFilesToDatabase(snapshot);
                }

                var sb = new StringBuilder();
                sb.AppendLine("Autor,Usuario,Archivo,Directorio,TamañoBytes,TamañoLegible,EsEspañol,EsDocumento,Fecha");

                foreach (var result in snapshot)
                {
                    sb.AppendLine(string.Join(",", new[]
                    {
                        EscapeCsv(result.Author),
                        EscapeCsv(result.Username),
                        EscapeCsv(result.FileName),
                        EscapeCsv(result.Directory),
                        result.SizeBytes.ToString(),
                        EscapeCsv(result.SizeReadable),
                        result.IsSpanish.ToString(),
                        result.IsDocument.ToString(),
                        result.Timestamp.ToString("yyyy-MM-dd HH:mm:ss")
                    }));
                }

                System.IO.File.WriteAllText(autoResultsCsvPath, sb.ToString(), Encoding.UTF8);
                AutoLog($" Resultados automáticos guardados en: {autoResultsCsvPath}");
                
                // También guardar en JSON
                SaveAutoResultsToJson();
            }
            catch (Exception ex)
            {
                AutoLog($" Error al guardar resultados automáticos: {ex.Message}");
            }
        }

        private static string EscapeCsv(string value)
        {
            if (string.IsNullOrEmpty(value)) return string.Empty;
            if (value.Contains('"')) value = value.Replace("\"", "\"\"");
            if (value.IndexOfAny(new[] { ',', '\n', '\r' }) >= 0) return $"\"{value}\"";
            return value;
        }

        private static string FormatFileSize(long bytes)
        {
            string[] sizes = { "B", "KB", "MB", "GB", "TB" };
            double len = bytes;
            int order = 0;
            while (len >= 1024 && order < sizes.Length - 1)
            {
                order++;
                len = len / 1024;
            }
            return $"{len:0.##} {sizes[order]}";
        }

        private static string FormatSpeed(double bytesPerSecond)
        {
            string[] sizes = { "B/s", "KB/s", "MB/s", "GB/s" };
            double speed = bytesPerSecond;
            int order = 0;
            while (speed >= 1024 && order < sizes.Length - 1)
            {
                order++;
                speed = speed / 1024;
            }
            return $"{speed:0.##} {sizes[order]}";
        }

        private void OpenAutoResultsCsv()
        {
            try
            {
                if (!System.IO.File.Exists(autoResultsCsvPath))
                {
                    AutoLog(" El archivo de resultados automáticos no existe todavía.");
                    MessageBox.Show("El archivo 'auto_search_results.csv' aún no se ha generado.", "Abrir resultados", MessageBoxButtons.OK, MessageBoxIcon.Information);
                    return;
                }

                Process.Start(new ProcessStartInfo { FileName = autoResultsCsvPath, UseShellExecute = true });
                AutoLog($" Abriendo resultados automáticos: {autoResultsCsvPath}");
            }
            catch (Exception ex)
            {
                AutoLog($" Error al abrir resultados: {ex.Message}");
            }
        }

