            {
                Text = "Descargas simultáneas:",
                Location = new Point(5, 12),
                AutoSize = true,
                ForeColor = Color.LightGray,
                Font = new Font("Segoe UI", 9)
            };
            configPanel.Controls.Add(lblSimultaneous);

            var numSimultaneous = new NumericUpDown
            {
                Location = new Point(180, 8),
                Width = 60,
                Minimum = 1,
                Maximum = 50,
                Value = maxSimultaneousDownloads,
                BackColor = Color.FromArgb(50, 50, 50),
                ForeColor = Color.White
            };
            numSimultaneous.ValueChanged += (s, e) =>
            {
                maxSimultaneousDownloads = (int)numSimultaneous.Value;
