            // Actualizar estadísticas globales
            Action updateGlobalStats = () =>
            {
                
                    var uniqueAuthors = autoSearchResults.Select(f => f.Author).Distinct().Count();
                    var totalSize = autoSearchResults.Sum(f => f.SizeBytes);
                    var totalSizeGB = totalSize / 1024.0 / 1024.0 / 1024.0;
                    
                    lblGlobalStats.Text = 
                        $"Total encontrados: {autoSearchResults.Count:N0} archivos\n" +
                        $"Descargados: {statistics.TotalFilesDownloaded:N0} | Tamaño: {(statistics.TotalBytesDownloaded / 1024.0 / 1024.0 / 1024.0):F2} GB\n" +
                        $"Autores únicos: {uniqueAuthors} | Vel. promedio: {statistics.AverageDownloadSpeed:F2} MB/s";
                
            };

            mainLayout.Controls.Add(topRightPanel, 1, 0);  // Columna 1, Fila 0
            mainLayout.SetRowSpan(topRightPanel, 2);  // Ocupa filas 0 y 1

            // Panel de búsqueda
            var searchPanel = new Panel
            {
                Dock = DockStyle.Top,
