                Cursor = Cursors.Hand
            };
            btnClearSearch.FlatAppearance.BorderSize = 0;
            btnClearSearch.Click += (s, e) => { txtSearch.Text = ""; txtSearch.Focus(); };
            searchPanel.Controls.Add(btnClearSearch);
            
            var lblSearchResults = new Label
            {
                Location = new Point(420, 10),
                AutoSize = true,
                ForeColor = Color.LightBlue,
                Font = new Font("Segoe UI", 8)
            };
            searchPanel.Controls.Add(lblSearchResults);

            // ListView para mostrar archivos
            var lvFiles = new ListView
            {
                Dock = DockStyle.Fill,
                View = View.Details,
                FullRowSelect = true,
                GridLines = true,
                CheckBoxes = true,
                BackColor = Color.FromArgb(30, 30, 30),
                ForeColor = Color.White,
                Font = new Font("Segoe UI", 9),
                HoverSelection = false
            };

            lvFiles.Columns.Add("Estado", 100);
            lvFiles.Columns.Add("Autor", 130);
            lvFiles.Columns.Add("Archivo", 250);
            lvFiles.Columns.Add("Extensión", 70);
            lvFiles.Columns.Add("Tamaño", 80);
            lvFiles.Columns.Add("Usuario", 100);
            lvFiles.Columns.Add("Directorio", 200);
            lvFiles.Columns.Add("Español", 60);
            lvFiles.Columns.Add("Doc", 50);
            lvFiles.Columns.Add("Fecha", 130);

            // Variables para ordenamiento
            int sortColumnIndex = -1;
            bool sortAscending = true;

            // Helper para obtener valor de ordenamiento según columna
            Func<ListViewItem, int, IComparable> GetSortValue = (item, columnIndex) =>
            {
                var file = (AutoSearchFileResult)item.Tag;
                switch (columnIndex)
                {
                    case 0: return item.Text; // Estado
                    case 1: return file.Author; // Autor
                    case 2: return file.FileName; // Archivo
                    case 3: return Path.GetExtension(file.FileName).ToLower(); // Extensión
                    case 4: return file.SizeBytes; // Tamaño (ordenar por bytes)
                    case 5: return file.Username; // Usuario
                    case 6: return file.Directory; // Directorio
                    case 7: return file.IsSpanish ? 0 : 1; // Español (Sí primero)
                    case 8: return file.IsDocument ? 0 : 1; // Doc (Sí primero)
                    case 9: return file.Timestamp; // Fecha
                    default: return item.Text;
                }
            };

            // Helper para actualizar encabezados con indicadores visuales
            Action<ListView, int, bool> UpdateColumnHeaders = (lv, sortCol, ascending) =>
            {
                string[] columnNames = { "Estado", "Autor", "Archivo", "Extensión", "Tamaño", "Usuario", "Directorio", "Español", "Doc", "Fecha" };
                for (int i = 0; i < lv.Columns.Count; i++)
                {
                    string header = columnNames[i];
                    if (i == sortCol)
                    {
                        header += ascending ? " ▲" : " ▼";
                    }
                    lv.Columns[i].Text = header;
                }
            };

            // Comparador personalizado para ordenamiento rápido
            var listViewItemComparer = new ListViewItemComparer(sortColumnIndex, sortAscending, GetSortValue);
            lvFiles.ListViewItemSorter = listViewItemComparer;

            // Event handler para ordenar al hacer clic en columnas (OPTIMIZADO)
            lvFiles.ColumnClick += (s, e) =>
            {
                // Si se hace clic en la misma columna, invertir orden
                if (e.Column == sortColumnIndex)
                {
                    sortAscending = !sortAscending;
                }
                else
                {
                    sortColumnIndex = e.Column;
                    sortAscending = true;
                }

                // Actualizar comparador y ordenar (MUY RÁPIDO)
                listViewItemComparer.ColumnIndex = sortColumnIndex;
                listViewItemComparer.Ascending = sortAscending;
                lvFiles.Sort();

                // Actualizar encabezados con indicador visual
                UpdateColumnHeaders(lvFiles, sortColumnIndex, sortAscending);
            };

            // Panel contenedor para búsqueda + lista
            var filesContainer = new Panel
            {
                Dock = DockStyle.Fill
            };
            filesContainer.Controls.Add(lvFiles);
            filesContainer.Controls.Add(searchPanel);
            
            mainLayout.Controls.Add(filesContainer, 0, 2);  // Fila 2: Grilla

            // TextBox de log en el lado derecho
            var txtDownloadLog = new TextBox
            {
                Dock = DockStyle.Fill,
                Multiline = true,
                ReadOnly = true,
                BackColor = Color.FromArgb(20, 20, 20),
                ForeColor = Color.LightGray,
                Font = new Font("Consolas", 9),
                ScrollBars = ScrollBars.Both,
                WordWrap = false
            };
            mainLayout.Controls.Add(txtDownloadLog, 1, 2);  // Fila 2: Log

            // Helper para agregar mensajes al log (OPTIMIZADO con límite)
            const int MAX_LOG_LINES = 500;
            Action<string> LogDownload = (msg) =>
            {
                Action appendLog = () =>
                {
                    txtDownloadLog.AppendText($"[{DateTime.Now:HH:mm:ss}] {msg}{Environment.NewLine}");
                    
                    // Optimización: limitar líneas del log
                    var lines = txtDownloadLog.Lines;
                    if (lines.Length > MAX_LOG_LINES)
                    {
                        var newLines = lines.Skip(lines.Length - MAX_LOG_LINES).ToArray();
                        txtDownloadLog.Lines = newLines;
                        txtDownloadLog.SelectionStart = txtDownloadLog.Text.Length;
                        txtDownloadLog.ScrollToCaret();
                    }
                };
                
                if (txtDownloadLog.InvokeRequired)
                    SafeBeginInvoke(appendLog);
                else
                    appendLog();
            };

            // Panel inferior con estadísticas
            var bottomPanel = new Panel
            {
                Dock = DockStyle.Fill,
                BackColor = Color.FromArgb(30, 30, 30),
                Padding = new Padding(10)
            };

            var lblStats = new Label
            {
                Text = "Total: 0 archivos",
                AutoSize = true,
                Font = new Font("Segoe UI", 9),
                ForeColor = Color.LightGray,
                Location = new Point(10, 15)
            };
            bottomPanel.Controls.Add(lblStats);

            mainLayout.Controls.Add(bottomPanel, 0, 3);  // Fila 3: Stats
            mainLayout.SetColumnSpan(bottomPanel, 2);  // Ocupa 2 columnas

            downloadsForm.Controls.Add(mainLayout);

            // Registrar evento ItemChecked DESPUÉS de crear lblStats
            lvFiles.ItemChecked += (s, e) =>
            {
                int checkedCount = lvFiles.CheckedItems.Count;
                var downloadPath = txtDownloadDir?.Text ?? Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.MyDocuments), "SlskDown");
                int existingCount = 0;
                
                foreach (ListViewItem item in lvFiles.Items)
                {
                    var file = (AutoSearchFileResult)item.Tag;
                    var fullPath = GetDownloadPath(file.FileName, file.Author);
                    if (IsFileDownloaded(fullPath)) existingCount++;
                }
                
                lblStats.Text = $"Total: {lvFiles.Items.Count} archivos | Descargados: {existingCount} | Pendientes: {lvFiles.Items.Count - existingCount} | Seleccionados: {checkedCount}";
            };

            // Cargar datos con filtros (OPTIMIZADO)
            Action<string> loadData = (searchFilter) =>
            {
                lvFiles.BeginUpdate(); // Optimización: suspender redibujado
                try
                {
                    lvFiles.Items.Clear();
                    List<AutoSearchFileResult> files;
                    
                        files = autoSearchResults.ToList();
                    

                    var downloadPath = txtDownloadDir?.Text ?? Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.MyDocuments), "SlskDown");
                    
                    int existingCount = 0;
                    int pendingCount = 0;
                    var existsCache = new Dictionary<string, bool>(files.Count);

                    // Contadores adicionales para stats
                    int displayedCount = 0;
                    const int MAX_DISPLAY_ITEMS = 10000; // Límite para evitar problemas de rendimiento
                    
                    // OPTIMIZACIÓN: Cachear valores de filtros (evitar acceso a controles en loop)
                    bool filterDocs = chkOnlyDocs.Checked;
                    bool filterSpanish = chkOnlySpanish.Checked;
                    long minSizeBytes = minFileSizeKB * 1024L;
                    string searchText = string.IsNullOrEmpty(searchFilter) ? txtSearch.Text.Trim().ToLower() : searchFilter.Trim().ToLower();
                    bool hasSearch = !string.IsNullOrEmpty(searchText);
                    int filteredBySearch = 0;

                    // Una sola iteración optimizada
                    foreach (var file in files)
                    {
                        // Filtrar autores en blacklist (PRIMERO para máxima eficiencia)
                        if (IsAuthorBlacklisted(file.Author)) continue;
                        
                        // Aplicar filtros de contenido primero (más rápido)
                        if (filterDocs && !file.IsDocument) continue;
                        if (filterSpanish && !file.IsSpanish) continue;
                        
                        // Filtro de tamaño mínimo (comparar bytes directamente)
                        if (minSizeBytes > 0 && file.SizeBytes < minSizeBytes) continue;
                        
                        // Filtro de búsqueda (archivo, autor o usuario)
                        if (hasSearch)
                        {
                            bool matches = file.FileName.ToLower().Contains(searchText) ||
                                          file.Author.ToLower().Contains(searchText) ||
                                          file.Username.ToLower().Contains(searchText);
                            if (!matches)
                            {
                                filteredBySearch++;
                                continue;
                            }
                        }

                        // Verificar existencia (con cache)
                        var fullPath = GetDownloadPath(file.FileName, file.Author);
                        if (!existsCache.TryGetValue(fullPath, out bool fileExists))
                        {
                            fileExists = IsFileDownloaded(fullPath);
                            existsCache[fullPath] = fileExists;
                        }
                        
                        if (fileExists) existingCount++;
                        else pendingCount++;

                        string status = fileExists ? "Descargado" : "Pendiente";
                        var statusColor = fileExists ? Color.LightGreen : Color.LightGray;

                        // OPTIMIZACIÓN: Cachear extensión para no calcularla dos veces
                        string extension = Path.GetExtension(file.FileName).ToLower();
                        
                        var item = new ListViewItem(status) { ForeColor = statusColor, Tag = file };
                        item.SubItems.Add(file.Author);
                        item.SubItems.Add(file.FileName);
                        item.SubItems.Add(extension);
                        item.SubItems.Add(file.SizeReadable);
                        item.SubItems.Add(file.Username);
                        item.SubItems.Add(file.Directory);
                        item.SubItems.Add(file.IsSpanish ? "Sí" : "No");
                        item.SubItems.Add(file.IsDocument ? "Sí" : "No");
                        item.SubItems.Add(file.Timestamp.ToString("yyyy-MM-dd HH:mm:ss"));
                        
                        // Marcar como seleccionado si está pendiente (no descargado)
                        item.Checked = !fileExists;
                        
                        lvFiles.Items.Add(item);
                        displayedCount++;
                        
                        // Límite de visualización para evitar problemas de rendimiento
                        if (displayedCount >= MAX_DISPLAY_ITEMS)
                        {
                            // LogDownload se declara después, se mostrará en lblStats
                            break;
                        }
                    }

                    var totalFiles = files.Count;
                    var hiddenFiles = totalFiles - displayedCount;
                    var statsText = $"Mostrando: {displayedCount:N0}";
                    if (hiddenFiles > 0) statsText += $" ({hiddenFiles:N0} ocultos - usa filtros)";
                    statsText += $" | Descargados: {existingCount:N0} | Pendientes: {pendingCount:N0} | Seleccionados: 0";
                    lblStats.Text = statsText;
                    
                    // Actualizar label de resultados de búsqueda
                    if (hasSearch)
                    {
                        lblSearchResults.Text = filteredBySearch > 0 
                            ? $"({filteredBySearch} filtrados por búsqueda)" 
                            : "";
                    }
                    else
                    {
                        lblSearchResults.Text = "";
                    }
                    
                    updateGlobalStats();
                }
                finally
                {
                    lvFiles.EndUpdate(); // Optimización: reanudar redibujado
                }
            };

            loadData("");
            
            // Event handler para búsqueda en tiempo real con debounce
            txtSearch.TextChanged += (s, e) =>
            {
                searchDebounceTimer?.Dispose();
                searchDebounceTimer = new System.Threading.Timer(_ => 
                {
                    SafeInvoke(() => loadData(""));
                }, null, 300, Timeout.Infinite); // 300ms delay
            };
            LogDownload("Ventana de descargas iniciada");

            // Configurar event handlers que necesitaban LogDownload
            numSimultaneous.ValueChanged += (s, e) =>
            {
                maxSimultaneousDownloads = (int)numSimultaneous.Value;
                LogDownload($"Límite de descargas simultáneas: {maxSimultaneousDownloads}");
            };

            btnApplyConfig.Click += (s, e) =>
            {
                MessageBox.Show($"Configuración aplicada:\n\nDescargas simultáneas: {maxSimultaneousDownloads}", "Configuración", MessageBoxButtons.OK, MessageBoxIcon.Information);
                LogDownload($"Configuración aplicada: {maxSimultaneousDownloads} descargas simultáneas");
            };

            // Debounce timer para búsqueda (optimización)
            // Event handlers para filtros
            chkOnlyDocs.CheckedChanged += (s, e) => { loadData(""); LogDownload($"Filtro documentos: {(chkOnlyDocs.Checked ? "ON" : "OFF")}"); };
            chkOnlySpanish.CheckedChanged += (s, e) => { loadData(""); LogDownload($"Filtro español: {(chkOnlySpanish.Checked ? "ON" : "OFF")}"); };
            numMinSizeKB.ValueChanged += (s, e) => { loadData(""); LogDownload($"Tamaño mínimo: {numMinSizeKB.Value:N0} KB"); };

            // Menú contextual para ignorar autores
            var contextMenu = new ContextMenuStrip
            {
                BackColor = Color.FromArgb(40, 40, 40),
                ForeColor = Color.White
            };

            var menuIgnoreAuthor = new ToolStripMenuItem("Ignorar este autor");
            menuIgnoreAuthor.Click += (s, e) =>
            {
                if (lvFiles.SelectedItems.Count > 0)
                {
                    var selectedItem = lvFiles.SelectedItems[0];
                    var file = (AutoSearchFileResult)selectedItem.Tag;
                    
                    var result = MessageBox.Show(
                        $"¿Ignorar todos los archivos del autor '{file.Author}'?\n\nEsto agregará el autor a la blacklist y filtrará sus archivos en futuras búsquedas.",
                        "Ignorar Autor",
                        MessageBoxButtons.YesNo,
                        MessageBoxIcon.Question);
                    
                    if (result == DialogResult.Yes)
                    {
                        AddToBlacklist(file.Author);
                        
                        // Eliminar archivos del autor de autoSearchResults
                        
                            int removedCount = RemoveAllFromAutoSearchResults(f => 
                                f.Author.Equals(file.Author, StringComparison.OrdinalIgnoreCase));
                            LogDownload($"Eliminados {removedCount} archivos de {file.Author} de la memoria");
                        
                        
                        // Recargar grilla sin el autor ignorado
                        loadData("");
                        
                        // Guardar CSV actualizado sin el autor ignorado
                        SaveAutoResultsToCsv();
                        
                        ShowNotification("Autor Ignorado", 
                            $"'{file.Author}' agregado a la blacklist\n\nLa lista se ha actualizado automáticamente.", 
                            ToolTipIcon.Warning);
                        
                        LogDownload($"Autor '{file.Author}' agregado a blacklist y eliminado de la lista");
                        LogDownload($"CSV actualizado - autor eliminado del archivo");
                    }
                }
            };
            contextMenu.Items.Add(menuIgnoreAuthor);

            lvFiles.ContextMenuStrip = contextMenu;

            // Event handlers
            btnLoadAuthorsFile.Click += async (s, e) =>
            {
                try
                {
                    LogDownload("═══════════════════════════════════════════════════");
                    LogDownload("CARGA DE LISTA DE AUTORES");
                    LogDownload("═══════════════════════════════════════════════════");
                    LogDownload("Abriendo diálogo de selección de archivo...");
                    
                    var openDialog = new OpenFileDialog
                    {
                        Filter = "Archivos de texto (*.txt)|*.txt|Todos los archivos (*.*)|*.*",
                        Title = "Seleccionar archivo de autores",
                        InitialDirectory = !string.IsNullOrEmpty(lastAuthorsFilePath) ? Path.GetDirectoryName(lastAuthorsFilePath) : ""
                    };
                    
                    if (openDialog.ShowDialog() == DialogResult.OK)
                    {
                        LogDownload($"Archivo seleccionado: {openDialog.FileName}");
                        LogDownload($"Tamaño: {new FileInfo(openDialog.FileName).Length / 1024.0:F2} KB");
                        
                        lastVaciarAuthorsFilePath = openDialog.FileName;
                        // No guardar en configuración - Vaciar usa su propia ruta
                        LogDownload("Ruta cargada para Vaciar");
                        
                        // Cargar lista de autores
                        LogDownload("Leyendo archivo...");
                        authorsList = System.IO.File.ReadAllLines(openDialog.FileName)
                            .Where(line => !string.IsNullOrWhiteSpace(line))
                            .Select(line => line.Trim())
                            .ToList();
                        
                        currentAuthorIndex = 0;
                        
                        LogDownload($"{authorsList.Count} autores cargados en la lista");
                        LogDownload($"Usa el botón 'Comenzar' para iniciar la búsqueda");
                        LogDownload("═══════════════════════════════════════════════════");
                        
                        // Habilitar botón Siguiente
                        btnNextAuthor.Enabled = true;
                        btnNextAuthor.Text = $"Actualizar (1/{authorsList.Count})";
                    }
                    else
                    {
                        LogDownload("Selección de archivo cancelada por el usuario");
                    }
                }
                catch (Exception ex)
                {
                    LogDownload("═══════════════════════════════════════════════════");
                    LogDownload($"ERROR CRÍTICO: {ex.Message}");
                    LogDownload($"Stack trace: {ex.StackTrace}");
                    LogDownload("═══════════════════════════════════════════════════");
                    MessageBox.Show($"Error al cargar archivo: {ex.Message}", "Error", MessageBoxButtons.OK, MessageBoxIcon.Error);
                }
            };

            btnNextAuthor.Click += async (s, e) =>
            {
                try
                {
                    if (currentAuthorIndex >= authorsList.Count)
                    {
                        LogDownload("═══════════════════════════════════════════════════");
                        LogDownload("TODOS LOS AUTORES PROCESADOS");
                        LogDownload("═══════════════════════════════════════════════════");
                        btnNextAuthor.Enabled = false;
                        return;
                    }

                    string currentAuthor = authorsList[currentAuthorIndex];
                    
                    LogDownload("═══════════════════════════════════════════════════");
                    LogDownload($"BUSCANDO AUTOR {currentAuthorIndex + 1}/{authorsList.Count}");
                    LogDownload($"Autor: {currentAuthor}");
                    LogDownload("═══════════════════════════════════════════════════");

                    // Validar conexión
                    if (client == null || !client.State.HasFlag(SoulseekClientStates.Connected))
                    {
                        LogDownload("ERROR: No conectado a Soulseek");
                        MessageBox.Show("Debes estar conectado a Soulseek.\n\nConéctate desde la pestaña principal primero.", "No conectado", MessageBoxButtons.OK, MessageBoxIcon.Warning);
                        return;
                    }

                    // Limpiar resultados anteriores de la grilla
                    autoSearchResults = new System.Collections.Concurrent.ConcurrentBag<AutoSearchFileResult>();
                    loadData("");
                    LogDownload("Grilla limpiada");

                    // Buscar archivos del autor actual REPETIDAMENTE hasta que no haya nuevos
                    LogDownload($"Buscando archivos de '{currentAuthor}' (búsqueda exhaustiva)...");
                    var searchStart = DateTime.Now;
                    
                    int totalNewFiles = 0;
                    int searchIteration = 0;
                    int consecutiveEmptySearches = 0;
                    const int MAX_EMPTY_SEARCHES = 1; // Solo 1 búsqueda por autor para mayor velocidad
                    
                    var seenFiles = new HashSet<string>(5000); // Pre-allocar para ~5k archivos
                    
                    while (consecutiveEmptySearches < MAX_EMPTY_SEARCHES)
                    {
                        searchIteration++;
                        LogDownload($"Búsqueda #{searchIteration}...");
                        
                        var searchResponse = await client.SearchAsync(SearchQuery.FromText(currentAuthor));
                        int totalUsers = searchResponse.Responses.Count;
                        
                        // OPTIMIZACIÓN: Cachear DateTime.Now (costoso si se llama miles de veces)
                        var timestamp = DateTime.Now;
                        
                        // Batch processing: procesar archivos en lote antes del lock
                        var newFilesToAdd = new List<AutoSearchFileResult>(1000); // Pre-allocar
                        int newFilesThisIteration = 0;
                        
                        foreach (var response in searchResponse.Responses)
                        {
                            // Filtrar usuarios de blacklist
                            if (blacklist.Contains(response.Username))
                                continue;
                            
                            foreach (var file in response.Files)
                            {
                                // Optimizar construcción de fileKey (evitar boxing)
                                string fileKey = string.Concat(response.Username, "|", file.Filename, "|", file.Size.ToString());
                                
                                if (seenFiles.Contains(fileKey))
                                    continue; // Ya lo tenemos
                                
                                seenFiles.Add(fileKey);
                                
                                // OPTIMIZACIÓN: ToLowerInvariant es más rápido que ToLower
                                string filenameLower = file.Filename.ToLowerInvariant();
                                
                                // Usar IndexOf con StringComparison para mejor rendimiento
                                bool isSpanish = filenameLower.IndexOf("spanish", StringComparison.Ordinal) >= 0 || 
                                               filenameLower.IndexOf("español", StringComparison.Ordinal) >= 0 ||
                                               filenameLower.IndexOf("castellano", StringComparison.Ordinal) >= 0;
                                
                                bool isDocument = filenameLower.EndsWith(".pdf") ||
                                                filenameLower.EndsWith(".epub") ||
                                                filenameLower.EndsWith(".mobi");

                                // OPTIMIZACIÓN: Cachear operaciones de Path
                                string fileName = Path.GetFileName(file.Filename);
                                string directory = Path.GetDirectoryName(file.Filename) ?? "";

                                // Preparar objeto fuera del lock
                                newFilesToAdd.Add(new AutoSearchFileResult
                                {
                                    Author = currentAuthor,
                                    Username = response.Username,
                                    FileName = fileName,
                                    Directory = directory,
                                    SizeBytes = file.Size,
                                    SizeReadable = FormatFileSize(file.Size),
                                    IsSpanish = isSpanish,
                                    IsDocument = isDocument,
                                    Timestamp = timestamp  // Usar timestamp cacheado
                                });
                                newFilesThisIteration++;
                                totalNewFiles++;
                            }
                        }
                        
                        // OPTIMIZACIÓN: Un solo lock para agregar todos los archivos
                        if (newFilesToAdd.Count > 0)
                        {
                            
                                AddRangeToAutoSearchResults(newFilesToAdd);
                            
                        }
                        
                        LogDownload($"   {totalUsers} usuarios, {newFilesThisIteration} archivos nuevos");
                        
                        if (newFilesThisIteration == 0)
                        {
                            consecutiveEmptySearches++;
                            LogDownload($"   Sin resultados nuevos ({consecutiveEmptySearches}/{MAX_EMPTY_SEARCHES})");
                        }
                        else
                        {
                            consecutiveEmptySearches = 0; // Resetear contador
                            // OPTIMIZACIÓN: Actualizar grilla solo cada 2 iteraciones con resultados
                            if (searchIteration % 2 == 0)
                            {
                                loadData("");
                            }
                        }
                        
                        // Pequeña pausa entre búsquedas para no saturar
                        await Task.Delay(500);
                    }

                    var searchDuration = (DateTime.Now - searchStart).TotalSeconds;
                    LogDownload($"BÚSQUEDA COMPLETADA:");
                    LogDownload($"   • {searchIteration} búsquedas realizadas");
                    LogDownload($"   • {totalNewFiles} archivos únicos encontrados");
                    LogDownload($"   • Duración: {searchDuration:F1}s");
                    
                    // Actualizar grilla final
                    loadData("");
                    LogDownload("Grilla actualizada con todos los resultados");

                    // Avanzar al siguiente autor
                    currentAuthorIndex++;
                    
                    if (currentAuthorIndex < authorsList.Count)
                    {
                        btnNextAuthor.Text = $"Actualizar ({currentAuthorIndex + 1}/{authorsList.Count})";
                        LogDownload($"Listo para buscar siguiente autor");
                    }
                    else
                    {
                        btnNextAuthor.Text = "Completado";
                        btnNextAuthor.Enabled = false;
                        LogDownload("═══════════════════════════════════════════════════");
                        LogDownload("TODOS LOS AUTORES PROCESADOS");
                        LogDownload("═══════════════════════════════════════════════════");
                        
                        // Notificación de finalización
                        ShowNotification("Búsqueda Completada", 
                            $"Se procesaron {authorsList.Count} autores. Total archivos: {totalNewFiles}", 
                            ToolTipIcon.Info);
                    }
                    
                    LogDownload("═══════════════════════════════════════════════════");
                }
                catch (Exception ex)
                {
                    LogDownload($"ERROR: {ex.Message}");
                    MessageBox.Show($"Error al buscar autor: {ex.Message}", "Error", MessageBoxButtons.OK, MessageBoxIcon.Error);
                }
            };

            btnDownloadSelected.Click += async (s, e) =>
            {
                var checkedItems = lvFiles.CheckedItems.Cast<ListViewItem>().ToList();
                if (checkedItems.Count == 0)
                {
                    MessageBox.Show("Selecciona al menos un archivo para descargar", "Descargar", MessageBoxButtons.OK, MessageBoxIcon.Information);
                    return;
                }

                var downloadPath = txtDownloadDir?.Text ?? Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.MyDocuments), "SlskDown");
                
                // Verificar cuántos archivos ya existen
                int existingFiles = 0;
                int newFiles = 0;
                foreach (ListViewItem item in checkedItems)
                {
                    var file = (AutoSearchFileResult)item.Tag;
                    var fullPath = GetDownloadPath(file.FileName, file.Author);
                    if (IsFileDownloaded(fullPath))
                        existingFiles++;
                    else
                        newFiles++;
                }

                if (existingFiles > 0 && newFiles == 0)
                {
                    MessageBox.Show(
                        $"Todos los archivos seleccionados ({existingFiles}) ya existen.\n\nUsa el botón 'Redescargar' para descargarlos de nuevo.",
                        "Archivos existentes",
                        MessageBoxButtons.OK,
                        MessageBoxIcon.Information
                    );
                    LogDownload($"{existingFiles} archivo(s) ya descargado(s), omitidos");
                    return;
                }

                string message = newFiles == checkedItems.Count
                    ? $"¿Descargar {newFiles} archivo(s)?"
                    : $"¿Descargar {newFiles} archivo(s) nuevo(s)?\n({existingFiles} ya descargado(s) serán omitidos)";

                var result = MessageBox.Show(message, "Confirmar descarga", MessageBoxButtons.YesNo, MessageBoxIcon.Question);

                if (result == DialogResult.Yes)
                {
                    LogDownload("═══════════════════════════════════════════════════");
                    LogDownload("INICIANDO PROCESO DE DESCARGA");
                    LogDownload("═══════════════════════════════════════════════════");
                    LogDownload($"Estadísticas:");
                    LogDownload($"   • Archivos seleccionados: {checkedItems.Count:N0}");
                    LogDownload($"   • Archivos nuevos a descargar: {newFiles:N0}");
                    LogDownload($"   • Archivos ya descargados (omitidos): {existingFiles:N0}");
                    LogDownload($"Carpeta de destino: {downloadPath}");
                    LogDownload($"Hora de inicio: {DateTime.Now:HH:mm:ss}");
                    LogDownload("───────────────────────────────────────────────────");
                    
                    int downloaded = 0;
                    int skipped = 0;

                    // Crear directorio si no existe
                    if (!System.IO.Directory.Exists(downloadPath))
                    {
                        System.IO.Directory.CreateDirectory(downloadPath);
                        LogDownload($"Carpeta creada: {downloadPath}");
                    }

                    foreach (ListViewItem item in checkedItems)
                    {
                        var file = (AutoSearchFileResult)item.Tag;
                        var fullPath = GetDownloadPath(file.FileName, file.Author);
                        
                        if (IsFileDownloaded(fullPath))
                        {
                            LogDownload($"  Omitido (ya existe): {file.FileName}");
                            skipped++;
                        }
                        else
                        {
                            LogDownload($"  Agregando a cola: {file.FileName} ({file.SizeReadable})");
                            AddToDownloadQueue(file, fullPath, item);
                            downloaded++;
                        }
                    }
                    
                    LogDownload("───────────────────────────────────────────────────");
                    LogDownload($"PROCESO COMPLETADO");
                    LogDownload($"Resumen:");
                    LogDownload($"   • Agregados a cola: {downloaded:N0}");
                    LogDownload($"   • Omitidos (ya existen): {skipped:N0}");
                    LogDownload($"   • Total procesados: {checkedItems.Count:N0}");
                    LogDownload($"Hora de finalización: {DateTime.Now:HH:mm:ss}");
                    LogDownload("═══════════════════════════════════════════════════");
                    LogDownload($"Las descargas comenzarán automáticamente");
                    LogDownload($"Límite de descargas simultáneas: {maxSimultaneousDownloads}");
                    LogDownload("═══════════════════════════════════════════════════");
                    
                    await Task.Delay(500);
                    loadData(""); // Actualizar lista
                }
            };

            btnRedownload.Click += async (s, e) =>
            {
                var checkedItems = lvFiles.CheckedItems.Cast<ListViewItem>().ToList();
                if (checkedItems.Count == 0)
                {
                    MessageBox.Show("Selecciona al menos un archivo para redescargar", "Redescargar", MessageBoxButtons.OK, MessageBoxIcon.Information);
                    return;
                }

                var result = MessageBox.Show(
                    $"¿Redescargar {checkedItems.Count} archivo(s)?\n\nEsto sobrescribirá los archivos existentes.",
                    "Confirmar redescargar",
                    MessageBoxButtons.YesNo,
                    MessageBoxIcon.Warning
                );

                if (result == DialogResult.Yes)
                {
                    var downloadPath = txtDownloadDir?.Text ?? Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.MyDocuments), "SlskDown");
                    
                    if (!System.IO.Directory.Exists(downloadPath))
                    {
                        System.IO.Directory.CreateDirectory(downloadPath);
                    }

                    LogDownload($"Recomenzando descarga de {checkedItems.Count} archivo(s)...");
                    foreach (ListViewItem item in checkedItems)
                    {
                        var file = (AutoSearchFileResult)item.Tag;
                        var fullPath = GetDownloadPath(file.FileName, file.Author);
                        
                        // Eliminar archivo existente si existe
                        if (IsFileDownloaded(fullPath))
                        {
                            try
                            {
                                System.IO.File.Delete(fullPath);
                                LogDownload($"  Eliminado archivo existente: {file.FileName}");
                            }
                            catch (Exception ex)
                            {
                                LogDownload($"  No se pudo eliminar {file.FileName}: {ex.Message}");
                            }
                        }
                        
                        LogDownload($"  Agregando a cola: {file.FileName} ({file.SizeReadable})");
                        AddToDownloadQueue(file, fullPath, item, true);
                    }
                    LogDownload($"{checkedItems.Count} descarga(s) reiniciada(s)");
                    await Task.Delay(500);
                    loadData(""); // Actualizar lista
                }
            };

            btnStopDownload.Click += (s, e) =>
            {
                PauseAllDownloads();
                LogDownload("Todas las descargas pausadas");
            };

            btnResumeDownload.Click += async (s, e) =>
            {
                await ResumeAllDownloads();
                LogDownload("Descargas reanudadas");
            };

            btnOpenFolder.Click += (s, e) =>
            {
                try
                {
                    var downloadPath = txtDownloadDir?.Text ?? Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.MyDocuments), "SlskDown");
                    if (System.IO.Directory.Exists(downloadPath))
                    {
                        Process.Start(new ProcessStartInfo { FileName = downloadPath, UseShellExecute = true });
                        LogDownload($"Abriendo carpeta: {downloadPath}");
                    }
                    else
                    {
                        MessageBox.Show($"La carpeta no existe: {downloadPath}", "Abrir Carpeta", MessageBoxButtons.OK, MessageBoxIcon.Warning);
                        LogDownload($"Carpeta no encontrada: {downloadPath}");
                    }
                }
                catch (Exception ex)
                {
                    LogDownload($"Error al abrir carpeta: {ex.Message}");
                }
            };

            btnExport.Click += (s, e) =>
            {
                var exportForm = new Form
                {
                    Text = "Exportar Resultados",
                    Size = new Size(400, 250),
                    StartPosition = FormStartPosition.CenterParent,
                    BackColor = Color.FromArgb(30, 30, 30),
                    FormBorderStyle = FormBorderStyle.FixedDialog,
                    MaximizeBox = false,
                    MinimizeBox = false
                };

                var lblTitle = new Label
                {
                    Text = "Selecciona formato de exportación:",
                    Location = new Point(20, 20),
                    AutoSize = true,
                    ForeColor = Color.White,
                    Font = new Font("Segoe UI", 10, FontStyle.Bold)
                };
                exportForm.Controls.Add(lblTitle);

                var btnExportHTML = CreateButton("HTML Interactivo", Color.FromArgb(0, 120, 215));
                btnExportHTML.Location = new Point(20, 60);
                btnExportHTML.Width = 340;
                btnExportHTML.Click += (se, ev) =>
                {
                    ExportToHTML(lvFiles);
                    LogDownload("Exportado a HTML");
                    exportForm.Close();
                };
                exportForm.Controls.Add(btnExportHTML);

                var btnExportJSON = CreateButton("JSON", Color.FromArgb(100, 60, 150));
                btnExportJSON.Location = new Point(20, 100);
                btnExportJSON.Width = 340;
                btnExportJSON.Click += (se, ev) =>
                {
                    SaveAutoResultsToJson();
                    LogDownload("Exportado a JSON");
                    MessageBox.Show($"Exportado a:\n{autoSearchResultsJsonPath}", "Exportar JSON", MessageBoxButtons.OK, MessageBoxIcon.Information);
                    exportForm.Close();
                };
                exportForm.Controls.Add(btnExportJSON);

                var btnExportCSV = CreateButton("CSV (Excel)", Color.FromArgb(0, 150, 0));
                btnExportCSV.Location = new Point(20, 140);
                btnExportCSV.Width = 340;
                btnExportCSV.Click += (se, ev) =>
                {
                    SaveAutoResultsToCsv();
                    LogDownload("Exportado a CSV");
                    MessageBox.Show($"Exportado a:\n{autoResultsCsvPath}", "Exportar CSV", MessageBoxButtons.OK, MessageBoxIcon.Information);
                    exportForm.Close();
                };
                exportForm.Controls.Add(btnExportCSV);

                var btnCancelExport = CreateButton("Cancelar", Color.FromArgb(150, 0, 0));
                btnCancelExport.Location = new Point(20, 180);
                btnCancelExport.Width = 340;
                btnCancelExport.Click += (se, ev) => exportForm.Close();
                exportForm.Controls.Add(btnCancelExport);

                exportForm.ShowDialog(downloadsForm);
            };

            btnClose.Click += (s, e) =>
            {
                LogDownload("Cerrando ventana de descargas");
                downloadsForm.Close();
            };

            downloadsForm.Show();
        }

        private void LoadCarbarherCache(Action<string> log = null)
        {
            if (carbarherCacheLoaded)
                return;

            carbarherFilesCache.Clear();
            
            // Intentar cargar desde caché en disco
            if (System.IO.File.Exists(calibreCacheFile))
            {
                try
                {
                    log?.Invoke("Cargando caché cbh comprimido desde disco...");
                    var sw = System.Diagnostics.Stopwatch.StartNew();
                    
                    // Descomprimir con GZip y leer líneas
                    using (var fileStream = new FileStream(calibreCacheFile, FileMode.Open, FileAccess.Read))
                    using (var gzipStream = new GZipStream(fileStream, CompressionMode.Decompress))
                    using (var reader = new StreamReader(gzipStream, Encoding.UTF8))
                    {
                        string line;
                        while ((line = reader.ReadLine()) != null)
                        {
                            if (!string.IsNullOrWhiteSpace(line))
                                carbarherFilesCache.Add(line.Trim());
                        }
                    }
                    
                    sw.Stop();
                    carbarherCacheLoaded = true;
                    log?.Invoke($"Caché cbh cargado: {carbarherFilesCache.Count:N0} archivos en {sw.ElapsedMilliseconds}ms");
                    return;
                }
                catch (Exception ex)
                {
                    log?.Invoke($"Error leyendo caché: {ex.Message}. Regenerando...");
                }
            }
            
            // Si no hay caché o falló, escanear carpeta
            if (!System.IO.Directory.Exists(carbarherPath))
            {
                log?.Invoke($"Carpeta cbh no encontrada: {carbarherPath}");
                carbarherCacheLoaded = true;
                return;
            }

            try
            {
                log?.Invoke("Iniciando escaneo carpeta cbh...");
                log?.Invoke($"   Ruta: {carbarherPath}");
                var sw = System.Diagnostics.Stopwatch.StartNew();
                
                // Usar EnumerateFiles para reducir uso de memoria (streaming)
                log?.Invoke("Enumerando archivos...");
                var enumerationStart = System.Diagnostics.Stopwatch.StartNew();
                var filesEnumerable = System.IO.Directory.EnumerateFiles(carbarherPath, "*.*", SearchOption.AllDirectories);
                var filesList = filesEnumerable.ToList(); // Materializar para contar
                enumerationStart.Stop();
                
                log?.Invoke($"Enumeración completada: {filesList.Count:N0} archivos encontrados en {enumerationStart.ElapsedMilliseconds}ms");
                log?.Invoke("Procesando archivos en paralelo...");
                
                var processingStart = System.Diagnostics.Stopwatch.StartNew();
                int processedCount = 0;
                int lastReportedCount = 0;
                var lockObj = new object();
                
                // Procesar en paralelo con PLINQ para mejor rendimiento
                var fileNames = filesList
                    .AsParallel()
                    .WithDegreeOfParallelism(Environment.ProcessorCount)
                    .Select((filePath, index) =>
                    {
                        var fileName = Path.GetFileName(filePath);
                        
                        // Reportar progreso thread-safe cada 1000 archivos
                        int currentCount;
                        lock (lockObj)
                        {
                            processedCount++;
                            currentCount = processedCount;
                        }
                        
                        if (currentCount - lastReportedCount >= 1000)
                        {
                            lock (lockObj)
                            {
                                if (currentCount - lastReportedCount >= 1000)
                                {
                                    var elapsed = processingStart.ElapsedMilliseconds;
                                    var rate = currentCount / (elapsed / 1000.0);
                                    var progress = (currentCount * 100.0) / filesList.Count;
                                    log?.Invoke($"   {currentCount:N0}/{filesList.Count:N0} ({progress:F1}%) - {rate:F0} archivos/seg");
                                    lastReportedCount = currentCount;
                                }
                            }
                        }
                        
                        return fileName;
                    })
                    .ToList();
                
                // Agregar todos los nombres al HashSet de una vez
                foreach (var fileName in fileNames)
                {
                    carbarherFilesCache.Add(fileName);
                }
                
                processingStart.Stop();
                sw.Stop();
                carbarherCacheLoaded = true;
                
                // Estadísticas finales
                log?.Invoke($"Procesamiento completado:");
                log?.Invoke($"   • Total archivos: {carbarherFilesCache.Count:N0}");
                log?.Invoke($"   • Tiempo enumeración: {enumerationStart.ElapsedMilliseconds:N0}ms");
                log?.Invoke($"   • Tiempo procesamiento: {processingStart.ElapsedMilliseconds:N0}ms");
                log?.Invoke($"   • Tiempo total: {sw.ElapsedMilliseconds:N0}ms ({sw.Elapsed.TotalSeconds:F1}s)");
                log?.Invoke($"   • Velocidad promedio: {(carbarherFilesCache.Count / sw.Elapsed.TotalSeconds):F0} archivos/seg");
                
                // Guardar caché en disco para próximas sesiones
                SaveCalibreCacheToDisk(log);
            }
            catch (Exception ex)
            {
                log?.Invoke($"Error cargando caché cbh: {ex.Message}");
                carbarherCacheLoaded = true;
            }
        }

        private void SaveCalibreCacheToDisk(Action<string> log = null)
        {
            try
            {
                log?.Invoke("Guardando caché comprimido en disco...");
                var sw = System.Diagnostics.Stopwatch.StartNew();
                
                // Comprimir con GZip para reducir tamaño
                using (var fileStream = new FileStream(calibreCacheFile, FileMode.Create, FileAccess.Write))
                using (var gzipStream = new GZipStream(fileStream, CompressionLevel.Optimal))
                using (var writer = new StreamWriter(gzipStream, Encoding.UTF8))
                {
                    foreach (var file in carbarherFilesCache)
                    {
                        writer.WriteLine(file);
                    }
                }
                
                sw.Stop();
                var fileInfo = new FileInfo(calibreCacheFile);
                var sizeKB = fileInfo.Length / 1024.0;
                log?.Invoke($"Caché guardado: {calibreCacheFile} ({sizeKB:F1} KB, {sw.ElapsedMilliseconds}ms)");
            }
            catch (Exception ex)
            {
                log?.Invoke($"No se pudo guardar caché: {ex.Message}");
            }
        }

        private void CreateFilesTab(Panel parent)
        {
            parent.BackColor = Color.FromArgb(30, 30, 30);
            
            var mainLayout = new TableLayoutPanel
            {
                Dock = DockStyle.Fill,
                ColumnCount = 2,
                RowCount = 3,
                Padding = new Padding(10),
                BackColor = Color.FromArgb(30, 30, 30)
            };
            mainLayout.ColumnStyles.Add(new ColumnStyle(SizeType.Percent, 50));
            mainLayout.ColumnStyles.Add(new ColumnStyle(SizeType.Percent, 50));
            mainLayout.RowStyles.Add(new RowStyle(SizeType.AutoSize)); // AutoSize para botones y filtros
            mainLayout.RowStyles.Add(new RowStyle(SizeType.Percent, 100));
            mainLayout.RowStyles.Add(new RowStyle(SizeType.AutoSize)); // AutoSize para stats

            // Variables para navegación autor por autor
            int currentAuthorIndex = 0;
            List<string> authorsList = new List<string>();
            
            // Panel superior izquierdo con controles de archivos
            var topLeftPanel = new FlowLayoutPanel
            {
                Dock = DockStyle.Fill,
                FlowDirection = FlowDirection.LeftToRight,
                WrapContents = true,
                AutoSize = true,
                AutoSizeMode = AutoSizeMode.GrowAndShrink,
                BackColor = Color.FromArgb(30, 30, 30),
                Padding = new Padding(5, 8, 5, 8)
            };

            // Botones con estilo moderno y consistente
            var btnNextAuthor = CreateButton("Actualizar", Color.FromArgb(0, 150, 215));
            var btnSelectAll = CreateButton("Todos", Color.FromArgb(70, 130, 180));
            var btnDeselectAll = CreateButton("Ninguno", Color.FromArgb(100, 100, 100));
            var btnDownloadSelected = CreateButton("Descargar", Color.FromArgb(0, 150, 0));
            var btnRedownload = CreateButton("Reintentar", Color.FromArgb(200, 100, 0));
            var btnStopDownload = CreateButton("Detener", Color.FromArgb(150, 100, 0));
            var btnResumeDownload = CreateButton("Continuar", Color.FromArgb(0, 150, 0));
            var btnOpenFolder = CreateButton("Carpeta", Color.FromArgb(60, 120, 60));
            var btnVerifyIntegrity = CreateButton("Verificar", Color.FromArgb(180, 50, 50));
            var btnDashboard = CreateButton("Dashboard", Color.FromArgb(50, 150, 200));

            // Agregar tooltips a botones
            AddTooltip(btnNextAuthor, "Actualiza la lista de archivos escaneando nuevamente la carpeta de descargas");
            AddTooltip(btnSelectAll, "Selecciona todos los archivos de la lista actual");
            AddTooltip(btnDeselectAll, "Deselecciona todos los archivos marcados");
            AddTooltip(btnDownloadSelected, "Agrega los archivos seleccionados a la cola de descargas");
            AddTooltip(btnRedownload, "Reintenta descargar los archivos que fallaron anteriormente");
            AddTooltip(btnStopDownload, "Detiene todas las descargas activas manteniendo el progreso");
            AddTooltip(btnResumeDownload, "Reanuda las descargas que fueron detenidas");
            AddTooltip(btnOpenFolder, "Abre la carpeta de descargas en el explorador de Windows");
            AddTooltip(btnVerifyIntegrity, "Verifica la integridad de los archivos descargados detectando corrupción");
            AddTooltip(btnDashboard, "Muestra estadísticas detalladas de descargas y archivos");

            // Ajustar tamaño de botones para que quepan mejor
            var buttons = new[] { btnNextAuthor, btnSelectAll, btnDeselectAll, btnDownloadSelected, btnRedownload, btnStopDownload, btnResumeDownload, btnOpenFolder, btnVerifyIntegrity, btnDashboard };
            foreach (var btn in buttons) { btn.Size = new Size(100, 30); btn.Font = new Font("Segoe UI", 8, FontStyle.Bold); btn.Margin = new Padding(0, 0, 4, 4); }
            
            foreach (var btn in buttons) topLeftPanel.Controls.Add(btn);

            // Panel de filtros (segunda línea del flow)
            var filterPanel = new FlowLayoutPanel { AutoSize = true, FlowDirection = FlowDirection.LeftToRight, WrapContents = false, Margin = new Padding(0, 5, 0, 0) };

            var lblSearchVaciar = new Label { Text = "Buscar:", AutoSize = true, ForeColor = Color.White, Font = new Font("Segoe UI", 9), Margin = new Padding(0, 6, 4, 0) };
            var txtSearchVaciar = new TextBox { Width = 120, Height = 25, BackColor = Color.FromArgb(50, 50, 50), ForeColor = Color.White, Font = new Font("Segoe UI", 9), PlaceholderText = "Filtrar...", Margin = new Padding(0, 2, 10, 0) };
            AddTooltip(txtSearchVaciar, "Filtra la lista de archivos escribiendo parte del nombre del autor o archivo");
            
            var lblMinSize = new Label { Text = "Min KB:", AutoSize = true, ForeColor = Color.White, Font = new Font("Segoe UI", 9), Margin = new Padding(0, 6, 4, 0) };
            var numMinSizeKB = new NumericUpDown { Width = 70, Height = 25, Minimum = 0, Maximum = 1000000, Value = 0, Increment = 100, BackColor = Color.FromArgb(50, 50, 50), ForeColor = Color.White, Font = new Font("Segoe UI", 9) };
            AddTooltip(numMinSizeKB, "Filtra archivos por tamaño mínimo en KB. Útil para excluir archivos muy pequeños");

            filterPanel.Controls.Add(lblSearchVaciar);
            filterPanel.Controls.Add(txtSearchVaciar);
            filterPanel.Controls.Add(lblMinSize);
            filterPanel.Controls.Add(numMinSizeKB);
            topLeftPanel.Controls.Add(filterPanel);
            
            mainLayout.Controls.Add(topLeftPanel, 0, 0);

            // Panel superior derecho - Título Log
            var topRightPanel = new FlowLayoutPanel { Dock = DockStyle.Fill, FlowDirection = FlowDirection.LeftToRight, BackColor = Color.FromArgb(30, 30, 30), Padding = new Padding(5, 5, 0, 0) };
            var lblLogTitle = new Label { Text = "LOG DE DESCARGAS", AutoSize = true, Font = new Font("Segoe UI", 10, FontStyle.Bold), ForeColor = Color.FromArgb(0, 120, 215), Margin = new Padding(0, 8, 0, 0) };
            topRightPanel.Controls.Add(lblLogTitle);
            mainLayout.Controls.Add(topRightPanel, 1, 0);

            // Panel para el log de descargas (ocupa todo el espacio restante)
            var logContainer = new Panel
            {
                Dock = DockStyle.Fill,
                BackColor = Color.FromArgb(20, 20, 20),
                Padding = new Padding(2)
            };
            topRightPanel.Controls.Add(logContainer);

            mainLayout.Controls.Add(topRightPanel, 1, 0);
            mainLayout.SetRowSpan(topRightPanel, 2);  // Ocupa filas 0 y 1 (botones + grilla)

            SafeLog( "CreateVaciarTab: Creando gridContainer\n");
            // Container para grilla
            var gridContainer = new Panel
            {
                Dock = DockStyle.Fill,
                BackColor = Color.FromArgb(30, 30, 30)
            };
            SafeLog( "CreateVaciarTab: gridContainer creado\n");

            SafeLog( "CreateVaciarTab: Creando ListView\n");
            // ListView para mostrar autores (igual que en Automático)
            lvVaciarAuthors = new ListView
            {
                Dock = DockStyle.Fill,
                View = View.Details,
                FullRowSelect = true,
                GridLines = true,
                CheckBoxes = true,
                VirtualMode = false,  // Explícitamente desactivar VirtualMode
                BackColor = Color.FromArgb(30, 30, 30),
                ForeColor = Color.White,
                Font = new Font("Segoe UI", 9),
                HeaderStyle = ColumnHeaderStyle.Clickable,
                HoverSelection = false
            };
            SafeLog( "CreateVaciarTab: ListView creado\n");

            SafeLog( "CreateVaciarTab: Agregando columnas\n");
            lvVaciarAuthors.Columns.Add("Autor", 150);
            lvVaciarAuthors.Columns.Add("Pendientes", 70);
            lvVaciarAuthors.Columns.Add("Descargados", 80);
            lvVaciarAuthors.Columns.Add("Tamaño Total", 90);
            lvVaciarAuthors.Columns.Add("% Completo", 80);
            lvVaciarAuthors.Columns.Add("Proveedores", 85);
            lvVaciarAuthors.Columns.Add("Última Desc.", 100);
            SafeLog( "CreateVaciarTab: Columnas agregadas\n");

            // Variables para ordenamiento
            int sortColumnIndex = -1;
            bool sortAscending = true;

            // Helper para actualizar encabezados con indicadores visuales
            Action<ListView, int, bool> UpdateColumnHeaders = (lv, sortCol, ascending) =>
            {
                string[] columnNames = { "Autor", "Pendientes", "Descargados", "Tamaño Total", "% Completo", "Proveedores", "Última Desc." };
                for (int i = 0; i < lv.Columns.Count; i++)
                {
                    string header = columnNames[i];
                    if (i == sortCol)
                    {
                        header += ascending ? " ▲" : " ▼";
                    }
                    lv.Columns[i].Text = header;
                }
            };

            SafeLog( "CreateVaciarTab: Registrando ColumnClick\n");
            // Event handler para ordenar al hacer clic en columnas
            lvVaciarAuthors.ColumnClick += (s, e) =>
            {
                if (e.Column == sortColumnIndex)
                {
                    sortAscending = !sortAscending;
                }
                else
                {
                    sortColumnIndex = e.Column;
                    sortAscending = true;
                }

                // Ordenar items
                var items = lvVaciarAuthors.Items.Cast<ListViewItem>().ToList();
                items.Sort((a, b) =>
                {
                    int result = 0;
                    switch (sortColumnIndex)
                    {
                        case 0: // Autor
                            result = string.Compare(a.Text, b.Text, StringComparison.OrdinalIgnoreCase);
                            break;
                        case 1: // Archivos (número)
                            result = int.Parse(a.SubItems[1].Text).CompareTo(int.Parse(b.SubItems[1].Text));
                            break;
                        case 2: // Estado
                            result = string.Compare(a.SubItems[2].Text, b.SubItems[2].Text, StringComparison.OrdinalIgnoreCase);
                            break;
                    }
                    return sortAscending ? result : -result;
                });

                lvVaciarAuthors.BeginUpdate();
                lvVaciarAuthors.Items.Clear();
                lvVaciarAuthors.Items.AddRange(items.ToArray());
                lvVaciarAuthors.EndUpdate();

                UpdateColumnHeaders(lvVaciarAuthors, sortColumnIndex, sortAscending);
            };
            SafeLog( "CreateVaciarTab: ColumnClick registrado\n");

            // Click izquierdo alterna selección directamente
            lvVaciarAuthors.MouseClick += (s, e) =>
            {
                if (e.Button == MouseButtons.Left)
                {
                    var hitTest = lvVaciarAuthors.HitTest(e.Location);
                    if (hitTest.Item != null)
                    {
                        hitTest.Item.Checked = !hitTest.Item.Checked;
                        Log($"[Vaciar] Autor '{hitTest.Item.Text}' {(hitTest.Item.Checked ? "seleccionado" : "deseleccionado")}");
                    }
                }
            };

            SafeLog( "CreateVaciarTab: Agregando controles al layout\n");
            gridContainer.Controls.Add(lvVaciarAuthors);
            mainLayout.Controls.Add(gridContainer, 0, 1);
            SafeLog( "CreateVaciarTab: Controles agregados\n");

            SafeLog( "CreateVaciarTab: Creando txtDownloadLog\n");
            // TextBox de log en el lado derecho
            var txtDownloadLog = new TextBox
            {
                Dock = DockStyle.Fill,
                Multiline = true,
                ReadOnly = true,
                BackColor = Color.FromArgb(20, 20, 20),
                ForeColor = Color.LightGray,
                Font = new Font("Consolas", 8),
                ScrollBars = ScrollBars.Both,
                WordWrap = false
            };
            logContainer.Controls.Add(txtDownloadLog);
            SafeLog( "CreateVaciarTab: txtDownloadLog agregado\n");

            // Helper para agregar mensajes al log
            SafeLog( "CreateVaciarTab: Definiendo LogDownload\n");
            const int MAX_LOG_LINES = 500;
            Action<string> LogDownload = (msg) =>
            {
                Action appendLog = () =>
                {
                    txtDownloadLog.AppendText($"[{DateTime.Now:HH:mm:ss}] {msg}{Environment.NewLine}");
                    
                    var lines = txtDownloadLog.Lines;
                    if (lines.Length > MAX_LOG_LINES)
                    {
                        var newLines = lines.Skip(lines.Length - MAX_LOG_LINES).ToArray();
                        txtDownloadLog.Lines = newLines;
                        txtDownloadLog.SelectionStart = txtDownloadLog.Text.Length;
                        txtDownloadLog.ScrollToCaret();
                    }
                };
                
                try
                {
                    if (txtDownloadLog.InvokeRequired)
                        txtDownloadLog.Invoke(appendLog);
                    else
                        appendLog();
                }
                catch (ObjectDisposedException) { }
                catch (InvalidOperationException) { }
            };
            SafeLog( "CreateVaciarTab: LogDownload definido\n");

            SafeLog( "CreateVaciarTab: Creando bottomPanel\n");
            // Panel inferior con estadísticas
            var bottomPanel = new Panel
            {
                Dock = DockStyle.Fill,
                BackColor = Color.FromArgb(30, 30, 30),
                Padding = new Padding(5)
            };

            var lblStats = new Label
            {
                Text = "Total: 0 archivos",
                Dock = DockStyle.Fill,
                Font = new Font("Segoe UI", 10, FontStyle.Bold),
                ForeColor = Color.White,
                TextAlign = ContentAlignment.MiddleLeft,
                Padding = new Padding(10, 0, 0, 0)
            };
            bottomPanel.Controls.Add(lblStats);
            
            // Panel de estadísticas en tiempo real (lado derecho)
            lblRealtimeStats = new Label
            {
                Text = "Estadísticas: Esperando...",
                Dock = DockStyle.Right,
                Font = new Font("Segoe UI", 9),
                ForeColor = Color.LightGray,
                TextAlign = ContentAlignment.MiddleRight,
                AutoSize = true,
                Padding = new Padding(0, 0, 10, 0)
            };
            bottomPanel.Controls.Add(lblRealtimeStats);
            
            // Timer para actualizar estadísticas cada segundo
            if (statsUpdateTimer == null)
            {
                statsUpdateTimer = new System.Windows.Forms.Timer();
                statsUpdateTimer.Interval = 1000; // 1 segundo
                statsUpdateTimer.Tick += (s, e) => UpdateRealtimeStats();
                statsUpdateTimer.Start();
            }
            
            SafeLog( "CreateVaciarTab: lblStats agregado\n");

            mainLayout.Controls.Add(bottomPanel, 0, 2);
            mainLayout.SetColumnSpan(bottomPanel, 2);
            SafeLog( "CreateVaciarTab: bottomPanel agregado\n");

            SafeLog( "CreateVaciarTab: Definiendo loadData\n");
            // Cargar datos con filtros (OPTIMIZADO)
            Action<string> loadData = (filterText) =>
            {
                lvVaciarAuthors.BeginUpdate();
                try
                {
                    lvVaciarAuthors.Items.Clear();

                    // Si filteredAuthorsData está vacía, llenarla desde autoSearchResults
                    if (filteredAuthorsData.Count == 0)
                    {
                        
                            if (autoSearchResults.Count > 0)
                            {
                                // Agrupar TODOS los autores primero
                                var authorGroups = autoSearchResults
                                    .GroupBy(f => f.Author)
                                    .Select(g =>
                                    {
                                        var allFiles = g.ToList();
                                        var uniqueFiles = allFiles
                                            .GroupBy(f => f.FileName, StringComparer.OrdinalIgnoreCase)
                                            .Select(fg => fg.First())
                                            .ToList();
                                        
                                        // Calcular archivos descargados
                                        var downloadedFiles = uniqueFiles
                                            .Where(f => IsFileDownloaded(GetDownloadPath(f.FileName, f.Author)))
                                            .ToList();
                                        
                                        // Calcular archivos pendientes
                                        var pendingFiles = uniqueFiles
                                            .Where(f => !carbarherCacheLoaded || !carbarherFilesCache.Contains(f.FileName))
                                            .Where(f => !IsAlreadyDownloaded(f.FileName, "", 0))
                                            .ToList();
                                        
                                        // Calcular tamaños
                                        long totalSize = uniqueFiles.Sum(f => f.SizeBytes);
                                        long downloadedSize = downloadedFiles.Sum(f => f.SizeBytes);
                                        
                                        // Contar proveedores únicos
                                        int providers = allFiles.Select(f => f.Username).Distinct().Count();
                                        
                                        // Obtener última fecha de descarga
                                        DateTime? lastDownload = null;
                                        try
                                        {
                                            var authorFolder = Path.Combine(downloadDir, g.Key);
                                            if (System.IO.Directory.Exists(authorFolder))
                                            {
                                                var files = System.IO.Directory.GetFiles(authorFolder);
                                                if (files.Length > 0)
                                                {
                                                    lastDownload = files.Max(f => System.IO.File.GetLastWriteTime(f));
                                                }
                                            }
                                        }
                                        catch { }
                                        
                                        return new AuthorData
                                        {
                                            Name = g.Key,
                                            FilesCount = pendingFiles.Count,
                                            DownloadedCount = downloadedFiles.Count,
                                            TotalSizeBytes = totalSize,
                                            DownloadedSizeBytes = downloadedSize,
                                            ProvidersCount = providers,
                                            LastDownloadDate = lastDownload,
                                            Status = "Listo",
                                            ForeColor = Color.White,
                                            IsChecked = false
                                        };
                                    })
                                    .ToList();
                                
                                filteredAuthorsData.Clear();
                                filteredAuthorsData.AddRange(authorGroups);
                                
                                var authorsWithFiles = authorGroups.Count(a => a.FilesCount > 0);
                                var pendingFiles = authorGroups.Sum(a => a.FilesCount);
                                LogDownload($"Cargados {filteredAuthorsData.Count:N0} autores ({authorsWithFiles:N0} con archivos pendientes, {pendingFiles:N0} archivos totales)");
                            }
                        
                    }

                    // Reutilizar los datos filtrados de la pestaña Automático
                    var authorsToShow = filteredAuthorsData.AsEnumerable();
                    
                    // Aplicar filtro de búsqueda si hay texto
                    if (!string.IsNullOrWhiteSpace(filterText))
                    {
                        var filter = filterText.ToLowerInvariant();
                        authorsToShow = authorsToShow.Where(a => a.Name.ToLowerInvariant().Contains(filter));
                    }
                    
                    var items = authorsToShow
                        .OrderBy(a => a.Name)
                        .Select(author =>
                        {
                            var item = new ListViewItem(author.Name)
                            {
                                ForeColor = author.ForeColor,
                                Checked = author.IsChecked,
                                Tag = author
                            };
                            
                            // Pendientes
                            item.SubItems.Add(author.FilesCount.ToString());
                            
                            // Descargados
                            item.SubItems.Add(author.DownloadedCount.ToString());
                            
                            // Tamaño Total
                            item.SubItems.Add(FormatFileSize(author.TotalSizeBytes));
                            
                            // % Completo
                            int totalFiles = author.FilesCount + author.DownloadedCount;
                            double percentage = totalFiles > 0 ? (author.DownloadedCount * 100.0 / totalFiles) : 0;
                            item.SubItems.Add($"{percentage:F1}%");
                            
                            // Proveedores
                            item.SubItems.Add(author.ProvidersCount.ToString());
                            
                            // Última Descarga
                            string lastDownload = author.LastDownloadDate.HasValue 
                                ? author.LastDownloadDate.Value.ToString("dd/MM/yy HH:mm")
                                : "-";
                            item.SubItems.Add(lastDownload);
                            
                            return item;
                        })
                        .ToArray();

                    lvVaciarAuthors.Items.AddRange(items);

                    int totalAuthors = filteredAuthorsData.Count;
                    int totalFiles = filteredAuthorsData.Sum(a => a.FilesCount);
                    lblStats.Text = $"Autores: {totalAuthors:N0} | Total archivos: {totalFiles:N0}";
                }
                finally
                {
                    lvVaciarAuthors.EndUpdate();
                }
            };

            // Refrescar grilla cuando cambia estado en Automático
            vaciarGridRefresher = () => loadData("");

            Action loadDataLegacy = () =>
            {
                lvVaciarAuthors.BeginUpdate();
                try
                {
                    loadData("");
                }
                finally
                {
                    lvVaciarAuthors.EndUpdate();
                }
            };

            SafeLog( "CreateVaciarTab: loadData definido\n");
            
            // Menú contextual para click derecho (DESPUÉS de loadData y LogDownload)
            var contextMenu = new ContextMenuStrip
            {
                BackColor = Color.FromArgb(40, 40, 40),
                ForeColor = Color.White
            };
            
            var menuViewFiles = new ToolStripMenuItem("Ver archivos del autor");
            menuViewFiles.Click += (s, e) =>
            {
                if (lvVaciarAuthors.SelectedItems.Count > 0)
                {
                    var selectedItem = lvVaciarAuthors.SelectedItems[0];
                    var authorData = (AuthorData)selectedItem.Tag;
                    string authorName = authorData.Name;
                    
                    // Obtener archivos del autor desde autoSearchResults
                    List<AutoSearchFileResult> allFiles;
                    
                        allFiles = autoSearchResults
                            .Where(f => f.Author.Equals(authorName, StringComparison.OrdinalIgnoreCase))
                            // FILTRAR archivos ya descargados en carbarher
                            .Where(f => !carbarherCacheLoaded || !carbarherFilesCache.Contains(f.FileName))
                            // FILTRAR archivos ya descargados en carpeta de descargas
                            .Where(f => !IsAlreadyDownloaded(f.FileName, "", 0))
                            .ToList();
                    
                    
                    // Eliminar duplicados por nombre de archivo (mantener el de mejor proveedor)
                    // Usar Rust si está disponible (20x más rápido), sino LINQ
                    List<AutoSearchFileResult> files;
                    if (SlskNativeInterop.IsAvailable && allFiles.Count > 100)
                    {
                        files = SlskNativeInterop.DeduplicateFiles(
                            allFiles,
                            f => f.FileName,
                            f => f.Username,
                            f => f.SizeBytes,
                            username => (int)GetProviderScore(username)
                        );
                    }
                    else
                    {
                        files = allFiles
                            .GroupBy(f => f.FileName, StringComparer.OrdinalIgnoreCase)
                            .Select(g => g.OrderByDescending(f => GetProviderScore(f.Username)).First())
                            .ToList();
                    }
                    
                    Log($"[Vaciar] Mostrando archivos únicos de '{authorName}' ({files.Count} únicos de {allFiles.Count} totales, filtrados por carbarher + descargas)");
                    
                    // Crear ventana para mostrar archivos
                    var filesForm = new Form
                    {
                        Text = $"Archivos de {authorName} ({files.Count} archivos únicos)",
                        Size = new Size(900, 600),
                        BackColor = Color.FromArgb(25, 25, 25),
                        ForeColor = Color.White,
                        StartPosition = FormStartPosition.CenterParent
                    };
                    
                    var lvAuthorFiles = new ListView
                    {
                        Dock = DockStyle.Fill,
                        View = View.Details,
                        FullRowSelect = true,
                        GridLines = true,
                        BackColor = Color.FromArgb(30, 30, 30),
                        ForeColor = Color.White,
                        Font = new Font("Segoe UI", 9),
                        HeaderStyle = ColumnHeaderStyle.Clickable,
                        HoverSelection = false
                    };
                    
                    lvAuthorFiles.Columns.Add("Archivo", 350);
                    lvAuthorFiles.Columns.Add("Tamaño", 100);
                    lvAuthorFiles.Columns.Add("Usuario", 150);
                    lvAuthorFiles.Columns.Add("Extensión", 100);
                    
                    // Variables para ordenamiento
                    int sortCol = 0;
                    bool sortAsc = true;
                    
                    // Función para actualizar headers con indicadores
                    Action updateHeaders = () =>
                    {
                        string[] colNames = { "Archivo", "Tamaño", "Usuario", "Extensión" };
                        for (int i = 0; i < lvAuthorFiles.Columns.Count; i++)
                        {
                            string header = colNames[i];
                            if (i == sortCol)
                            {
                                header += sortAsc ? " ▲" : " ▼";
                            }
                            lvAuthorFiles.Columns[i].Text = header;
                        }
                    };
                    
                    // Función para cargar y ordenar datos
                    Action loadAndSort = () =>
                    {
                        lvAuthorFiles.BeginUpdate();
                        lvAuthorFiles.Items.Clear();
                        
                        IEnumerable<AutoSearchFileResult> sortedFiles = files;
                        
                        // Ordenar según columna
                        sortedFiles = sortCol switch
                        {
                            0 => sortAsc ? files.OrderBy(f => f.FileName) : files.OrderByDescending(f => f.FileName),
                            1 => sortAsc ? files.OrderBy(f => f.SizeBytes) : files.OrderByDescending(f => f.SizeBytes),
                            2 => sortAsc ? files.OrderBy(f => f.Username) : files.OrderByDescending(f => f.Username),
                            3 => sortAsc ? files.OrderBy(f => Path.GetExtension(f.FileName)) : files.OrderByDescending(f => Path.GetExtension(f.FileName)),
                            _ => files.OrderBy(f => f.FileName)
                        };
                        
                        foreach (var file in sortedFiles)
                        {
                            var item = new ListViewItem(file.FileName);
                            item.SubItems.Add(file.SizeReadable);
                            item.SubItems.Add(file.Username);
                            
                            // Obtener extensión (sin el punto inicial)
                            string extension = Path.GetExtension(file.FileName);
                            if (!string.IsNullOrEmpty(extension) && extension.StartsWith("."))
                            {
                                extension = extension.Substring(1).ToUpper(); // Quitar punto y poner en mayúsculas
                            }
                            else if (string.IsNullOrEmpty(extension))
                            {
                                extension = "(sin ext)";
                            }
                            item.SubItems.Add(extension);
                            
                            item.Tag = file;
                            lvAuthorFiles.Items.Add(item);
                        }
                        
                        lvAuthorFiles.EndUpdate();
                        updateHeaders();
                    };
                    
                    // Event handler para click en columnas
                    lvAuthorFiles.ColumnClick += (sender, args) =>
                    {
                        if (args.Column == sortCol)
                        {
                            sortAsc = !sortAsc;
                        }
                        else
                        {
                            sortCol = args.Column;
                            sortAsc = true;
                        }
                        loadAndSort();
                    };
                    
                    // Cargar datos iniciales
                    loadAndSort();
                    
                    filesForm.Controls.Add(lvAuthorFiles);
                    filesForm.ShowDialog();
                }
            };
            contextMenu.Items.Add(menuViewFiles);
            
            var menuDeleteAuthor = new ToolStripMenuItem("Eliminar autor");
            menuDeleteAuthor.Click += (s, e) =>
            {
                if (lvVaciarAuthors.SelectedItems.Count > 0)
                {
                    var selectedItems = lvVaciarAuthors.SelectedItems.Cast<ListViewItem>().ToList();
                    var authorNames = string.Join(", ", selectedItems.Select(i => i.Text));
                    
                    var result = MessageBox.Show(
                        $"¿Eliminar {selectedItems.Count} autor(es)?\n\n{authorNames}\n\nEsto eliminará todos sus archivos de la lista y los excluirá de búsquedas activas.",
                        "Confirmar eliminación",
                        MessageBoxButtons.YesNo,
                        MessageBoxIcon.Warning
                    );
                    
                    if (result == DialogResult.Yes)
                    {
                        Log($"[Vaciar] Eliminando {selectedItems.Count} autor(es): {authorNames}");
                        
                        // Obtener lista de autores y archivos a eliminar
                        var authorsToExclude = new List<string>();
                        var filesToRemove = new List<AutoSearchFileResult>();
                        
                        foreach (var item in selectedItems)
                        {
                            var authorData = (AuthorData)item.Tag;
                            string authorName = authorData.Name;
                            authorsToExclude.Add(authorName);
                            
                            // Obtener archivos del autor desde autoSearchResults
                            
                                var files = autoSearchResults
                                    .Where(f => f.Author.Equals(authorName, StringComparison.OrdinalIgnoreCase))
                                    .ToList();
                                filesToRemove.AddRange(files);
                            
                        }
                        
                        // Agregar a blacklist permanente y lista de excluidos
                        foreach (var author in authorsToExclude)
                        {
                            // Agregar a blacklist para que no reaparezca
                            AddToBlacklist(author);
                            Log($"   Autor agregado a blacklist: {author}");
                            
                            // Agregar a lista de excluidos (afecta búsquedas activas)
                            excludedAuthors.Add(author);
                            Log($"   Autor excluido de búsquedas activas: {author}");
                        }
                        
                        // Eliminar de autoSearchResults
                        
                            RemoveAllFromAutoSearchResults(f => filesToRemove.Contains(f));
                        
                        
                        // Recargar grilla
                        loadData("");
                        
                        // Guardar CSV actualizado sin los autores eliminados
                        SaveAutoResultsToCsv();
                        
                        LogDownload($"Eliminados {selectedItems.Count} autor(es) ({filesToRemove.Count} archivos)");
                        LogDownload($"{authorsToExclude.Count} autor(es) excluidos de búsquedas activas");
                        LogDownload($"CSV actualizado - autores eliminados del archivo");
                    }
                }
            };
            contextMenu.Items.Add(menuDeleteAuthor);
            
            lvVaciarAuthors.ContextMenuStrip = contextMenu;
            SafeLog( "CreateVaciarTab: Menú contextual configurado\n");
            
            // Cargar cachés en paralelo (DIFERIDO para no bloquear el arranque)
            // NO pasar LogDownload aquí porque causa deadlock durante la inicialización
            Task.Run(async () => 
            {
                await Task.Delay(1000); // Esperar a que el form esté completamente inicializado
                try
                {
                    LogDownload("Iniciando escaneo de carpetas en paralelo...");
                    var sw = System.Diagnostics.Stopwatch.StartNew();
                    
                    // Ejecutar ambos escaneos en paralelo
                    await Task.WhenAll(
                        Task.Run(() => ScanDownloadFolderToHistory(LogDownload)),
                        Task.Run(() => LoadCarbarherCache(LogDownload))
                    );
                    
                    sw.Stop();
                    LogDownload($"Cachés cargados en {sw.ElapsedMilliseconds}ms ({sw.Elapsed.TotalSeconds:F1}s)");
                }
                catch (Exception ex)
                {
                    LogDownload($"Error cargando cachés: {ex.Message}");
                }
            });
            
            SafeLog( "CreateVaciarTab: Llamando loadData(\"\")\n");
            // COMENTADO: loadData hace operaciones pesadas de I/O que bloquean el UI thread
            // Se cargará automáticamente cuando el usuario abra la pestaña
            // loadData("");
            SafeLog( "CreateVaciarTab: loadData(\"\") omitido (se cargará al abrir tab)\n");
            
            // NO llamar LogDownload durante la inicialización - causa deadlock
            // Programar el mensaje para después de que el form esté completamente cargado
            // LogDownload("Pestaña Vaciar iniciada");
            
            // En su lugar, programar el mensaje para después de que el form esté completamente cargado
            Task.Run(async () => 
            {
                await Task.Delay(500); // Esperar a que el form esté completamente inicializado
                LogDownload("Pestaña Vaciar iniciada");
            });
            
            SafeLog( "CreateVaciarTab: Inicialización básica completada\n");

            SafeLog( "CreateVaciarTab: Registrando event handlers de filtros\n");
            // Event handlers para filtros
            numMinSizeKB.ValueChanged += (s, e) => { loadData(""); LogDownload($"Tamaño mínimo: {numMinSizeKB.Value:N0} KB"); };
            
            // Búsqueda incremental
            txtSearchVaciar.TextChanged += (s, e) =>
            {
                loadData(txtSearchVaciar.Text);
            };
            
            SafeLog( "CreateVaciarTab: Event handlers de filtros registrados\n");

            // Event handler para verificar y actualizar conteo de archivos filtrados
            btnVerifyIntegrity.Click += async (s, e) =>
            {
                try
                {
                    Log("[Vaciar] Botón 'Verificar' pulsado");
                    LogDownload("════════════════════════════════════");
                    LogDownload("VERIFICANDO ARCHIVOS");
                    LogDownload("════════════════════════════════════");
                    
                    btnVerifyIntegrity.Enabled = false;
                    
                    int totalFiles = 0;
                    int filteredFiles = 0;
                    int authorsWithFiles = 0;
                    var minSizeKB = (int)numMinSizeKB.Value;
                    
                    
                        totalFiles = autoSearchResults.Count;
                        
                        // ELIMINAR archivos que NO pasan los filtros
                        var validFiles = autoSearchResults.Where(f =>
                        {
                            // Filtro 1: Blacklist de usuarios
                            if (blacklist.Contains(f.Username))
                                return false;
                            
                            // Filtro 2: Tamaño mínimo
                            if (minSizeKB > 0 && f.SizeBytes < (minSizeKB * 1024))
                                return false;
                            
                            // Filtro 3: Idioma español
                            if (!IsSpanishText(f.FileName))
                                return false;
                            
                            // Filtro 4: Tipo de documento
                            if (!IsDocumentFile(f.FileName))
                                return false;
                            
                            // Filtro 5: Ya descargado (en carbarher)
                            if (carbarherCacheLoaded && carbarherFilesCache.Contains(f.FileName))
                                return false;
                            
                            // Filtro 6: Ya descargado (en carpeta de descargas)
                            if (IsAlreadyDownloaded(f.FileName, "", 0))
                                return false;
                            
                            return true;
                        }).ToList();
                        
                        filteredFiles = validFiles.Count;
                        
                        // Reemplazar lista con solo archivos válidos
                        autoSearchResults = new System.Collections.Concurrent.ConcurrentBag<AutoSearchFileResult>();
                        AddRangeToAutoSearchResults(validFiles);
                        
                        // Contar autores con archivos válidos
                        authorsWithFiles = autoSearchResults
                            .GroupBy(f => f.Author)
                            .Count();
                    
                    
                    var excludedFiles = totalFiles - filteredFiles;
                    LogDownload($"Archivos totales: {totalFiles:N0}");
                    LogDownload($"Archivos válidos: {filteredFiles:N0}");
                    LogDownload($"Archivos filtrados: {excludedFiles:N0}");
                    LogDownload($"Autores con archivos válidos: {authorsWithFiles:N0}");
                    LogDownload("════════════════════════════════════");
                    
                    // Actualizar contadores de archivos por autor sin eliminar autores
                    
                        var authorFileCounts = autoSearchResults
                            .GroupBy(f => f.Author)
                            .ToDictionary(g => g.Key, g => g.Count());
                        
                        // Actualizar contadores en allAuthorsData y filteredAuthorsData
                        foreach (var author in allAuthorsData)
                        {
                            if (authorFileCounts.TryGetValue(author.Name, out int count))
                            {
                                author.FilesCount = count;
                                author.Status = $"{count} archivo(s) válido(s)";
                            }
                            else
                            {
                                author.FilesCount = 0;
                                author.Status = "Sin archivos válidos";
                            }
                        }
                    
                    
                    // Refrescar la vista sin eliminar autores
                    if (lvAutoAuthors != null)
                    {
                        RefreshAuthorsListView();
                        UpdateAuthorCount();
                    }
                    
                    // Refrescar la grilla de Vaciar
                    loadData("");
                    
                    ShowNotification("Verificación Completada",
                        $"{filteredFiles:N0} archivos válidos\n" +
                        $"{excludedFiles:N0} archivos filtrados\n" +
                        $"{authorsWithFiles:N0} autores con archivos",
                        ToolTipIcon.Info);
                }
                catch (Exception ex)
                {
                    LogDownload($"Error en verificación: {ex.Message}");
                    LogDownload("════════════════════════════════════");
                }
                finally
                {
                    btnVerifyIntegrity.Enabled = true;
                }
            };
            
            // Event handler para dashboard de estadísticas en tiempo real
            btnDashboard.Click += (s, e) =>
            {
                try
                {
                    Log("[Vaciar] Botón 'Dashboard' pulsado");
                    
                    var dashboardForm = new Form
                    {
                        Text = "Dashboard de Estadísticas en Tiempo Real",
                        Size = new Size(900, 700),
                        BackColor = Color.FromArgb(20, 20, 20),
                        ForeColor = Color.White,
                        StartPosition = FormStartPosition.CenterScreen,
                        FormBorderStyle = FormBorderStyle.Sizable,
                        MinimumSize = new Size(700, 500)
                    };
                    
                    var mainPanel = new Panel
                    {
                        Dock = DockStyle.Fill,
                        Padding = new Padding(20),
                        AutoScroll = true
                    };
                    
                    var lblStats = new Label
                    {
                        Dock = DockStyle.Fill,
                        Font = new Font("Consolas", 10),
                        TextAlign = ContentAlignment.TopLeft,
                        AutoSize = false
                    };
                    
                    mainPanel.Controls.Add(lblStats);
                    dashboardForm.Controls.Add(mainPanel);
                    
                    // Método para actualizar estadísticas
                    Action updateStats = () =>
                    {
                        try
                        {
                            var stats = new StringBuilder();
                            
                            stats.AppendLine("═══════════════════════════════════════════════════════════════");
                            stats.AppendLine("DASHBOARD DE ESTADÍSTICAS - ACTUALIZACIÓN EN TIEMPO REAL");
                            stats.AppendLine("═══════════════════════════════════════════════════════════════");
                            stats.AppendLine();
                            
                            // SECCIÓN 1: Biblioteca General
                            stats.AppendLine("BIBLIOTECA GENERAL");
                            stats.AppendLine("─────────────────────────────────────────────────────────────");
                            
                            int totalFiles = 0;
                            long totalSize = 0;
                            int withHash = 0;
                            
                            lock (downloadHistoryLock)
                            {
                                totalFiles = downloadHistory.Count;
                                totalSize = downloadHistory.Sum(h => h.SizeBytes);
                                withHash = downloadHistory.Count(h => !string.IsNullOrEmpty(h.Hash));
                            }
                            
                            stats.AppendLine($"   Total de archivos: {totalFiles:N0}");
                            stats.AppendLine($"   Espacio total: {FormatFileSize(totalSize)}");
                            stats.AppendLine($"   Con hash BLAKE3: {withHash:N0} ({(totalFiles > 0 ? (withHash * 100.0 / totalFiles) : 0):F1}%)");
                            stats.AppendLine($"   Sin hash: {totalFiles - withHash:N0}");
                            stats.AppendLine();
                            
                            // SECCIÓN 2: Descargas Recientes
                            stats.AppendLine("DESCARGAS RECIENTES");
                            stats.AppendLine("─────────────────────────────────────────────────────────────");
                            
                            var last24h = 0;
                            var last7days = 0;
                            var last30days = 0;
                            
                            lock (downloadHistoryLock)
                            {
                                var now = DateTime.Now;
                                last24h = downloadHistory.Count(h => (now - h.DownloadedAt).TotalHours < 24);
                                last7days = downloadHistory.Count(h => (now - h.DownloadedAt).TotalDays < 7);
                                last30days = downloadHistory.Count(h => (now - h.DownloadedAt).TotalDays < 30);
                            }
                            
                            stats.AppendLine($"   Últimas 24 horas: {last24h:N0} archivos");
                            stats.AppendLine($"   Últimos 7 días: {last7days:N0} archivos");
                            stats.AppendLine($"   Últimos 30 días: {last30days:N0} archivos");
                            stats.AppendLine();
                            
                            // SECCIÓN 3: Velocidades
                            stats.AppendLine("VELOCIDADES DE DESCARGA");
                            stats.AppendLine("─────────────────────────────────────────────────────────────");
                            
                            double avgSpeed = 0;
                            double maxSpeed = 0;
                            double minSpeed = 0;
                            
                            lock (downloadHistoryLock)
                            {
                                var speedsData = downloadHistory.Where(h => h.SpeedMBps > 0).ToList();
                                if (speedsData.Any())
                                {
                                    avgSpeed = speedsData.Average(h => h.SpeedMBps);
                                    maxSpeed = speedsData.Max(h => h.SpeedMBps);
                                    minSpeed = speedsData.Min(h => h.SpeedMBps);
                                }
                            }
                            
                            stats.AppendLine($"   Promedio: {avgSpeed:F2} MB/s");
                            stats.AppendLine($"   Máxima: {maxSpeed:F2} MB/s");
                            stats.AppendLine($"   Mínima: {minSpeed:F2} MB/s");
                            stats.AppendLine();
                            
                            // SECCIÓN 4: Top Proveedores
                            stats.AppendLine("🏆 TOP 10 PROVEEDORES");
                            stats.AppendLine("─────────────────────────────────────────────────────────────");
                            
                            lock (downloadHistoryLock)
                            {
                                var topProviders = downloadHistory
                                    .GroupBy(h => h.Username)
                                    .Select(g => new
                                    {
                                        Username = g.Key,
                                        Count = g.Count(),
                                        TotalSize = g.Sum(h => h.SizeBytes),
                                        AvgSpeed = g.Where(h => h.SpeedMBps > 0).Average(h => (double?)h.SpeedMBps) ?? 0
                                    })
                                    .OrderByDescending(p => p.Count)
                                    .Take(10);
                                
                                int rank = 1;
                                foreach (var provider in topProviders)
                                {
                                    stats.AppendLine($"   {rank++}. {provider.Username}");
                                    stats.AppendLine($"      Archivos: {provider.Count:N0} | " +
                                        $"Total: {FormatFileSize(provider.TotalSize)} | " +
                                        $"Vel. prom: {provider.AvgSpeed:F2} MB/s");
                                }
                            }
                            stats.AppendLine();
                            
                            // SECCIÓN 5: Cola de Descargas Actual
                            stats.AppendLine("COLA DE DESCARGAS ACTUAL");
                            stats.AppendLine("─────────────────────────────────────────────────────────────");
                            
                            int queueCount = 0;
                            int activeDownloads = 0;
                            
                            lock (downloadQueueLock)
                            {
                                queueCount = downloadQueue.Count;
                                activeDownloads = downloadQueue.Count(t => 
                                    t.Status == DownloadStatus.Downloading);
                            }
                            
                            stats.AppendLine($"   En cola: {queueCount:N0} archivos");
                            stats.AppendLine($"   Descargando ahora: {activeDownloads} archivos");
                            stats.AppendLine($"   Pendientes: {queueCount - activeDownloads} archivos");
                            stats.AppendLine();
                            
                            // SECCIÓN 6: Extensiones Más Comunes
                            stats.AppendLine("EXTENSIONES MÁS COMUNES");
                            stats.AppendLine("─────────────────────────────────────────────────────────────");
                            
                            lock (downloadHistoryLock)
                            {
                                var topExtensions = downloadHistory
                                    .GroupBy(h => Path.GetExtension(h.FileName).ToLower())
                                    .Select(g => new { Extension = g.Key, Count = g.Count() })
                                    .OrderByDescending(e => e.Count)
                                    .Take(10);
                                
                                foreach (var ext in topExtensions)
                                {
                                    var extName = string.IsNullOrEmpty(ext.Extension) ? "(sin extensión)" : ext.Extension;
                                    stats.AppendLine($"   {extName}: {ext.Count:N0} archivos");
                                }
                            }
                            stats.AppendLine();
                            
                            // SECCIÓN 7: Información del Sistema
                            stats.AppendLine("INFORMACIÓN DEL SISTEMA");
                            stats.AppendLine("─────────────────────────────────────────────────────────────");
                            stats.AppendLine($"   Hora actual: {DateTime.Now:yyyy-MM-dd HH:mm:ss}");
                            stats.AppendLine($"   Uptime de la app: {(DateTime.Now - Process.GetCurrentProcess().StartTime):hh\\:mm\\:ss}");
                            stats.AppendLine($"   Uso de memoria: {FormatFileSize(Process.GetCurrentProcess().WorkingSet64)}");
                            stats.AppendLine();
                            
                            stats.AppendLine("═══════════════════════════════════════════════════════════════");
                            stats.AppendLine("Actualización automática cada 1 segundo");
                            stats.AppendLine("═══════════════════════════════════════════════════════════════");
                            
                            lblStats.Text = stats.ToString();
                        }
                        catch (Exception ex)
                        {
                            lblStats.Text = $"Error actualizando dashboard: {ex.Message}";
                        }
                    };
                    
                    // Timer para actualizar cada segundo
                    var updateTimer = new System.Windows.Forms.Timer { Interval = 1000 };
                    updateTimer.Tick += (ts, te) => updateStats();
                    
                    // Actualizar inmediatamente
                    updateStats();
                    
                    // Iniciar timer
                    updateTimer.Start();
                    
                    // Detener timer al cerrar
                    dashboardForm.FormClosed += (fs, fe) =>
                    {
                        updateTimer.Stop();
                        updateTimer.Dispose();
                        Log("Dashboard cerrado");
                    };
                    
                    dashboardForm.Show();
                    Log("Dashboard abierto");
                }
                catch (Exception ex)
                {
                    Log($"Error abriendo dashboard: {ex.Message}");
                    MessageBox.Show($"Error abriendo dashboard: {ex.Message}", "Error", 
                        MessageBoxButtons.OK, MessageBoxIcon.Error);
                }
            };

            // Mensaje inicial en el log (sin carga automática para evitar race conditions)
            LogDownload("═══════════════════════════════════════════════════");
            LogDownload("TAB VACIAR - Listo para usar");
            LogDownload("═══════════════════════════════════════════════════");
            LogDownload("Presiona 'Actualizar' para cargar los datos");
            LogDownload("═══════════════════════════════════════════════════");

            // Event handler para siguiente autor (búsqueda exhaustiva)
            btnNextAuthor.Click += async (s, e) =>
            {
                try
                {
                    Log("[Vaciar] Botón 'Actualizar' pulsado");
                    if (currentAuthorIndex >= authorsList.Count)
                    {
                        LogDownload("TODOS LOS AUTORES PROCESADOS");
                        btnNextAuthor.Enabled = false;
                        return;
                    }

                    string currentAuthor = authorsList[currentAuthorIndex];
                    
                    // Verificar si el autor fue excluido
                    if (excludedAuthors.Contains(currentAuthor))
                    {
                        LogDownload($"Autor excluido, saltando: {currentAuthor}");
                        currentAuthorIndex++;
                        
                        // Continuar con el siguiente autor
                        if (currentAuthorIndex < authorsList.Count)
                        {
                            btnNextAuthor.Text = $"Actualizar ({currentAuthorIndex + 1}/{authorsList.Count})";
                            await Task.Delay(100);
                            btnNextAuthor.PerformClick();
                        }
                        else
                        {
                            btnNextAuthor.Text = "Completado";
                            btnNextAuthor.Enabled = false;
                            LogDownload("TODOS LOS AUTORES PROCESADOS");
                        }
                        return;
                    }
                    
                    Log($"[Vaciar] Procesando autor {currentAuthorIndex + 1}/{authorsList.Count}: {currentAuthor}");
                    LogDownload("════════════════════════════════════");
                    LogDownload($"AUTOR {currentAuthorIndex + 1}/{authorsList.Count}: {currentAuthor}");
                    LogDownload("════════════════════════════════════");

                    if (client == null || !client.State.HasFlag(SoulseekClientStates.Connected))
                    {
                        LogDownload("No conectado");
                        MessageBox.Show("Debes estar conectado a Soulseek.", "No conectado", MessageBoxButtons.OK, MessageBoxIcon.Warning);
                        return;
                    }

                    var searchStart = DateTime.Now;
                    
                    int totalNewFiles = 0;
                    int totalCarbarherDuplicates = 0;
                    int totalNonDocuments = 0;
                    int totalNonSpanish = 0;
                    int totalAlreadyDownloaded = 0;
                    int searchIteration = 0;
                    int consecutiveEmptySearches = 0;
                    const int MAX_EMPTY_SEARCHES = 1;
                    
                    var seenFiles = new HashSet<string>(5000); // Pre-allocar para ~5k archivos por búsqueda
                    
                    while (consecutiveEmptySearches < MAX_EMPTY_SEARCHES)
                    {
                        searchIteration++;
                        LogDownload($"Búsqueda #{searchIteration}...");
                        
                        var searchResponse = await client.SearchAsync(SearchQuery.FromText(currentAuthor));
                        int totalUsers = searchResponse.Responses.Count;
                        
                        var timestamp = DateTime.Now;
                        var newFilesToAdd = new List<AutoSearchFileResult>(1000); // Pre-allocate
                        int newFilesThisIteration = 0;
                        int carbarherDuplicatesThisIteration = 0;
                        int nonDocumentsThisIteration = 0;
                        int nonSpanishThisIteration = 0;
                        // Procesar respuestas en paralelo para mejor rendimiento
                        var allFiles = searchResponse.Responses
                            .Where(r => !r.Username.Equals("carbarher", StringComparison.OrdinalIgnoreCase))
                            .SelectMany(r => r.Files.Select(f => new { Response = r, File = f }))
                            .Where(item => item.File.Size > 0) // Filtrar archivos de 0 bytes
                            .Where(item => minFileSizeKB == 0 || item.File.Size >= (minFileSizeKB * 1024)) // Filtrar por tamaño mínimo
                            .AsParallel()
                            .WithDegreeOfParallelism(Environment.ProcessorCount)
                            .Select(item =>
                            {
                                // Filtrar archivos sin extensión
                                string extension = Path.GetExtension(item.File.Filename);
                                if (string.IsNullOrEmpty(extension))
                                    return null;
                                
                                // Optimizar construcción de fileKey (evitar boxing de Size)
                                var fileKey = string.Concat(item.Response.Username, "|", item.File.Filename, "|", item.File.Size.ToString());
                                
                                var filenameLower = item.File.Filename.ToLowerInvariant();
                                
                                // Usar IndexOf con StringComparison para mejor rendimiento
                                bool isSpanish = filenameLower.IndexOf("spanish", StringComparison.Ordinal) >= 0 || 
                                               filenameLower.IndexOf("español", StringComparison.Ordinal) >= 0 ||
                                               filenameLower.IndexOf("castellano", StringComparison.Ordinal) >= 0;
                                
                                bool isDocument = filenameLower.EndsWith(".pdf") ||
                                                filenameLower.EndsWith(".epub") ||
                                                filenameLower.EndsWith(".mobi");

                                string fileName = Path.GetFileName(item.File.Filename);
                                string directory = Path.GetDirectoryName(item.File.Filename) ?? "";

                                return new
                                {
                                    FileKey = fileKey,
                                    FileName = fileName,
                                    Directory = directory,
                                    Username = item.Response.Username,
                                    Size = item.File.Size,
                                    IsSpanish = isSpanish,
                                    IsDocument = isDocument
                                };
                            })
                            .Where(item => item != null) // Filtrar nulos (archivos sin extensión)
                            .ToList();
                        
                        // Procesar resultados secuencialmente para mantener thread-safety
                        foreach (var item in allFiles)
                        {
                            if (seenFiles.Contains(item.FileKey))
                                continue;
                            
                            seenFiles.Add(item.FileKey);
                            
                            // Contar archivos filtrados
                            if (!item.IsDocument)
                            {
                                nonDocumentsThisIteration++;
                                totalNonDocuments++;
                                continue;
                            }
                            
                            if (!item.IsSpanish)
                            {
                                nonSpanishThisIteration++;
                                totalNonSpanish++;
                                continue;
                            }

                            // Verificar si ya existe en cbh
                            if (carbarherCacheLoaded && carbarherFilesCache.Contains(item.FileName))
                            {
                                carbarherDuplicatesThisIteration++;
                                totalCarbarherDuplicates++;
                                continue;
                            }
                            
                            // Verificar si ya fue descargado - OMITIR si ya existe
                            bool alreadyDownloaded = IsAlreadyDownloaded(item.FileName, item.Username, item.Size);
                            
                            if (alreadyDownloaded)
                            {
                                totalAlreadyDownloaded++;
                                continue; // OMITIR archivos ya descargados
                            }

                            newFilesToAdd.Add(new AutoSearchFileResult
                            {
                                Author = currentAuthor,
                                Username = item.Username,
                                FileName = item.FileName,
                                Directory = item.Directory,
                                SizeBytes = item.Size,
                                SizeReadable = FormatFileSize(item.Size),
                                IsSpanish = item.IsSpanish,
                                IsDocument = true,
                                Timestamp = timestamp
                            });
                            newFilesThisIteration++;
                            totalNewFiles++;
                        }
                        
                        if (newFilesToAdd.Count > 0)
                        {
                            
                                AddRangeToAutoSearchResults(newFilesToAdd);
                            
                        }
                        
                        LogDownload($"   {totalUsers} usr, {newFilesThisIteration} nuevos");
                        if (nonDocumentsThisIteration > 0 || nonSpanishThisIteration > 0 || carbarherDuplicatesThisIteration > 0)
                        {
                            var filters = new List<string>();
                            if (nonDocumentsThisIteration > 0) filters.Add($"{nonDocumentsThisIteration} no-doc");
                            if (nonSpanishThisIteration > 0) filters.Add($"{nonSpanishThisIteration} no-es");
                            if (carbarherDuplicatesThisIteration > 0) filters.Add($"{carbarherDuplicatesThisIteration} cbh");
                            LogDownload($"      ↳ {string.Join(", ", filters)}");
                        }
                        
                        if (newFilesThisIteration == 0)
                        {
                            consecutiveEmptySearches++;
                            LogDownload($"   Sin resultados nuevos ({consecutiveEmptySearches}/{MAX_EMPTY_SEARCHES})");
                        }
                        else
                        {
                            consecutiveEmptySearches = 0;
                            if (searchIteration % 2 == 0)
                            {
                                ClearFileCache();
                                loadData("");
                            }
                        }
                        
                        await Task.Delay(500);
                    }

                    var searchDuration = (DateTime.Now - searchStart).TotalSeconds;
                    LogDownload($"COMPLETADO en {searchDuration:F1}s");
                    LogDownload($"   {totalNewFiles} archivos encontrados ({searchIteration} búsquedas)");
                    
                    var summary = new List<string>();
                    if (totalNonDocuments > 0) summary.Add($"{totalNonDocuments} no-doc");
                    if (totalNonSpanish > 0) summary.Add($"{totalNonSpanish} no-es");
                    if (totalCarbarherDuplicates > 0) summary.Add($"{totalCarbarherDuplicates} cbh");
                    if (totalAlreadyDownloaded > 0) summary.Add($"{totalAlreadyDownloaded} ya descargados");
                    
                    if (summary.Count > 0)
                        LogDownload($"   Filtrados: {string.Join(", ", summary)}");
                    
                    if (totalAlreadyDownloaded > 0)
                        LogDownload($"   {totalAlreadyDownloaded} archivos marcados como duplicados (ya descargados)");
                    
                    LogDownload("════════════════════════════════════");
                    
                    // Limpiar caché de archivos antes de actualizar grilla
                    ClearFileCache();
                    loadData("");

                    currentAuthorIndex++;
                    
                    if (currentAuthorIndex < authorsList.Count)
                    {
                        btnNextAuthor.Text = $"Actualizar ({currentAuthorIndex + 1}/{authorsList.Count})";
                        LogDownload("═══════════════════════════════════════════════════");
                        
                        // Continuar automáticamente con el siguiente autor
                        await Task.Delay(100); // Pequeña pausa para que se vea el log
                        btnNextAuthor.PerformClick();
                    }
                    else
                    {
                        btnNextAuthor.Text = "Completado";
                        btnNextAuthor.Enabled = false;
                        LogDownload("═══════════════════════════════════════════════════");
                        LogDownload("TODOS LOS AUTORES PROCESADOS");
                        
                        // Notificación de finalización
                        ShowNotification("Búsqueda Completada", 
                            $"Se procesaron {authorsList.Count} autores. Total archivos: {totalNewFiles}", 
                            ToolTipIcon.Info);
                    }
                }
                catch (Exception ex)
                {
                    LogDownload($"ERROR: {ex.Message}");
                    MessageBox.Show($"Error al buscar autor: {ex.Message}", "Error", MessageBoxButtons.OK, MessageBoxIcon.Error);
                }
            };

            // Event handlers para selección
            btnSelectAll.Click += (s, e) =>
            {
                Log("[Vaciar] Botón 'Seleccionar Todo' pulsado");
                lvVaciarAuthors.BeginUpdate();
                foreach (ListViewItem item in lvVaciarAuthors.Items)
                {
                    item.Checked = true;
                }
                lvVaciarAuthors.EndUpdate();
                
                int totalCount = lvVaciarAuthors.Items.Count;
                LogDownload($"Seleccionados todos los autores ({totalCount:N0})");
            };

            btnDeselectAll.Click += (s, e) =>
            {
                Log("[Vaciar] Botón 'Deseleccionar Todo' pulsado");
                lvVaciarAuthors.BeginUpdate();
                foreach (ListViewItem item in lvVaciarAuthors.Items)
                {
                    item.Checked = false;
                }
                lvVaciarAuthors.EndUpdate();
                
                LogDownload($"Deseleccionados todos los autores");
            };

            // Event handlers para otros botones
            btnDownloadSelected.Click += async (s, e) =>
            {
                Log("[Vaciar] Botón 'Descargar' pulsado");
                var selectedAuthors = lvVaciarAuthors.CheckedItems.Cast<ListViewItem>().ToList();

                if (selectedAuthors.Count == 0)
                {
                    Log("[Vaciar] No hay autores seleccionados");
                    MessageBox.Show("No hay autores seleccionados.\n\nMarca los autores que deseas descargar.", "Sin selección", MessageBoxButtons.OK, MessageBoxIcon.Warning);
                    return;
                }

                var downloadPath = txtDownloadDir?.Text ?? Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.MyDocuments), "SlskDown");
                int totalFiles = 0;
                int skippedDuplicates = 0;
                
                // PASO 1: Recopilar SOLO los archivos FILTRADOS de los autores seleccionados
                // (solo autores visibles en la grilla después de aplicar filtros)
                List<AutoSearchFileResult> allFilesFromAllAuthors = new List<AutoSearchFileResult>();
                
                // Obtener lista de autores visibles en la grilla (después de filtros)
                HashSet<string> visibleAuthors = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
                SafeInvoke(() =>
                {
                    foreach (ListViewItem item in lvVaciarAuthors.Items)
                    {
                        var authorData = (AuthorData)item.Tag;
                        visibleAuthors.Add(authorData.Name);
                    }
                });
                
                Log($"[Vaciar] Autores visibles después de filtros: {visibleAuthors.Count}");
                
                foreach (var authorItem in selectedAuthors)
                {
                    var authorData = (AuthorData)authorItem.Tag;
                    
                    // Solo procesar si el autor está visible (no filtrado)
                    if (!visibleAuthors.Contains(authorData.Name))
                    {
                        Log($"[Vaciar] Autor '{authorData.Name}' omitido (filtrado)");
                        continue;
                    }
                    
                    
                        var authorFiles = autoSearchResults.Where(f => f.Author.Equals(authorData.Name, StringComparison.OrdinalIgnoreCase)).ToList();
                        allFilesFromAllAuthors.AddRange(authorFiles);
                    
                }
                
                Log($"[Vaciar] Total de archivos recopilados de {selectedAuthors.Count} autores: {allFilesFromAllAuthors.Count}");
                
                // PASO 2: Deduplicar GLOBALMENTE (entre todos los autores)
                List<AutoSearchFileResult> uniqueFiles;
                if (SlskNativeInterop.IsAvailable && allFilesFromAllAuthors.Count > 100)
                {
                    Log($"[Rust] Deduplicando {allFilesFromAllAuthors.Count} archivos globalmente con Rust...");
                    var sw = System.Diagnostics.Stopwatch.StartNew();
                    uniqueFiles = SlskNativeInterop.DeduplicateFiles(
                        allFilesFromAllAuthors,
                        f => f.FileName,
                        f => f.Username,
                        f => f.SizeBytes,
                        username => (int)GetProviderScore(username)
                    );
                    sw.Stop();
                    Log($"[Rust] Deduplicación completada en {sw.ElapsedMilliseconds}ms ({allFilesFromAllAuthors.Count} -> {uniqueFiles.Count} únicos)");
                }
                else
                {
                    var reason = !SlskNativeInterop.IsAvailable ? "Rust no disponible" : $"Lista pequeña ({allFilesFromAllAuthors.Count} archivos)";
                    Log($"[C#] Deduplicando globalmente con LINQ ({reason})");
                    uniqueFiles = allFilesFromAllAuthors
                        .GroupBy(f => f.FileName, StringComparer.OrdinalIgnoreCase)
                        .Select(g => g.OrderByDescending(f => GetProviderScore(f.Username)).First())
                        .ToList();
                    Log($"[C#] Deduplicación completada ({allFilesFromAllAuthors.Count} -> {uniqueFiles.Count} únicos)");
                }
                
                // PASO 3: Agregar archivos únicos a la cola de descargas
                foreach (var file in uniqueFiles)
                {
                    // FILTRO DE SEGURIDAD: Solo descargar archivos en español
                    if (!file.IsSpanish)
                    {
                        Log($"⚠️ Archivo rechazado (no español): {file.FileName}");
                        continue;
                    }
                    
                    
                    var localPath = GetDownloadPath(downloadPath, file.FileName, file.Author);
                    
                    // Verificar duplicados por hash antes de agregar
                    if (await ShouldSkipDownloadDuplicate(file))
                    {
                        skippedDuplicates++;
                        continue;
                    }
                    
                    // Solo agregar si no está ya descargado
                    if (!System.IO.File.Exists(localPath))
                    {
                        // Crear ListViewItem para la grilla de descargas
                        ListViewItem downloadItem = null;
                        SafeInvoke(() =>
                        {
                            downloadItem = new ListViewItem(file.FileName);
                            // Agregar indicador premium al username
                            string usernameDisplay = premiumUsers.Contains(file.Username) ? $"[PREMIUM] {file.Username}" : file.Username;
                            downloadItem.SubItems.Add(usernameDisplay);
                            downloadItem.SubItems.Add("0%");
                            downloadItem.SubItems.Add("En cola");
                            downloadItem.SubItems.Add(file.SizeReadable);
                            downloadItem.SubItems.Add(GetMetadataStatusSync(file.FileName));
                            downloadItem.ForeColor = Color.LightGray;
                            lvDownloads.Items.Add(downloadItem);
                        });
                        
                        AddToDownloadQueue(file, localPath, downloadItem, false);
                        totalFiles++;
                    }
                }

                // Log detallado por autor
                Log($"[Vaciar] Desglose por autor:");
                foreach (ListViewItem authorItem in lvVaciarAuthors.CheckedItems)
                {
                    var authorData = (AuthorData)authorItem.Tag;
                    int authorFileCount = 0;
                    
                        authorFileCount = autoSearchResults.Count(f => f.Author.Equals(authorData.Name, StringComparison.OrdinalIgnoreCase));
                    
                    Log($"   • {authorData.Name}: {authorFileCount} archivos");
                }
                
                var message = $"{totalFiles} archivos agregados a la cola de descargas\n\nAutores: {selectedAuthors.Count}";
                if (skippedDuplicates > 0)
                {
                    message += $"\nDuplicados omitidos: {skippedDuplicates}";
                }
                
                Log($"[Vaciar] TOTAL: {totalFiles} archivos agregados, {skippedDuplicates} duplicados omitidos");
                LogDownload($"{totalFiles} archivos agregados, {skippedDuplicates} duplicados omitidos");
                MessageBox.Show(message, "Descarga iniciada", MessageBoxButtons.OK, MessageBoxIcon.Information);
                
                // Cambiar a pestaña de descargas para ver el progreso
                if (totalFiles > 0)
                {
                    SafeInvoke(() => tabControl.SelectedIndex = 1);
                }
            };

            btnOpenFolder.Click += (s, e) =>
            {
                Log("[Vaciar] Botón 'Abrir Carpeta' pulsado");
                var downloadPath = txtDownloadDir?.Text ?? Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.MyDocuments), "SlskDown");
                if (System.IO.Directory.Exists(downloadPath))
                {
                    Process.Start("explorer.exe", downloadPath);
                    LogDownload($"Abriendo carpeta: {downloadPath}");
                }
            };

            btnRedownload.Click += async (s, e) =>
            {
                Log("[Vaciar] Botón 'Redescargar' pulsado");
                
                var selectedAuthors = lvVaciarAuthors.CheckedItems.Cast<ListViewItem>().ToList();
                if (selectedAuthors.Count == 0)
                {
                    LogDownload("No hay autores seleccionados para redescargar");
                    MessageBox.Show("Marca los autores cuyas descargas deseas redescargar.", "Sin selección", MessageBoxButtons.OK, MessageBoxIcon.Warning);
                    return;
                }
                
                var result = MessageBox.Show(
                    $"¿Redescargar archivos de {selectedAuthors.Count} autor(es)?\n\nEsto volverá a descargar TODOS los archivos, incluso los ya descargados.",
                    "Confirmar redescargar",
                    MessageBoxButtons.YesNo,
                    MessageBoxIcon.Question
                );
                
                if (result == DialogResult.Yes)
                {
                    LogDownload("════════════════════════════════════");
                    LogDownload("REDESCARGANDO ARCHIVOS");
                    LogDownload("════════════════════════════════════");
                    
                    var downloadPath = txtDownloadDir?.Text ?? Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.MyDocuments), "SlskDown");
                    int totalFiles = 0;
                    
                    foreach (var authorItem in selectedAuthors)
                    {
                        var authorData = (AuthorData)authorItem.Tag;
                        List<AutoSearchFileResult> files;
                        
                        
                            files = autoSearchResults.Where(f => f.Author.Equals(authorData.Name, StringComparison.OrdinalIgnoreCase)).ToList();
                        
                        
                        LogDownload($"Autor: {authorData.Name} ({files.Count} archivos)");
                        
                        foreach (var file in files)
                        {
                            // FILTRO DE SEGURIDAD: Solo descargar archivos en español
                            if (!file.IsSpanish)
                            {
                                LogDownload($"⚠️ Archivo rechazado (no español): {file.FileName}");
                                continue;
                            }
                            
                            
                            var localPath = GetDownloadPath(downloadPath, file.FileName, authorData.Name);
                            
                            // Eliminar archivo existente si existe
                            if (System.IO.File.Exists(localPath))
                            {
                                try
                                {
                                    System.IO.File.Delete(localPath);
                                    LogDownload($"  Eliminado: {file.FileName}");
                                }
                                catch (Exception ex)
                                {
                                    LogDownload($"  Error eliminando {file.FileName}: {ex.Message}");
                                    continue;
                                }
                            }
                            
                            // Crear ListViewItem para la grilla de descargas
                            ListViewItem downloadItem = null;
                            SafeInvoke(() =>
                            {
                                downloadItem = new ListViewItem(file.FileName);
                                // Agregar indicador premium al username
                                string usernameDisplay = premiumUsers.Contains(file.Username) ? $"[PREMIUM] {file.Username}" : file.Username;
                                downloadItem.SubItems.Add(usernameDisplay);
                                downloadItem.SubItems.Add("0%");
                                downloadItem.SubItems.Add("Recomenzando");
                                downloadItem.SubItems.Add(file.SizeReadable);
                                downloadItem.SubItems.Add(GetMetadataStatusSync(file.FileName));
                                downloadItem.ForeColor = Color.Orange;
                                lvDownloads.Items.Add(downloadItem);
                            });
                            
                            AddToDownloadQueue(file, localPath, downloadItem, true);
                            totalFiles++;
                            await Task.Delay(10); // Pequeña pausa para no saturar
                        }
                    }
                    
                    Log($"[Vaciar] {totalFiles} archivos de {selectedAuthors.Count} autores recomenzados");
                    LogDownload($"{totalFiles} archivos agregados a la cola para recomenzar");
                    MessageBox.Show($"{totalFiles} archivos agregados a la cola\n\nAutores: {selectedAuthors.Count}", "Descargas recomenzadas", MessageBoxButtons.OK, MessageBoxIcon.Information);
                    
                    // Cambiar a pestaña de descargas para ver el progreso
                    if (totalFiles > 0)
                    {
                        SafeInvoke(() => tabControl.SelectedIndex = 1);
                    }
                }
            };

            btnStopDownload.Click += (s, e) =>
            {
                Log("[Vaciar] Botón 'Detener' pulsado");
                
                var result = MessageBox.Show(
                    "¿Pausar todas las descargas en curso?",
                    "Confirmar pausa",
                    MessageBoxButtons.YesNo,
                    MessageBoxIcon.Question
                );
                
                if (result == DialogResult.Yes)
                {
                    PauseAllDownloads();
                    LogDownload("Todas las descargas pausadas");
                    Log("[Vaciar] Todas las descargas pausadas");
                }
            };

            btnResumeDownload.Click += async (s, e) =>
            {
                Log("[Vaciar] Botón 'Continuar' pulsado");
                
                await ResumeAllDownloads();
                LogDownload("Descargas reanudadas");
                Log("[Vaciar] Descargas reanudadas");
                
                // Reiniciar el gestor de descargas si no está corriendo
                if (!downloadManagerRunning)
                {
                    _ = Task.Run(async () => await StartDownloadManager());
                    LogDownload("Gestor de descargas reiniciado");
                }
            };
            
            // BOTÓN DE DIAGNÓSTICO: Forzar procesamiento de cola
            var btnForceQueue = new Button
            {
                Text = "Forzar Cola",
                Size = new Size(120, 30),
                BackColor = Color.FromArgb(255, 140, 0),
                ForeColor = Color.White,
                FlatStyle = FlatStyle.Flat,
                Font = new Font("Segoe UI", 9, FontStyle.Bold),
                Cursor = Cursors.Hand
            };
            btnForceQueue.FlatAppearance.BorderSize = 0;
            btnForceQueue.Click += async (s, e) =>
            {
                Log("[Diagnóstico] Forzando procesamiento de cola");
                
                int pending, downloading, paused, failed, completed;
                lock (downloadQueueLock)
                {
                    pending = downloadQueue.Count(t => t.Status == DownloadStatus.Queued);
                    downloading = downloadQueue.Count(t => t.Status == DownloadStatus.Downloading);
                    paused = downloadQueue.Count(t => t.Status == DownloadStatus.Paused);
                    failed = downloadQueue.Count(t => t.Status == DownloadStatus.Failed);
                    completed = downloadQueue.Count(t => t.Status == DownloadStatus.Completed);
                }
                
                LogDownload("═══════════════════════════════════════════════════");
                LogDownload("DIAGNÓSTICO DE COLA DE DESCARGAS");
                LogDownload("═══════════════════════════════════════════════════");
                LogDownload($"Estado de la cola:");
                LogDownload($"   Pendientes: {pending}");
                LogDownload($"   Descargando: {downloading}");
                LogDownload($"   Pausadas: {paused}");
                LogDownload($"   Fallidas: {failed}");
                LogDownload($"   Completadas: {completed}");
                LogDownload($"Gestor activo: {(downloadManagerRunning ? "SÍ" : "NO")}");
                LogDownload($"Límite simultáneas: {maxSimultaneousDownloads}");
                LogDownload($"Slots disponibles: {maxSimultaneousDownloads - downloading}");
                
                // Forzar reinicio del gestor
                if (!downloadManagerRunning)
                {
                    LogDownload("Reiniciando gestor de descargas...");
                    _ = Task.Run(async () => await StartDownloadManager());
                    await Task.Delay(500);
                }
                
                // Forzar procesamiento de tareas pendientes
                if (pending > 0)
                {
                    LogDownload($"Forzando procesamiento de {Math.Min(pending, maxSimultaneousDownloads - downloading)} tareas...");
                    
                    DownloadTask[] tasksToForce;
                    lock (downloadQueueLock)
                    {
                        tasksToForce = downloadQueue
                            .Where(t => t.Status == DownloadStatus.Queued)
                            .Take(maxSimultaneousDownloads - downloading)
                            .ToArray();
                    }
                    
                    foreach (var task in tasksToForce)
                    {
                        LogDownload($"   Iniciando: {task.File.FileName}");
                        _ = Task.Run(async () => await ProcessDownload(task));
                    }
                }
                
                LogDownload("Diagnóstico completado");
                LogDownload("═══════════════════════════════════════════════════");
            };
            topLeftPanel.Controls.Add(btnForceQueue);
            
            SafeLog( "CreateVaciarTab: Agregando mainLayout al parent\n");
            parent.Controls.Add(mainLayout);
            SafeLog( "CreateVaciarTab: Completado\n");
        }
        
        private void CreateWishlistTab(Panel parent)
