                ForeColor = Color.White,
                Font = new Font("Segoe UI", 10, FontStyle.Bold),
                AutoSize = true,
                Margin = new Padding(0, 10, 10, 0)
            };
            AddTooltip(chkAutoSearch, "Activa/desactiva la búsqueda automática periódica de los términos en la wishlist");
            chkAutoSearch.CheckedChanged += (s, e) =>
            {
                wishlistAutoSearchEnabled = chkAutoSearch.Checked;
                if (wishlistAutoSearchEnabled)
                {
                    StartWishlistTimer();
                    Log("Búsqueda automática de wishlist activada");
                }
                else
