                    StopWishlistTimer();
                    Log("Búsqueda automática de wishlist desactivada");
                }
            };
            
            // TextBox de búsqueda incremental
            var txtWishlistSearch = new TextBox
            {
                Size = new Size(180, 30),
                BackColor = Color.FromArgb(50, 50, 50),
                ForeColor = Color.White,
                Font = new Font("Segoe UI", 9),
                PlaceholderText = "Filtrar...",
                Margin = new Padding(0, 4, 0, 0)
            };
            AddTooltip(txtWishlistSearch, "Filtra la lista de wishlist en tiempo real escribiendo parte del término o autor");
            
            topFlow.Controls.Add(btnAdd);
            topFlow.Controls.Add(btnRemove);
            topFlow.Controls.Add(btnSearchNow);
            topFlow.Controls.Add(chkAutoSearch);
            topFlow.Controls.Add(txtWishlistSearch);
            
            mainLayout.Controls.Add(topFlow, 0, 0);
            
            // ListView para mostrar items de wishlist
            var lvWishlist = new ListView
            {
                Dock = DockStyle.Fill,
                View = View.Details,
                FullRowSelect = true,
                GridLines = true,
                VirtualMode = false,
                BackColor = Color.FromArgb(30, 30, 30),
                ForeColor = Color.White,
                Font = new Font("Segoe UI", 9),
                BorderStyle = BorderStyle.None
            };
            
            lvWishlist.Columns.Add("Término de Búsqueda", 250);
            lvWishlist.Columns.Add("Autor", 150);
            lvWishlist.Columns.Add("Agregado", 120);
            lvWishlist.Columns.Add("Última Búsqueda", 120);
            lvWishlist.Columns.Add("Encontrados", 80);
            lvWishlist.Columns.Add("Auto", 60);
            lvWishlist.Columns.Add("Notas", 200);
            
            // Habilitar doble búfer para evitar parpadeos
            typeof(Control).GetProperty("DoubleBuffered", System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance)
                ?.SetValue(lvWishlist, true, null);

            // Cargar wishlist
            // LoadWishlist(); // TODO: Implementar método LoadWishlist
            RefreshWishlistUI(lvWishlist, "");
            
            // Búsqueda incremental
            txtWishlistSearch.TextChanged += (s, e) =>
            {
                RefreshWishlistUI(lvWishlist, txtWishlistSearch.Text);
            };
            
            // Guardar referencia al ListView
            lvWishlist.Tag = "wishlistView";
            
            mainLayout.Controls.Add(lvWishlist, 0, 1);
            parent.Controls.Add(mainLayout);
            
            // Iniciar timer si está habilitado
            if (wishlistAutoSearchEnabled)
            {
                StartWishlistTimer();
            }
        }

