        private void CreateSeriesTab(TabPage parent)
        {
            parent.BackColor = Color.FromArgb(30, 30, 30);
            
            var mainLayout = new TableLayoutPanel
            {
                Dock = DockStyle.Fill,
                ColumnCount = 1,
                RowCount = 3,
                Padding = new Padding(10),
                BackColor = Color.FromArgb(30, 30, 30)
            };
            mainLayout.RowStyles.Add(new RowStyle(SizeType.AutoSize)); // Botones
            mainLayout.RowStyles.Add(new RowStyle(SizeType.Percent, 100)); // Lista de series
            mainLayout.RowStyles.Add(new RowStyle(SizeType.AutoSize)); // Log
            
            // Panel de botones
            var btnPanel = new FlowLayoutPanel
            {
                Dock = DockStyle.Fill,
                FlowDirection = FlowDirection.LeftToRight,
                WrapContents = true,
                AutoSize = true,
                AutoSizeMode = AutoSizeMode.GrowAndShrink,
                BackColor = Color.FromArgb(30, 30, 30),
                Padding = new Padding(5, 8, 5, 8)
            };
            
            var btnScanLibrary = CreateButton("Escanear Biblioteca", Color.FromArgb(0, 120, 215));
            var btnSearchMissing = CreateButton("Buscar Faltantes", Color.FromArgb(0, 150, 0));
            var btnRefresh = CreateButton("Actualizar", Color.FromArgb(100, 100, 100));
            var btnExport = CreateButton("Exportar", Color.FromArgb(150, 100, 0));
            
            btnPanel.Controls.Add(btnScanLibrary);
            btnPanel.Controls.Add(btnSearchMissing);
            btnPanel.Controls.Add(btnRefresh);
            btnPanel.Controls.Add(btnExport);
            
            mainLayout.Controls.Add(btnPanel, 0, 0);
            
            // ListView para mostrar series
            var lvSeries = new ListView
            {
                Dock = DockStyle.Fill,
                View = View.Details,
                FullRowSelect = true,
                GridLines = true,
                VirtualMode = false,
                BackColor = Color.FromArgb(30, 30, 30),
                ForeColor = Color.White,
                Font = new Font("Segoe UI", 9),
                BorderStyle = BorderStyle.None,
                CheckBoxes = true
            };
            
            lvSeries.Columns.Add("Serie", 300);
            lvSeries.Columns.Add("Autor", 150);
            lvSeries.Columns.Add("Progreso", 100);
            lvSeries.Columns.Add("Faltantes", 80);
            lvSeries.Columns.Add("Estado", 100);
            
            mainLayout.Controls.Add(lvSeries, 0, 1);
            
            // TextBox de log
            var txtSeriesLog = new TextBox
            {
                Dock = DockStyle.Fill,
                Multiline = true,
                ReadOnly = true,
                BackColor = Color.FromArgb(20, 20, 20),
                ForeColor = Color.LightGray,
                Font = new Font("Consolas", 9),
                BorderStyle = BorderStyle.None,
                ScrollBars = ScrollBars.Vertical
            };
            
            mainLayout.Controls.Add(txtSeriesLog, 0, 2);
            
            // Helper para log
            void LogSeries(string message)
            {
                SafeInvoke(() =>
                {
                    txtSeriesLog.AppendText($"[{DateTime.Now:HH:mm:ss}] {message}\r\n");
                    txtSeriesLog.SelectionStart = txtSeriesLog.Text.Length;
                    txtSeriesLog.ScrollToCaret();
                });
            }
            
            // Evento: Escanear biblioteca
            btnScanLibrary.Click += async (s, e) =>
            {
                try
                {
                    btnScanLibrary.Enabled = false;
                    LogSeries("Escaneando biblioteca...");
                    
                    // Obtener todos los archivos descargados
                    var downloadedFiles = new List<string>();
                    
                    if (System.IO.Directory.Exists(downloadDir))
                    {
                        var files = System.IO.Directory.GetFiles(downloadDir, "*.*", SearchOption.AllDirectories)
                            .Where(f => f.EndsWith(".epub", StringComparison.OrdinalIgnoreCase) ||
                                       f.EndsWith(".pdf", StringComparison.OrdinalIgnoreCase) ||
                                       f.EndsWith(".mobi", StringComparison.OrdinalIgnoreCase))
                            .Select(f => Path.GetFileName(f))
                            .ToList();
                        
                        downloadedFiles.AddRange(files);
                    }
                    
                    LogSeries($"Encontrados {downloadedFiles.Count} libros");
                    
                    // Detectar series
                    var seriesList = SeriesDetector.DetectSeries(downloadedFiles);
                    
                    LogSeries($"Detectadas {seriesList.Count} series");
                    
                    // Actualizar ListView
                    lvSeries.Items.Clear();
                    
                    foreach (var series in seriesList)
                    {
                        var item = new ListViewItem(series.SeriesName);
                        item.SubItems.Add(series.Author);
                        item.SubItems.Add($"{series.DownloadedBooks}/{series.TotalBooks} ({series.CompletionPercentage:F0}%)");
                        item.SubItems.Add(series.MissingNumbers.Count.ToString());
                        item.SubItems.Add(series.IsComplete ? "Completa" : "Incompleta");
                        item.Tag = series;
                        
                        // Marcar incompletas
                        if (!series.IsComplete)
                        {
                            item.ForeColor = Color.Yellow;
                        }
                        
                        lvSeries.Items.Add(item);
                    }
                    
                    LogSeries($"Escaneo completado");
                    
                    // Mostrar resumen
                    var incomplete = seriesList.Count(s => !s.IsComplete);
                    if (incomplete > 0)
                    {
                        LogSeries($"{incomplete} series incompletas encontradas");
                    }
                }
                catch (Exception ex)
                {
                    LogSeries($"Error: {ex.Message}");
                }
                finally
                {
                    btnScanLibrary.Enabled = true;
                }
            };
            
            // Evento: Buscar faltantes
            btnSearchMissing.Click += async (s, e) =>
            {
                try
                {
                    var checkedSeries = lvSeries.CheckedItems.Cast<ListViewItem>()
                        .Select(i => i.Tag as SeriesDetector.SeriesInfo)
                        .Where(s => s != null && !s.IsComplete)
                        .ToList();
                    
                    if (checkedSeries.Count == 0)
                    {
                        LogSeries("Selecciona series incompletas para buscar");
                        return;
                    }
                    
                    btnSearchMissing.Enabled = false;
                    LogSeries($"Buscando libros faltantes de {checkedSeries.Count} series...");
                    
                    foreach (var series in checkedSeries)
                    {
                        LogSeries($"Serie: {series.SeriesName} - Faltan: {string.Join(", ", series.MissingNumbers)}");
                        
                        var searchTerms = SeriesDetector.GenerateSearchTerms(series);
                        
                        foreach (var term in searchTerms.Take(3)) // Limitar a 3 búsquedas por serie
                        {
                            LogSeries($"   Buscando: {term}");
                            
                            // Agregar a la cola de búsqueda
                            // SafeInvoke(() =>
                            // {
                            //     if (txtSearch != null)
                            //     {
                            //         txtSearch.Text = term;
                            //     }
                            // });
                            
                            await Task.Delay(500); // Pequeña pausa entre búsquedas
                        }
                    }
                    
                    LogSeries($"Búsqueda completada");
                }
                catch (Exception ex)
                {
                    LogSeries($"Error: {ex.Message}");
                }
                finally
                {
                    btnSearchMissing.Enabled = true;
                }
            };
            
            // Evento: Actualizar
            btnRefresh.Click += (s, e) =>
            {
                btnScanLibrary.PerformClick();
            };
            
            // Evento: Exportar
            btnExport.Click += (s, e) =>
            {
                try
                {
                    var seriesList = lvSeries.Items.Cast<ListViewItem>()
                        .Select(i => i.Tag as SeriesDetector.SeriesInfo)
                        .Where(s => s != null)
                        .ToList();
                    
                    if (seriesList.Count == 0)
                    {
                        LogSeries("No hay series para exportar");
                        return;
                    }
                    
                    var exportPath = Path.Combine(dataDir, "series_report.txt");
                    var lines = new List<string>();
                    
                    lines.Add("═══════════════════════════════════════════════════════");
                    lines.Add($"REPORTE DE SERIES - {DateTime.Now:dd/MM/yyyy HH:mm}");
                    lines.Add("═══════════════════════════════════════════════════════");
                    lines.Add("");
                    
                    foreach (var series in seriesList.OrderBy(s => s.Author).ThenBy(s => s.SeriesName))
                    {
                        lines.Add(SeriesDetector.FormatSeriesInfo(series));
                        
                        if (!series.IsComplete)
                        {
                            lines.Add($"  → Términos de búsqueda:");
                            var terms = SeriesDetector.GenerateSearchTerms(series);
                            foreach (var term in terms.Take(3))
                            {
                                lines.Add($"     • {term}");
                            }
                        }
                        
                        lines.Add("");
                    }
                    
                    System.IO.File.WriteAllLines(exportPath, lines);
                    LogSeries($"Reporte exportado: {exportPath}");
                    
                    System.Diagnostics.Process.Start("notepad.exe", exportPath);
                }
                catch (Exception ex)
                {
                    LogSeries($"Error exportando: {ex.Message}");
                }
            };
            
            parent.Controls.Add(mainLayout);
            
            LogSeries("Pestaña de Series lista");
            LogSeries("Haz clic en 'Escanear Biblioteca' para comenzar");
        }

        private async Task StartDownloadManager()
        {
            if (downloadManagerRunning)
            {
                AutoLog("Gestor de descargas ya está corriendo");
                return;
            }
            
            downloadManagerRunning = true;
            AutoLog("Gestor de descargas iniciado");
            Log("Gestor de descargas iniciado");
            int saveCounter = 0;
            
            while (downloadManagerRunning)
            {
                DownloadTask[] tasksToProcess;
                DownloadTask[] stuckTasks;
                DownloadTask[] failedTasksToRetry;
                List<DownloadTask> oldFailures;
                
                // OPTIMIZACIÓN: Lock corto - solo copiar datos
                lock (downloadQueueLock)
                {
                    // Auto-limpieza de fallidos antiguos (#1)
                    oldFailures = downloadQueue.Where(t => 
                        t.Status == DownloadStatus.Failed && 
                        !t.AutoRetryEnabled &&
                        t.FinalFailureTime.HasValue &&
                        (DateTime.Now - t.FinalFailureTime.Value).TotalDays > 7
                    ).ToList();
                    
                    foreach (var task in oldFailures)
                    {
                        downloadQueue.Remove(task);
                    }
                    
                    var activeDownloads = downloadQueue.Count(t => t.Status == DownloadStatus.Downloading);
                    var pendingTasks = downloadQueue
                        .Where(t => t.Status == DownloadStatus.Queued)
                        .OrderByDescending(t => t.Priority)
                        .ThenBy(t => t.StartTime)
                        .ToArray();
                    
                    // Detectar descargas atascadas (más de 60 segundos en 0%)
                    stuckTasks = downloadQueue.Where(t => 
                        t.Status == DownloadStatus.Downloading && 
                        t.ProgressPercent == 0 && 
                        ((DateTime.Now - t.StartTime)?.TotalSeconds ?? 0) > 60
                    ).ToArray();
                    
                    // Copiar tareas fallidas para procesar fuera del lock
                    var candidateFailed = downloadQueue.Where(t =>
                        t.Status == DownloadStatus.Failed &&
                        t.AutoRetryEnabled &&
                        t.RetryCount < t.MaxRetries
                    ).ToArray();
                    
                    var slotsAvailable = maxSimultaneousDownloads - activeDownloads;
                    tasksToProcess = pendingTasks.Take(slotsAvailable).ToArray();
                    
                    // Log de diagnóstico
                    if (pendingTasks.Length > 0 || activeDownloads > 0)
                    {
                        AutoLog($"Cola: {pendingTasks.Length} pendientes, {activeDownloads} activas, {slotsAvailable} slots disponibles, procesando {tasksToProcess.Length}");
                    }
                    
                    // Filtrar fallidas FUERA del lock principal
                    failedTasksToRetry = candidateFailed.Where(t =>
                    {
                        // Verificar límite global de intentos
                        string fileKey = $"{t.File.FileName}_{t.File.Username}";
                        if (downloadRetryCount.ContainsKey(fileKey) && 
                            downloadRetryCount[fileKey] >= MAX_TOTAL_ATTEMPTS)
                        {
                            t.AutoRetryEnabled = false;
                            t.FinalFailureTime = DateTime.Now;
                            return false;
                        }
                        
                        // MEJORA #8: Aplicar backoff exponencial
                        if (t.LastRetryTime.HasValue)
                        {
                            int retryDelay = GetRetryDelay(t.RetryCount);
                            if ((DateTime.Now - t.LastRetryTime.Value).TotalSeconds <= retryDelay)
                            {
                                return false;
                            }
                        }
                        
                        // Verificar si el proveedor está en blacklist temporal (lock separado, corto)
                        bool isBlacklisted = false;
                        lock (providerBlacklist)
                        {
                            if (providerBlacklist.TryGetValue(t.File.Username, out var data))
                            {
                                isBlacklisted = data.failures >= PROVIDER_BLACKLIST_THRESHOLD && 
                                    (DateTime.Now - data.lastFail).TotalHours < PROVIDER_BLACKLIST_HOURS;
                            }
                        }
                        
                        if (isBlacklisted)
                        {
                            // Proveedor en blacklist, buscar alternativa en lugar de reintentar
                            if (t.RetryCount == 0) // Solo buscar alternativa una vez
                            {
                                _ = Task.Run(async () => await TryFindAlternativeProvider(t));
                            }
                            return false;
                        }
                        
                        return true;
                    })
                    .OrderBy(t => t.File.SizeBytes) // Pequeños primero
                    .ThenByDescending(t => t.Priority)
                    .ToArray();
                }
                
                // Log fuera del lock
                foreach (var task in oldFailures)
                {
                    AutoLog($"Limpiado fallo antiguo (>7 días): {task.File.FileName}");
                }
                
                // Cancelar descargas atascadas y marcar para reintento
                foreach (var stuckTask in stuckTasks)
                {
                    AutoLog($"Descarga atascada detectada: {stuckTask.File.FileName}");
                    stuckTask.CancellationToken?.Cancel();
                    stuckTask.Status = DownloadStatus.Failed;
                    stuckTask.ErrorMessage = "Timeout: Sin progreso en 60 segundos";
                    stuckTask.RetryCount++;
                    stuckTask.LastRetryTime = DateTime.Now;
                    
                    if (stuckTask.RetryCount < stuckTask.MaxRetries)
                    {
                        UpdateDownloadUI(stuckTask, $"Reintentando ({stuckTask.RetryCount}/{stuckTask.MaxRetries})...");
                        AutoLog($"Reintento automático {stuckTask.RetryCount}/{stuckTask.MaxRetries}: {stuckTask.File.FileName}");
                    }
                    else
                    {
                        UpdateDownloadUI(stuckTask, "Timeout (máx. reintentos)");
                        AutoLog($"Máximo de reintentos alcanzado: {stuckTask.File.FileName}");
                        // Buscar proveedor alternativo
                        _ = Task.Run(async () => await TryFindAlternativeProvider(stuckTask));
                    }
                }
                
                // Reintentar descargas fallidas automáticamente
                foreach (var failedTask in failedTasksToRetry)
                {
                    failedTask.Status = DownloadStatus.Queued;
                    failedTask.RetryCount++;
                    failedTask.LastRetryTime = DateTime.Now;
                    failedTask.BytesDownloaded = 0;
                    failedTask.ProgressPercent = 0;
                    
                    UpdateDownloadUI(failedTask, $"Reintento {failedTask.RetryCount}/{failedTask.MaxRetries}...");
                    AutoLog($"Reintento automático {failedTask.RetryCount}/{failedTask.MaxRetries}: {failedTask.File.FileName}");
                }

                foreach (var task in tasksToProcess)
                {
                    AutoLog($"Iniciando descarga: {task.File.FileName} de {task.File.Username}");
                    Log($"Iniciando descarga: {task.File.FileName} de {task.File.Username}");
                    _ = Task.Run(async () => await ProcessDownload(task));
                }

                // Guardar cola cada 30 segundos (60 iteraciones * 500ms)
                saveCounter++;
                if (saveCounter >= 60)
                {
                    _ = SaveDownloadQueueAsync(); // Solo usar versión async
                    saveCounter = 0;
                }

                await Task.Delay(500);
            }
        }

        private async Task ProcessDownload(DownloadTask task)
        {
            task.Status = DownloadStatus.Downloading;
            task.StartTime = DateTime.Now;
            task.CancellationToken = new CancellationTokenSource();
            
            // Búsqueda proactiva de múltiples fuentes (#5)
            if (!task.IsMultiSource && task.RetryCount == 0)
            {
                try
                {
                    var sources = await FindMultipleSources(task.File, maxSources: 3);
                    if (sources.Count > 1)
                    {
                        task.IsMultiSource = true;
                        task.AlternativeSources = sources;
                        AutoLog($"{sources.Count} fuentes encontradas, usando multi-source para: {task.File.FileName}");
                    }
                }
                catch (Exception ex)
                {
                    AutoLog($"No se pudieron buscar fuentes múltiples: {ex.Message}");
                }
            }
            
            // Si hay múltiples fuentes, usar descarga multi-source
            if (task.IsMultiSource && task.AlternativeSources.Count > 1)
            {
                AutoLog($"Iniciando descarga multi-source: {task.File.FileName}");
                await DownloadMultiSource(task);
                return;
            }

            // Verificar si hay descarga parcial existente
            long startPosition = 0;
            if (System.IO.File.Exists(task.LocalPath))
            {
                var fileInfo = new FileInfo(task.LocalPath);
                if (fileInfo.Length > 0 && fileInfo.Length < task.File.SizeBytes)
                {
                    startPosition = fileInfo.Length;
                    task.BytesDownloaded = startPosition;
                    task.ProgressPercent = (double)startPosition / task.File.SizeBytes * 100;
                    AutoLog($"Reanudando descarga desde {FormatFileSize(startPosition)}: {task.File.FileName}");
                }
            }

            UpdateDownloadUI(task, $"Descargando... {task.ProgressPercent:F1}%");

            try
            {
                // Verificar disponibilidad del usuario antes de descargar (con timeout)
                try
                {
                    using var timeoutCts = new CancellationTokenSource(TimeSpan.FromSeconds(5));
                    var userInfo = await client.GetUserInfoAsync(task.File.Username, timeoutCts.Token);
                    if (userInfo.HasFreeUploadSlot || userInfo.QueueLength < 10)
                    {
                        AutoLog($"Usuario {task.File.Username} disponible (Queue: {userInfo.QueueLength})");
                    }
                    else
                    {
                        AutoLog($"Usuario {task.File.Username} ocupado (Queue: {userInfo.QueueLength})");
                    }
                }
                catch (OperationCanceledException)
                {
                    AutoLog($"Timeout verificando disponibilidad de {task.File.Username}");
                }
                catch
                {
                    // Si falla la verificación, continuar de todos modos
                }
                
                var remotePath = Path.Combine(task.File.Directory, task.File.FileName).Replace("/", "\\");
                
                // Optimización #19: Streaming con backpressure (20-30% menos memoria)
                await client.DownloadAsync(
                    task.File.Username,
                    remotePath,
                    () => Task.FromResult<Stream>(new FileStream(
                        task.LocalPath, 
                        FileMode.OpenOrCreate,
                        FileAccess.Write,
                        FileShare.None,
                        bufferSize: 81920, // 80KB buffer (óptimo para streaming)
                        useAsync: true
                    )),
                    task.File.SizeBytes,
                    startOffset: startPosition,
                    cancellationToken: task.CancellationToken.Token,
                    options: new TransferOptions(
                        stateChanged: (args) =>
                        {
                            if (args.Transfer.State.HasFlag(TransferStates.InProgress))
                            {
                                task.BytesDownloaded = startPosition + args.Transfer.BytesTransferred;
                                task.ProgressPercent = (double)task.BytesDownloaded / task.File.SizeBytes * 100;
                                task.SpeedMBps = args.Transfer.AverageSpeed / 1024.0 / 1024.0;
                                task.LastSpeedMeasurement = args.Transfer.AverageSpeed; // En bytes/s para el gráfico
                                
                                var status = $"{task.ProgressPercent:F1}% - {task.SpeedMBps:F2} MB/s";
                                UpdateDownloadUI(task, status);
                            }
                        },
                        progressUpdated: (args) =>
                        {
                            task.BytesDownloaded = startPosition + args.Transfer.BytesTransferred;
                            task.ProgressPercent = (double)task.BytesDownloaded / task.File.SizeBytes * 100;
                            
                            var elapsed = (DateTime.Now - task.StartTime)?.TotalSeconds ?? 0;
                            if (elapsed > 0)
                            {
                                task.SpeedMBps = (task.BytesDownloaded / elapsed) / 1024.0 / 1024.0;
                            }
                            
                            // Verificar si la descarga es muy lenta y buscar alternativa
                            _ = Task.Run(async () => await CheckSlowDownloadAndFindAlternative(task));
                        }
                    )
                );

                task.Status = DownloadStatus.Completed;
                task.EndTime = DateTime.Now;
                task.ProgressPercent = 100;
                
                // Velocidad adaptativa: registrar velocidad y ajustar descargas paralelas
                if (adaptiveSpeed && task.SpeedMBps > 0)
                {
                    UpdateAdaptiveSpeed(task.SpeedMBps);
                }
                
                // Invalidar caché del archivo descargado
                InvalidateFileCache(task.LocalPath);
                
                // Verificar integridad con hash BLAKE3 (ultra-rápido)
                string fileHash = null;
                try
                {
                    // Verificar que el archivo existe y la ruta es válida
                    if (!string.IsNullOrEmpty(task.LocalPath) && System.IO.File.Exists(task.LocalPath))
                    {
                        fileHash = SlskDownCore.HashFileBlake3(task.LocalPath);
                        
                        if (!string.IsNullOrEmpty(fileHash))
                        {
                            AutoLog($"Hash verificado: {fileHash.Substring(0, 16)}...");
                            
                            // Optimización #15: Verificar duplicados y crear hardlink si existe
                            var existingPath = CheckDuplicateFile(task.LocalPath, fileHash);
                            if (existingPath != null)
                            {
                                // Archivo duplicado encontrado, crear hardlink
                                var fileInfo = new FileInfo(task.LocalPath);
                                var savedSpace = fileInfo.Length;
                                
                                System.IO.File.Delete(task.LocalPath);
                                CreateHardLink(existingPath, task.LocalPath);
                                
                                AutoLog($"Espacio ahorrado: {FormatFileSize(savedSpace)}");
                            }
                        }
                    }
                    else
                    {
                        AutoLog($"No se puede calcular hash: archivo no existe o ruta inválida");
                    }
                }
                catch (Exception hashEx)
                {
                    AutoLog($"No se pudo calcular hash: {hashEx.Message}");
                }
                
                // Renombrar a formato Calibre si es un ebook
                RenameToLibreFormat(task.LocalPath, task.File.Author);
                
                // Notificación de descarga completada
                ShowNotification("Descarga completada", 
                    $"{task.File.FileName}\n\nTamaño: {task.File.SizeReadable} | Velocidad: {task.SpeedMBps:F2} MB/s", 
                    ToolTipIcon.Info);
                
                // Registrar en log general
                Log($"Descarga completada: {task.File.FileName} ({task.File.SizeReadable}) - {task.SpeedMBps:F2} MB/s");
                
                // Registrar en historial con hash para verificación futura
                lock (downloadHistoryLock)
                {
                    downloadHistory.Add(new DownloadHistory
                    {
                        FileName = task.File.FileName,
                        Author = task.File.Author,
                        Username = task.File.Username,
                        SizeBytes = task.File.SizeBytes,
                        DownloadedAt = DateTime.Now,
                        Status = "Completed",
                        SpeedMBps = task.SpeedMBps,
                        Hash = fileHash // BLAKE3 hash for integrity verification
                    });
                    // Actualizar caché HashSet para lookups O(1)
                    downloadHistoryCache.Add(task.File.FileName);
                }

                // Actualizar estadísticas
                statistics.TotalFilesDownloaded++;
                statistics.TotalBytesDownloaded += task.File.SizeBytes;
                var downloadTime = (task.EndTime.Value - task.StartTime)?.TotalSeconds ?? 0;
                if (downloadTime > 0)
                {
                    var totalTime = statistics.TotalDownloadTime.TotalSeconds + downloadTime;
                    statistics.TotalDownloadTime = TimeSpan.FromSeconds(totalTime);
                    statistics.AverageDownloadSpeed = (statistics.TotalBytesDownloaded / totalTime) / 1024.0 / 1024.0;
                }

                SaveDownloadHistory();
                SaveStatistics();
                
                // Optimización #2: Descarga predictiva - pre-buscar siguiente archivo
                lock (downloadQueueLock)
                {
                    var nextTask = downloadQueue
                        .Where(t => t.Status == DownloadStatus.Queued)
                        .OrderByDescending(t => t.Priority)
                        .FirstOrDefault();
                    
                    if (nextTask != null && nextTask.AlternativeSources.Count == 0)
                    {
                        _ = Task.Run(async () =>
                        {
                            try
                            {
                                AutoLog($"Pre-buscando fuentes para: {nextTask.File.FileName}");
                                var sources = await FindMultipleSources(nextTask.File, maxSources: 3);
                                if (sources.Count > 0)
                                {
                                    nextTask.AlternativeSources.AddRange(sources.Take(3));
                                    AutoLog($"{sources.Count} fuentes pre-cargadas para: {nextTask.File.FileName}");
                                }
                            }
                            catch { }
                        });
                    }
                }
                
                // Actualizar estadísticas del proveedor
                UpdateProviderStats(task.File.Username, true, task.SpeedMBps, task.File.SizeBytes);
                SaveProviderStatsToDatabase();
                
                // Invalidar cache para este archivo
                InvalidateFileCache(task.LocalPath);
                
                // Optimización #1: Caché de validación de archivos
                bool isValidFile = true;
                bool needsValidation = true;
                
                // Verificar caché primero (1000x más rápido)
                if (validationCache.TryGetValue(task.LocalPath, out var cached))
                {
                    // Validar solo si tiene >1 día o tamaño cambió
                    var fileInfo = new FileInfo(task.LocalPath);
                    if ((DateTime.Now - cached.validated).TotalDays < 1 && 
                        fileInfo.Length == task.File.SizeBytes)
                    {
                        needsValidation = false;
                        AutoLog($"Validación en caché: {task.File.FileName}");
                    }
                }
                
                if (needsValidation)
                {
                    try
                    {
                        if (!SlskDownCore.ValidateFile(task.LocalPath))
                        {
                            AutoLog($"Archivo corrupto detectado: {task.File.FileName}");
                            
                            // Intentar reparar
                            if (SlskDownCore.RepairFile(task.LocalPath))
                            {
                                AutoLog($"Archivo reparado automáticamente: {task.File.FileName}");
                                isValidFile = true;
                            }
                            else
                            {
                                AutoLog($"No se pudo reparar el archivo: {task.File.FileName}");
                                isValidFile = false;
                            }
                        }
                        
                        // Cachear resultado
                        if (isValidFile)
                        {
                            validationCache[task.LocalPath] = ("", DateTime.Now);
                        }
                    }
                    catch (Exception valEx)
                    {
                        AutoLog($"Error validando archivo con Rust: {valEx.Message}");
                        // Continuar sin validación Rust
                    }
                }
                
                if (isValidFile)
                {
                    // Organizar archivo automáticamente
                    var organizedPath = OrganizeDownloadedFile(task.LocalPath, task.File);
                    task.LocalPath = organizedPath;
                    
                    UpdateDownloadUI(task, "Completado");
                    AutoLog($"Descarga completada y verificada: {task.File.FileName}");
                    Log($"Descarga verificada: {task.File.FileName}");
                    
                    // MEJORA #5: Verificar hitos de progreso
                    CheckProgressMilestone();
                }
                else
                {
                    UpdateDownloadUI(task, "Corrupto");
                    AutoLog($"Descarga completada pero archivo corrupto: {task.File.FileName}");
                    Log($"Archivo corrupto: {task.File.FileName}");
                }
            }
            catch (OperationCanceledException)
            {
                // Solo marcar como cancelado si no fue marcado como fallido previamente
                // (las cancelaciones automáticas por lentitud ya están marcadas como Failed)
                if (task.Status != DownloadStatus.Failed)
                {
                    task.Status = DownloadStatus.Cancelled;
                    task.EndTime = DateTime.Now;
                    UpdateDownloadUI(task, "Cancelado");
                    AutoLog($"Descarga cancelada manualmente: {task.File.FileName}");
                    
                    // Eliminar archivo incompleto
                    DeleteIncompleteFile(task.LocalPath, "cancelada");
                }
                else
                {
                    // Ya fue marcado como Failed (cancelación automática)
                    AutoLog($"Descarga interrumpida (reintento automático): {task.File.FileName}");
                }
            }
            catch (Exception ex)
            {
                task.Status = DownloadStatus.Failed;
                task.EndTime = DateTime.Now;
                task.ErrorMessage = ex.Message;
                task.LastRetryTime = DateTime.Now;
                
                // MEJORA #1: Detección agresiva de usuarios offline
                if (ex.Message.Contains("appears to be offline", StringComparison.OrdinalIgnoreCase))
                {
                    lock (providerBlacklist)
                    {
                        providerBlacklist[task.File.Username] = (PROVIDER_BLACKLIST_THRESHOLD, DateTime.Now);
                        AutoLog($"Usuario {task.File.Username} offline detectado, blacklist inmediata");
                    }
                    
                    // Buscar proveedor alternativo inmediatamente
                    _ = Task.Run(async () => await TryFindAlternativeProvider(task));
                }
                
                // Modo agresivo para archivos difíciles (#7)
                if (task.RetryCount >= 2)
                {
                    task.MaxRetries = 5; // Más reintentos
                    AutoLog($"Modo agresivo activado para: {task.File.FileName}");
                }
                
                // Determinar si se reintentará automáticamente
                if (task.AutoRetryEnabled && task.RetryCount < task.MaxRetries)
                {
                    // MEJORA #8: Mostrar tiempo de espera con backoff exponencial
                    int retryDelay = GetRetryDelay(task.RetryCount);
                    UpdateDownloadUI(task, $"Error (reintento {task.RetryCount + 1}/{task.MaxRetries} en {retryDelay}s)");
                    AutoLog($"Error: {task.File.FileName} - {ex.Message} (reintento {task.RetryCount + 1}/{task.MaxRetries} en {retryDelay}s)");
                }
                else
                {
                    task.FinalFailureTime = DateTime.Now; // Marcar fallo definitivo (#1)
                    UpdateDownloadUI(task, $"Error: {ex.Message}");
                    AutoLog($"Fallo definitivo: {task.File.FileName} - {ex.Message}");
                    
                    // Eliminar archivo incompleto en fallo definitivo
                    DeleteIncompleteFile(task.LocalPath, "fallida");
                    
                    // Notificación consolidada (#9)
                    ShowNotification("Descarga fallida", 
                        $"{task.File.FileName}\n\nError: {ex.Message}\n\nReintentos: {task.MaxRetries}", 
                        ToolTipIcon.Error);
                    
                    // Intentar buscar proveedor alternativo solo después de agotar reintentos
                    _ = Task.Run(async () => await TryFindAlternativeProvider(task));
                }
                
                // Actualizar estadísticas del proveedor (fallo) y blacklist temporal (#8)
                UpdateProviderStats(task.File.Username, false, 0, 0);
                SaveProviderStatsToDatabase();
                
                // Agregar a blacklist temporal si falla repetidamente
                lock (providerBlacklist)
                {
                    if (providerBlacklist.TryGetValue(task.File.Username, out var data))
                    {
                        providerBlacklist[task.File.Username] = (data.failures + 1, DateTime.Now);
                        
                        if (data.failures + 1 >= PROVIDER_BLACKLIST_THRESHOLD)
                        {
                            AutoLog($"Proveedor {task.File.Username} en blacklist temporal ({data.failures + 1} fallos)");
                        }
                    }
                    else
                    {
                        providerBlacklist[task.File.Username] = (1, DateTime.Now);
                    }
                }
            }
        }
        
        private async Task SearchFailedInOtherUsers()
        {
            try
            {
                List<DownloadTask> failedTasks;
                lock (downloadQueueLock)
                {
                    failedTasks = downloadQueue.Where(t => t.Status == DownloadStatus.Failed).ToList();
                }
                
                if (failedTasks.Count == 0)
                {
                    MessageBox.Show("No hay archivos fallidos para buscar.", "Sin archivos fallidos", MessageBoxButtons.OK, MessageBoxIcon.Information);
                    return;
                }
                
                var result = MessageBox.Show(
                    $"Se buscarán {failedTasks.Count} archivo(s) fallido(s) en otros usuarios.\n\n" +
                    "Esta operación puede tardar varios minutos.\n\n" +
                    "¿Deseas continuar?",
                    "Buscar en Otros Usuarios",
                    MessageBoxButtons.YesNo,
                    MessageBoxIcon.Question
                );
                
                if (result != DialogResult.Yes)
                    return;
                
                Log($"Iniciando búsqueda de {failedTasks.Count} archivo(s) fallido(s) en otros usuarios...");
                
                int foundCount = 0;
                int notFoundCount = 0;
                int errorCount = 0;
                
                foreach (var task in failedTasks)
                {
                    try
                    {
                        Log($"Buscando: {task.File.FileName}");
                        UpdateDownloadUI(task, "Buscando en otros usuarios...");
                        
                        // Usar cliente del pool para búsqueda
                        var searchClient = GetClientFromPool();
                        var searchResults = await searchClient.SearchAsync(
                            SearchQuery.FromText(task.File.FileName),
                            options: new Soulseek.SearchOptions(
                                searchTimeout: 20000,
                                filterResponses: true,
                                minimumResponseFileCount: 1
                            )
                        );
                        
                        // MEJORA #3: Buscar proveedores alternativos excluyendo blacklist
                        var alternatives = searchResults.Responses
                            .Where(r => 
                            {
                                // Excluir proveedor original
                                if (r.Username.Equals(task.File.Username, StringComparison.OrdinalIgnoreCase))
                                    return false;
                                
                                // Excluir proveedores en blacklist temporal
                                lock (providerBlacklist)
                                {
                                    if (providerBlacklist.TryGetValue(r.Username, out var data))
                                    {
                                        if (data.failures >= PROVIDER_BLACKLIST_THRESHOLD && 
                                            (DateTime.Now - data.lastFail).TotalHours < PROVIDER_BLACKLIST_HOURS)
                                        {
                                            return false;
                                        }
                                    }
                                }
                                
                                return true;
                            })
                            .SelectMany(r => r.Files.Select(f => new { Response = r, File = f }))
                            .Where(item => 
                                item.File.Filename.Equals(task.File.FileName, StringComparison.OrdinalIgnoreCase) &&
                                Math.Abs(item.File.Size - task.File.SizeBytes) < 1024 * 100) // Tolerancia de 100KB
                            .OrderByDescending(item =>
                            {
                                var stats = GetProviderStats(item.Response.Username);
                                return stats != null ? stats.QualityScore : item.File.Size / 1024.0 / 1024.0;
                            })
                            .ToList();
                        
                        if (alternatives.Count > 0)
                        {
                            var alternative = alternatives.First();
                            Log($"Encontrado en: {alternative.Response.Username} ({alternatives.Count} alternativa(s))");
                            
                            // Crear nuevo AutoSearchFileResult con el proveedor alternativo
                            var newFile = new AutoSearchFileResult
                            {
                                FileName = task.File.FileName,
                                Author = task.File.Author,
                                Username = alternative.Response.Username,
                                Directory = alternative.File.Filename.Contains("\\") ? 
                                    alternative.File.Filename.Substring(0, alternative.File.Filename.LastIndexOf("\\")) : "",
                                SizeBytes = alternative.File.Size,
                                SizeReadable = FormatFileSize(alternative.File.Size),
                                IsSpanish = task.File.IsSpanish,
                                IsDocument = task.File.IsDocument,
                                Timestamp = DateTime.Now
                            };
                            
                            // Actualizar la tarea con el nuevo proveedor
                            task.File = newFile;
                            task.Status = DownloadStatus.Queued;
                            task.RetryCount = 0;
                            task.ErrorMessage = null;
                            task.FinalFailureTime = null;
                            task.LastRetryTime = null;
                            
                            UpdateDownloadUI(task, $"En cola (nuevo: {alternative.Response.Username})");
                            foundCount++;
                        }
                        else
                        {
                            Log($"No se encontraron alternativas para: {task.File.FileName}");
                            UpdateDownloadUI(task, "Sin alternativas disponibles");
                            notFoundCount++;
                        }
                        
                        // Pequeña pausa entre búsquedas
                        await Task.Delay(500);
                    }
                    catch (Exception ex)
                    {
                        Log($"Error buscando {task.File.FileName}: {ex.Message}");
                        errorCount++;
                    }
                }
                
                var summary = $"Búsqueda completada:\n\n" +
                             $"Encontrados: {foundCount}\n" +
                             $"No encontrados: {notFoundCount}\n" +
                             $"Errores: {errorCount}\n\n" +
                             $"Los archivos encontrados se agregarán a la cola de descargas.";
                
                Log($"{summary.Replace("\n", " ")}");
                MessageBox.Show(summary, "Búsqueda Completada", MessageBoxButtons.OK, MessageBoxIcon.Information);
            }
            catch (Exception ex)
            {
                Log($"Error en SearchFailedInOtherUsers: {ex.Message}");
                MessageBox.Show($"Error buscando archivos:\n{ex.Message}", "Error", MessageBoxButtons.OK, MessageBoxIcon.Error);
            }
        }
        
        private async Task TryFindAlternativeProvider(DownloadTask failedTask)
        {
            try
            {
                // Verificar límite de reintentos
                string fileKey = $"{failedTask.File.FileName}_{failedTask.File.SizeBytes}";
                
                lock (downloadQueueLock)
                {
                    if (!downloadRetryCount.ContainsKey(fileKey))
                    {
                        downloadRetryCount[fileKey] = 0;
                    }
                    
                    downloadRetryCount[fileKey]++;
                    
                    // Verificar límite global absoluto
                    if (downloadRetryCount[fileKey] >= MAX_TOTAL_ATTEMPTS)
                    {
                        AutoLog($"LÍMITE GLOBAL alcanzado ({MAX_TOTAL_ATTEMPTS} intentos) para: {failedTask.File.FileName}");
                        UpdateDownloadUI(failedTask, $"Fallo definitivo ({downloadRetryCount[fileKey]} intentos)");
                        failedTask.Status = DownloadStatus.Failed;
                        failedTask.FinalFailureTime = DateTime.Now;
                        failedTask.AutoRetryEnabled = false;
                        return;
                    }
                    
                    // Verificar límite de proveedores alternativos
                    if (downloadRetryCount[fileKey] > maxAlternativeRetries)
                    {
                        AutoLog($"Límite de alternativas alcanzado ({maxAlternativeRetries}) para: {failedTask.File.FileName}");
                        UpdateDownloadUI(failedTask, $"Sin alternativas ({downloadRetryCount[fileKey]} intentos)");
                        failedTask.Status = DownloadStatus.Failed;
                        failedTask.FinalFailureTime = DateTime.Now;
                        failedTask.AutoRetryEnabled = false;
                        return;
                    }
                }
                
                AutoLog($"Buscando proveedor alternativo para: {failedTask.File.FileName} (intento {downloadRetryCount[fileKey]}/{maxAlternativeRetries})");
                UpdateDownloadUI(failedTask, "Buscando alternativa...");
                
                // Optimización #8: Usar cliente del pool
                var searchClient = GetClientFromPool();
                var searchResults = await searchClient.SearchAsync(
                    SearchQuery.FromText(failedTask.File.FileName),
                    options: new Soulseek.SearchOptions(
                        searchTimeout: 15000,
                        filterResponses: true,
                        minimumResponseFileCount: 1
                    )
                );
                
                // Buscar proveedores alternativos (excluir el que falló y blacklist temporal #8)
                var alternatives = searchResults.Responses
                    .Where(r => 
                    {
                        // Excluir el que falló
                        if (r.Username.Equals(failedTask.File.Username, StringComparison.OrdinalIgnoreCase))
                            return false;
                        
                        // Excluir proveedores en blacklist temporal
                        lock (providerBlacklist)
                        {
                            if (providerBlacklist.TryGetValue(r.Username, out var data))
                            {
                                if (data.failures >= PROVIDER_BLACKLIST_THRESHOLD && 
                                    (DateTime.Now - data.lastFail).TotalHours < PROVIDER_BLACKLIST_HOURS)
                                {
                                    AutoLog($"Proveedor {r.Username} en blacklist temporal, omitiendo");
                                    return false;
                                }
                            }
                        }
                        
                        return true;
                    })
                    .SelectMany(r => r.Files.Select(f => new { Response = r, File = f }))
                    .Where(item => 
                        item.File.Filename.Equals(failedTask.File.FileName, StringComparison.OrdinalIgnoreCase) &&
                        Math.Abs(item.File.Size - failedTask.File.SizeBytes) < 1024 * 100) // Tolerancia de 100KB
                    .OrderByDescending(item =>
                    {
                        // Ordenar por calidad del proveedor si existe, sino por tamaño
                        var stats = GetProviderStats(item.Response.Username);
                        return stats != null ? stats.QualityScore : item.File.Size / 1024.0 / 1024.0;
                    })
                    .ToList();
                
                if (alternatives.Count > 0)
                {
                    var alternative = alternatives.First();
                    AutoLog($"Proveedor alternativo encontrado: {alternative.Response.Username}");
                    AutoLog($"   {alternatives.Count} alternativa(s) disponible(s)");
                    
                    // Crear nueva tarea con el proveedor alternativo
                    var newFile = new AutoSearchFileResult
                    {
                        Author = failedTask.File.Author,
                        Username = alternative.Response.Username,
                        FileName = alternative.File.Filename,
                        Directory = Path.GetDirectoryName(alternative.File.Filename) ?? "",
                        SizeBytes = alternative.File.Size,
                        SizeReadable = FormatFileSize(alternative.File.Size),
                        IsSpanish = failedTask.File.IsSpanish,
                        IsDocument = failedTask.File.IsDocument,
                        Timestamp = DateTime.Now
                    };
                    
                    // Actualizar UI con nuevo proveedor
                    SafeInvoke(() =>
                    {
                        if (failedTask.ListViewItem != null)
                        {
                            failedTask.ListViewItem.SubItems[1].Text = alternative.Response.Username;
                        }
                    });
                    
                    // Agregar nueva descarga a la cola
                    AddToDownloadQueue(newFile, failedTask.LocalPath, failedTask.ListViewItem, true);
                    
                    AutoLog($"Reintentando descarga desde: {alternative.Response.Username}");
                }
                else
                {
                    AutoLog($"No se encontraron proveedores alternativos para: {failedTask.File.FileName}");
                    UpdateDownloadUI(failedTask, "Sin alternativas");
                }
            }
            catch (Exception ex)
            {
                AutoLog($"Error buscando proveedor alternativo: {ex.Message}");
                UpdateDownloadUI(failedTask, $"Error: {failedTask.ErrorMessage}");
            }
        }
        
        private async Task CheckSlowDownloadAndFindAlternative(DownloadTask task)
        {
            try
            {
                // Verificar si ha pasado suficiente tiempo desde el inicio
                var elapsed = (DateTime.Now - task.StartTime)?.TotalSeconds ?? 0;
                if (elapsed < SLOW_DOWNLOAD_CHECK_SECONDS)
                    return;
                
                // Verificar si es momento de hacer otra verificación
                var timeSinceLastCheck = (DateTime.Now - task.LastSpeedCheck).TotalSeconds;
                if (timeSinceLastCheck < SLOW_DOWNLOAD_CHECK_SECONDS)
                    return;
                
                // Calcular velocidad actual en KB/s
                long bytesSinceLastCheck = task.BytesDownloaded - task.LastBytesDownloaded;
                double speedKBps = (bytesSinceLastCheck / timeSinceLastCheck) / 1024.0;
                
                task.LastSpeedCheck = DateTime.Now;
                task.LastBytesDownloaded = task.BytesDownloaded;
                
                // Verificar si la velocidad es muy lenta
                if (speedKBps < MIN_SPEED_KBPS)
                {
                    task.SlowDownloadChecks++;
                    AutoLog($"Descarga lenta detectada: {task.File.FileName} ({speedKBps:F2} KB/s) - Check {task.SlowDownloadChecks}/{SLOW_DOWNLOAD_THRESHOLD_CHECKS}");
                    
                    // Si se alcanza el umbral, buscar alternativa
                    if (task.SlowDownloadChecks >= SLOW_DOWNLOAD_THRESHOLD_CHECKS)
                    {
                        AutoLog($"Descarga demasiado lenta, buscando proveedor alternativo: {task.File.FileName}");
                        
                        // Marcar como fallida (no cancelada) para que se reintente
                        task.Status = DownloadStatus.Failed;
                        task.ErrorMessage = "Velocidad muy lenta (< 10 KB/s)";
                        task.CancellationToken?.Cancel();
                        
                        UpdateDownloadUI(task, "Buscando alternativa (muy lento)...");
                        
                        // Buscar proveedor alternativo
                        await TryFindAlternativeProvider(task);
                    }
                }
                else
                {
                    // Resetear contador si la velocidad mejora
                    if (task.SlowDownloadChecks > 0)
                    {
                        AutoLog($"Velocidad mejorada: {task.File.FileName} ({speedKBps:F2} KB/s)");
                        task.SlowDownloadChecks = 0;
                    }
                }
            }
            catch (Exception ex)
            {
                AutoLog($"Error verificando velocidad de descarga: {ex.Message}");
            }
        }
        
        private void UpdateRealtimeStats()
        {
            if (lblRealtimeStats == null || downloadQueue == null) return;
            
            try
            {
                lock (downloadQueueLock)
                {
                    var downloading = downloadQueue.Count(t => t.Status == DownloadStatus.Downloading);
                    var pending = downloadQueue.Count(t => t.Status == DownloadStatus.Queued);
                    var paused = downloadQueue.Count(t => t.Status == DownloadStatus.Paused);
                    var completed = downloadQueue.Count(t => t.Status == DownloadStatus.Completed);
                    var failed = downloadQueue.Count(t => t.Status == DownloadStatus.Failed);
                    
                    // Calcular velocidad promedio de descargas activas
                    var activeDownloads = downloadQueue.Where(t => t.Status == DownloadStatus.Downloading && t.SpeedMBps > 0).ToList();
                    double avgSpeed = activeDownloads.Any() ? activeDownloads.Average(t => t.SpeedMBps) : 0;
                    
                    // Calcular tamaño total completado
                    long totalBytes = downloadQueue.Where(t => t.Status == DownloadStatus.Completed).Sum(t => t.File.SizeBytes);
                    string totalSize = FormatFileSize(totalBytes);
                    
                    // Contar archivos con alternativa
                    int withAlternative = downloadRetryCount.Count(kvp => kvp.Value > 1 && kvp.Value <= maxAlternativeRetries);
                    
                    SafeInvoke(() =>
                    {
                        lblRealtimeStats.Text = $"{downloading} descargando | {pending} en cola | {paused} pausadas | " +
                                               $"{completed} ({totalSize}) | {failed} fallidos | " +
                                               $"{withAlternative} con alternativa | {avgSpeed:F1} MB/s";
                    });
                    
                    // Notificar cuando todas las descargas se completen
                    var total = downloadQueue.Count;
                    if (total > 0 && pending == 0 && downloading == 0 && !allDownloadsCompletedNotified)
                    {
                        allDownloadsCompletedNotified = true;
                        ShowNotification("Todas las descargas completadas", 
                            $"Finalizadas {completed} descargas exitosas\n\n" +
                            $"Total descargado: {totalSize}\n" +
                            $"Fallidas: {failed}", 
                            ToolTipIcon.Info);
                        AutoLog($"Todas las descargas completadas: {completed} exitosas, {failed} fallidas");
                    }
                    
                    // Resetear flag si hay nuevas descargas
                    if (pending > 0 || downloading > 0)
                    {
                        allDownloadsCompletedNotified = false;
                    }
                }
            }
            catch
            {
                // Ignorar errores en actualización de stats
            }
        }

        private void DeleteIncompleteFile(string filePath, string reason)
        {
            try
            {
                if (System.IO.File.Exists(filePath))
                {
                    var fileInfo = new FileInfo(filePath);
                    long fileSize = fileInfo.Length;
                    
                    System.IO.File.Delete(filePath);
                    AutoLog($"Archivo incompleto eliminado ({reason}): {Path.GetFileName(filePath)} ({FormatFileSize(fileSize)})");
                }
            }
            catch (Exception ex)
            {
                AutoLog($"No se pudo eliminar archivo incompleto: {ex.Message}");
            }
        }

        private void UpdateDownloadUI(DownloadTask task, string status)
        {
            if (task.ListViewItem != null && task.ListViewItem.ListView != null)
            {
                SafeInvoke(() =>
                {
                    // Actualizar progreso (columna 2)
                    if (task.ProgressPercent > 0)
                    {
                        string progressText = $"{task.ProgressPercent:F1}%";
                        
                        // Agregar tiempo restante si está descargando
                        if (task.Status == DownloadStatus.Downloading && task.EstimatedTimeRemaining != TimeSpan.MaxValue)
                        {
                            var eta = task.EstimatedTimeRemaining;
                            if (eta.TotalHours >= 1)
                                progressText += $" (ETA: {eta.Hours}h {eta.Minutes}m)";
                            else if (eta.TotalMinutes >= 1)
                                progressText += $" (ETA: {eta.Minutes}m {eta.Seconds}s)";
                            else
                                progressText += $" (ETA: {eta.Seconds}s)";
                        }
                        
                        task.ListViewItem.SubItems[2].Text = progressText;
                    }
                    
                    // Actualizar estado (columna 3)
                    task.ListViewItem.SubItems[3].Text = status;
                    
                    // Actualizar color según estado
                    task.ListViewItem.ForeColor = task.Status switch
                    {
                        DownloadStatus.Completed => Color.LightGreen,
                        DownloadStatus.Downloading => Color.LightBlue,
                        DownloadStatus.Failed => Color.Red,
                        DownloadStatus.Cancelled => Color.Orange,
                        DownloadStatus.Paused => Color.Yellow,
                        _ => Color.LightGray
                    };
                });
            }
        }

        private void AddToDownloadQueue(AutoSearchFileResult file, string localPath, ListViewItem listItem, bool forceRedownload = false)
        {
            DownloadTask task;
            
            lock (downloadQueueLock)
            {
                // Validar que el archivo no sea basura o tenga nombre inválido
                if (IsGarbageFile(file.FileName))
                {
                    AutoLog($"Archivo basura ignorado: {file.FileName}");
                    return;
                }
                
                // Verificar si está blacklisteado
                if (IsFileBlacklisted(file.FileName, file.Username))
                {
                    AutoLog($"Archivo blacklisteado ignorado: {file.FileName}");
                    return;
                }
                
                // Verificar si ya está en cola
                if (downloadQueue.Any(t => t.File.FileName == file.FileName && t.File.Username == file.Username))
                {
                    // No loguear si ya se mostró antes (evitar spam)
                    return;
                }
                
                // Detectar duplicados en carpeta de descargas (si no es forzado)
                if (!forceRedownload && System.IO.File.Exists(localPath))
                {
                    var existingFileInfo = new FileInfo(localPath);
                    long sizeDiff = Math.Abs(existingFileInfo.Length - file.SizeBytes);
                    
                    // Si el archivo existe y tiene tamaño similar (±1KB)
                    if (sizeDiff < 1024)
                    {
                        AutoLog($"Duplicado omitido: {file.FileName} ya existe ({FormatFileSize(existingFileInfo.Length)})");
                        
                        // Omitir automáticamente sin preguntar (para evitar bloqueos con grandes volúmenes)
                        if (listItem != null)
                        {
                            Task.Run(() =>
                            {
                                SafeInvoke(() =>
                                {
                                    if (listItem != null && !listItem.ListView.IsDisposed)
                                    {
                                        listItem.SubItems[3].Text = "Ya existe";
                                        listItem.ForeColor = Color.Gray;
                                    }
                                });
                            });
                        }
                        return;
                    }
                }

                task = new DownloadTask
                {
                    File = file,
                    LocalPath = localPath,
                    Status = DownloadStatus.Queued,
                    ListViewItem = listItem,
                    Priority = IsGutenbergAuthor(file.Author) ? DownloadPriority.High : DownloadPriority.Normal
                };
                
                // Habilitar multi-source para archivos grandes (>50MB)
                if (file.SizeBytes > 50 * 1024 * 1024)
                {
                    _ = Task.Run(async () =>
                    {
                        var sources = await FindMultipleSources(file, 3);
                        if (sources.Count > 1)
                        {
                            task.AlternativeSources = sources;
                            task.IsMultiSource = true;
                            AutoLog($"Multi-source habilitado para {file.FileName}: {sources.Count} fuentes");
                        }
                    });
                }

                // MEJORA #14: Insertar según prioridad (Gutenberg > tamaño)
                int insertIndex = downloadQueue.Count;
                bool isGutenberg = task.Priority == DownloadPriority.High;
                
                if (isGutenberg || priorityBySize)
                {
                    // Buscar posición correcta
                    for (int i = 0; i < downloadQueue.Count; i++)
                    {
                        var existing = downloadQueue[i];
                        if (existing.Status != DownloadStatus.Queued)
                            continue;
                            
                        // Prioridad 1: Autores Gutenberg primero
                        if (isGutenberg && existing.Priority != DownloadPriority.High)
                        {
                            insertIndex = i;
                            break;
                        }
                        
                        // Prioridad 2: Entre mismo nivel, ordenar por tamaño si está activado
                        if (priorityBySize && task.Priority == existing.Priority && existing.File.SizeBytes > file.SizeBytes)
                        {
                            insertIndex = i;
                            break;
                        }
                    }
                    downloadQueue.Insert(insertIndex, task);
                    var priorityLabel = isGutenberg ? "[GUTENBERG]" : "";
                    AutoLog($"Agregado a cola (pos {insertIndex}) {priorityLabel}: {file.FileName} ({downloadQueue.Count} en cola)");
                }
                else
                {
                    downloadQueue.Add(task);
                    Log($"[COLA] Agregado: {file.FileName} desde {file.Username} ({file.SizeReadable}) - Total en cola: {downloadQueue.Count}");
                }
                
                // Incrementar contador de coincidencias para el autor
                if (authorIndex.TryGetValue(file.Author, out var authorData))
                {
                    authorData.DownloadedCount++;
                    RefreshAuthorsListView();
                }
                
                // MEJORA #5: Actualizar total de descargas en sesión
                totalDownloadsInSession = Math.Max(totalDownloadsInSession, downloadQueue.Count);
            }
            
            // Actualizar UI inmediatamente
            UpdateDownloadUI(task, "En cola...");

            // Iniciar gestor si no está corriendo
            if (!downloadManagerRunning)
            {
                _ = Task.Run(async () => await StartDownloadManager());
            }
            
            // MODO AUTOMÁTICO: Limpiar resultados si hay muchos
            AutoCleanSearchResults();
        }

        private void CancelDownload(DownloadTask task)
        {
            if (task.Status == DownloadStatus.Downloading)
            {
                task.CancellationToken?.Cancel();
            }
            else if (task.Status == DownloadStatus.Queued)
            {
                lock (downloadQueueLock)
                {
                    downloadQueue.Remove(task);
                }
                task.Status = DownloadStatus.Cancelled;
                UpdateDownloadUI(task, "Cancelado");
            }
        }

        private async Task SaveAutoResultsToJsonAsync()
        {
            // Evitar escrituras concurrentes
            if (!Monitor.TryEnter(jsonSaveLock, 0))
            {
                // Ya hay otra operación de guardado en curso, salir silenciosamente
                return;
            }
            
            try
            {
                List<AutoSearchFileResult> snapshot;
                
                    snapshot = autoSearchResults.ToList();
                

                if (!System.IO.Directory.Exists(dataDir))
                {
                    System.IO.Directory.CreateDirectory(dataDir);
                }

                // Optimización #7: Comprimir con Brotli (70-90% menos espacio)
                var compressedPath = autoSearchResultsJsonPath + ".br";
                long originalSize = 0;
                long compressedSize = 0;
                
                await Task.Run(() =>
                {
                    using (var fileStream = System.IO.File.Create(compressedPath))
                    using (var brotliStream = new System.IO.Compression.BrotliStream(fileStream, System.IO.Compression.CompressionLevel.Fastest))
                    {
                        var jsonBytes = JsonSerializer.SerializeToUtf8Bytes(snapshot);
                        originalSize = jsonBytes.Length;
                        brotliStream.Write(jsonBytes, 0, jsonBytes.Length);
                        compressedSize = fileStream.Length;
                    }
                });
                
                var compressionRatio = (1 - (double)compressedSize / originalSize) * 100;
                AutoLog($"JSON comprimido: {snapshot.Count} archivos | {FormatFileSize(originalSize)} -> {FormatFileSize(compressedSize)} ({compressionRatio:F1}% reducción)");
            }
            catch (Exception ex)
            {
                AutoLog($"Error guardando JSON comprimido: {ex.Message}");
            }
            finally
            {
                Monitor.Exit(jsonSaveLock);
            }
        }

        private void SaveAutoResultsToJson()
        {
            // Versión síncrona para compatibilidad
            _ = SaveAutoResultsToJsonAsync();
        }

        private void LoadAutoResultsFromJson()
        {
            try
            {
                // Optimización #7: Intentar cargar archivo comprimido primero
                var compressedPath = autoSearchResultsJsonPath + ".br";
                List<AutoSearchFileResult> results = null;
                
                if (System.IO.File.Exists(compressedPath))
                {
                    using (var fileStream = System.IO.File.OpenRead(compressedPath))
                    using (var brotliStream = new System.IO.Compression.BrotliStream(fileStream, System.IO.Compression.CompressionMode.Decompress))
                    {
                        results = JsonSerializer.Deserialize<List<AutoSearchFileResult>>(brotliStream);
                    }
                    AutoLog($"Cargados {results?.Count ?? 0} resultados desde JSON comprimido");
                }
                else if (System.IO.File.Exists(autoSearchResultsJsonPath))
                {
                    // Fallback a JSON sin comprimir
                    var json = System.IO.File.ReadAllText(autoSearchResultsJsonPath, Encoding.UTF8);
                    results = JsonSerializer.Deserialize<List<AutoSearchFileResult>>(json);
                    AutoLog($"Cargados {results?.Count ?? 0} resultados desde JSON sin comprimir");
                }
                else
                {
                    AutoLog("No hay resultados previos guardados");
                    return;
                }

                if (results != null && results.Count > 0)
                {
                    
                        autoSearchResults = new System.Collections.Concurrent.ConcurrentBag<AutoSearchFileResult>();
                        AddRangeToAutoSearchResults(results);
                    
                }
            }
            catch (Exception ex)
            {
                AutoLog($"Error cargando JSON: {ex.Message}");
            }
        }

        private void SaveDownloadHistory()
        {
            try
            {
                List<DownloadHistory> snapshot;
                lock (downloadHistoryLock)
                {
                    snapshot = downloadHistory.ToList();
                }

                if (!System.IO.Directory.Exists(dataDir))
                {
                    System.IO.Directory.CreateDirectory(dataDir);
                }

                var json = JsonSerializer.Serialize(snapshot, new JsonSerializerOptions { WriteIndented = true });
                System.IO.File.WriteAllText(downloadHistoryPath, json, Encoding.UTF8);
            }
            catch (Exception ex)
            {
                AutoLog($"Error guardando historial: {ex.Message}");
            }
        }

        private void LoadDownloadHistory()
        {
            try
            {
                if (!System.IO.File.Exists(downloadHistoryPath))
                    return;

                var json = System.IO.File.ReadAllText(downloadHistoryPath, Encoding.UTF8);
                var history = JsonSerializer.Deserialize<List<DownloadHistory>>(json);

                if (history != null)
                {
                    lock (downloadHistoryLock)
                    {
                        downloadHistory.Clear();
                        downloadHistory.AddRange(history);
                    }
                    AutoLog($"Cargado historial: {history.Count} descargas");
                }
            }
            catch (Exception ex)
            {
                AutoLog($"Error cargando historial: {ex.Message}");
            }
        }
        
        private void ScanDownloadFolderToHistory(Action<string> log = null)
        {
            try
            {
                var downloadPath = txtDownloadDir?.Text ?? 
                    Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.MyDocuments), "SlskDown");
                
                if (!System.IO.Directory.Exists(downloadPath))
                {
                    log?.Invoke($"Carpeta de descargas no existe: {downloadPath}");
                    return;
                }
                
                log?.Invoke("Escaneando carpeta de descargas...");
                log?.Invoke($"   Ruta: {downloadPath}");
                var sw = System.Diagnostics.Stopwatch.StartNew();
                
                var files = System.IO.Directory.GetFiles(downloadPath, "*.*", SearchOption.AllDirectories)
                    .Where(f => !f.EndsWith(".zst", StringComparison.OrdinalIgnoreCase))
                    .ToList();
                
                log?.Invoke($"   Encontrados {files.Count:N0} archivos");
                
                lock (downloadHistoryLock)
                {
                    downloadHistory.Clear();
                    downloadHistoryCache.Clear();
                    
                    foreach (var filePath in files)
                    {
                        try
                        {
                            var fileInfo = new FileInfo(filePath);
                            var fileName = Path.GetFileName(filePath);
                            
                            // Usar HashSet para verificación O(1) en vez de .Any() O(n)
                            if (!downloadHistoryCache.Contains(fileName))
                            {
                                downloadHistory.Add(new DownloadHistory
                                {
                                    FileName = fileName,
                                    Author = "", // No tenemos esta info del archivo
                                    Hash = "", // Se calculará si es necesario
                                    Username = "", // No tenemos esta info del archivo
                                    SizeBytes = fileInfo.Length,
                                    DownloadedAt = fileInfo.LastWriteTime,
                                    Status = "Existente",
                                    SpeedMBps = 0
                                });
                                downloadHistoryCache.Add(fileName);
                            }
                        }
                        catch (Exception ex)
                        {
                            log?.Invoke($"Error procesando {Path.GetFileName(filePath)}: {ex.Message}");
                        }
                    }
                }
                
                sw.Stop();
                downloadHistoryLoaded = true;
                log?.Invoke($"Historial de descargas inicializado:");
                log?.Invoke($"   • Total archivos: {downloadHistory.Count:N0}");
                log?.Invoke($"   • Tiempo: {sw.ElapsedMilliseconds:N0}ms ({sw.Elapsed.TotalSeconds:F1}s)");
            }
            catch (Exception ex)
            {
                log?.Invoke($"Error escaneando carpeta de descargas: {ex.Message}");
                downloadHistoryLoaded = true; // Marcar como cargado para no reintentar
            }
        }
        
        private bool IsAlreadyDownloaded(string fileName, string username, long size)
        {
            // Si el historial no está cargado aún, no filtrar (evitar falsos positivos)
            if (!downloadHistoryLoaded)
                return false;
            
            // Usar HashSet para lookup O(1) en vez de .Any() O(n)
            return downloadHistoryCache.Contains(fileName);
        }

        private void SaveStatistics()
        {
            try
            {
                if (!System.IO.Directory.Exists(dataDir))
                {
                    System.IO.Directory.CreateDirectory(dataDir);
                }

                var json = JsonSerializer.Serialize(statistics, new JsonSerializerOptions { WriteIndented = true });
                System.IO.File.WriteAllText(statsPath, json, Encoding.UTF8);
            }
            catch (Exception ex)
            {
                AutoLog($"Error guardando estadísticas: {ex.Message}");
            }
        }

        private void LoadStatistics()
        {
            try
            {
                if (!System.IO.File.Exists(statsPath))
                {
                    statistics = new AppStatistics();
                    return;
                }

                var json = System.IO.File.ReadAllText(statsPath, Encoding.UTF8);
                var stats = JsonSerializer.Deserialize<AppStatistics>(json);
                
                if (stats != null)
                {
                    statistics = stats;
                    AutoLog($"Estadísticas cargadas: {statistics.TotalFilesDownloaded} descargas");
                }
            }
            catch (Exception ex)
            {
                AutoLog($"Error cargando estadísticas: {ex.Message}");
                statistics = new AppStatistics();
            }
        }

        private async Task<(bool IsValid, string Message)> VerifyFileIntegrity(string filePath, long expectedSize)
        {
            try
            {
                if (!System.IO.File.Exists(filePath))
                    return (false, "Archivo no existe");

                var fileInfo = new FileInfo(filePath);
                
                // Verificar tamaño
                if (fileInfo.Length != expectedSize)
                {
                    return (false, $"Tamaño incorrecto: {fileInfo.Length} bytes (esperado: {expectedSize})");
                }

                // Calcular hash con BLAKE3 (10x más rápido que MD5)
                try
                {
                    var hashString = await Task.Run(() => SlskDownCore.HashFileBlake3(filePath));
                    return (true, $"BLAKE3: {hashString}");
                }
                catch (Exception hashEx)
                {
                    // Fallback a MD5 si Rust falla
                    AutoLog($"Error con BLAKE3, usando MD5: {hashEx.Message}");
                    using (var md5 = System.Security.Cryptography.MD5.Create())
                    using (var stream = System.IO.File.OpenRead(filePath))
                    {
                        var hash = await Task.Run(() => md5.ComputeHash(stream));
                        var hashString = BitConverter.ToString(hash).Replace("-", "").ToLowerInvariant();
                        return (true, $"MD5: {hashString}");
                    }
                }
            }
            catch (Exception ex)
            {
                return (false, $"Error: {ex.Message}");
            }
        }

        private string OrganizeDownloadedFile(string filePath, AutoSearchFileResult fileInfo)
        {
            try
            {
                if (!System.IO.File.Exists(filePath))
                    return filePath;

                var downloadDir = Path.GetDirectoryName(filePath);
                var fileName = Path.GetFileName(filePath);

                // Crear estructura de carpetas
                string targetFolder = downloadDir;

                // Por idioma
                if (fileInfo.IsSpanish)
                {
                    targetFolder = Path.Combine(targetFolder, "Español");
                }
                else
                {
                    targetFolder = Path.Combine(targetFolder, "Otros_Idiomas");
                }

                // Por tipo
                if (fileInfo.IsDocument)
                {
                    targetFolder = Path.Combine(targetFolder, "Documentos");
                }
                else
                {
                    targetFolder = Path.Combine(targetFolder, "Otros");
                }

                // Por autor (sanitizar nombre)
                var authorFolder = SanitizeFolderName(fileInfo.Author);
                targetFolder = Path.Combine(targetFolder, authorFolder);

                // Crear carpetas si no existen
                if (!System.IO.Directory.Exists(targetFolder))
                {
                    System.IO.Directory.CreateDirectory(targetFolder);
                }

                // Mover archivo
                var newPath = Path.Combine(targetFolder, fileName);
                
                // Si ya existe, agregar número
                int counter = 1;
                while (System.IO.File.Exists(newPath))
                {
                    var nameWithoutExt = Path.GetFileNameWithoutExtension(fileName);
                    var extension = Path.GetExtension(fileName);
                    newPath = Path.Combine(targetFolder, $"{nameWithoutExt}_{counter}{extension}");
                    counter++;
                }

                System.IO.File.Move(filePath, newPath);
                AutoLog($"Organizado: {fileName} -> {Path.GetFileName(targetFolder)}");
                
                return newPath;
            }
            catch (Exception ex)
            {
                AutoLog($"Error organizando archivo: {ex.Message}");
                return filePath;
            }
        }

        private string SanitizeFolderName(string name)
        {
            if (string.IsNullOrWhiteSpace(name))
                return "Sin_Autor";

            var invalidChars = Path.GetInvalidFileNameChars();
            var sanitized = string.Join("_", name.Split(invalidChars, StringSplitOptions.RemoveEmptyEntries));
            
            // Limitar longitud
            if (sanitized.Length > 50)
                sanitized = sanitized.Substring(0, 50);

            return sanitized.Trim();
        }
        
        /// <summary>
        /// Obtiene el path de descarga, organizando por idioma y autor si está activado
        /// Estructura: baseDir/español/Autor/archivo.epub
        /// </summary>
        private string GetDownloadPath(string baseDir, string fileName, string authorName = null)
        {
            if (organizeByAuthor && !string.IsNullOrWhiteSpace(authorName))
            {
                // Detectar si el archivo es en español
                bool isSpanish = IsSpanishText(fileName);
                
                string targetDir;
                if (isSpanish)
                {
                    // Estructura: baseDir/español/Autor
                    var spanishFolder = Path.Combine(baseDir, "español");
                    targetDir = Path.Combine(spanishFolder, SanitizeFolderName(authorName));
                }
                else
                {
                    // Estructura: baseDir/Autor (sin subcarpeta de idioma)
                    targetDir = Path.Combine(baseDir, SanitizeFolderName(authorName));
                }
                
                System.IO.Directory.CreateDirectory(targetDir);
                return Path.Combine(targetDir, fileName);
            }
            else
            {
                // Descarga directa en la carpeta base
                return Path.Combine(baseDir, fileName);
            }
        }

