        private async Task PurgeAuthorsWithoutResults()
        {
            if (allAuthorsData.Count == 0)
            {
                AutoLog("⚠️ No se puede purgar: lista vacía.");
                return;
            }
            
            if (client == null)
            {
                AutoLog("⚠️ No se puede purgar: cliente Soulseek no inicializado.");
                return;
            }
            
            // Verificación detallada de conexión
            var clientState = client.State;
            AutoLog($"🔌 Estado de conexión: {clientState}");
            
            if (!client.State.HasFlag(SoulseekClientStates.Connected) && !client.State.HasFlag(SoulseekClientStates.LoggedIn))
            {
                AutoLog("⚠️ No se puede purgar: no estás conectado a Soulseek.");
                AutoLog("💡 Conecta primero usando el botón 'Conectar' en la pestaña Búsqueda.");
                return;
            }

            var allAuthors = allAuthorsData.Select(a => a.Name).ToList();
            if (allAuthors.Count == 0) return;

            AutoLog("");
            AutoLog($"📋 PURGA: Verificando {allAuthors.Count} autores...");
            AutoLog($"🔌 Conectado a Soulseek: {clientState}");
            if (chkAutoSpanishDocuments?.Checked == true) AutoLog("🌍 Filtro: Solo documentos en español");
            AutoLog("⏱️ Timeout por búsqueda: 30 segundos");
            AutoLog("🔄 Búsquedas paralelas: 3");
            AutoLog("");

            autoPurgeRunning = true;

            autoSearchCts?.Dispose();
            autoSearchCts = new CancellationTokenSource();
            var cancellationToken = autoSearchCts.Token;

            // Habilitar botón Detener DIRECTAMENTE
            if (btnStopAuto != null)
            {
                btnStopAuto.Enabled = true;
                btnStopAuto.BackColor = Color.FromArgb(0, 255, 0); // Verde
                btnStopAuto.Refresh();
            }
            if (btnPurge != null)
                btnPurge.Enabled = false;
            if (btnStartAuto != null)
                btnStartAuto.Enabled = false;

            var authorsWithFiles = new HashSet<string>();
            var authorsWithErrors = new HashSet<string>();
            int successfulSearches = 0;
            int failedSearches = 0;

            foreach (var author in allAuthors)
            {
                UpdateAuthorData(author, 0, "En cola");
            }

            try
            {
                using (var semaphore = new SemaphoreSlim(3))
                {
                    await Task.WhenAll(allAuthors.Select(async author =>
                {
                    await semaphore.WaitAsync(cancellationToken);
                    try
                    {
                        if (!autoPurgeRunning || cancellationToken.IsCancellationRequested)
                        {
                            return;
                        }

                        AutoLog($"    🔍 Buscando: {author}...");
                        UpdateAuthorStatus(author, "Buscando...");

                        var searchStart = DateTime.Now;
                        var results = await client.SearchAsync(SearchQuery.FromText(author),
                            options: new Soulseek.SearchOptions(searchTimeout: 30000, maximumPeerQueueLength: 50000, filterResponses: false, minimumResponseFileCount: 1, minimumPeerUploadSpeed: 0),
                            cancellationToken: cancellationToken);
                        var searchDuration = (DateTime.Now - searchStart).TotalSeconds;

                        var responses = results.Responses;
                        var responseCount = responses?.Count ?? 0;
                        var filesCount = responses?.Sum(r => r.Files?.Count ?? 0) ?? 0;
                        AutoLog($"        ⏱️ Búsqueda completada en {searchDuration:F1}s - {responseCount} respuestas, {filesCount} archivos");
                        bool hasValid = false;

                        if (responses != null)
                        {
                            foreach (var response in responses)
                            {
                                if (response.Files == null) continue;
                                
                                // Validación más permisiva
                                foreach (var file in response.Files)
                                {
                                    if (!IsDocumentFile(file.Filename)) continue;
                                    
                                    // Si el filtro español está desactivado, aceptar cualquier documento
                                    if (chkAutoSpanishDocuments?.Checked != true)
                                    {
                                        hasValid = true;
                                        break;
                                    }
                                    
                                    // Si está activado, validación más permisiva:
                                    // Aceptar si NO es obviamente inglés (en lugar de requerir evidencia positiva de español)
                                    var filename = file.Filename.ToLower();
                                    bool isObviouslyEnglish = filename.Contains(" the ") || filename.Contains(" of ") || 
                                                             filename.Contains(" and ") || filename.Contains(" in ") ||
                                                             filename.EndsWith("ing.pdf") || filename.EndsWith("ing.epub") ||
                                                             filename.EndsWith("tion.pdf") || filename.EndsWith("tion.epub");
                                    
                                    if (!isObviouslyEnglish)
                                    {
                                        hasValid = true;
                                        break;
                                    }
                                }
                                
                                if (hasValid) break;
                            }
                        }

                        if (hasValid)
                        {
                            lock (authorsWithFiles) authorsWithFiles.Add(author);
                            AutoLog($"        ✅ {author}: {responseCount} respuestas, {filesCount} archivos, válido: sí");
                            UpdateAuthorData(author, filesCount, "Válido", Color.LightGreen);
                            System.Threading.Interlocked.Increment(ref successfulSearches);
                        }
                        else
                        {
                            AutoLog($"        ❌ {author}: {responseCount} respuestas, {filesCount} archivos, válido: no");
                            UpdateAuthorData(author, filesCount, "Sin resultados", Color.LightCoral);
                            System.Threading.Interlocked.Increment(ref successfulSearches);
                        }
                    }
                    catch (OperationCanceledException)
                    {
                        AutoLog($"        {author}: Búsqueda cancelada");
                        UpdateAuthorData(author, 0, "Cancelado", Color.Gray);
                        lock (authorsWithErrors) authorsWithErrors.Add(author);
                    }
                    catch (Exception ex)
                    {
                        AutoLog($"        ❌ Error buscando {author}: {ex.Message}");
                        UpdateAuthorData(author, 0, $"Error", Color.Khaki);
                        lock (authorsWithErrors) authorsWithErrors.Add(author);
                        System.Threading.Interlocked.Increment(ref failedSearches);
                    }
                    finally
                    {
                        semaphore.Release();
                    }
                }));
                } // Cerrar using del semaphore

                AutoLog("");
                AutoLog($"📊 Resumen de búsquedas:");
                AutoLog($"   ✅ Exitosas: {successfulSearches}");
                AutoLog($"   ❌ Con errores: {failedSearches}");
                AutoLog($"   📁 Con archivos válidos: {authorsWithFiles.Count}");
                AutoLog("");

                // Solo eliminar autores si hubo búsquedas exitosas
                // No eliminar si todos fallaron por error de red
                if (failedSearches >= allAuthors.Count * 0.8) // Si más del 80% falló
                {
                    AutoLog("⚠️ ADVERTENCIA: Más del 80% de las búsquedas fallaron.");
                    AutoLog("⚠️ Posible problema de conexión. NO se eliminarán autores.");
                    AutoLog("💡 Verifica tu conexión a Soulseek y vuelve a intentar.");
                }
                else
                {
                    // Solo eliminar autores que NO tuvieron errores Y NO tienen archivos
                    var toRemove = allAuthorsData.Where(a => 
                        !authorsWithFiles.Contains(a.Name) && 
                        !authorsWithErrors.Contains(a.Name)
                    ).ToList();
                    
                    foreach (var author in toRemove)
                    {
                        AutoLog($"        🗑️ Eliminado: {author.Name} (sin archivos válidos)");
                        allAuthorsData.Remove(author);
                    }
                    
                    filteredAuthorsData = new List<AuthorData>(allAuthorsData);
                    RefreshAuthorsListView();
                    UpdateAuthorCount();

                    if (cancellationToken.IsCancellationRequested)
                    {
                        AutoLog($"\n⏹️ PURGA CANCELADA: {authorsWithFiles.Count} válidos, {toRemove.Count} eliminados, {authorsWithErrors.Count} con errores\n");
                    }
                    else
                    {
                        AutoLog($"\n✅ PURGA COMPLETADA: {authorsWithFiles.Count} válidos, {toRemove.Count} eliminados, {authorsWithErrors.Count} con errores\n");
                    }
                }
            }
            finally
            {
                autoPurgeRunning = false;
                
                // Restaurar botones DIRECTAMENTE
                if (btnStopAuto != null)
                {
                    btnStopAuto.Enabled = false;
                    btnStopAuto.BackColor = Color.FromArgb(150, 0, 0); // Rojo oscuro
                    btnStopAuto.Refresh();
                }
                if (btnPurge != null)
                    btnPurge.Enabled = true;
                if (btnStartAuto != null)
                    btnStartAuto.Enabled = true;
                    
                AutoLog("Botones restaurados");
            }
        }

