        /// <summary>
        /// Ejecuta una acción en el thread de UI de forma segura
        /// </summary>
        private void SafeInvoke(Action action)
        {
            if (InvokeRequired)
            {
                try
                {
                    BeginInvoke(action); // No bloqueante - evita deadlocks
                }
                catch (ObjectDisposedException)
                {
                    // Control ya destruido, ignorar
                }
                catch (InvalidOperationException)
                {
                    // Thread de destino ya no existe, ignorar
                }
            }
            else
            {
                try
                {
                    action();
                }
                catch (ObjectDisposedException)
                {
                    // Control ya destruido, ignorar
                }
                catch (InvalidOperationException)
                {
                    // Thread de destino ya no existe, ignorar
                }
            }
        }

        /// <summary>
        /// Actualiza un control de forma thread-safe
        /// </summary>
        private void UpdateControl(Control control, Action<Control> updateAction)
        {
            if (control == null) return;
            SafeInvoke(() => updateAction(control));
        }
        
        /// <summary>
        /// Ejecuta una acción en el thread de UI de forma asíncrona (no bloqueante)
        /// Usar cuando NO necesitas esperar el resultado
        /// </summary>
        private void SafeBeginInvoke(Action action)
        {
            if (IsDisposed || Disposing) return;
            
            try
            {
                if (InvokeRequired)
                    BeginInvoke(action);
                else
                    action();
            }
            catch (ObjectDisposedException)
            {
                // Control ya destruido, ignorar
            }
            catch (InvalidOperationException)
            {
                // Handle cerrado, ignorar
            }
        }

        /// <summary>
        /// Actualiza el texto de un control de forma thread-safe
        /// </summary>
        private void UpdateControlText(Control? control, string text)
        {
            if (control == null) return;
            SafeInvoke(() => control.Text = text);
        }

        /// <summary>
        /// Actualiza el estado enabled de un control de forma thread-safe
        /// </summary>
        private void UpdateControlEnabled(Control? control, bool enabled)
        {
            if (control == null) return;
            SafeInvoke(() => control.Enabled = enabled);
        }
        
        private DateTime lastUpdateTime = DateTime.MinValue;
        private const int UPDATE_THROTTLE_MS = 500; // Actualizar UI máximo cada 500ms
        
        /// <summary>
        /// Actualiza los resultados de búsqueda usando Virtual ListView
        /// </summary>
        private void UpdateSearchResults(List<SearchResultItem> items)
        {
            // Validación de entrada
            if (items == null || items.Count == 0)
            {
                SafeInvoke(() =>
                {
                    lock (lvResultsLock)
                    {
                        if (lvResults != null && lblResultsCount != null)
                        {
                            lvResults.BeginUpdate();
                            try
                            {
                                lvResults.Items.Clear();
                                lblResultsCount.Text = "0 archivos";
                            }
                            finally
                            {
                                lvResults.EndUpdate();
                            }
                        }
                    }
                });
                return;
            }
            
            // Throttling: solo actualizar si han pasado 500ms desde la última actualización
            var now = DateTime.Now;
            if ((now - lastUpdateTime).TotalMilliseconds < UPDATE_THROTTLE_MS)
            {
                return; // Saltar esta actualización para no saturar el UI thread
            }
            lastUpdateTime = now;
            
            SafeInvoke(() =>
            {
                // Sincronizar acceso a lvResults para evitar parpadeo
                lock (lvResultsLock)
                {
                    try
                    {
                        // Validar que lvResults existe y está inicializado
                        if (lvResults == null || lvResults.IsDisposed)
                        {
                            Log("lvResults no está disponible");
                            return;
                        }
                        
                        // Suspender redibujado durante actualización masiva
                        lvResults.BeginUpdate();
                        try
                        {
                            lvResults.Items.Clear();
                        
                        // Crear lista de items para agregar
                        var listItems = new List<ListViewItem>();
                        for (int i = 0; i < items.Count; i++)
                        {
                            try
                            {
                                var item = items[i];
                                if (item == null) continue;
                                
                                // Detectar fuente (Soulseek por defecto, eMule si viene del NetworkOrchestrator)
                                var source = SlskDown.Core.SourceIdentifier.SearchSource.Soulseek;
                                if (item.Source != null && item.Source.Contains("emule", StringComparison.OrdinalIgnoreCase))
                                    source = SlskDown.Core.SourceIdentifier.SearchSource.EMule;
                                
                                // Crear item con icono de fuente
                                var sourceIcon = SlskDown.Core.SourceIdentifier.GetSourceIcon(source);
                                var listItem = new ListViewItem(sourceIcon);
                                listItem.SubItems.Add(item.Username ?? "");
                                listItem.SubItems.Add(item.Filename ?? "");
                                listItem.SubItems.Add(FormatSize(item.Size));
                                listItem.SubItems.Add(item.Extension ?? "");
                                listItem.SubItems.Add(item.FolderPath ?? "");
                                listItem.Tag = item;
                                
                                // Aplicar color de fuente
                                var sourceColor = SlskDown.Core.SourceIdentifier.GetSourceColor(source);
                                listItem.SubItems[0].ForeColor = sourceColor; // Columna fuente con color distintivo
                                
                                // Aplicar colores según calidad
                                if (!string.IsNullOrEmpty(item.Extension) && item.Extension.ToLower() == ".flac")
                                    listItem.ForeColor = Color.FromArgb(50, 255, 255);
                                else if (item.Bitrate >= 320)
                                    listItem.ForeColor = Color.FromArgb(50, 255, 50);
                                else if (item.Bitrate >= 192)
                                    listItem.ForeColor = Color.FromArgb(255, 255, 50);
                                else if (item.Size > 100 * 1024 * 1024)
                                    listItem.ForeColor = Color.FromArgb(255, 80, 80);
                                
                                listItems.Add(listItem);
                            }
                            catch (Exception ex)
                            {
                                Log($"Error procesando item {i}: {ex.Message}");
                            }
                        }
                        
                        // Agregar todos los items de una vez
                        if (listItems.Count > 0)
                        {
                            lvResults.Items.AddRange(listItems.ToArray());
                        }
                        
                        if (lblResultsCount != null)
                        {
                            lblResultsCount.Text = $"{listItems.Count:N0} archivos";
                        }
                    }
                        finally
                        {
                            // Reanudar redibujado
                            lvResults.EndUpdate();
                        }
                    }
                    catch (Exception ex)
                    {
                        Log($"Error en UpdateSearchResults: {ex.Message}");
                        SafeLog($"Error en UpdateSearchResults: {ex.Message}\n{ex.StackTrace}\n");
                    }
                }
            });
        }
        
        /// <summary>
        /// Agrega resultados incrementalmente
        /// </summary>
        private void AddSearchResults(List<SearchResultItem> newItems)
        {
            // Throttling: solo actualizar si han pasado 500ms desde la última actualización
            var now = DateTime.Now;
            if ((now - lastUpdateTime).TotalMilliseconds < UPDATE_THROTTLE_MS)
            {
                return; // Saltar esta actualización para no saturar el UI thread
            }
            lastUpdateTime = now;
            
            SafeInvoke(() =>
            {
                // Performance tracking disabled
                {
                    // Suspender redibujado durante actualización masiva
                    lvResults.BeginUpdate();
                    try
                    {
                        // Crear array de items para agregar en batch
                        var listItems = new ListViewItem[newItems.Count];
                        for (int i = 0; i < newItems.Count; i++)
                        {
                            var item = newItems[i];
                            
                            // Detectar fuente
                            var source = SlskDown.Core.SourceIdentifier.SearchSource.Soulseek;
                            if (item.Source != null && item.Source.Contains("emule", StringComparison.OrdinalIgnoreCase))
                                source = SlskDown.Core.SourceIdentifier.SearchSource.EMule;
                            
                            // Crear item con icono de fuente
                            var sourceIcon = SlskDown.Core.SourceIdentifier.GetSourceIcon(source);
                            var listItem = new ListViewItem(sourceIcon);
                            listItem.SubItems.Add(item.Username);
                            listItem.SubItems.Add(item.Filename);
                            listItem.SubItems.Add(FormatSize(item.Size));
                            listItem.SubItems.Add(item.Extension);
                            listItem.SubItems.Add(item.FolderPath);
                            listItem.Tag = item;
                            
                            // Aplicar color de fuente
                            var sourceColor = SlskDown.Core.SourceIdentifier.GetSourceColor(source);
                            listItem.SubItems[0].ForeColor = sourceColor;
                            
                            // Aplicar colores según calidad
                            if (item.Extension.ToLower() == ".flac")
                                listItem.ForeColor = Color.FromArgb(50, 255, 255);
                            else if (item.Bitrate >= 320)
                                listItem.ForeColor = Color.FromArgb(50, 255, 50);
                            else if (item.Bitrate >= 192)
                                listItem.ForeColor = Color.FromArgb(255, 255, 50);
                            else if (item.Size > 100 * 1024 * 1024)
                                listItem.ForeColor = Color.FromArgb(255, 80, 80);
                            
                            listItems[i] = listItem;
                        }
                        
                        // Agregar todos los items de una vez (más rápido que Add individual)
                        lvResults.Items.AddRange(listItems);
                        lblResultsCount.Text = $"{lvResults.Items.Count:N0} archivos";
                    }
                    finally
                    {
                        // Reanudar redibujado
                        lvResults.EndUpdate();
                    }
                }
            });
        }
        
        /// <summary>
        /// Limpia los resultados de búsqueda
        /// </summary>
        private void ClearSearchResults()
        {
            SafeInvoke(() =>
            {
                lock (lvResultsLock)
                {
                    lvResults.BeginUpdate();
                    try
                    {
                        lvResults.Items.Clear();
                        lblResultsCount.Text = "0 archivos";
                    }
                    finally
                    {
                        lvResults.EndUpdate();
                    }
                }
            });
        }
        
        // ═══════════════════════════════════════════════════════════
        // PERSISTENCIA DE COLA DE DESCARGAS
        // ═══════════════════════════════════════════════════════════
        
        private async Task SaveDownloadQueueAsync()
        {
            // Evitar guardados simultáneos
            if (!await saveQueueSemaphore.WaitAsync(0))
            {
                return; // Ya hay un guardado en progreso, saltar
            }
            
            try
            {
                List<DownloadTask> snapshot;
                lock (downloadQueueLock)
                {
                    // Solo guardar tareas pendientes o pausadas
                    snapshot = downloadQueue
                        .Where(t => t.Status == DownloadStatus.Queued || t.Status == DownloadStatus.Paused)
                        .ToList();
                }
                
                if (snapshot.Count == 0)
                {
                    // Si no hay nada pendiente, eliminar el archivo
                    if (System.IO.File.Exists(downloadQueuePath))
                    {
                        System.IO.File.Delete(downloadQueuePath);
                    }
                    return;
                }
                
                // Crear objeto serializable (sin CancellationToken ni ListViewItem)
                var serializableQueue = snapshot.Select(t => new
                {
                    t.File,
                    t.LocalPath,
                    Status = t.Status.ToString(),
                    Priority = t.Priority.ToString(),
                    t.BytesDownloaded,
                    t.ProgressPercent
                }).ToList();
                
                var json = await Task.Run(() => JsonSerializer.Serialize(serializableQueue, new JsonSerializerOptions { WriteIndented = false }));
                
                // MEJORA #12: Comprimir cola con GZip (50-70% menos espacio)
                var jsonBytes = Encoding.UTF8.GetBytes(json);
                using (var outputStream = new FileStream(downloadQueuePath + ".gz", FileMode.Create))
                using (var gzipStream = new GZipStream(outputStream, CompressionLevel.Optimal))
                {
                    await gzipStream.WriteAsync(jsonBytes, 0, jsonBytes.Length);
                }
                
                // Eliminar archivo sin comprimir si existe
                if (System.IO.File.Exists(downloadQueuePath))
                {
                    System.IO.File.Delete(downloadQueuePath);
                }
                
                var originalSize = jsonBytes.Length;
                var compressedSize = new FileInfo(downloadQueuePath + ".gz").Length;
                var savings = (1 - (double)compressedSize / originalSize) * 100;
                
                Log($"Cola guardada (comprimida): {snapshot.Count} tareas | {FormatFileSize(compressedSize)} ({savings:F0}% ahorro)");
            }
            catch (Exception ex)
            {
                Log($"Error guardando cola de descargas: {ex.Message}");
            }
            finally
            {
                saveQueueSemaphore.Release();
            }
        }
        
        private async Task LoadDownloadQueueAsync()
        {
            try
            {
                string json;
                
                // MEJORA #12: Intentar cargar archivo comprimido primero
                if (System.IO.File.Exists(downloadQueuePath + ".gz"))
                {
                    using (var inputStream = new FileStream(downloadQueuePath + ".gz", FileMode.Open))
                    using (var gzipStream = new GZipStream(inputStream, CompressionMode.Decompress))
                    using (var reader = new StreamReader(gzipStream, Encoding.UTF8))
                    {
                        json = await reader.ReadToEndAsync();
                    }
                    Log($"📂 Cola descomprimida: {FormatFileSize(new FileInfo(downloadQueuePath + ".gz").Length)}");
                }
                else if (System.IO.File.Exists(downloadQueuePath))
                {
                    // Fallback: archivo sin comprimir (compatibilidad)
                    json = await System.IO.File.ReadAllTextAsync(downloadQueuePath, Encoding.UTF8);
                }
                else
                {
                    return;
                }
                
                var items = JsonSerializer.Deserialize<List<JsonElement>>(json);
                
                if (items != null && items.Count > 0)
                {
                    int loaded = 0;
                    foreach (var item in items)
                    {
                        try
                        {
                            // Usar TryGetProperty para evitar errores si falta alguna propiedad
                            if (!item.TryGetProperty("File", out var fileProp) ||
                                !item.TryGetProperty("LocalPath", out var localPathProp) ||
                                !item.TryGetProperty("Status", out var statusProp))
                            {
                                Log($"Descarga con datos incompletos, omitiendo...");
                                continue;
                            }
                            
                            var file = JsonSerializer.Deserialize<AutoSearchFileResult>(fileProp.GetRawText());
                            var localPath = localPathProp.GetString();
                            var status = Enum.Parse<DownloadStatus>(statusProp.GetString());
                            
                            // Verificar blacklist antes de restaurar
                            if (blacklist.Contains(file.Username))
                            {
                                Log($"⛔ Usuario bloqueado al restaurar cola async: {file.Username} - Descarga omitida: {file.FileName}");
                                continue;
                            }
                            
                            // Restaurar todas las descargas (incluidas completadas) para estadísticas
                            // Si el archivo existe y está completado, mantener estado Completed
                            var fileExists = System.IO.File.Exists(localPath);
                            var finalStatus = status;
                            
                            if (fileExists && status == DownloadStatus.Completed)
                            {
                                // Mantener como completada para el contador
                                finalStatus = DownloadStatus.Completed;
                            }
                            else if (fileExists && status != DownloadStatus.Completed)
                            {
                                // Si el archivo existe pero no estaba marcado como completado, omitir
                                continue;
                            }
                            
                            var task = new DownloadTask
                            {
                                File = file,
                                LocalPath = localPath,
                                Status = finalStatus,
                                BytesDownloaded = item.TryGetProperty("BytesDownloaded", out var bytesProp) ? bytesProp.GetInt64() : 0,
                                ProgressPercent = item.TryGetProperty("ProgressPercent", out var progressProp) ? progressProp.GetDouble() : 0
                            };
                            
                            lock (downloadQueueLock)
                            {
                                downloadQueue.Add(task);
                            }
                            
                            // Agregar a la grilla visual
                            SafeInvoke(() =>
                            {
                                if (lvDownloads != null)
                                {
                                    var downloadItem = new ListViewItem(file.FileName);
                                    downloadItem.SubItems.Add(file.Username);
                                    downloadItem.SubItems.Add($"{task.ProgressPercent:F1}%");
                                    downloadItem.SubItems.Add(GetStatusText(status));
                                    downloadItem.SubItems.Add(task.Priority.ToString());
                                    downloadItem.SubItems.Add(file.SizeReadable);
                                    downloadItem.SubItems.Add(GetMetadataStatusSync(file.FileName));
                                    downloadItem.ForeColor = GetStatusColor(status);
                                    downloadItem.Tag = task;
                                    task.ListViewItem = downloadItem;
                                    lvDownloads.Items.Add(downloadItem);
                                }
                            });
                            
                            loaded++;
                        }
                        catch (Exception ex)
                        {
                            Log($"Error restaurando tarea de descarga: {ex.Message}");
                        }
                    }
                    
                    if (loaded > 0)
                    {
                        Log($"📂 Cola de descargas restaurada: {loaded} tareas pendientes");
                        
                        // Actualizar progreso inmediatamente
                        UpdateProgressDisplay();
                        
                        // NO iniciar gestor automáticamente - el usuario debe hacerlo manualmente
                    }
                    
                    // Eliminar archivo después de cargar
                    System.IO.File.Delete(downloadQueuePath);
                }
            }
            catch (Exception ex)
            {
                Log($"Error cargando cola de descargas: {ex.Message}");
            }
        }
        
