        private void ToggleAdvancedFilters()
        {
            if (pnlAdvancedFilters == null)
            {
                Log("Panel de filtros avanzados no inicializado");
                return;
            }
            
            advancedFiltersVisible = !advancedFiltersVisible;
            pnlAdvancedFilters.Visible = advancedFiltersVisible;
            
            if (btnToggleFilters != null)
            {
                btnToggleFilters.Text = advancedFiltersVisible ? "FILTROS -" : "FILTROS +";
            }
            
            if (advancedFiltersVisible)
            {
                Log("Filtros avanzados mostrados");
            }
            else
            {
                Log("Filtros avanzados ocultados");
            }
        }
        
        private void ApplyAdvancedFilters()
        {
            if (allResults.Count == 0) return;
            
            var filtered = new List<SearchResultItem>(allResults);
            
            // Filtro por tamaño
            if (numMinSize.Value > 0)
            {
                long minBytes = (long)(numMinSize.Value * 1024 * 1024);
                filtered = filtered.Where(r => r.Size >= minBytes).ToList();
            }
            
            if (numMaxSize.Value > 0)
            {
                long maxBytes = (long)(numMaxSize.Value * 1024 * 1024);
                filtered = filtered.Where(r => r.Size <= maxBytes).ToList();
            }
            
            // Filtro por extensión
            if (cmbExtensionFilter.SelectedIndex > 0)
            {
                string ext = cmbExtensionFilter.SelectedItem.ToString();
                filtered = filtered.Where(r => r.Extension.Equals(ext, StringComparison.OrdinalIgnoreCase)).ToList();
            }
            
            // Filtro por bitrate
            if (numMinBitrate.Value > 0)
            {
                filtered = filtered.Where(r => r.Bitrate >= numMinBitrate.Value).ToList();
            }
            
            // Filtro por slots libres
            if (chkOnlyFreeSlots.Checked)
            {
                filtered = filtered.Where(r => r.FreeUploadSlots > 0).ToList();
            }
            
            // Ordenar
            switch (cmbSortBy.SelectedIndex)
            {
                case 1: // Tamaño ↑
                    filtered = filtered.OrderBy(r => r.Size).ToList();
                    break;
                case 2: // Tamaño ↓
                    filtered = filtered.OrderByDescending(r => r.Size).ToList();
                    break;
                case 3: // Nombre A-Z
                    filtered = filtered.OrderBy(r => r.Filename).ToList();
                    break;
                case 4: // Usuario A-Z
                    filtered = filtered.OrderBy(r => r.Username).ToList();
                    break;
                case 5: // Velocidad ↑
                    filtered = filtered.OrderByDescending(r => r.UploadSpeed).ToList();
                    break;
            }
            
            // Aplicar filtro de texto también
            if (!string.IsNullOrWhiteSpace(txtFilterResults.Text))
            {
                var filterText = txtFilterResults.Text.ToLower();
                filtered = filtered.Where(r => 
                    r.Filename.ToLower().Contains(filterText) || 
                    r.Username.ToLower().Contains(filterText) ||
                    r.FolderPath.ToLower().Contains(filterText)
                ).ToList();
            }
            
            UpdateSearchResults(filtered);
            SafeInvoke(() => lblResultsCount.Text = $"{filtered.Count:N0} / {allResults.Count:N0} archivos");
        }
        
        // ===== COLA DE DESCARGAS INTELIGENTE =====
        
        private void ApplyQueuePrioritization()
        {
            if (queueStrategy == QueuePrioritizationStrategy.Manual)
            {
                Log("✋ Modo manual - no se aplica priorización automática");
                return;
            }
            
            lock (downloadQueueLock)
            {
                var pendingTasks = downloadQueue.Where(t => t.Status == DownloadStatus.Queued).ToList();
                
                if (pendingTasks.Count == 0)
                {
                    Log("No hay descargas pendientes para priorizar");
                    return;
                }
                
                List<DownloadTask> sortedTasks = queueStrategy switch
                {
                    QueuePrioritizationStrategy.FastestFirst => 
                        pendingTasks.OrderByDescending(t => t.SpeedMBps).ToList(),
                        
                    QueuePrioritizationStrategy.SmallestFirst => 
                        pendingTasks.OrderBy(t => t.File.SizeBytes).ToList(),
                        
                    QueuePrioritizationStrategy.LargestFirst => 
                        pendingTasks.OrderByDescending(t => t.File.SizeBytes).ToList(),
                        
                    QueuePrioritizationStrategy.Balanced => 
                        // Balance: priorizar archivos pequeños
                        pendingTasks.OrderBy(t => 
                        {
                            double speed = t.SpeedMBps > 0 ? t.SpeedMBps : 1;
                            double sizeMB = t.File.SizeBytes / (1024.0 * 1024.0);
                            // Menor score = mayor prioridad
                            // Favorece archivos pequeños con velocidad conocida
                            return sizeMB / (speed + 1);
                        }).ToList(),
                        
                    _ => pendingTasks
                };
                
                // Reasignar prioridades basadas en el orden
                for (int i = 0; i < sortedTasks.Count; i++)
                {
                    sortedTasks[i].Priority = (DownloadPriority)(sortedTasks.Count - i); // Mayor número = mayor prioridad
                }
                
                Log($"🎯 Priorización aplicada a {sortedTasks.Count} descargas pendientes");
                
                // Actualizar UI si es necesario
                SafeInvoke(() =>
                {
                    // Refrescar la vista de descargas para mostrar nuevas prioridades
                    UpdateDownloadListView();
                });
            }
        }
        
        private void UpdateDownloadListView()
        {
            // Método auxiliar para refrescar la vista de descargas
            // Esto actualizará el orden visual basado en las nuevas prioridades
            lock (downloadQueueLock)
            {
                var sortedQueue = downloadQueue
                    .OrderByDescending(t => t.Priority)
                    .ThenBy(t => t.Status)
                    .ToList();
                
                lvDownloads.BeginUpdate();
                lvDownloads.Items.Clear();
                
                foreach (var task in sortedQueue)
                {
                    // Detectar fuente
                    var source = SlskDown.Core.SourceIdentifier.SearchSource.Soulseek;
                    if (task.Source != null && task.Source.Contains("emule", StringComparison.OrdinalIgnoreCase))
                        source = SlskDown.Core.SourceIdentifier.SearchSource.EMule;
                    
                    // Crear item con icono de fuente
                    var sourceIcon = SlskDown.Core.SourceIdentifier.GetSourceIcon(source);
                    var item = new ListViewItem(sourceIcon);
                    item.SubItems.Add(Path.GetFileName(task.File.FileName));
                    item.SubItems.Add(task.File.Username);
                    item.SubItems.Add(task.ProgressPercent > 0 ? $"{task.ProgressPercent:F1}%" : "0%");
                    item.SubItems.Add(GetStatusText(task.Status));
                    item.SubItems.Add(GetPriorityText(task.Priority));
                    item.SubItems.Add(task.File.SizeReadable);
                    item.SubItems.Add(GetMetadataStatusSync(task.File.FileName));
                    
                    // Aplicar color de fuente
                    var sourceColor = SlskDown.Core.SourceIdentifier.GetSourceColor(source);
                    item.SubItems[0].ForeColor = sourceColor;
                    
                    // Color según estado
                    item.ForeColor = task.Status switch
                    {
                        DownloadStatus.Completed => Color.FromArgb(0, 200, 0),
                        DownloadStatus.Failed => Color.FromArgb(200, 0, 0),
                        DownloadStatus.Downloading => Color.FromArgb(100, 200, 255),
                        DownloadStatus.Paused => Color.Gray,
                        _ => Color.White
                    };
                    
                    item.Tag = task;
                    lvDownloads.Items.Add(item);
                }
                
                lvDownloads.EndUpdate();
            }
        }
        
        private string GetStatusText(DownloadStatus status)
        {
            return status switch
            {
                DownloadStatus.Queued => "En cola",
                DownloadStatus.Downloading => "Descargando",
                DownloadStatus.Completed => "Completado",
                DownloadStatus.Failed => "Fallido",
                DownloadStatus.Cancelled => "Cancelado",
                DownloadStatus.Paused => "Pausado",
                _ => "Desconocido"
            };
        }
        
        private string GetPriorityText(DownloadPriority priority)
        {
            return priority switch
            {
                DownloadPriority.High => "Alta",
                DownloadPriority.Normal => "Normal",
                DownloadPriority.Low => "Baja",
                _ => "Normal"
            };
        }
        
        private Color GetStatusColor(DownloadStatus status)
        {
            return status switch
            {
                DownloadStatus.Queued => Color.LightGray,
                DownloadStatus.Downloading => Color.LightBlue,
                DownloadStatus.Completed => Color.LightGreen,
                DownloadStatus.Failed => Color.LightCoral,
                DownloadStatus.Cancelled => Color.Orange,
                DownloadStatus.Paused => Color.Yellow,
                _ => Color.White
            };
        }
        
        private async Task<string> GetMetadataStatus(string fileName)
        {
            try
            {
                var (title, author) = ParseFileName(fileName);
                if (string.IsNullOrEmpty(title)) return "Sin metadata";
                
                // Verificar si hay metadata en caché
                string cacheKey = $"synopsis_{title}_{author}";
                var cachedMetadata = GetCachedMetadata<BookMetadata>(cacheKey);
                
                if (cachedMetadata != null)
                {
                    return "OK";
                }
                
                // Si no está en caché, intentar buscar (sin bloquear UI)
                var metadata = await FetchBookMetadataFromGoogleBooks(title, author);
                if (metadata != null && !string.IsNullOrEmpty(metadata.Synopsis))
                {
                    SetCachedMetadata(cacheKey, metadata);
                    return "OK";
                }
                
                // Intentar Open Library
                metadata = await FetchBookMetadataFromOpenLibrary(title, author);
                if (metadata != null && !string.IsNullOrEmpty(metadata.Synopsis))
                {
                    SetCachedMetadata(cacheKey, metadata);
                    return "OK";
                }
                
                return "Sin metadata";
            }
            catch
            {
                return "?";
            }
        }
        
        private string GetMetadataStatusSync(string fileName)
        {
            try
            {
                var (title, author) = ParseFileName(fileName);
                if (string.IsNullOrEmpty(title)) return "Sin metadata";
                
                // Solo verificar caché (sin hacer peticiones HTTP)
                string cacheKey = $"synopsis_{title}_{author}";
                var cachedMetadata = GetCachedMetadata<BookMetadata>(cacheKey);
                
                return cachedMetadata != null ? "OK" : "?";
            }
            catch
            {
                return "?";
            }
        }

        // Comparador personalizado para ListView
        private class ListViewItemComparer : System.Collections.IComparer
        {
            public int ColumnIndex { get; set; }
            public bool Ascending { get; set; }
            private Func<ListViewItem, int, IComparable> GetSortValue { get; set; }

            public ListViewItemComparer(int columnIndex, bool ascending, Func<ListViewItem, int, IComparable> getSortValue)
            {
                ColumnIndex = columnIndex;
                Ascending = ascending;
                GetSortValue = getSortValue;
            }

            public int Compare(object x, object y)
            {
                var itemX = (ListViewItem)x;
                var itemY = (ListViewItem)y;

                var valueX = GetSortValue(itemX, ColumnIndex);
                var valueY = GetSortValue(itemY, ColumnIndex);

                int result = valueX.CompareTo(valueY);
                return Ascending ? result : -result;
            }
        }
    
