        private void AddToWishlist()
        {
            var dialog = new Form
            {
                Text = "Agregar a Lista de Deseos",
                Size = new Size(450, 280),
                StartPosition = FormStartPosition.CenterParent,
                BackColor = Color.FromArgb(30, 30, 30),
                ForeColor = Color.White,
                FormBorderStyle = FormBorderStyle.FixedDialog,
                MaximizeBox = false,
                MinimizeBox = false
            };
            
            var lblSearch = new Label { Text = "Término de búsqueda:", Location = new Point(20, 20), AutoSize = true, ForeColor = Color.White };
            var txtSearch = new TextBox { Location = new Point(20, 45), Size = new Size(400, 25), BackColor = Color.FromArgb(50, 50, 50), ForeColor = Color.White };
            
            var lblAuthor = new Label { Text = "Autor (opcional):", Location = new Point(20, 80), AutoSize = true, ForeColor = Color.White };
            var txtAuthor = new TextBox { Location = new Point(20, 105), Size = new Size(400, 25), BackColor = Color.FromArgb(50, 50, 50), ForeColor = Color.White };
            
            var lblNotes = new Label { Text = "Notas (opcional):", Location = new Point(20, 140), AutoSize = true, ForeColor = Color.White };
            var txtNotes = new TextBox { Location = new Point(20, 165), Size = new Size(400, 25), BackColor = Color.FromArgb(50, 50, 50), ForeColor = Color.White };
            
            var btnOk = new Button { Text = "Agregar", Location = new Point(250, 200), Size = new Size(80, 30), DialogResult = DialogResult.OK };
            var btnCancel = new Button { Text = "Cancelar", Location = new Point(340, 200), Size = new Size(80, 30), DialogResult = DialogResult.Cancel };
            
            dialog.Controls.AddRange(new Control[] { lblSearch, txtSearch, lblAuthor, txtAuthor, lblNotes, txtNotes, btnOk, btnCancel });
            dialog.AcceptButton = btnOk;
            dialog.CancelButton = btnCancel;
            
            if (dialog.ShowDialog() == DialogResult.OK && !string.IsNullOrWhiteSpace(txtSearch.Text))
            {
                var item = new WishlistItem
                {
                    SearchTerm = txtSearch.Text.Trim(),
                    Author = txtAuthor.Text.Trim(),
                    DateAdded = DateTime.Now,
                    Notes = txtNotes.Text.Trim(),
                    AutoSearch = true
                };
                
                wishlist.Add(item);
                // SaveWishlist(); // TODO: Implementar método SaveWishlist
                RefreshWishlistUI(null, "");
                Log($"⭐ Agregado a wishlist: {item.SearchTerm}");
            }
        }
        
        private void RemoveFromWishlist()
        {
            var lvWishlist = FindWishlistView();
            if (lvWishlist == null || lvWishlist.SelectedItems.Count == 0) return;
            
            var selectedIndex = lvWishlist.SelectedIndices[0];
            if (selectedIndex >= 0 && selectedIndex < wishlist.Count)
            {
                var item = wishlist[selectedIndex];
                wishlist.RemoveAt(selectedIndex);
                // SaveWishlist(); // TODO: Implementar método SaveWishlist
                RefreshWishlistUI(lvWishlist, "");
                Log($"Eliminado de wishlist: {item.SearchTerm}");
            }
        }
        
        private async Task SearchWishlistItems()
        {
            if (wishlist.Count == 0)
            {
                MessageBox.Show("La lista de deseos está vacía.", "Wishlist", MessageBoxButtons.OK, MessageBoxIcon.Information);
                return;
            }
            
            Log($"Buscando {wishlist.Count} item(s) de la wishlist...");
            
            foreach (var item in wishlist.Where(i => i.AutoSearch))
            {
                try
                {
                    Log($"Buscando: {item.SearchTerm}");
                    item.LastSearched = DateTime.Now;
                    
                    var searchClient = GetClientFromPool();
                    var searchResults = await searchClient.SearchAsync(
                        SearchQuery.FromText(item.SearchTerm),
                        options: new Soulseek.SearchOptions(
                            searchTimeout: 15000,
                            filterResponses: true,
                            minimumResponseFileCount: 1
                        )
                    );
                    
                    int foundCount = searchResults.Responses.Sum(r => r.Files.Count());
                    item.TimesFound += foundCount;
                    
                    if (foundCount > 0)
                    {
                        Log($"Encontrados {foundCount} archivo(s) para: {item.SearchTerm}");
                        // Aquí podrías agregar lógica para auto-descargar
                    }
                    else
                    {
                        Log($"No se encontraron resultados para: {item.SearchTerm}");
                    }
                    
                    await Task.Delay(1000); // Pausa entre búsquedas
                }
                catch (Exception ex)
                {
                    Log($"Error buscando {item.SearchTerm}: {ex.Message}");
                }
            }
            
            await SaveWishlistAsync();
            RefreshWishlistUI(null, "");
            Log("Búsqueda de wishlist completada");
        }
        
        private async Task LoadWishlistAsync()
        {
            try
            {
                if (System.IO.File.Exists(wishlistPath))
                {
                    var json = await System.IO.File.ReadAllTextAsync(wishlistPath);
                    wishlist = JsonSerializer.Deserialize<List<WishlistItem>>(json) ?? new List<WishlistItem>();
                    Log($"Wishlist cargada: {wishlist.Count} item(s)");
                }
            }
            catch (Exception ex)
            {
                Log($"Error cargando wishlist: {ex.Message}");
            }
        }
        
        private async Task SaveWishlistAsync()
        {
            try
            {
                var options = new JsonSerializerOptions { WriteIndented = true };
                var json = JsonSerializer.Serialize(wishlist, options);
                System.IO.File.WriteAllText(wishlistPath, json);
            }
            catch (Exception ex)
            {
                Log($"Error guardando wishlist: {ex.Message}");
            }
        }
        
        private void RefreshWishlistUI(ListView lvWishlist, string filterText = "")
        {
            if (lvWishlist == null)
            {
                lvWishlist = FindWishlistView();
            }
            
            if (lvWishlist == null) return;
            
            SafeInvoke(() =>
            {
                lvWishlist.Items.Clear();
                
                // Filtrar items si hay texto de búsqueda
                var itemsToShow = wishlist.AsEnumerable();
                if (!string.IsNullOrWhiteSpace(filterText))
                {
                    var filter = filterText.ToLowerInvariant();
                    itemsToShow = itemsToShow.Where(item =>
                        item.SearchTerm.ToLowerInvariant().Contains(filter) ||
                        (item.Author != null && item.Author.ToLowerInvariant().Contains(filter)) ||
                        (item.Notes != null && item.Notes.ToLowerInvariant().Contains(filter)));
                }
                
                foreach (var item in itemsToShow)
                {
                    var lvi = new ListViewItem(item.SearchTerm);
                    lvi.SubItems.Add(item.Author ?? "-");
                    lvi.SubItems.Add(item.DateAdded.ToString("dd/MM/yyyy"));
                    lvi.SubItems.Add(item.LastSearched?.ToString("dd/MM/yyyy HH:mm") ?? "Nunca");
                    lvi.SubItems.Add(item.TimesFound.ToString());
                    lvi.SubItems.Add(item.AutoSearch ? "Sí" : "No");
                    lvi.SubItems.Add(item.Notes ?? "-");
                    lvWishlist.Items.Add(lvi);
                }
            });
        }
        
        private ListView FindWishlistView()
        {
            foreach (TabPage tab in tabControl.TabPages)
            {
                if (tab.Text.Contains("Lista de Deseos"))
                {
                    return FindControlRecursive<ListView>(tab, "wishlistView");
                }
            }
            return null;
        }
        
        private T FindControlRecursive<T>(Control parent, string tag) where T : Control
        {
            foreach (Control ctrl in parent.Controls)
            {
                if (ctrl is T && ctrl.Tag?.ToString() == tag)
                    return (T)ctrl;
                    
                var found = FindControlRecursive<T>(ctrl, tag);
                if (found != null)
                    return found;
            }
            return null;
        }
        
        private void StartWishlistTimer()
        {
            if (wishlistSearchTimer == null)
            {
                wishlistSearchTimer = new System.Windows.Forms.Timer();
                wishlistSearchTimer.Interval = wishlistSearchIntervalMinutes * 60 * 1000;
                wishlistSearchTimer.Tick += async (s, e) =>
                {
                    // Protección contra ejecuciones concurrentes
                    if (wishlistSearchRunning)
                    {
                        Log("⚠️ Wishlist timer: búsqueda anterior aún en ejecución, omitiendo...");
                        return;
                    }
                    
                    try
                    {
                        wishlistSearchRunning = true;
                        await SearchWishlistItems();
                    }
                    catch (Exception ex)
                    {
                        Log($"❌ Error en wishlist timer: {ex.Message}");
                    }
                    finally
                    {
                        wishlistSearchRunning = false;
                    }
                };
            }
            
            wishlistSearchTimer.Start();
            Log($"Timer de wishlist iniciado (cada {wishlistSearchIntervalMinutes} min)");
        }
        
        private void StopWishlistTimer()
        {
            wishlistSearchTimer?.Stop();
            Log("Timer de wishlist detenido");
        }
        
