        // VELOCIDAD ADAPTATIVA
        // ═══════════════════════════════════════════════════════════
        
        private void UpdateAdaptiveSpeed(double speedMBps)
        {
            lock (recentSpeeds)
            {
                recentSpeeds.Add(speedMBps);
                
                // Mantener solo las últimas N velocidades
                if (recentSpeeds.Count > SPEED_HISTORY_SIZE)
                {
                    recentSpeeds.RemoveAt(0);
                }
                
                // Calcular velocidad promedio
                averageDownloadSpeed = recentSpeeds.Average();
                
                // Ajustar descargas paralelas según velocidad
                AdjustParallelDownloads();
                
                Log($"Velocidad adaptativa: {speedMBps:F2} MB/s | Promedio: {averageDownloadSpeed:F2} MB/s");
            }
        }
        
        private void AdjustParallelDownloads()
        {
            if (!adaptiveSpeed) return;
            
            int newMaxParallel = maxParallelDownloads;
            
            // Si la velocidad promedio es alta (>5 MB/s), aumentar descargas paralelas
            if (averageDownloadSpeed > 5.0 && maxParallelDownloads < 6)
            {
                newMaxParallel = Math.Min(maxParallelDownloads + 1, 6);
                Log($"Velocidad alta detectada, aumentando descargas paralelas a {newMaxParallel}");
            }
            // Si la velocidad promedio es baja (<1 MB/s), reducir descargas paralelas
            else if (averageDownloadSpeed < 1.0 && maxParallelDownloads > 1)
            {
                newMaxParallel = Math.Max(maxParallelDownloads - 1, 1);
                Log($"Velocidad baja detectada, reduciendo descargas paralelas a {newMaxParallel}");
            }
            // Si la velocidad es media (1-5 MB/s), mantener o ajustar a 3
            else if (averageDownloadSpeed >= 1.0 && averageDownloadSpeed <= 5.0 && maxParallelDownloads != 3)
            {
                newMaxParallel = 3;
                Log($"Velocidad media detectada, ajustando descargas paralelas a {newMaxParallel}");
            }
            
            // Actualizar si cambió
            if (newMaxParallel != maxParallelDownloads)
            {
                maxParallelDownloads = newMaxParallel;
                
                // Actualizar UI si existe el control
                SafeInvoke(() =>
                {
                    if (numParallelDownloads != null)
                    {
                        numParallelDownloads.Value = maxParallelDownloads;
                    }
                });
            }
        }
        
