        private void ShowMetadataForSelectedFile()
        {
            try
            {
                // Verificar que hay un archivo seleccionado
                if (lvDownloads.SelectedItems.Count == 0)
                {
                    MessageBox.Show(
                        "Selecciona un archivo descargado primero.",
                        "Información",
                        MessageBoxButtons.OK,
                        MessageBoxIcon.Information);
                    return;
                }

                var selectedItem = lvDownloads.SelectedItems[0];
                var fileName = selectedItem.Text; // Columna 0: Archivo
                
                // Buscar el archivo en la carpeta de descargas
                var filePath = FindDownloadedFile(fileName);
                
                if (string.IsNullOrEmpty(filePath) || !System.IO.File.Exists(filePath))
                {
                    MessageBox.Show(
                        $"No se pudo encontrar el archivo:\n{fileName}\n\nVerifica que la descarga se haya completado correctamente.",
                        "Archivo no encontrado",
                        MessageBoxButtons.OK,
                        MessageBoxIcon.Warning);
                    return;
                }

                // Abrir ventana de metadata
                Log($"📖 Abriendo metadata para: {fileName}");
                var metadataViewer = new BookMetadataViewer(filePath);
                metadataViewer.ShowDialog();
            }
            catch (Exception ex)
            {
                Log($"Error al mostrar metadata: {ex.Message}");
                MessageBox.Show(
                    $"Error al abrir metadata:\n{ex.Message}",
                    "Error",
                    MessageBoxButtons.OK,
                    MessageBoxIcon.Error);
            }
        }
        
        private string FindDownloadedFile(string fileName)
        {
            try
            {
                // Buscar en la carpeta de descargas y subcarpetas
                var files = System.IO.Directory.GetFiles(downloadDir, fileName, SearchOption.AllDirectories);
                
                if (files.Length > 0)
                {
                    return files[0]; // Retornar el primero encontrado
                }
                
                // Si no se encuentra, intentar con búsqueda más flexible (sin extensión)
                var fileNameWithoutExt = Path.GetFileNameWithoutExtension(fileName);
                files = System.IO.Directory.GetFiles(downloadDir, $"{fileNameWithoutExt}.*", SearchOption.AllDirectories);
                
                if (files.Length > 0)
                {
                    return files[0];
                }
            }
            catch (Exception ex)
            {
                Log($"Error buscando archivo: {ex.Message}");
            }
            
            return null;
        }
        
        private (string title, string author) ParseFileName(string fileName)
        {
            // Limpiar extensión y caracteres especiales
            fileName = Path.GetFileNameWithoutExtension(fileName);
            fileName = fileName.Replace("_", " ").Replace(".", " ");
            
            // Patrón: "Autor - Titulo"
            if (fileName.Contains(" - "))
            {
                var parts = fileName.Split(new[] { " - " }, 2, StringSplitOptions.None);
                return (parts[1].Trim(), parts[0].Trim());
            }
            
            // Patrón: "Titulo (Autor)"
            if (fileName.Contains("(") && fileName.Contains(")"))
            {
                var titleEnd = fileName.IndexOf("(");
                var authorStart = fileName.IndexOf("(") + 1;
                var authorEnd = fileName.IndexOf(")");
                
                if (titleEnd > 0 && authorEnd > authorStart)
                {
                    var title = fileName.Substring(0, titleEnd).Trim();
                    var author = fileName.Substring(authorStart, authorEnd - authorStart).Trim();
                    return (title, author);
                }
            }
            
            // Si no hay patrón reconocible, asumir que todo es el título
            return (fileName, null);
        }
        
        // ============================================================================
        // MODO AUTOMÁTICO - Simplificación UI
        // ============================================================================
        
        private void InitializeAutoMode()
        {
            if (!autoMode) return;
            
            // Timer para limpieza automática de cachés (cada hora)
            autoCleanupTimer = new System.Windows.Forms.Timer();
            autoCleanupTimer.Interval = 60 * 60 * 1000; // 1 hora
            autoCleanupTimer.Tick += (s, e) => AutoCleanOldCaches();
            autoCleanupTimer.Start();
            
            // Timer para test de conexión (cada 5 minutos)
            autoTestTimer = new System.Windows.Forms.Timer();
            autoTestTimer.Interval = 5 * 60 * 1000; // 5 minutos
            autoTestTimer.Tick += async (s, e) =>
            {
                // Protección contra ejecuciones concurrentes
                if (autoTestRunning)
                    return;
                
                try
                {
                    autoTestRunning = true;
                    await AutoTestConnection();
                }
                catch (Exception ex)
                {
                    Log($"❌ Error en auto test timer: {ex.Message}");
                }
                finally
                {
                    autoTestRunning = false;
                }
            };
            autoTestTimer.Start();
            
            // Auto-inicio de cola al conectar
            if (client != null && client.State == SoulseekClientStates.Connected)
            {
                AutoStartQueue();
            }
            
            // Ejecutar limpieza inicial
            AutoCleanOldCaches();
        }
        
        private void StopAutoMode()
        {
            autoCleanupTimer?.Stop();
            autoCleanupTimer?.Dispose();
            autoTestTimer?.Stop();
            autoTestTimer?.Dispose();
        }
        
        private void AutoCleanOldCaches()
        {
            if (!autoMode) return;
            
            try
            {
                // Limpieza de archivos de caché antiguos
                var cacheFiles = new[]
                {
                    Path.Combine(dataDir, "search_cache.json"),
                    Path.Combine(dataDir, "metadata_cache.json"),
                    Path.Combine(dataDir, "provider_cache.json")
                };
                
                int deleted = 0;
                foreach (var file in cacheFiles)
                {
                    if (System.IO.File.Exists(file))
                    {
                        var lastWrite = System.IO.File.GetLastWriteTime(file);
                        if ((DateTime.Now - lastWrite).TotalDays > 30)
                        {
                            System.IO.File.Delete(file);
                            deleted++;
                            AutoLog($"Auto-limpieza: {Path.GetFileName(file)} (>30 días)");
                        }
                    }
                }
                
                if (deleted > 0)
                {
                    AutoLog($"Modo Automático: {deleted} caché(s) antigua(s) eliminada(s)");
                }
                
                // Limpieza de memoria: autoSearchResults
                if (autoSearchResults.Count > CLEANUP_THRESHOLD)
                {
                    CleanupOldAutoSearchResults();
                }
                
                // Limpieza de caché de texto español
                if (spanishTextCache.Count > MAX_SPANISH_CACHE_SIZE * 0.9)
                {
                    spanishTextCache.Clear();
                    AutoLog($"🧹 Caché de texto español limpiado");
                }
                
                // Limpieza de caché de autores
                var oldCacheEntries = authorSearchCache
                    .Where(kvp => (DateTime.Now - kvp.Value.cached).TotalHours > AUTHOR_CACHE_HOURS)
                    .Select(kvp => kvp.Key)
                    .ToList();
                
                foreach (var key in oldCacheEntries)
                {
                    authorSearchCache.Remove(key);
                }
                
                if (oldCacheEntries.Count > 0)
                {
                    AutoLog($"🧹 {oldCacheEntries.Count} entradas de caché de autores eliminadas");
                }
            }
            catch (Exception ex)
            {
                AutoLog($"Error en auto-limpieza: {ex.Message}");
            }
        }
        
        private async Task AutoTestConnection()
        {
            if (!autoMode) return;
            
            try
            {
                // Solo testear si no hay actividad reciente
                if (client != null && client.State == SoulseekClientStates.Connected)
                {
                    var lastActivity = DateTime.Now; // TODO: trackear última actividad
                    if ((DateTime.Now - lastActivity).TotalMinutes > 5)
                    {
                        await TestConnection();
                    }
                }
            }
            catch (Exception ex)
            {
                AutoLog($"Error en auto-test: {ex.Message}");
            }
        }
        
        private void AutoStartQueue()
        {
            if (!autoMode) return;
            
            try
            {
                lock (downloadQueueLock)
                {
                    var pausedTasks = downloadQueue.Where(t => t.Status == DownloadStatus.Paused).ToList();
                    if (pausedTasks.Count > 0)
                    {
                        foreach (var task in pausedTasks)
                        {
                            task.Status = DownloadStatus.Queued;
                            SafeInvoke(() =>
                            {
                                if (task.ListViewItem != null)
                                {
                                    task.ListViewItem.SubItems[3].Text = "Pendiente";
                                    task.ListViewItem.ForeColor = Color.Yellow;
                                }
                            });
                        }
                        
                        AutoLog($"Modo Automático: {pausedTasks.Count} descarga(s) reanudada(s)");
                    }
                }
            }
            catch (Exception ex)
            {
                AutoLog($"Error en auto-inicio de cola: {ex.Message}");
            }
        }
        
        private void AutoCleanSearchResults()
        {
            if (!autoMode) return;
            
            try
            {
                // Limpiar resultados después de añadir a descargas
                SafeInvoke(() =>
                {
                    if (lvResults != null && lvResults.Items.Count > 100)
                    {
                        ClearSearchResults();
                        allResults.Clear();
                        AutoLog("Modo Automático: Resultados de búsqueda limpiados (>100 items)");
                    }
                });
            }
            catch (Exception ex)
            {
                AutoLog($"Error en auto-limpieza de resultados: {ex.Message}");
            }
        }
        
        private async Task<bool> AutoDetectDuplicate(string fileName, string downloadPath)
        {
            if (!autoMode) return false;
            
            try
            {
                // Usar Rust para detección rápida de duplicados
                var existingFiles = System.IO.Directory.GetFiles(downloadDir, "*.epub", SearchOption.AllDirectories)
                    .Concat(System.IO.Directory.GetFiles(downloadDir, "*.mobi", SearchOption.AllDirectories))
                    .Concat(System.IO.Directory.GetFiles(downloadDir, "*.pdf", SearchOption.AllDirectories))
                    .Select(f => Path.GetFileName(f))
                    .ToList();
                
                foreach (var existing in existingFiles)
                {
                    double similarity = SlskDownCore.CalculateSimilarity(fileName, existing);
                    if (similarity > 0.85) // 85% similar
                    {
                        AutoLog($"Duplicado detectado: {fileName} ≈ {existing} ({similarity:P0})");
                        
                        var result = MessageBox.Show(
                            $"Archivo similar encontrado:\n\n" +
                            $"Nuevo: {fileName}\n" +
                            $"Existente: {existing}\n" +
                            $"Similitud: {similarity:P0}\n\n" +
                            $"¿Descargar de todos modos?",
                            "Duplicado Detectado",
                            MessageBoxButtons.YesNo,
                            MessageBoxIcon.Question
                        );
                        
                        return result == DialogResult.No;
                    }
                }
            }
            catch (Exception ex)
            {
                AutoLog($"Error en auto-detección de duplicados: {ex.Message}");
            }
            
            return false;
        }
        
