        private async Task SaveProgressCheckpoint(int processed, List<string> allAuthors)
        {
            try
            {
                var checkpoint = new
                {
                    ProcessedCount = processed,
                    TotalCount = allAuthors.Count,
                    RemainingAuthors = allAuthors.Skip(processed).ToList(),
                    Timestamp = DateTime.Now,
                    TotalResults = autoSearchResults.Count
                };
                
                var json = JsonSerializer.Serialize(checkpoint, new JsonSerializerOptions { WriteIndented = true });
                await System.IO.File.WriteAllTextAsync(checkpointPath, json);
                
                AutoLog($"Checkpoint guardado: {processed}/{allAuthors.Count} autores procesados");
            }
            catch (Exception ex)
            {
                AutoLog($"⚠️ Error guardando checkpoint: {ex.Message}");
            }
        }
        
        private async Task<List<string>> LoadCheckpointIfExists(List<string> authors)
        {
            try
            {
                if (!System.IO.File.Exists(checkpointPath))
                    return authors;
                
                var json = await System.IO.File.ReadAllTextAsync(checkpointPath);
                var checkpoint = JsonSerializer.Deserialize<JsonElement>(json);
                
                var processed = checkpoint.GetProperty("ProcessedCount").GetInt32();
                var total = checkpoint.GetProperty("TotalCount").GetInt32();
                var timestamp = checkpoint.GetProperty("Timestamp").GetDateTime();
                var totalResults = checkpoint.GetProperty("TotalResults").GetInt32();
                
                // Solo usar checkpoint si es reciente (menos de 24h)
                if ((DateTime.Now - timestamp).TotalHours > 24)
                {
                    AutoLog("Checkpoint antiguo (>24h), ignorando");
                    System.IO.File.Delete(checkpointPath);
                    return authors;
                }
                
                var result = MessageBox.Show(
                    $"CHECKPOINT ENCONTRADO\n\n" +
                    $"Fecha: {timestamp:dd/MM/yyyy HH:mm}\n" +
                    $"Procesados: {processed}/{total} autores\n" +
                    $"Resultados: {totalResults:N0} archivos\n" +
                    $"Restantes: {total - processed} autores\n\n" +
                    $"¿Continuar desde el checkpoint?",
                    "Recuperar Progreso",
                    MessageBoxButtons.YesNo,
                    MessageBoxIcon.Question
                );
                
                if (result == DialogResult.Yes)
                {
                    var remaining = checkpoint.GetProperty("RemainingAuthors")
                        .EnumerateArray()
                        .Select(e => e.GetString())
                        .ToList();
                    
                    AutoLog($"Continuando desde checkpoint: {remaining.Count} autores restantes");
                    return remaining;
                }
                else
                {
                    System.IO.File.Delete(checkpointPath);
                    AutoLog("Checkpoint descartado, iniciando búsqueda completa");
                }
            }
            catch (Exception ex)
            {
                AutoLog($"Error cargando checkpoint: {ex.Message}");
            }
            
            return authors;
        }
        
        private void DeleteCheckpoint()
        {
            try
            {
                if (System.IO.File.Exists(checkpointPath))
                {
                    System.IO.File.Delete(checkpointPath);
                    AutoLog("Checkpoint eliminado");
                }
            }
            catch (Exception ex)
            {
                AutoLog($"Error eliminando checkpoint: {ex.Message}");
            }
        }

        private void LvAutoAuthors_ColumnClick(object sender, ColumnClickEventArgs e)
        {
            // Si se hace clic en la misma columna, invertir el orden
            if (e.Column == sortColumn)
            {
                sortAscending = !sortAscending;
            }
            else
            {
                sortColumn = e.Column;
                sortAscending = true;
            }

            // Ordenar filteredAuthorsData según la columna
            switch (sortColumn)
            {
                case 0: // Autor (Nombre)
                    filteredAuthorsData = sortAscending
                        ? filteredAuthorsData.OrderBy(a => a.Name).ToList()
                        : filteredAuthorsData.OrderByDescending(a => a.Name).ToList();
                    break;
                case 1: // Archivos (FilesCount)
                    filteredAuthorsData = sortAscending
                        ? filteredAuthorsData.OrderBy(a => a.FilesCount).ToList()
                        : filteredAuthorsData.OrderByDescending(a => a.FilesCount).ToList();
                    break;
                case 2: // Estado
                    filteredAuthorsData = sortAscending
                        ? filteredAuthorsData.OrderBy(a => a.Status).ToList()
                        : filteredAuthorsData.OrderByDescending(a => a.Status).ToList();
                    break;
            }

            // Actualizar encabezados de columnas con indicadores visuales
            string[] columnNames = { "Autor", "Archivos", "Estado" };
            for (int i = 0; i < lvAutoAuthors.Columns.Count; i++)
            {
                string header = columnNames[i];
                if (i == sortColumn)
                {
                    header += sortAscending ? " ▲" : " ▼";
                }
                lvAutoAuthors.Columns[i].Text = header;
            }

            // Recargar items en modo normal
            RefreshAuthorsListView();
        }
        
        private void LoadAuthorsIntoVirtualList(string[] authorNames)
        {
            allAuthorsData.Clear();
            authorIndex.Clear();
            
            // Calcular contadores de archivos desde autoSearchResults
            Dictionary<string, int> authorFileCounts = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
            
                if (autoSearchResults.Count > 0)
                {
                    authorFileCounts = autoSearchResults
                        .GroupBy(f => f.Author, StringComparer.OrdinalIgnoreCase)
                        .ToDictionary(g => g.Key, g => g.Count(), StringComparer.OrdinalIgnoreCase);
                }
            
            
            foreach (var name in authorNames)
            {
                if (!string.IsNullOrWhiteSpace(name))
                {
                    var trimmedName = name.Trim();
                    int filesCount = 0;
                    string status = "Listo";
                    
                    // Buscar coincidencias en autoSearchResults
                    if (authorFileCounts.TryGetValue(trimmedName, out int count))
                    {
                        filesCount = count;
                        status = $"{count} archivo(s) encontrado(s)";
                    }
                    
                    var authorData = new AuthorData
                    {
                        Name = trimmedName,
                        FilesCount = filesCount,
                        Status = status,
                        ForeColor = filesCount > 0 ? Color.LightGreen : Color.White,
                        IsChecked = true
                    };
                    allAuthorsData.Add(authorData);
                    authorIndex[authorData.Name] = authorData;
                }
            }

            filteredAuthorsData = new List<AuthorData>(allAuthorsData);
            RefreshAuthorsListView();
            UpdateAuthorCount();
        }
        
        // Indexación incremental: agregar o actualizar autores sin recargar toda la lista
        private void AddOrUpdateAuthorsIncremental(string[] newAuthorNames)
        {
            if (newAuthorNames == null || newAuthorNames.Length == 0)
                return;
            
            // Calcular contadores de archivos desde autoSearchResults
            Dictionary<string, int> authorFileCounts = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
            
            if (autoSearchResults.Count > 0)
            {
                authorFileCounts = autoSearchResults
                    .GroupBy(f => f.Author, StringComparer.OrdinalIgnoreCase)
                    .ToDictionary(g => g.Key, g => g.Count(), StringComparer.OrdinalIgnoreCase);
            }
            
            bool hasChanges = false;
            
            foreach (var name in newAuthorNames)
            {
                if (string.IsNullOrWhiteSpace(name))
                    continue;
                
                var trimmedName = name.Trim();
                
                // Si el autor ya existe, actualizar sus datos
                if (authorIndex.TryGetValue(trimmedName, out var existingAuthor))
                {
                    int filesCount = authorFileCounts.TryGetValue(trimmedName, out int count) ? count : 0;
                    
                    if (existingAuthor.FilesCount != filesCount)
                    {
                        existingAuthor.FilesCount = filesCount;
                        existingAuthor.Status = filesCount > 0 ? $"{filesCount} archivo(s) encontrado(s)" : "Listo";
                        existingAuthor.ForeColor = filesCount > 0 ? Color.LightGreen : Color.White;
                        hasChanges = true;
                    }
                }
                else
                {
                    // Autor nuevo, agregarlo
                    int filesCount = authorFileCounts.TryGetValue(trimmedName, out int count) ? count : 0;
                    
                    var authorData = new AuthorData
                    {
                        Name = trimmedName,
                        FilesCount = filesCount,
                        Status = filesCount > 0 ? $"{filesCount} archivo(s) encontrado(s)" : "Listo",
                        ForeColor = filesCount > 0 ? Color.LightGreen : Color.White,
                        IsChecked = true
                    };
                    
                    allAuthorsData.Add(authorData);
                    authorIndex[authorData.Name] = authorData;
                    hasChanges = true;
                }
            }
            
            if (hasChanges)
            {
                // Reconstruir filteredAuthorsData manteniendo el orden
                filteredAuthorsData = new List<AuthorData>(allAuthorsData);
                RefreshAuthorsListView();
                UpdateAuthorCount();
            }
        }
        
        // Actualizar contadores de archivos para todos los autores (más eficiente que recargar)
        private void RefreshAuthorFileCounts()
        {
            // Calcular contadores de archivos desde autoSearchResults
            Dictionary<string, int> authorFileCounts = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
            
            if (autoSearchResults.Count > 0)
            {
                authorFileCounts = autoSearchResults
                    .GroupBy(f => f.Author, StringComparer.OrdinalIgnoreCase)
                    .ToDictionary(g => g.Key, g => g.Count(), StringComparer.OrdinalIgnoreCase);
            }
            
            bool hasChanges = false;
            
            foreach (var author in allAuthorsData)
            {
                int filesCount = authorFileCounts.TryGetValue(author.Name, out int count) ? count : 0;
                
                if (author.FilesCount != filesCount)
                {
                    author.FilesCount = filesCount;
                    author.Status = filesCount > 0 ? $"{filesCount} archivo(s) encontrado(s)" : "Listo";
                    author.ForeColor = filesCount > 0 ? Color.LightGreen : Color.White;
                    hasChanges = true;
                }
            }
            
            if (hasChanges)
            {
                RefreshAuthorsListView();
            }
        }
        
        private void RefreshAuthorsListView()
        {
            if (lvAutoAuthors == null) return;
            
            lvAutoAuthors.BeginUpdate();
            lvAutoAuthors.Items.Clear();
            
            foreach (var author in filteredAuthorsData)
            {
                var item = new ListViewItem(author.Name)
                {
                    ForeColor = author.ForeColor,
                    BackColor = Color.FromArgb(30, 30, 30)
                };
                item.SubItems.Add(author.FilesCount.ToString());
                item.SubItems.Add(author.Status ?? "");
                lvAutoAuthors.Items.Add(item);
            }
            
            lvAutoAuthors.EndUpdate();
        }
        
