        private static HashSet<string> LoadGutenbergAuthors()
        {
            try
            {
                var baseDir = AppDomain.CurrentDomain.BaseDirectory;
                var gutenbergPath = Path.Combine(baseDir, "Data", "gutenberg_authors.txt");

                if (System.IO.File.Exists(gutenbergPath))
                {
                    var lines = System.IO.File.ReadAllLines(gutenbergPath)
                        .Where(line => !string.IsNullOrWhiteSpace(line) && !line.StartsWith("#"))
                        .Select(line => line.Trim())
                        .ToArray();
                    return new HashSet<string>(lines, StringComparer.OrdinalIgnoreCase);
                }
            }
            catch { }
            return new HashSet<string>(StringComparer.OrdinalIgnoreCase);
        }
        
        private static bool IsGutenbergAuthor(string authorName)
        {
            if (string.IsNullOrWhiteSpace(authorName))
                return false;
                
            return gutenbergAuthorsSet.Contains(authorName.Trim());
        }
        
        private void FilterAuthors(string searchText)
        {
            IEnumerable<AuthorData> baseList = allAuthorsData;
            
            // Aplicar filtro de búsqueda de texto
            if (!string.IsNullOrWhiteSpace(searchText))
            {
                var search = searchText.ToLower();
                baseList = baseList.Where(a => a.Name.ToLower().Contains(search));
            }
            
            filteredAuthorsData = baseList.ToList();

            RefreshAuthorsListView();
            UpdateAuthorCount();
        }

        private void UpdateAuthorCount()
        {
            var lblCount = lvAutoAuthors?.Parent?.Controls.Find("lblAuthorCount", true).FirstOrDefault() as Label;
            if (lblCount != null)
            {
                int total = allAuthorsData.Count;
                int filtered = filteredAuthorsData.Count;
                int selected = filteredAuthorsData.Count(a => a.IsChecked);
                
                if (total == filtered)
                {
                    lblCount.Text = $"{total:N0} autores | {selected:N0} seleccionados";
                }
                else
                {
                    lblCount.Text = $"{filtered:N0} de {total:N0} autores | {selected:N0} seleccionados";
                }
            }
        }

        private void UpdateAuthorData(string authorName, int filesCount, string status, Color? foreColor = null)
        {
            if (authorIndex.TryGetValue(authorName, out var author))
            {
                author.FilesCount = filesCount;
                author.Status = status;
                if (foreColor.HasValue)
                    author.ForeColor = foreColor.Value;

                RefreshAuthorsListView();

                if (vaciarGridRefresher != null)
                {
                    if (lvVaciarAuthors != null && lvVaciarAuthors.IsHandleCreated)
                    {
                        if (lvVaciarAuthors.InvokeRequired)
                            lvVaciarAuthors.BeginInvoke(new Action(() => vaciarGridRefresher?.Invoke()));
                        else
                            vaciarGridRefresher.Invoke();
                    }
                    else
                    {
                        vaciarGridRefresher.Invoke();
                    }
                }
            }
        }
        
        // Helper method para logging seguro (no falla si el archivo está bloqueado)
        private void SafeLog(string message)
        {
            try
            {
                // Determinar estado de conexión: S (conectado) o N (no conectado)
                var connectionStatus = (client != null && client.State.HasFlag(SoulseekClientStates.Connected)) ? "S" : "N";
                var logMessage = $"[{DateTime.Now:HH:mm:ss}|{connectionStatus}] {message}";
                System.IO.File.AppendAllText("startup_log.txt", logMessage);
            }
            catch
            {
                // Ignorar errores de logging
            }
        }

        // ===== MÉTODOS STUB PARA CARACTERÍSTICAS PENDIENTES =====
        
        private void InitializeNicotineEnhancements()
        {
            // Inicializar timer de verificación activa de conexión (estilo Nicotine+)
            // Verifica cada 30 segundos si la conexión está activa
            connectionCheckTimer = new System.Windows.Forms.Timer();
            connectionCheckTimer.Interval = 30000; // 30 segundos
            connectionCheckTimer.Tick += async (s, e) =>
            {
                // Protección contra ejecuciones concurrentes
                if (connectionCheckRunning)
                    return;
                
                try
                {
                    connectionCheckRunning = true;
                    
                    // Solo verificar si auto-reconexión está habilitada
                    if (!autoReconnect)
                        return;
                    
                    // Modo de bajo consumo: si no hay actividad por 10 minutos, reducir frecuencia
                    var timeSinceActivity = (DateTime.Now - lastActivityTime).TotalMinutes;
                    if (timeSinceActivity > 10 && !lowPowerMode)
                    {
                        lowPowerMode = true;
                        connectionCheckTimer.Interval = 60000; // 60 segundos
                        Log("Modo bajo consumo activado (sin actividad por 10min)");
                    }
                    else if (timeSinceActivity <= 10 && lowPowerMode)
                    {
                        lowPowerMode = false;
                        connectionCheckTimer.Interval = 30000; // 30 segundos
                        Log("Modo normal reactivado (actividad detectada)");
                    }
                    
                    // Verificar si el cliente está desconectado
                    if (client == null || client.State == SoulseekClientStates.Disconnected)
                    {
                        Log("Verificación activa: Cliente desconectado detectado");
                        
                        // No intentar reconectar si ya hay un intento en curso
                        if (!isReconnecting && !isConnecting)
                        {
                            Log("Iniciando reconexión automática desde verificación activa...");
                            await CheckAndReconnect();
                        }
                    }
                    else if (client != null && client.State.HasFlag(SoulseekClientStates.Connected))
                    {
                        // Verificar calidad de conexión (latencia simulada con timestamp)
                        var pingStart = DateTime.Now.Ticks;
                        try
                        {
                            // Verificar que el cliente responde
                            var state = client.State;
                            var pingEnd = DateTime.Now.Ticks;
                            lastPingTime = (pingEnd - pingStart) / TimeSpan.TicksPerMillisecond;
                            
                            if (lastPingTime > 5000) // > 5 segundos es muy lento
                            {
                                Log($"Latencia alta detectada: {lastPingTime}ms");
                            }
                        }
                        catch (Exception ex)
                        {
                            Log($"Error verificando calidad de conexión: {ex.Message}");
                        }
                    }
                    
                    // Detectar patrones de desconexión
                    DetectDisconnectionPatterns();
                }
                catch (Exception ex)
                {
                    Log($"❌ Error en connection check timer: {ex.Message}");
                }
                finally
                {
                    connectionCheckRunning = false;
                }
            };
            connectionCheckTimer.Start();
            Log("Timer de verificación de conexión iniciado (cada 30s)");
            
            // ═══════════════════════════════════════════════════════════════
            // INICIALIZAR TODAS LAS CARACTERÍSTICAS ADICIONALES
            // ═══════════════════════════════════════════════════════════════
            
            try
            {
                // FASE 3: Características Adicionales
                transferStats = new SlskDown.Core.Statistics.TransferStatistics();
                
                // Comentadas temporalmente - usar nuevas implementaciones
                // var userNotesFile = Path.Combine(dataDir, "user_notes.json");
                // userNotesSystem = new SlskDown.Core.UserNotesSystem(userNotesFile);
                // notificationSystem = new SlskDown.Core.NotificationSystem(notifyIcon);
                // autoReplySystem = new SlskDown.Core.AdvancedAutoReply(
                //     () => GetActiveDownloadsCount(),
                //     (username) => GetUserQueuePosition(username)
                // );
                // var layoutsDir = Path.Combine(dataDir, "layouts");
                // if (!System.IO.Directory.Exists(layoutsDir))
                //     System.IO.Directory.CreateDirectory(layoutsDir);
                // uiCustomization = new SlskDown.Core.UICustomization(layoutsDir);
                // similarUserFinder = new SlskDown.Core.SimilarUserFinder();
                
                // NUEVAS MEJORAS IMPLEMENTADAS
                notificationManager = new SlskDown.Core.NotificationManager();
                filterPresetManager = new SlskDown.Core.FilterPresetManager(dataDir);
                intelligentWishlistManager = new SlskDown.Core.IntelligentWishlistManager(
                    dataDir, filterPresetManager, notificationManager);
                
                // Búsquedas correlacionadas (se inicializa después de conectar)
                // correlatedSearch = new SlskDown.Core.CorrelatedSearch(client);
                
