        private void DetectDisconnectionPatterns()
        {
            // Analizar historial de desconexiones para detectar patrones
            if (disconnectHistory.Count < 3)
                return;
            
            // Obtener desconexiones de las últimas 24 horas
            var last24h = disconnectHistory.Where(d => (DateTime.Now - d).TotalHours <= 24).ToList();
            
            if (last24h.Count >= 5)
            {
                // Verificar si hay un patrón horario (desconexiones a la misma hora)
                var hours = last24h.Select(d => d.Hour).ToList();
                var hourGroups = hours.GroupBy(h => h).Where(g => g.Count() >= 3).ToList();
                
                if (hourGroups.Any())
                {
                    foreach (var group in hourGroups)
                    {
                        Log($"Patrón detectado: {group.Count()} desconexiones cerca de las {group.Key}:00h");
                        Log("Posible causa: problema de red/ISP a esa hora");
                    }
                }
                
                // Verificar si las desconexiones son muy frecuentes
                if (last24h.Count >= 10)
                {
                    Log($"Desconexiones frecuentes: {last24h.Count} en 24h");
                    Log("Posibles causas:");
                    Log("   • Conexión a Internet inestable");
                    Log("   • Firewall bloqueando conexiones");
                    Log("   • Problemas con el ISP");
                }
            }
        }

