        private void SaveConnectionLog()
        {
            try
            {
                var logPath = Path.Combine(dataDir, "connection_log.json");
                var json = System.Text.Json.JsonSerializer.Serialize(connectionLog, new System.Text.Json.JsonSerializerOptions { WriteIndented = true });
                System.IO.File.WriteAllText(logPath, json);
                Log($"Log de conexión guardado: {connectionLog.Count} eventos");
            }
            catch (Exception ex)
            {
                Log($"Error guardando log de conexión: {ex.Message}");
            }
        }
        
        private void LoadConnectionLog()
        {
            try
            {
                var logPath = Path.Combine(dataDir, "connection_log.json");
                if (System.IO.File.Exists(logPath))
                {
                    var json = System.IO.File.ReadAllText(logPath);
                    connectionLog = System.Text.Json.JsonSerializer.Deserialize<List<ConnectionEvent>>(json) ?? new List<ConnectionEvent>();
                    Log($"Log de conexión cargado: {connectionLog.Count} eventos");
                }
            }
            catch (Exception ex)
            {
                Log($"Error cargando log de conexión: {ex.Message}");
                connectionLog = new List<ConnectionEvent>();
            }
        }
        
        private void ShowConnectionStats()
        {
            Log("=== ESTADÍSTICAS DE CONEXIÓN ===");
            Log($"Tiempo total conectado: {totalConnectedTime.TotalHours:F1} horas");
            Log($"Desconexiones totales: {disconnectCount}");
            
            if (connectionStartTime.HasValue)
            {
                var currentSession = DateTime.Now - connectionStartTime.Value;
                Log($"Sesión actual: {currentSession.TotalMinutes:F1} minutos");
            }
            
            if (lastDisconnectTime.HasValue)
            {
                var timeSinceDisconnect = DateTime.Now - lastDisconnectTime.Value;
                Log($"Última desconexión: hace {timeSinceDisconnect.TotalMinutes:F1} minutos");
            }
            
            var last24h = disconnectHistory.Where(d => (DateTime.Now - d).TotalHours <= 24).Count();
            Log($"Desconexiones (24h): {last24h}");
            
            if (lastPingTime > 0)
            {
