        private void ExecuteCommand(string commandId)
        {
            if (string.IsNullOrEmpty(commandId))
                return;
            
            try
            {
                switch (commandId)
                {
                    case "search_new":
                        // txtSearch?.Focus(); // TODO: Implementar cuando txtSearch esté disponible
                        break;
                    case "downloads_view":
                        // ShowPanel(downloadsContentPanel); // TODO: Implementar cuando ShowPanel esté disponible
                        break;
                    case "stats_dashboard":
                        ShowStatsDashboard();
                        break;
                    case "config_advanced":
                        ShowAdvancedSettings();
                        break;
                    case "backup_create":
                        CreateBackupNow();
                        break;
                    case "help_shortcuts":
                        SlskDown.UI.HelpSystem.ShowAllShortcuts(this);
                        break;
                    case "network_reconnect":
                        ReconnectToServer();
                        break;
                    default:
                        Log($"Comando: {commandId}");
                        break;
                }
            }
            catch (Exception ex)
            {
                Log($"Error ejecutando comando {commandId}: {ex.Message}");
            }
        }
        
