    // Métodos de IA (Ollama)
    public partial class MainForm
    {
        private void ExecuteAICommand(AICommandParser.ParsedCommand command)
        {
            if (command == null || command.Type == AICommandParser.CommandType.None)
                return;

            try
            {
                switch (command.Type)
                {
                    case AICommandParser.CommandType.SearchAndDownload:
                        // Buscar y descargar automáticamente
                        SafeInvoke(() =>
                        {
                            // Cambiar a pestaña de búsqueda
                            if (tabControl != null)
                                tabControl.SelectedIndex = 0;

                            // Configurar filtros
                            if (command.SpanishOnly && chkSpanishOnly != null)
                                chkSpanishOnly.Checked = true;

                            if (!string.IsNullOrEmpty(command.Extension) && cmbExtension != null)
                            {
                                for (int i = 0; i < cmbExtension.Items.Count; i++)
                                {
                                    if (cmbExtension.Items[i].ToString().Contains(command.Extension, StringComparison.OrdinalIgnoreCase))
                                    {
                                        cmbExtension.SelectedIndex = i;
                                        break;
                                    }
                                }
                            }

                            // Configurar búsqueda
                            if (cmbSearch != null)
                                cmbSearch.Text = command.Query;

                            Log($"Comando IA: Buscando '{command.Query}' (Español: {command.SpanishOnly}, Ext: {command.Extension ?? "todas"})");
                        });

                        // Ejecutar búsqueda
                        _ = Task.Run(async () =>
                        {
                            await SearchAsync();

                            // Si es descarga automática, esperar resultados y descargar todos
                            if (command.AutoDownload)
                            {
                                await Task.Delay(5000); // Esperar a que lleguen resultados

                                bool hasResults = false;
                                int resultCount = 0;
                                
                                SafeInvoke(() =>
                                {
                                    if (lvResults != null && lvResults.Items.Count > 0)
                                    {
                                        // Seleccionar todos los resultados
                                        foreach (ListViewItem item in lvResults.Items)
                                            item.Selected = true;
                                        
                                        hasResults = true;
                                        resultCount = lvResults.Items.Count;
                                    }
                                });
                                
                                if (hasResults)
                                {
                                    await DownloadMultipleAsync();
                                    Log($"Comando IA: {resultCount} archivos agregados a la cola de descarga");
                                }
                                else
                                {
                                    Log($"Comando IA: No se encontraron resultados para '{command.Query}'");
                                }
                            }
                        });
                        break;

                    case AICommandParser.CommandType.Search:
                        // Solo buscar, no descargar
                        SafeInvoke(() =>
                        {
                            if (tabControl != null)
                                tabControl.SelectedIndex = 0;

                            if (command.SpanishOnly && chkSpanishOnly != null)
                                chkSpanishOnly.Checked = true;

                            if (cmbSearch != null)
                                cmbSearch.Text = command.Query;

                            Log($"Comando IA: Buscando '{command.Query}'");
                        });

                        _ = SearchAsync();
                        break;

                    case AICommandParser.CommandType.AddAuthor:
                        // Agregar autor a la lista de búsqueda automática
                        if (!string.IsNullOrEmpty(command.Author))
                        {
                            SafeInvoke(() =>
                            {
                                if (!authors.Contains(command.Author))
                                {
                                    authors.Add(command.Author);
                                    SaveAuthors();
                                    Log($"Comando IA: Autor '{command.Author}' agregado a la lista de búsqueda automática");
                                }
                                else
                                {
                                    Log($"Comando IA: Autor '{command.Author}' ya está en la lista");
                                }
                            });
                        }
                        break;
                }
            }
            catch (Exception ex)
            {
                Log($"Error ejecutando comando IA: {ex.Message}");
            }
        }

