        // Métodos auxiliares para ConcurrentBag
        // Límite de archivos en memoria para evitar fugas
        private const int MAX_AUTO_SEARCH_RESULTS = 100000; // 100k archivos máximo
        private const int CLEANUP_THRESHOLD = 90000; // Limpiar cuando se alcancen 90k
        private const int CLEANUP_TARGET = 50000; // Reducir a 50k archivos
        
        private void AddRangeToAutoSearchResults(IEnumerable<AutoSearchFileResult> items)
        {
            foreach (var item in items)
            {
                autoSearchResults.Add(item);
            }
            
            // Verificar límite de memoria y limpiar si es necesario
            if (autoSearchResults.Count >= CLEANUP_THRESHOLD)
            {
                CleanupOldAutoSearchResults();
            }
        }
        
        private void CleanupOldAutoSearchResults()
        {
            try
            {
                var count = autoSearchResults.Count;
                if (count < CLEANUP_THRESHOLD)
                    return;
                
                Log($"🧹 Limpiando archivos antiguos de memoria ({count} archivos)...");
                
                // Mantener solo los archivos más recientes
                var sortedFiles = autoSearchResults
                    .OrderByDescending(f => f.Timestamp)
                    .Take(CLEANUP_TARGET)
                    .ToList();
                
                autoSearchResults = new System.Collections.Concurrent.ConcurrentBag<AutoSearchFileResult>(sortedFiles);
                
                var removed = count - autoSearchResults.Count;
                Log($"✅ Limpieza completada: {removed} archivos antiguos eliminados, {autoSearchResults.Count} archivos retenidos");
                
                // Forzar recolección de basura para liberar memoria
                GC.Collect(2, GCCollectionMode.Optimized);
            }
            catch (Exception ex)
            {
                Log($"❌ Error en limpieza de memoria: {ex.Message}");
            }
        }
        
        private int RemoveAllFromAutoSearchResults(Func<AutoSearchFileResult, bool> predicate)
        {
            var itemsToKeep = autoSearchResults.Where(f => !predicate(f)).ToList();
            var originalCount = autoSearchResults.Count;
            autoSearchResults = new System.Collections.Concurrent.ConcurrentBag<AutoSearchFileResult>(itemsToKeep);
            return originalCount - itemsToKeep.Count;
        }
        
    }
